// ─── API RESPONSE CACHE — 12h TTL (modèle OddAlerts/Datafoot) ──────────
// Toutes les réponses API (Odds, API-Football) sont stockées en SQLite
// avec un TTL de 12h. Au boot, on charge depuis le cache au lieu de
// refaire les appels. Reset complet après 12h.

const API_CACHE_TTL = 12 * 3600 * 1000; // 12 heures

// ── QA CRIT-3 fix (bd ParisScorebis-401) ────────────────────────────────────
// Helper throttled trace pour broad catch blocks. Silence en production
// par défaut, verbose en dev OR si DEBUG_TRACE=1 env. Throttle 60s par label
// pour éviter spam logs.
const _qaTraceTs = new Map();
function _traceCatch(label, err) {
  const isDev = process.env.NODE_ENV !== 'production' || process.env.DEBUG_TRACE === '1';
  if (!isDev) return;
  const now = Date.now();
  const last = _qaTraceTs.get(label) || 0;
  if (now - last < 60000) return; // throttle 1 log/min par label
  _qaTraceTs.set(label, now);
  console.warn(`[TRACE:${label}]`, err && err.code ? `${err.code} ${err.message || ''}` : (err && err.message) || err);
}

// Fail-soft wrappers (bd ParisScorebis-amc — SQLITE_NOTADB runtime error
// observé en prod sur tv-channel route). Si la DB est corrompue/indisponible
// (disque plein, fichier overwritten, WAL/SHM cassé entre boot et runtime), on
// log une fois par minute et on retourne un cache-miss au lieu de crash le
// process. Cron de healthcheck VPS détecte le warn pour alerter ops.
//
// bd b50 — extension : si erreur SQLITE_NOTADB / SQLITE_CORRUPT au runtime,
// tenter UNE FOIS (cooldown 5min) de fermer + quarantaine + recréer la DB.
// Évite la spirale crash-loop quand le fichier est devenu invalide en cours
// d'exécution (cause D : copy/backup pendant write, ou disque plein qui
// tronque header). Auto-recovery non-destructive : rename → fresh DB.
let _apiCacheDbWarnTs = 0;
let _dbRecoveryAttemptTs = 0;
let _dbRecoveryCount = 0;
let _dbLastWarnCode = null;
const _DB_RECOVERY_COOLDOWN_MS = 5 * 60 * 1000;
// bd b50 — Module-scope cache pour route /api/v1/db-health. Doit être ici
// (PAS dans le handler) sinon let/const re-init à chaque request → cache
// jamais hit → pragma quick_check exécuté chaque appel = 5-30s sous cron-load.
let _dbHealthCacheTs = 0;
let _dbHealthCachePayload = null;
const _DB_HEALTH_CACHE_MS = 60 * 1000;
function _attemptRuntimeDbRecovery(err) {
  const code = err && err.code;
  if (code !== 'SQLITE_NOTADB' && code !== 'SQLITE_CORRUPT') return false;
  _dbLastWarnCode = code;
  const now = Date.now();
  if (now - _dbRecoveryAttemptTs < _DB_RECOVERY_COOLDOWN_MS) return false;
  _dbRecoveryAttemptTs = now;
  _dbRecoveryCount++;
  console.error(`\x1b[31m[SQLITE_RECOVERY] Runtime ${code} détecté → tentative auto-recovery (rename + fresh DB)\x1b[0m`);
  try {
    try { if (sqldb && sqldb.open) sqldb.close(); } catch (_) {}
    const stamp = new Date().toISOString().replace(/[:.]/g, '-');
    for (const suf of ['', '-wal', '-shm']) {
      try {
        if (fs.existsSync(SQLITE_FILE + suf)) {
          fs.renameSync(SQLITE_FILE + suf, `${SQLITE_FILE}.corrupt-${stamp}${suf}`);
        }
      } catch (_) {}
    }
    initSQLite();
    console.error(`\x1b[33m[SQLITE_RECOVERY] ✓ Base recréée. Données quarantaine : ${SQLITE_FILE}.corrupt-${stamp} . Recovery offline : sqlite3 ${SQLITE_FILE}.corrupt-${stamp} ".recover" | sqlite3 recovered.db\x1b[0m`);
    return true;
  } catch (e) {
    console.error('[SQLITE_RECOVERY] ✗ échec auto-recovery:', e.message);
    return false;
  }
}
function _apiCacheDbWarn(ctx, err) {
  const now = Date.now();
  if (now - _apiCacheDbWarnTs > 60_000) {
    _apiCacheDbWarnTs = now;
    console.error(`[apiCache:${ctx}] DB error: ${err && err.code || ''} ${err && err.message || err}`);
  }
  // bd b50 — auto-recovery sur erreur fatale fichier DB (SQLITE_NOTADB / SQLITE_CORRUPT)
  _attemptRuntimeDbRecovery(err);
}

function apiCacheGet(key) {
  try {
    const row = sqldb.prepare('SELECT data, expires_at FROM api_cache WHERE key = ?').get(key);
    if (!row) return null;
    if (Date.now() > row.expires_at) {
      try { sqldb.prepare('DELETE FROM api_cache WHERE key = ?').run(key); } catch (_) {}
      return null;
    }
    try { return JSON.parse(row.data); } catch { return null; }
  } catch (e) {
    _apiCacheDbWarn('get', e);
    return null; // cache-miss fail-soft
  }
}

function apiCacheSet(key, data, source, ttlMs) {
  try {
    const now = Date.now();
    const expires = now + (typeof ttlMs === 'number' && ttlMs > 0 ? ttlMs : API_CACHE_TTL);
    sqldb.prepare('INSERT OR REPLACE INTO api_cache (key, data, source, created_at, expires_at) VALUES (?, ?, ?, ?, ?)').run(
      key, JSON.stringify(data), source, now, expires
    );
  } catch (e) {
    _apiCacheDbWarn('set', e);
  }
}

function apiCacheSetBatch(entries, source) {
  try {
    const stmt = sqldb.prepare('INSERT OR REPLACE INTO api_cache (key, data, source, created_at, expires_at) VALUES (?, ?, ?, ?, ?)');
    const now = Date.now();
    const exp = now + API_CACHE_TTL;
    sqldb.transaction(() => {
      for (const [key, data] of entries) stmt.run(key, JSON.stringify(data), source, now, exp);
    })();
  } catch (e) {
    _apiCacheDbWarn('setBatch', e);
  }
}

function apiCacheClear(source) {
  if (source) {
    sqldb.prepare('DELETE FROM api_cache WHERE source = ?').run(source);
  } else {
    sqldb.prepare('DELETE FROM api_cache').run();
  }
}

// ─── bd 3vn — TTL cache homogène (Phase 1) ──────────────────────────────────
// Source unique TTL via cache_profiles.json (root projet, sibling de leagues_config.json).
// Override env var: CACHE_TTL_<PROFILE_UPPERCASE> (ex: CACHE_TTL_BSD_INCIDENTS=120000)
// Fallback: si profile.json absent OU clé absente OU parsing fail → renvoie `fallbackMs`
// → ZÉRO régression : code existant continue à utiliser TTL hardcoded en l'absence du config.
// Lecture fichier mise en cache 60s (mtime check + reload), évite I/O répété sur chemin chaud.
const _CACHE_PROFILES_FILE = path.join(__dirname, 'cache_profiles.json');
const _CACHE_PROFILES_RELOAD_MS = 60 * 1000;
let _cacheProfilesCache = { data: null, loadedAt: 0, mtimeMs: 0, lastErr: null };

function _loadCacheProfiles() {
  const now = Date.now();
  if (_cacheProfilesCache.data && (now - _cacheProfilesCache.loadedAt) < _CACHE_PROFILES_RELOAD_MS) {
    return _cacheProfilesCache.data;
  }
  try {
    const stat = fs.statSync(_CACHE_PROFILES_FILE);
    if (_cacheProfilesCache.data && stat.mtimeMs === _cacheProfilesCache.mtimeMs) {
      _cacheProfilesCache.loadedAt = now;
      return _cacheProfilesCache.data;
    }
    const raw = fs.readFileSync(_CACHE_PROFILES_FILE, 'utf8');
    const parsed = JSON.parse(raw);
    _cacheProfilesCache = { data: parsed, loadedAt: now, mtimeMs: stat.mtimeMs, lastErr: null };
    return parsed;
  } catch (e) {
    if (!_cacheProfilesCache.lastErr || _cacheProfilesCache.lastErr.code !== e.code) {
      console.warn(`  ⚠ cache_profiles.json indisponible (${e.code || e.message}) — fallbacks hardcoded utilisés`);
    }
    _cacheProfilesCache = { data: null, loadedAt: now, mtimeMs: 0, lastErr: e };
    return null;
  }
}

/**
 * getCacheTTL(profileKey, fallbackMs)
 * - Lit cache_profiles.json (cache fichier 60s + mtime invalidation)
 * - Override prioritaire: process.env.CACHE_TTL_<PROFILE_UPPERCASE> (parseInt strict)
 * - Renvoie fallbackMs si profile absent OU fichier introuvable OU env var invalide
 * → ZÉRO régression: les call sites passent leur TTL hardcoded historique en fallback.
 */
function getCacheTTL(profileKey, fallbackMs) {
  if (typeof profileKey === 'string' && profileKey.length > 0) {
    const envKey = 'CACHE_TTL_' + profileKey.toUpperCase().replace(/[^A-Z0-9_]/g, '_');
    const envVal = process.env[envKey];
    if (envVal !== undefined) {
      const n = parseInt(envVal, 10);
      if (Number.isFinite(n) && n > 0) return n;
    }
  }
  const profiles = _loadCacheProfiles();
  if (profiles && Object.prototype.hasOwnProperty.call(profiles, profileKey)) {
    const v = profiles[profileKey];
    if (Number.isFinite(v) && v > 0) return v;
  }
  if (Number.isFinite(fallbackMs) && fallbackMs > 0) return fallbackMs;
  return API_CACHE_TTL;
}

/** Diag route admin — snapshot état runtime profiles + overrides env */
function getCacheProfilesSnapshot() {
  const profiles = _loadCacheProfiles();
  const overrides = {};
  for (const k of Object.keys(process.env)) {
    if (k.startsWith('CACHE_TTL_')) {
      const n = parseInt(process.env[k], 10);
      overrides[k] = Number.isFinite(n) && n > 0 ? n : `<invalid: ${process.env[k]}>`;
    }
  }
  return {
    file: _CACHE_PROFILES_FILE,
    loadedAt: _cacheProfilesCache.loadedAt,
    mtimeMs: _cacheProfilesCache.mtimeMs,
    lastError: _cacheProfilesCache.lastErr ? (_cacheProfilesCache.lastErr.code || _cacheProfilesCache.lastErr.message) : null,
    profileCount: profiles ? Object.keys(profiles).filter(k => k !== '_meta').length : 0,
    profiles: profiles || null,
    envOverrides: overrides,
  };
}

function apiCacheCleanExpired() {
  const before = sqldb.prepare('SELECT COUNT(*) as c FROM api_cache WHERE expires_at < ?').get(Date.now());
  sqldb.prepare('DELETE FROM api_cache WHERE expires_at < ?').run(Date.now());
  return before.c;
}

function apiCacheStats() {
  const total = sqldb.prepare('SELECT COUNT(*) as c FROM api_cache').get();
  const bySource = sqldb.prepare('SELECT source, COUNT(*) as c FROM api_cache GROUP BY source').all();
  const oldest = sqldb.prepare('SELECT MIN(created_at) as min_ts FROM api_cache').get();
  const newest = sqldb.prepare('SELECT MAX(created_at) as max_ts FROM api_cache').get();
  return {
    total: total.c,
    bySource: bySource,
    oldest: oldest.min_ts ? new Date(oldest.min_ts).toISOString() : null,
    newest: newest.max_ts ? new Date(newest.max_ts).toISOString() : null,
  };
}

function oddsCacheCleanExpired() {
  const now = Date.now();
  let cleaned = 0;
  for (const key of Object.keys(oddsCache)) {
    if (now - oddsCache[key].ts > ODDS_CACHE_TTL) {
      delete oddsCache[key];
      cleaned++;
    }
  }
  return cleaned;
}

function oddsCacheStats() {
  return {
    entries: Object.keys(oddsCache).length,
    ttl_minutes: ODDS_CACHE_TTL / 60000,
    keys: Object.keys(oddsCache).slice(0, 10),
  };
}

// ─── POWER SCORE USAGE TRACKING ───────────────────────────────────────
const POWER_SCORE_COOLDOWN_IP = new Map(); // IP -> { count, reset }

function getPowerScoreUsage(userId) {
  const raw = kvGet(`ps_usage_${userId}`);
  if (!raw) return { count: 0, reset: Date.now() + 24 * 3600 * 1000 };
  if (Date.now() > raw.reset) return { count: 0, reset: Date.now() + 24 * 3600 * 1000 };
  return raw;
}

function incrementPowerScoreUsage(userId, role) {
  const usage = getPowerScoreUsage(userId);
  const limit = POWER_SCORE_LIMITS[role]?.daily ?? 1;
  if (usage.count >= limit) return { allowed: false, used: usage.count, limit };
  usage.count += 1;
  kvSet(`ps_usage_${userId}`, usage);
  return { allowed: true, used: usage.count, limit };
}

function checkIpAbuse(ip) {
  const now = Date.now();
  const entry = POWER_SCORE_COOLDOWN_IP.get(ip);
  if (!entry || now > entry.reset) {
    POWER_SCORE_COOLDOWN_IP.set(ip, { count: 1, reset: now + 60000 });
    return false;
  }
  entry.count += 1;
  if (entry.count > 30) return true; // >30 requests/minute = abuse
  return false;
}

function getRemainingQuota(userId, role) {
  const usage = getPowerScoreUsage(userId);
  const limit = POWER_SCORE_LIMITS[role]?.daily ?? 1;
  return Math.max(0, limit - usage.count);
}

// ─── QUOTA VUES TABLEAU MATCHS — Freemium : 10 vues / jour ────────────────
const FREEMIUM_MATCHES_DAILY = 10;
function getMatchesViewUsage(userId) {
  const raw = kvGet(`mv_usage_${userId}`);
  if (!raw || Date.now() > raw.reset) return { count: 0, reset: Date.now() + 24 * 3600 * 1000 };
  return raw;
}
function incrementMatchesView(userId) {
  const u = getMatchesViewUsage(userId);
  if (u.count >= FREEMIUM_MATCHES_DAILY) return { allowed: false, used: u.count, limit: FREEMIUM_MATCHES_DAILY };
  u.count += 1;
  kvSet(`mv_usage_${userId}`, u);
  return { allowed: true, used: u.count, limit: FREEMIUM_MATCHES_DAILY };
}

function kvScan(prefix) {
  return sqldb.prepare("SELECT key, value FROM kv WHERE key LIKE ?").all(prefix + '%')
    .map(row => { try { return { key: row.key, value: JSON.parse(row.value) }; } catch { return null; } })
    .filter(Boolean);
}

// ─── DATABASE ────────────────────────────────────────────────────────────────

let _lastSanityCheck = 0;
function sanityCheckTeamStats() {
  const now = Date.now();
  if (now - _lastSanityCheck < 5 * 60 * 1000) return; // cooldown 5min
  _lastSanityCheck = now;
  const issues = [];
  for (const [key, stats] of Object.entries(db.teamStats || {})) {
    if (!stats || typeof stats !== 'object') { issues.push(`${key}: invalid entry (not object)`); continue; }
    if (stats._real && stats.rank === 0) issues.push(`${key}: rank=0 (marked real data, API returned explicit 0)`);
    const homeStats = stats.home || {};
    const awayStats = stats.away || {};
    if (homeStats.ppg === 0 && homeStats.played > 5) issues.push(`${key}: home PPG=0 but played=${homeStats.played}`);
    if (awayStats.ppg === 0 && awayStats.played > 5) issues.push(`${key}: away PPG=0 but played=${awayStats.played}`);
    if (stats._real && !stats.form) {
      // Auto-repair: synthétise depuis PPG saison (deriveFormFromStats retourne ≥ 'LLLLL')
      const synForm = deriveFormFromStats(stats.home) || deriveFormFromStats(stats.away);
      if (synForm) {
        stats.form = synForm; // mute db.teamStats[key] in-place — silences future checks
      } else {
        issues.push(`${key}: empty form (real data, no PPG fallback)`);
      }
    }
  }
  if (issues.length) {
    console.error(`\x1b[31m[SANITY] ${issues.length} data anomalies detected:\x1b[0m`);
    issues.slice(0, 10).forEach(iss => console.error(`  \x1b[31m• ${iss}\x1b[0m`));
    if (issues.length > 10) console.error(`  \x1b[31m... and ${issues.length - 10} more\x1b[0m`);
    return false;
  }
  console.log(`  [SANITY] ✓ Team stats valid (${Object.keys(db.teamStats).length} teams, all checks passed)`);
  return true;
}

function saveDB() {
  // 🛡️ PROTECTION ANTI-EFFACEMENT (Zero-Data Guard)
  // Si on tente de sauvegarder un tableau vide alors qu'on avait des données, 
  // on bloque la sauvegarde pour éviter de wipe la base de données suite à une erreur API.
  if (db.matches && db.matches.length === 0 && cachedMatches.length > 0) {
    console.error('\x1b[31m[DB_GUARD] Tentative de sauvegarde d\'un tableau vide détectée ! Blocage de l\'écriture pour protéger les données.\x1b[0m');
    return;
  }

  // v9.9 #7 : ne pas persister des stats corrompues (cumuls saison / Poisson 0%)
  // — on garde le match (planning) mais on neutralise les valeurs fausses + flag.
  try {
    if (Array.isArray(db.matches)) {
      for (const _m of db.matches) {
        if (!_m || !_m.stats) continue;
        const _h = _m.stats.home || {}, _a = _m.stats.away || {};
        const _bad = [_h.avgScored, _a.avgScored, _h.avgConceded, _a.avgConceded]
          .some(v => typeof v === 'number' && v > 8) ||
          (_m.expectedGoals && (_m.expectedGoals.home > 8 || _m.expectedGoals.away > 8)) ||
          (_m.poisson && _m.poisson.homeWin === 0 && _m.poisson.draw === 0 && _m.poisson.awayWin === 0);
        if (_bad) {
          _m.bsd_status = 'FAILED_INTEGRITY';
          _m.poisson = { error: 'BAD_LAMBDA', over25: 0, btts: 0, homeWin: 0, draw: 0, awayWin: 0 };
          _m.expectedGoals = { home: 0, away: 0 };
        }
      }
    }
  } catch (_e) { /* sanitation best-effort */ }

  try {
    kvSetBatch([
      ['db_matches', db.matches],
      ['db_team_stats', db.teamStats],
      ['db_adv_stats', db.advancedTeamStats],
      ['db_top_scorers', db.topScorers],
      ['db_meta', {
        status: db.status,
        lastOddsUpdate: db.lastOddsUpdate,
        lastStatsUpdate: db.lastStatsUpdate,
        oddsQuotaRemaining: db.oddsQuotaRemaining,
        statsUpdateByLeague: db.statsUpdateByLeague
      }],
    ]);
    sanityCheckTeamStats();
  } catch (e) {
    console.error('\x1b[31m[DB_ERROR] Échec critique de la sauvegarde SQLite :\x1b[0m', e.message);
  }
  // Rebuild matchIndex pour lookups O(1)
  db.matchIndex = new Map((db.matches || []).map(m => [m.id, m]));
}

function syncCacheBuffers() {
  // 🛡️ PROTECTION ANTI-WIPE :
  // Si la base de données principale est vide, on NE SYNCHRONISE PAS les buffers.
  // On conserve les anciennes données dans cachedMatches pour éviter que le site 
  // ne devienne totalement vide en cas d'échec critique des API.
  if (!db.matches || db.matches.length === 0) {
    if (cachedMatches.length > 0) {
      console.warn('\x1b[33m[SYNC] db.matches est vide, mais cachedMatches contient des données. Protection activée : on conserve le tampon mémoire.\x1b[0m');
    }
    return;
  }

  try {
    console.log(`  [Sync] Synchronisation des buffers mémoire (${db.matches.length} matchs)...`);

    // 1. CLONAGE PROFOND (Deep Clone)
    // On utilise JSON.parse/stringify pour casser les références d'objets.
    // Cela évite qu'une modification accidentelle de db.matches n'altère cachedMatches.
    cachedMatches = JSON.parse(JSON.stringify(db.matches));

    lastCacheUpdate = Date.now();
    cacheVersion++;

    // 2. SYNCHRONISATION DES BLESSURES
    // On vide et on reconstruit le dictionnaire des blessures par ID de match.
    cachedInjuries = {};
    for (const m of db.matches) {
      if (m.injuries && Object.keys(m.injuries).length > 0) {
        cachedInjuries[m.id] = m.injuries;
      }
    }

    // 3. SYNCHRONISATION DES LIGUES ET PAYS
    // On reconstruit la liste des ligues groupées par pays.
    cachedLeagues = {};
    const leagueMap = new Map();

    for (const m of db.matches) {
      if (!m.league || m.league === '?') continue;
      const country = detectCountryFromLeague(m.league, m.sport, m.country, m._bsd_league_id);
      const key = `${m.league}__${country}`;
      if (!leagueMap.has(key)) leagueMap.set(key, { leagueName: m.league, country });
    }

    for (const { leagueName, country } of leagueMap.values()) {
      if (!cachedLeagues[country]) {
        cachedLeagues[country] = [];
      }

      // On évite les doublons dans la liste du pays
      if (!cachedLeagues[country].find(l => l.name === leagueName)) {
        cachedLeagues[country].push({
          name: leagueName,
          id: leagueName.toLowerCase().replace(/\s+/g, '_')
        });
      }
    }

    console.log(`  [Sync] ✓ Buffers mis à jour. Version: ${cacheVersion}`);
  } catch (e) {
    console.error('\x1b[31m[SYNC_ERROR] Erreur critique lors de la synchronisation des buffers :\x1b[0m', e.message);
    console.error(e.stack);
  }
}

// Helper: détecte le pays depuis le match (pays explicite > sport_key > nom ligue)
function detectCountryFromLeague(leagueName, sportKey = null, explicitCountry = null, bsdLeagueId = null) {
  const forced = forceCountryForKnownCollisions(leagueName, explicitCountry, bsdLeagueId);
  if (forced) return forced;

  const cfgBySport = getLeagueConfigBySportKey(sportKey);
  if (cfgBySport?.country) return cfgBySport.country;

  if (isHomonymLeagueName(leagueName)) {
    return 'Unknown';
  }

  const countryMap = {
    'France': ['Ligue 1', 'Ligue 2', 'Coupe de France'],
    'England': ['Championship', 'FA Cup', 'League Cup'],
    'Spain': ['La Liga', 'Segunda Division', 'Copa del Rey'],
    'Germany': ['Bundesliga', '2. Bundesliga', 'DFB Pokal'],
    'Italy': ['Serie A', 'Coppa Italia'],
    'Portugal': ['Liga Portugal', 'Taca de Portugal'],
    'Netherlands': ['Eredivisie', 'KNVB Beker'],
    'Belgium': ['Jupiler Pro League', 'Belgian Cup'],
    'Brazil': ['Brasileirao', 'Campeonato Brasileiro'],
    'Europe': ['Champions League', 'Europa League', 'Conference League'],
    'World': ['Club Friendlies', 'World Cup'],
  };
  const leagueNorm = normText(leagueName);
  for (const [country, leagues] of Object.entries(countryMap)) {
    if (leagues.some(l => leagueNorm.includes(normText(l)))) return country;
  }
  return 'Unknown';
}

function loadDB() {
  // Rétrocompat : migration one-shot depuis database.json
  if (fs.existsSync(DB_FILE)) {
    try {
      const old = JSON.parse(fs.readFileSync(DB_FILE, 'utf8'));
      db = { ...db, ...old };
      if (!db.advancedTeamStats) db.advancedTeamStats = {};
      if (!db.topScorers) db.topScorers = {};
      saveDB();
      fs.renameSync(DB_FILE, DB_FILE + '.migrated');
      console.log(`  ✓ database.json migré vers SQLite (${db.matches.length} matchs)`);
      syncCacheBuffers(); // Populate buffers from migrated data
      return;
    } catch (e) { console.warn('[DB] Migration JSON→SQLite échouée:', e.message); }
  }

  db.matches = kvGet('db_matches', []);
  db.teamStats = kvGet('db_team_stats', {});
  db.advancedTeamStats = kvGet('db_adv_stats', {});
  db.topScorers = kvGet('db_top_scorers', {});
  db.fbrefStats = {};
  const meta = kvGet('db_meta', {});
  db.status = meta.status || 'initialisation';
  db.lastOddsUpdate = meta.lastOddsUpdate || null;
  db.lastStatsUpdate = meta.lastStatsUpdate || null;
  db.statsUpdateByLeague = meta.statsUpdateByLeague || {};
  db.oddsQuotaRemaining = meta.oddsQuotaRemaining || null;

  // ─── Sanitizer cross-source (one-shot boot) ───────────────────────────────
  // Pour toute ligue couverte par BSD, on supprime les lignes `api-football`
  // périmées (saison N-1 figée d'un ancien run) qui cohabitent et faussent le
  // classement (doublons au mauvais rang, ex: K League). On efface aussi le
  // gate de fraîcheur de ces ligues pour que fetchStats les repeuple via BSD.
  try {
    const bsdCovered = new Set(Object.keys(BSD_CONFIG_TO_BSD).map(k => parseInt(k)));
    const contaminated = new Set();
    for (const k of Object.keys(db.teamStats)) {
      const s = db.teamStats[k];
      if (s && s._source === 'api-football' && bsdCovered.has(s.leagueId)) {
        contaminated.add(s.leagueId);
        delete db.teamStats[k];
      }
    }
    if (contaminated.size) {
      for (const lid of contaminated) delete db.statsUpdateByLeague[lid];
      console.warn(`  [SANITIZE] Lignes api-football périmées purgées pour ligues BSD: ${[...contaminated].join(', ')} (gate de fraîcheur réinitialisé)`);
    }
  } catch (e) {
    console.warn('  [SANITIZE] erreur:', e.message);
  }

  // ─── One-shot rank=0 cleanup ─────────────────────────────────────────────
  // API-Football returns rank=0 for some end-of-season entries; that corrupt
  // value was persisted before the guard was added. Nullify on load so the
  // sanity checker stops firing and Poisson ranking logic gets null (= unknown)
  // instead of a misleading 0.
  let rankZeroFixed = 0;
  for (const k of Object.keys(db.teamStats)) {
    if (db.teamStats[k]?.rank === 0) { db.teamStats[k].rank = null; rankZeroFixed++; }
  }
  if (rankZeroFixed) console.warn(`  [SANITIZE] ${rankZeroFixed} rank=0 entries nullified on load`);

  console.log(`  ✓ SQLite chargé (${db.matches.length} matchs, ${Object.keys(db.teamStats).length} équipes, ${Object.keys(db.advancedTeamStats).length} stats avancées)`);
  syncCacheBuffers(); // Populate buffers from SQLite on startup
}

// Backfill home_form / away_form depuis stats PPG pour les matchs sans form string
function backfillMatchForms() {
  let fixed = 0;
  for (const m of db.matches) {
    if (!m.home_form || m.home_form.length < 2) {
      const stats = m.stats?.home;
      if (stats) {
        const form = deriveFormFromStats(stats);
        if (form) { m.home_form = form; fixed++; }
      }
    }
    if (!m.away_form || m.away_form.length < 2) {
      const stats = m.stats?.away;
      if (stats) {
        const form = deriveFormFromStats(stats);
        if (form) { m.away_form = form; fixed++; }
      }
    }
  }
  if (fixed > 0) {
    console.log(`  [Backfill] ✓ ${fixed} champs home_form/away_form synthétisés depuis PPG`);
    saveDB();
  }
}

// ─── UTILS HTTPS ─────────────────────────────────────────────────────────────
function formatIsoTimestamp(date) {
  return date.toISOString().replace(/\.\d{3}Z$/, 'Z');
}

function formatDateOnly(date) {
  return date.toISOString().slice(0, 10);
}

// ── Multi-provider streaming for Deep Analysis ───────────────────────────────
// Streams text chunks via SSE events: chunk | done | error
// Tries providers in order, falls back on 429/401/5xx
function streamDeepWithProviders(promptText, res, onDone, providerIdx = 0) {
  if (providerIdx >= AI_DEEP_PROVIDERS.length) {
    try { res.write(`event: error\ndata: ${JSON.stringify({ message: 'Tous les providers IA sont indisponibles ou non configurés' })}\n\n`); res.end(); } catch { }
    return;
  }
  const prov = AI_DEEP_PROVIDERS[providerIdx];
  console.log(`  [AI-AL] Tentative ${prov.name} (idx ${providerIdx})`);

  const tryNext = (reason) => {
    console.log(`  [AI-AL] ${prov.name} → fallback (${reason})`);
    streamDeepWithProviders(promptText, res, onDone, providerIdx + 1);
  };

  if (prov.type === 'gemini') {
    // ── Gemini SSE ──────────────────────────────────────────────────────────
    const payload = JSON.stringify({
      contents: [{ parts: [{ text: promptText }] }],
      generationConfig: { temperature: 0.8, maxOutputTokens: 2800 },
      safetySettings: GEMINI_SAFETY_SETTINGS,
    });
    const gemUrl = new URL(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:streamGenerateContent?key=${GEMINI_API_KEY}&alt=sse`);
    const opts = { hostname: gemUrl.hostname, path: gemUrl.pathname + gemUrl.search, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) } };
    let fullText = '';
    const req = https.request(opts, gemRes => {
      if (gemRes.statusCode === 429 || gemRes.statusCode === 401) {
        gemRes.resume();
        return tryNext(gemRes.statusCode);
      }
      let buf = '';
      gemRes.on('data', chunk => {
        buf += chunk.toString();
        const lines = buf.split('\n'); buf = lines.pop();
        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          const raw = line.slice(6).trim();
          if (raw === '[DONE]') continue;
          try {
            const txt = JSON.parse(raw)?.candidates?.[0]?.content?.parts?.[0]?.text || '';
            if (txt) { fullText += txt; try { res.write(`event: chunk\ndata: ${JSON.stringify({ text: txt, provider: prov.name })}\n\n`); } catch { } }
          } catch { }
        }
      });
      gemRes.on('end', () => {
        if (!fullText) return tryNext('vide');
        onDone(fullText, prov.name);
      });
      gemRes.on('error', () => tryNext('erreur réseau'));
    });
    req.on('error', () => tryNext('erreur req'));
    req.write(payload); req.end();

  } else {
    // ── OpenAI-compatible SSE (Groq / Grok / OpenRouter) ────────────────────
    const payload = JSON.stringify({
      model: prov.model,
      messages: [{ role: 'user', content: promptText }],
      temperature: 0.8,
      max_tokens: 5500,
      stream: true,
    });
    const opts = {
      hostname: prov.host,
      path: prov.path,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${prov.key}`,
        'Content-Length': Buffer.byteLength(payload),
        'HTTP-Referer': 'https://pariscore.io',
        'X-Title': 'PariScore AI-AL',
      },
    };
    let fullText = '';
    const req = https.request(opts, apiRes => {
      if (apiRes.statusCode === 429 || apiRes.statusCode === 401 || apiRes.statusCode >= 500) {
        apiRes.resume();
        return tryNext(apiRes.statusCode);
      }
      let buf = '';
      apiRes.on('data', chunk => {
        buf += chunk.toString();
        const lines = buf.split('\n'); buf = lines.pop();
        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          const raw = line.slice(6).trim();
          if (raw === '[DONE]') continue;
          try {
            const txt = JSON.parse(raw)?.choices?.[0]?.delta?.content || '';
            if (txt) { fullText += txt; try { res.write(`event: chunk\ndata: ${JSON.stringify({ text: txt, provider: prov.name })}\n\n`); } catch { } }
          } catch { }
        }
      });
      apiRes.on('end', () => {
        if (!fullText) return tryNext('vide');
        onDone(fullText, prov.name);
      });
      apiRes.on('error', () => tryNext('erreur réseau'));
    });
    req.on('error', () => tryNext('erreur req'));
    req.write(payload); req.end();
  }
}

function httpsGet(urlStr, headers = {}, timeoutMs = 15000) {
  return new Promise((resolve, reject) => {
    const u = new URL(urlStr);
    const opts = {
      hostname: u.hostname, port: 443,
      path: u.pathname + (u.search || ''),
      method: 'GET',
      headers: { 'Accept': 'application/json', 'User-Agent': 'PariScore/2.0', ...headers },
    };
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, headers: res.headers, data: JSON.parse(body) });
        } catch (e) {
          resolve({ status: res.statusCode, headers: res.headers, data: body });
        }
      });
    });
    req.on('error', reject);
    req.setTimeout(timeoutMs, () => { req.destroy(); reject(new Error('Timeout')); });
    req.end();
  });
}

function httpsPost(urlStr, body, headers = {}) {
  return new Promise((resolve, reject) => {
    const u = new URL(urlStr);
    const payload = JSON.stringify(body);
    const opts = {
      hostname: u.hostname, port: 443,
      path: u.pathname + (u.search || ''),
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload), ...headers },
    };
    const req = https.request(opts, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
        catch (e) { resolve({ status: res.statusCode, data }); }
      });
    });
    req.on('error', reject);
    req.setTimeout(30000, () => { req.destroy(); reject(new Error('Timeout')); });
    req.write(payload);
    req.end();
  });
}

function mockParlayOdds() {
  return {
    status: 200,
    mocked: true,
    source: 'local-mock',
    matches: [
      { home_team: 'PSG', away_team: 'Olympique Lyonnais', league: 'Ligue 1', commence_time: new Date(Date.now() + 2 * 3600000).toISOString(), odds: { home: 1.45, draw: 4.20, away: 7.80 } },
      { home_team: 'Manchester City', away_team: 'Liverpool', league: 'Premier League', commence_time: new Date(Date.now() + 4 * 3600000).toISOString(), odds: { home: 2.10, draw: 3.40, away: 3.20 } },
    ],
  };
}

function mockGameForecast(match = {}) {
  return {
    status: 200,
    mocked: true,
    source: 'local-mock',
    home: match.home_team || 'Home',
    away: match.away_team || 'Away',
    league: match.league || 'Unknown',
    predicted: {
      homeWin: 48,
      draw: 27,
      awayWin: 25,
      value: 'BTTS probable',
    },
  };
}

async function fetchParlayOdds() {
  if (!PARLAY_API_HOST || !PARLAY_API_KEY) return mockParlayOdds();
  try {
    const qs = new URLSearchParams({ sport: 'soccer', region: 'eu', market: 'h2h', oddsFormat: 'decimal', dateFormat: 'iso', timeframe: '7d' }).toString();
    return await httpsGet(`https://${PARLAY_API_HOST}${PARLAY_API_PATH}?${qs}`, {
      'X-RapidAPI-Key': PARLAY_API_KEY,
      'X-RapidAPI-Host': PARLAY_API_HOST,
      'Accept': 'application/json',
    });
  } catch (e) {
    return { status: 500, error: e.message };
  }
}

async function fetchGameForecast(match = {}) {
  if (!GAMEFORECAST_API_HOST || !GAMEFORECAST_API_KEY) return mockGameForecast(match);
  try {
    const qs = new URLSearchParams({
      home: match.home_team || '',
      away: match.away_team || '',
      league: match.league || '',
      date: match.commence_time || '',
    }).toString();
    return await httpsGet(`https://${GAMEFORECAST_API_HOST}${GAMEFORECAST_API_PATH}?${qs}`, {
      'X-RapidAPI-Key': GAMEFORECAST_API_KEY,
      'X-RapidAPI-Host': GAMEFORECAST_API_HOST,
      'Accept': 'application/json',
    });
  } catch (e) {
    return { status: 500, error: e.message };
  }
}

function normalizeRapidApiMatches(payload) {
  const data = payload?.matches || payload?.data || payload?.response || payload;
  return Array.isArray(data) ? data : [];
}

function findParlayMatch(parlayData, match) {
  const entries = normalizeRapidApiMatches(parlayData);
  const homeKey = normName(match.home_team);
  const awayKey = normName(match.away_team);
  for (const entry of entries) {
    const entryHome = normName(entry.home_team || entry.home || '');
    const entryAway = normName(entry.away_team || entry.away || '');
    if (entryHome === homeKey && entryAway === awayKey) return entry;
    if (entryHome === awayKey && entryAway === homeKey) return entry;
  }
  return null;
}

async function getRapidApiDualCheck(matches = []) {
  const parlayData = await fetchParlayOdds();
  return Promise.all(matches.map(async match => {
    const parlayMatch = findParlayMatch(parlayData, match);
    const forecast = await fetchGameForecast(match);
    return {
      id: match.id,
      home_team: match.home_team,
      away_team: match.away_team,
      league: match.league,
      commence_time: match.commence_time,
      parlay: {
        status: parlayData.status,
        source: parlayData.mocked ? 'mock' : 'rapidapi',
        found: !!parlayMatch,
        match: parlayMatch || null,
      },
      gameForecast: {
        status: forecast.status,
        source: forecast.mocked ? 'mock' : 'rapidapi',
        data: forecast.data || forecast,
      },
    };
  }));
}

// ─── NORMALISATION & MATCHING ÉQUIPES ────────────────────────────────────────
function normName(name) {
  return (name || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim();
}

// Codes de club courants (pr\u00e9fixe/suffixe) retir\u00e9s pour la d\u00e9dup cross-source.
// normName("ACF Fiorentina") = "acf fiorentina" \u2260 "fiorentina" \u2192 faux doublon
// sans ce strip. NE PAS utiliser pour l'affichage (purement comparaison).
const _CLUB_AFFIX = new Set([
  'fc', 'afc', 'cf', 'cfc', 'fco', 'ac', 'acf', 'as', 'aas', 'ss', 'ssc', 'ssd',
  'us', 'usl', 'sc', 'scf', 'sco', 'sd', 'cd', 'ca', 'rc', 'rcd', 'ud', 'fk',
  'sk', 'nk', 'if', 'bk', 'bfc', 'bc', 'bsc', 'sv', 'vfb', 'vfl', 'vfr', 'tsg',
  'hsv', 'ogc', 'rco', 'spvgg', 'al', 'club', 'calcio', 'fbc', 'ec'
]);
function teamKey(name) {
  const n = normName(name);
  if (!n) return '';
  const toks = n.split(' ').filter(w => !_CLUB_AFFIX.has(w));
  const k = toks.join(' ').trim();
  return k || n; // si tout retir\u00e9 (nom = code seul), garder le nom brut
}
// Rapprochement tol\u00e9rant aux codes de club, sans sur-fusionner les vrais
// homonymes partiels (ex. "Manchester United" vs "Manchester City" \u2192 faux).
function xsTeamMatch(a, b) {
  const ka = teamKey(a), kb = teamKey(b);
  if (!ka || !kb) return false;
  if (ka === kb) return true;
  const ta = ka.split(' '), tb = kb.split(' ');
  const [shrt, lng] = ta.length <= tb.length ? [ta, tb] : [tb, ta];
  // tous les tokens du court pr\u00e9sents dans le long, au mot pr\u00e8s, \u22641 token d'\u00e9cart
  return lng.length - shrt.length <= 1 && shrt.every(w => lng.includes(w));
}
function xsSameMatch(exH, exA, exT, mH, mA, mT) {
  return xsTeamMatch(exH, mH) && xsTeamMatch(exA, mA) &&
    Math.abs(new Date(exT).getTime() - new Date(mT).getTime()) < 24 * 3600 * 1000;
}

// Distance de Levenshtein pour fuzzy matching robuste
function levenshtein(a, b) {
  const m = a.length, n = b.length;
  const dp = Array.from({ length: m + 1 }, (_, i) =>
    Array.from({ length: n + 1 }, (_, j) => i === 0 ? j : j === 0 ? i : 0)
  );
  for (let i = 1; i <= m; i++)
    for (let j = 1; j <= n; j++)
      dp[i][j] = a[i - 1] === b[j - 1] ? dp[i - 1][j - 1]
        : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
  return dp[m][n];
}

// bd lzdg Phase 1 — Fix perf boot CPU 80%+ findFuzzy O(N×M) sur 5000+ teamStats.
// Optimisations :
//   (a) Cache LRU 1000 entries (hit = skip levenshtein entierement)
//   (b) Prefix index char-0 lazy-rebuilt si teamStats size change → réduit candidates ~1/26
//   (c) Early exit bestDist === 0 (perfect match found)
//   (d) skipExact + excludeEntry pas cachés (collision keys complexes, fallback path original)
const _fuzzyCache = new Map();
const FUZZY_CACHE_MAX = 1000;
let _teamStatsPrefixIdx = null;
let _teamStatsIdxSize = 0;

function _rebuildTeamStatsPrefixIdx() {
  _teamStatsPrefixIdx = new Map();
  for (const k of Object.keys(db.teamStats)) {
    const c = k.charAt(0);
    let bucket = _teamStatsPrefixIdx.get(c);
    if (!bucket) { bucket = []; _teamStatsPrefixIdx.set(c, bucket); }
    bucket.push(k);
  }
  _teamStatsIdxSize = Object.keys(db.teamStats).length;
}

function _setFuzzyCacheLRU(k, v) {
  if (_fuzzyCache.size >= FUZZY_CACHE_MAX) {
    // Drop oldest (Map iteration order = insertion order)
    _fuzzyCache.delete(_fuzzyCache.keys().next().value);
  }
  _fuzzyCache.set(k, v);
}

function findFuzzy(key, { skipExact = false, excludeEntry = null } = {}) {
  if (!key) return null;
  const tsSize = Object.keys(db.teamStats).length;
  if (tsSize === 0) return null;

  // Cache lookup — only safe quand excludeEntry null (collision risk sinon)
  const cacheable = !excludeEntry;
  const cacheKey = cacheable ? `${skipExact ? 1 : 0}|${key}` : null;
  if (cacheKey && _fuzzyCache.has(cacheKey)) {
    const hit = _fuzzyCache.get(cacheKey);
    // LRU touch : delete + re-set move to end
    _fuzzyCache.delete(cacheKey);
    _fuzzyCache.set(cacheKey, hit);
    return hit;
  }

  // 1. Match exact d'abord (sauf si skipExact)
  if (!skipExact && db.teamStats[key] && db.teamStats[key] !== excludeEntry) {
    if (cacheKey) _setFuzzyCacheLRU(cacheKey, db.teamStats[key]);
    return db.teamStats[key];
  }

  // Lazy rebuild prefix index si teamStats size changed (cron stats add/remove)
  if (!_teamStatsPrefixIdx || tsSize !== _teamStatsIdxSize) {
    _rebuildTeamStatsPrefixIdx();
  }

  // 2. Prefix match firstWord — restreint au bucket char-0 du firstWord
  const firstWord = key.split(' ')[0];
  if (firstWord.length >= 4) {
    const firstWordChar = firstWord.charAt(0);
    const candidates = _teamStatsPrefixIdx.get(firstWordChar) || [];
    for (const k of candidates) {
      if (k === key && skipExact) continue;
      if (k.startsWith(firstWord) && db.teamStats[k] !== excludeEntry) {
        if (cacheKey) _setFuzzyCacheLRU(cacheKey, db.teamStats[k]);
        return db.teamStats[k];
      }
    }
  }

  // 3. Levenshtein strict — restreint au bucket char-0 du key (1/26 reduction typique)
  const keyChar = key.charAt(0);
  const candidates = _teamStatsPrefixIdx.get(keyChar) || [];
  let best = null, bestDist = Infinity;
  for (const k of candidates) {
    if (k === key && skipExact) continue;
    if (db.teamStats[k] === excludeEntry) continue;
    const dist = levenshtein(k, key);
    const threshold = key.length <= 4 ? 1 : 2;
    if (dist < bestDist && dist <= threshold) {
      bestDist = dist; best = k;
      if (bestDist === 0) break;  // perfect match — early exit
    }
  }
  const result = best ? db.teamStats[best] : null;
  if (best && !excludeEntry) {
    console.warn(`  [Fuzzy] "${key}" → "${best}" (dist=${bestDist}) — ATTENTION: match approximatif`);
  }
  if (cacheKey) _setFuzzyCacheLRU(cacheKey, result);
  return result;
}

// Saison dynamique : avant juillet → saison précédente
function currentSeason() {
  const now = new Date();
  return now.getMonth() >= 6 ? now.getFullYear() : now.getFullYear() - 1;
}

// Nettoyage des matchs expirés — 150min après kickoff, jamais pendant un live actif
// v10.5: Triple verrou — LIVE > 4h OU minute > 130 = purgé
function cleanExpiredMatches() {
  const cutoff = Date.now() - 150 * 60 * 1000;
  const staleCutoff = Date.now() - 240 * 60 * 1000; // 4h
  const before = db.matches.length;
  db.matches = db.matches.filter(m => {
    if (m.live_score) {
      // Verrou minute > 130
      const minuteVal = parseInt(m.live_minute || m.minute || 0);
      if (minuteVal > 130) {
        console.log(`  [Clean] Stale LIVE purged (minute > 130): ${m.home_team} vs ${m.away_team}`);
        return false;
      }
      // Verrou temporel > 4h
      const kickoff = new Date(m.commence_time).getTime();
      if (!isNaN(kickoff) && kickoff < staleCutoff) {
        console.log(`  [Clean] Stale LIVE purged (> 4h): ${m.home_team} vs ${m.away_team}`);
        return false;
      }
      return true;
    }
    return new Date(m.commence_time).getTime() > cutoff;
  });
  const removed = before - db.matches.length;
  if (removed > 0) console.log(`  [Clean] ${removed} matchs expirés supprimés`);
}

// ─── CALCUL DES PROBABILITÉS ─────────────────────────────────────────────────

// Distribution de Poisson : P(X=k) = (λ^k × e^-λ) / k!
function poissonPMF(lambda, k) {
  if (lambda <= 0) return k === 0 ? 1 : 0;
  let logP = -lambda + k * Math.log(lambda);
  for (let i = 2; i <= k; i++) logP -= Math.log(i); // log(k!)
  return Math.exp(logP);
}

// Matrice de scores (jusqu'à 6-6) → dérive toutes les probas de marché
function computePoisson(expHome, expAway) {
  const MAX = 7;
  const matrix = [];
  for (let h = 0; h < MAX; h++) {
    matrix[h] = [];
    for (let a = 0; a < MAX; a++) {
      matrix[h][a] = poissonPMF(expHome, h) * poissonPMF(expAway, a);
    }
  }

  let over05 = 0, over15 = 0, over25 = 0, over35 = 0;
  let btts = 0, under15 = 0, cs00 = 0;
  let homeWin = 0, draw = 0, awayWin = 0;

  for (let h = 0; h < MAX; h++) {
    for (let a = 0; a < MAX; a++) {
      const p = matrix[h][a];
      const total = h + a;
      if (total > 0) over05 += p;
      if (total > 1) over15 += p;
      if (total > 2) over25 += p;
      if (total > 3) over35 += p;
      if (total <= 1) under15 += p;
      if (h > 0 && a > 0) btts += p;
      if (h === 0 && a === 0) cs00 = p;
      if (h > a) homeWin += p;
      if (h === a) draw += p;
      if (h < a) awayWin += p;
    }
  }

  // Top 5 scores les plus probables
  const scores = [];
  for (let h = 0; h < MAX; h++)
    for (let a = 0; a < MAX; a++)
      scores.push({ score: `${h}-${a}`, prob: matrix[h][a] });
  scores.sort((a, b) => b.prob - a.prob);

  return {
    over05: Math.round(over05 * 100),
    over15: Math.round(over15 * 100),
    over25: Math.round(over25 * 100),
    over35: Math.round(over35 * 100),
    btts: Math.round(btts * 100),
    under15: Math.round(under15 * 100),
    cs00: Math.round(cs00 * 100),
    homeWin: Math.round(homeWin * 100),
    draw: Math.round(draw * 100),
    awayWin: Math.round(awayWin * 100),
    topScores: scores.slice(0, 5).map(s => ({ score: s.score, prob: Math.round(s.prob * 100) })),
    method: 'poisson',
  };
}

// ═══════════════════════════════════════════════════════════════════════════════
// bd — Dixon-Coles (1997) : correction du Poisson indépendant pour le foot.
// Ajoute un paramètre ρ (rho) modélisant la dépendance basse entre les buts.
// τ(0,0)=1-λh·λa·ρ, τ(0,1)=1+λh·ρ, τ(1,0)=1+λa·ρ, τ(1,1)=1-ρ
// Corrige le biais du Poisson sur 0-0/1-0/0-1/1-1 (±3-5 points de proba).
// ρ calibré empiriquement: -0.05 (PL/PD/BL1/SA), -0.03 (FL1/L1 faible score)
function computeDixonColes(expHome, expAway, rho = -0.05) {
  const MAX = 7;
  const matrix = [];
  // Base Poisson indépendant
  for (let h = 0; h < MAX; h++) {
    matrix[h] = [];
    for (let a = 0; a < MAX; a++) {
      matrix[h][a] = poissonPMF(expHome, h) * poissonPMF(expAway, a);
    }
  }

  // Dixon-Coles τ adjustment (low-score correction)
  const tau00 = 1 - expHome * expAway * rho;
  const tau01 = 1 + expHome * rho;
  const tau10 = 1 + expAway * rho;
  const tau11 = 1 - rho;

  matrix[0][0] *= Math.max(0, tau00);
  matrix[0][1] *= Math.max(0, tau01);
  matrix[1][0] *= Math.max(0, tau10);
  matrix[1][1] *= Math.max(0, tau11);

  // Renormalize
  let total = 0;
  for (let h = 0; h < MAX; h++)
    for (let a = 0; a < MAX; a++)
      total += matrix[h][a];
  if (total > 0) {
    for (let h = 0; h < MAX; h++)
      for (let a = 0; a < MAX; a++)
        matrix[h][a] /= total;
  }

  let over05 = 0, over15 = 0, over25 = 0, over35 = 0;
  let btts = 0, under15 = 0, cs00 = 0;
  let homeWin = 0, draw = 0, awayWin = 0;

  for (let h = 0; h < MAX; h++) {
    for (let a = 0; a < MAX; a++) {
      const p = matrix[h][a];
      const totalG = h + a;
      if (totalG > 0) over05 += p;
      if (totalG > 1) over15 += p;
      if (totalG > 2) over25 += p;
      if (totalG > 3) over35 += p;
      if (totalG <= 1) under15 += p;
      if (h > 0 && a > 0) btts += p;
      if (h === 0 && a === 0) cs00 = p;
      if (h > a) homeWin += p;
      if (h === a) draw += p;
      if (h < a) awayWin += p;
    }
  }

  const scores = [];
  for (let h = 0; h < MAX; h++)
    for (let a = 0; a < MAX; a++)
      scores.push({ score: `${h}-${a}`, prob: matrix[h][a] });
  scores.sort((a, b) => b.prob - a.prob);

  return {
    over05: Math.round(over05 * 100),
    over15: Math.round(over15 * 100),
    over25: Math.round(over25 * 100),
    over35: Math.round(over35 * 100),
    btts: Math.round(btts * 100),
    under15: Math.round(under15 * 100),
    cs00: Math.round(cs00 * 100),
    homeWin: Math.round(homeWin * 100),
    draw: Math.round(draw * 100),
    awayWin: Math.round(awayWin * 100),
    topScores: scores.slice(0, 5).map(s => ({ score: s.score, prob: Math.round(s.prob * 100) })),
    method: 'dixon-coles',
    rho,
    // Delta vs Poisson pour diagnostic
    _dc_delta_cs00: Math.round((cs00 - (matrix[0][0] / Math.max(0.0001, tau00 > 0 ? tau00 : 1))) * 10000) / 100,
  };
}

// ═══════════════════════════════════════════════════════════════════════════════
// bd cnvg — Poisson Time-Inhomogène live (innovation backlog edge math)
//
// Recompute Poisson conditionnel minute par minute + score state. Modèle :
//   λ_remaining = λ_full × (minutes_left/90) × score_adjustment(side, score_diff)
//
// score_adjustment (heuristique tactique standard observable) :
//   trailing -2+ → ×1.40 (push désespéré)
//   trailing -1  → ×1.20 (push offensif)
//   tied         → ×1.00
//   leading +1   → ×0.85 (gestion défensive légère)
//   leading +2+  → ×0.75 (gestion défensive forte)
//
// Probabilités markets recalculées sur score FINAL = score_so_far + remaining goals.
// Retourne null si match non-live, minute hors [1,89], ou xG manquants.
// ═══════════════════════════════════════════════════════════════════════════════
function computeLivePoissonInhomogeneous(match) {
  if (!match || !match.is_live) return null;
  const minute = Number(match.live_minute) || 0;
  if (minute <= 0 || minute >= 90) return null;
  const exp = match.expectedGoals || {};
  const lambdaH = Number(exp.home) || 0;
  const lambdaA = Number(exp.away) || 0;
  if (lambdaH <= 0 || lambdaA <= 0) return null;

  // Score state actuel
  let sH = 0, sA = 0;
  if (match.live_score && /^\d+-\d+$/.test(String(match.live_score))) {
    const parts = String(match.live_score).split('-');
    sH = parseInt(parts[0], 10) || 0;
    sA = parseInt(parts[1], 10) || 0;
  }

  // Time-remaining factor (0..1)
  const minLeft = Math.max(0, 90 - minute);
  const timeFactor = minLeft / 90;

  // Score-state adjustment per side
  const adjFactor = (diff) => {
    if (diff <= -2) return 1.40;
    if (diff === -1) return 1.20;
    if (diff === 0) return 1.00;
    if (diff === 1) return 0.85;
    return 0.75; // diff >= 2
  };
  const diffH = sH - sA, diffA = sA - sH;
  const adjH = adjFactor(diffH), adjA = adjFactor(diffA);

  // bd z3fp — Context Engine weather adjustment (both sides identique).
  // Pluie >3mm/h dégrade contrôle balle + passes longues → λ ×0.92.
  // Vent >30km/h impact passes longues + crosses → λ ×0.95.
  // Effets multiplicatifs combinés si simultanés.
  let weatherFactor = 1.0;
  const mw = match.match_weather || null;
  if (mw) {
    if (mw.precipitation_mm != null && mw.precipitation_mm > 3) weatherFactor *= 0.92;
    if (mw.wind_kmh != null && mw.wind_kmh > 30) weatherFactor *= 0.95;
  }

  // bd z3fp — Context Engine travel adjustment (away only — fatigue jet-lag visiteurs).
  // Fatigue factor déjà calculé bd i8gw (0.88-1.00 selon bucket distance).
  let travelFactor = 1.0;
  const mt = match.match_travel || null;
  if (mt && typeof mt.fatigue_factor === 'number') travelFactor = mt.fatigue_factor;

  // Combine all factors
  const lambdaH_rem = lambdaH * timeFactor * adjH * weatherFactor;
  const lambdaA_rem = lambdaA * timeFactor * adjA * weatherFactor * travelFactor;

  // Recompute Poisson sur remaining goals
  const MAX = 7;
  let over05 = 0, over15 = 0, over25 = 0, over35 = 0;
  let btts = 0, under15 = 0;
  let homeWin = 0, draw = 0, awayWin = 0;
  for (let h = 0; h < MAX; h++) {
    for (let a = 0; a < MAX; a++) {
      const p = poissonPMF(lambdaH_rem, h) * poissonPMF(lambdaA_rem, a);
      const finalH = sH + h, finalA = sA + a;
      const total = finalH + finalA;
      if (total > 0) over05 += p;
      if (total > 1) over15 += p;
      if (total > 2) over25 += p;
      if (total > 3) over35 += p;
      if (total <= 1) under15 += p;
      if (finalH > 0 && finalA > 0) btts += p;
      if (finalH > finalA) homeWin += p;
      if (finalH === finalA) draw += p;
      if (finalH < finalA) awayWin += p;
    }
  }

  return {
    minute_at_compute: minute,
    score_at_compute: `${sH}-${sA}`,
    lambda_home_rem: parseFloat(lambdaH_rem.toFixed(3)),
    lambda_away_rem: parseFloat(lambdaA_rem.toFixed(3)),
    adjustments: {
      time_factor: parseFloat(timeFactor.toFixed(3)),
      adj_home: adjH,
      adj_away: adjA,
      score_diff_home: diffH,
      weather_factor: parseFloat(weatherFactor.toFixed(3)),
      travel_factor: parseFloat(travelFactor.toFixed(3)),
    },
    markets: {
      over05: Math.round(over05 * 100),
      over15: Math.round(over15 * 100),
      over25: Math.round(over25 * 100),
      over35: Math.round(over35 * 100),
      btts: Math.round(btts * 100),
      under15: Math.round(under15 * 100),
      homeWin: Math.round(homeWin * 100),
      draw: Math.round(draw * 100),
      awayWin: Math.round(awayWin * 100),
    },
    method: 'poisson_time_inhomogeneous',
  };
}

// Alias nommé — retourne la matrice brute (max+1 × max+1) de probabilités de scores
function calculatePoisson(lH, lA, max = 6) {
  const matrix = [];
  for (let h = 0; h <= max; h++) {
    matrix[h] = [];
    for (let a = 0; a <= max; a++) {
      matrix[h][a] = poissonPMF(lH, h) * poissonPMF(lA, a);
    }
  }
  return matrix;
}

// ═══════════════════════════════════════════════════════════════════════════════
//  v7.0 QUANT ENGINE — Devigging, Bayesian Blender, Calibration
// ═══════════════════════════════════════════════════════════════════════════════

// ── DÉVIGAGE DES COTES — 3 méthodes ──────────────────────────────────────────

// Méthode additive (simple) : retire proportionnellement la marge
function devigAdditive(odds) {
  const invSum = odds.reduce((s, o) => s + 1 / o, 0);
  const margin = invSum - 1;
  return odds.map(o => {
    const implied = 1 / o;
    const fair = implied - margin * (implied / invSum);
    return fair > 0 ? 1 / fair : null;
  });
}

// Méth Shin-Hurley (asymétrique) : les favoris absorbent plus de marge
// Reference: Shin (1993), Hurley & Pavitt (2021)
function devigShinHurley(odds) {
  const n = odds.length;
  if (n < 2) return odds.map(o => 1 / (1 / o));

  // Binary search for the Shin parameter θ
  let lo = 0.0001, hi = 0.9999;
  for (let iter = 0; iter < 100; iter++) {
    const mid = (lo + hi) / 2;
    let sum = 0;
    for (const o of odds) {
      const inv = 1 / o;
      const num = Math.sqrt(inv * inv + 4 * mid * (1 - mid));
      const denom = 2 * (1 - mid);
      sum += (num - inv) / denom;
    }
    if (sum > 1) hi = mid;
    else lo = mid;
  }
  const theta = (lo + hi) / 2;

  // Compute fair probabilities
  const fairProbs = odds.map(o => {
    const inv = 1 / o;
    const num = Math.sqrt(inv * inv + 4 * theta * (1 - theta));
    const denom = 2 * (1 - theta);
    return (num - inv) / denom;
  });

  // Normalize
  const sumFair = fairProbs.reduce((s, p) => s + p, 0);
  return fairProbs.map(p => p / sumFair);
}

// Méthode power (exponentielle) : bon compromis pour les cotes 1X2
function devigPower(odds) {
  const invProbs = odds.map(o => 1 / o);
  const sumInv = invProbs.reduce((s, p) => s + p, 0);
  // Find power α such that sum(p^α) = 1
  let alpha = 1;
  for (let iter = 0; iter < 100; iter++) {
    const sumPow = invProbs.reduce((s, p) => s + Math.pow(p, alpha), 0);
    const deriv = invProbs.reduce((s, p) => s + Math.pow(p, alpha) * Math.log(p), 0);
    if (Math.abs(deriv) < 1e-15) break;
    alpha -= (sumPow - 1) / deriv;
    alpha = Math.max(0.1, Math.min(3, alpha));
  }
  const fairProbs = invProbs.map(p => Math.pow(p, alpha));
  const sumFair = fairProbs.reduce((s, p) => s + p, 0);
  return fairProbs.map(p => p / sumFair);
}

// Devigage 1X2 — retourne { home, draw, away } en probabilités fair
function devig1X2(homeOdds, drawOdds, awayOdds, method = 'shin') {
  if (!homeOdds || !awayOdds) return null;
  const dOdds = drawOdds || (homeOdds + awayOdds) / 2;
  const odds = [homeOdds, dOdds, awayOdds];

  let fairProbs;
  if (method === 'shin') fairProbs = devigShinHurley(odds);
  else if (method === 'power') fairProbs = devigPower(odds);
  else fairProbs = devigAdditive(odds).map(p => p || 0.01);

  // Normalize
  const sum = fairProbs.reduce((s, p) => s + p, 0);
  const norm = fairProbs.map(p => p / sum);

  const margin = ((1 / homeOdds + 1 / dOdds + 1 / awayOdds) - 1) * 100;

  return {
    home: norm[0], draw: norm[1], away: norm[2],
    margin: parseFloat(margin.toFixed(2)),
    method,
  };
}

// Devigage 2-way (Tennis h2h, MMA, etc.) — pas de nul possible
// Retourne { p1, p2, margin, method } en probabilités fair normalisées.
function devig2way(p1Odds, p2Odds, method = 'shin') {
  if (!p1Odds || !p2Odds || p1Odds <= 1 || p2Odds <= 1) return null;
  const odds = [p1Odds, p2Odds];

  let fairProbs;
  if (method === 'shin') fairProbs = devigShinHurley(odds);
  else if (method === 'power') fairProbs = devigPower(odds);
  else fairProbs = devigAdditive(odds).map(p => p || 0.01);

  const sum = fairProbs.reduce((s, p) => s + p, 0);
  const norm = fairProbs.map(p => p / sum);

  const margin = ((1 / p1Odds + 1 / p2Odds) - 1) * 100;

  return {
    p1: norm[0],
    p2: norm[1],
    margin: parseFloat(margin.toFixed(2)),
    method,
  };
}

// ── BAYESIAN MODEL BLENDER — Fusion de 3 modèles ─────────────────────────────

// Elo dynamique (simplifié, basé sur les stats BSD)
function computeEloProbs(match) {
  const hs = match.stats?.home;
  const as = match.stats?.away;
  if (!hs || !as) return null;

  // Elo proxy: PPG × 100 + avgScored × 20 - avgConceded × 15
  const homeElo = (hs.ppg || 1.3) * 100 + (hs.avgScored || 1.2) * 20 - (hs.avgConceded || 1.3) * 15 + 50; // home advantage
  const awayElo = (as.ppg || 1.3) * 100 + (as.avgScored || 1.2) * 20 - (as.avgConceded || 1.3) * 15;

  const expected = 1 / (1 + Math.pow(10, (awayElo - homeElo) / 400));
  const drawProb = 0.25 + Math.abs(homeElo - awayElo) < 50 ? 0.05 : 0; // closer = more draws

  const homeWin = expected * (1 - drawProb);
  const awayWin = (1 - expected) * (1 - drawProb);

  return {
    homeWin: Math.round(homeWin * 100),
    draw: Math.round(drawProb * 100),
    awayWin: Math.round(awayWin * 100),
    method: 'elo',
    homeElo: Math.round(homeElo),
    awayElo: Math.round(awayElo),
  };
}

// xG Logistic — probabilité basée sur le différentiel xG
function computeXGLogisticProbs(match) {
  const xg = match.expectedGoals;
  if (!xg || xg.home == null || xg.away == null) return null;

  const xgDiff = xg.home - xg.away;
  const xgTotal = xg.home + xg.away;

  // Logistic function pour 1X2
  const homeWin = 1 / (1 + Math.exp(-0.8 * (xgDiff - 0.15)));
  const awayWin = 1 / (1 + Math.exp(0.8 * (xgDiff + 0.15)));
  const draw = Math.max(0, 1 - homeWin - awayWin);

  // Over/Under via xG total (logistic)
  const over25 = 1 / (1 + Math.exp(-1.5 * (xgTotal - 2.5)));
  const btts = 1 / (1 + Math.exp(-2.0 * (Math.min(xg.home, xg.away) - 0.65)));

  return {
    homeWin: Math.round(homeWin * 100),
    draw: Math.round(draw * 100),
    awayWin: Math.round(awayWin * 100),
    over25: Math.round(over25 * 100),
    btts: Math.round(btts * 100),
    method: 'xg_logistic',
    xgDiff: parseFloat(xgDiff.toFixed(2)),
  };
}

// Bayesian Model Averaging — pondère les modèles par leur performance historique
function bayesianBlend(poissonProbs, eloProbs, xgProbs, weights = null) {
  // Poids par défaut si non spécifiés
  const w = weights || { poisson: 0.50, elo: 0.25, xg: 0.25 };

  const blended = {
    homeWin: 0, draw: 0, awayWin: 0,
    over25: 0, btts: 0, over05: 0, over15: 0, over35: 0,
    under15: 0, cs00: 0,
    topScores: poissonProbs?.topScores || [],
    method: 'bayesian_blend',
    weights: w,
  };

  // 1X2 blending
  if (poissonProbs) {
    blended.homeWin += poissonProbs.homeWin * w.poisson;
    blended.draw += poissonProbs.draw * w.poisson;
    blended.awayWin += poissonProbs.awayWin * w.poisson;
    blended.over25 += poissonProbs.over25 * w.poisson;
    blended.btts += poissonProbs.btts * w.poisson;
    blended.over05 += poissonProbs.over05 * w.poisson;
    blended.over15 += poissonProbs.over15 * w.poisson;
    blended.over35 += poissonProbs.over35 * w.poisson;
    blended.under15 += poissonProbs.under15 * w.poisson;
    blended.cs00 += poissonProbs.cs00 * w.poisson;
  }
  if (eloProbs) {
    blended.homeWin += eloProbs.homeWin * w.elo;
    blended.draw += eloProbs.draw * w.elo;
    blended.awayWin += eloProbs.awayWin * w.elo;
  }
  if (xgProbs) {
    blended.homeWin += xgProbs.homeWin * w.xg;
    blended.draw += xgProbs.draw * w.xg;
    blended.awayWin += xgProbs.awayWin * w.xg;
    blended.over25 += (xgProbs.over25 || 0) * w.xg;
    blended.btts += (xgProbs.btts || 0) * w.xg;
  }

  // Normalize 1X2
  const sum1X2 = blended.homeWin + blended.draw + blended.awayWin;
  if (sum1X2 > 0) {
    blended.homeWin = Math.round(blended.homeWin / sum1X2 * 100) / 100;
    blended.draw = Math.round(blended.draw / sum1X2 * 100) / 100;
    blended.awayWin = Math.round(blended.awayWin / sum1X2 * 100) / 100;
  }

  // Round market probs
  blended.over25 = Math.round(blended.over25);
  blended.btts = Math.round(blended.btts);
  blended.over05 = Math.round(blended.over05);
  blended.over15 = Math.round(blended.over15);
  blended.over35 = Math.round(blended.over35);
  blended.under15 = Math.round(blended.under15);
  blended.cs00 = Math.round(blended.cs00);

  return blended;
}

// ── CALIBRATION MAP — Ajuste les probabilités brutes via reliability diagram ─
// Basé sur l'historique des 500 derniers matchs

const CALIBRATION_BINS = [
  { min: 0, max: 10, raw: 5, calibrated: 4 },  // Modèle surestime les improbables
  { min: 10, max: 20, raw: 15, calibrated: 13 },
  { min: 20, max: 30, raw: 25, calibrated: 23 },
  { min: 30, max: 40, raw: 35, calibrated: 33 },
  { min: 40, max: 50, raw: 45, calibrated: 44 },
  { min: 50, max: 60, raw: 55, calibrated: 55 },  // Zone bien calibrée
  { min: 60, max: 70, raw: 65, calibrated: 64 },
  { min: 70, max: 80, raw: 75, calibrated: 72 },  // Modèle sous-estime les probables
  { min: 80, max: 90, raw: 85, calibrated: 80 },
  { min: 90, max: 100, raw: 95, calibrated: 88 },
];

function calibrateProbability(rawProb) {
  if (rawProb == null) return null;
  for (const bin of CALIBRATION_BINS) {
    if (rawProb >= bin.min && rawProb < bin.max) {
      // Interpolation linéaire dans le bin
      const t = (rawProb - bin.min) / (bin.max - bin.min);
      return Math.round((bin.raw + t * (bin.calibrated - bin.raw)) * 10) / 10;
    }
  }
  return rawProb;
}

// Applique la calibration à un objet de probabilités Poisson/blended
function calibrateProbs(probs) {
  if (!probs) return null;
  const calibrated = { ...probs };
  calibrated.homeWin = calibrateProbability(probs.homeWin);
  calibrated.draw = calibrateProbability(probs.draw);
  calibrated.awayWin = calibrateProbability(probs.awayWin);
  calibrated.over25 = calibrateProbability(probs.over25);
  calibrated.btts = calibrateProbability(probs.btts);
  calibrated.over05 = calibrateProbability(probs.over05);
  calibrated.over15 = calibrateProbability(probs.over15);
  calibrated.over35 = calibrateProbability(probs.over35);
  // Renormalize 1X2
  const sum = (calibrated.homeWin || 0) + (calibrated.draw || 0) + (calibrated.awayWin || 0);
  if (sum > 0) {
    calibrated.homeWin = Math.round(calibrated.homeWin / sum * 1000) / 10;
    calibrated.draw = Math.round(calibrated.draw / sum * 1000) / 10;
    calibrated.awayWin = Math.round(calibrated.awayWin / sum * 1000) / 10;
  }
  calibrated.calibrated = true;
  return calibrated;
}

// ══════════════════════════════════════════════════════════════════════════════
//  P1 QUANT — BOOTSTRAP UQD (Uncertainty Quantification & Decision)
//  Auteur : Hermes · Date : 2026-05-06
// ══════════════════════════════════════════════════════════════════════════════

// ── Box-Muller : générateur N(0,1) sans dépendance externe ───────────────────
function boxMullerGaussian() {
  const u1 = Math.max(1e-10, Math.random()); // nosemgrep: insecure-random — statistical simulation
  const u2 = Math.random(); // nosemgrep: insecure-random — statistical simulation
  return Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
}

// ── BOOTSTRAP UQD — 500 itérations, IC 90% sur les marchés Poisson ───────────
// Principe : perturbation log-normale des λ (expHome, expAway) selon l'incertitude
//            sur les moyennes de buts (σ ≈ 1/√played — approx. variance de Poisson)
// Complexité : O(N × 7 × 7) ≈ 24 500 ops/match — non-bloquant (<50ms sur 50 matchs)
function computeBootstrapUQD(expHome, expAway, playedHome, playedAway, N) {
  N = N || 500;
  if (!expHome || !expAway || expHome <= 0 || expAway <= 0) return null;

  // Écart-type log-normal : 1/√n (variance Poisson de la moyenne des buts)
  const sigH = 1 / Math.sqrt(Math.max(1, playedHome || 10));
  const sigA = 1 / Math.sqrt(Math.max(1, playedAway || 10));
  const lnH = Math.log(expHome);
  const lnA = Math.log(expAway);

  // Tableaux d'échantillons par marché
  const sOver25 = [], sBtts = [], sHomeWin = [], sDraw = [], sAwayWin = [];
  const sOver15 = [], sOver35 = [];

  for (let i = 0; i < N; i++) {
    // Perturbation log-normale : λ' = exp(ln(λ) + σ·Z) reste toujours > 0
    const lH = Math.exp(lnH + sigH * boxMullerGaussian());
    const lA = Math.exp(lnA + sigA * boxMullerGaussian());

    // Matrice Poisson 7×7 rapide
    let o25 = 0, o15 = 0, o35 = 0, btts = 0, hw = 0, dr = 0, aw = 0;
    for (let h = 0; h < 7; h++) {
      for (let a = 0; a < 7; a++) {
        const p = poissonPMF(lH, h) * poissonPMF(lA, a);
        const tot = h + a;
        if (tot > 2) o25 += p;
        if (tot > 1) o15 += p;
        if (tot > 3) o35 += p;
        if (h > 0 && a > 0) btts += p;
        if (h > a) hw += p;
        if (h === a) dr += p;
        if (h < a) aw += p;
      }
    }
    sOver25.push(o25 * 100);
    sOver15.push(o15 * 100);
    sOver35.push(o35 * 100);
    sBtts.push(btts * 100);
    sHomeWin.push(hw * 100);
    sDraw.push(dr * 100);
    sAwayWin.push(aw * 100);
  }

  // Extraction des percentiles (5th = borne inf IC 90%, 95th = borne sup)
  const percentile = (arr, p) => {
    arr.sort((a, b) => a - b);
    const idx = (p / 100) * (arr.length - 1);
    const lo = Math.floor(idx), hi = Math.ceil(idx);
    if (lo === hi) return Math.round(arr[lo] * 10) / 10;
    return Math.round((arr[lo] + (idx - lo) * (arr[hi] - arr[lo])) * 10) / 10;
  };

  const summarize = (arr) => {
    const mean = Math.round(arr.reduce((s, v) => s + v, 0) / N * 10) / 10;
    const lower = percentile([...arr], 5);
    const upper = percentile([...arr], 95);
    return { mean, lower, upper, width: Math.round((upper - lower) * 10) / 10 };
  };

  return {
    n: N,
    ic_level: 90,
    markets: {
      over25: summarize(sOver25),
      over15: summarize(sOver15),
      over35: summarize(sOver35),
      btts: summarize(sBtts),
      homeWin: summarize(sHomeWin),
      draw: summarize(sDraw),
      awayWin: summarize(sAwayWin),
    },
  };
}

// ── SCORE DE FIABILITÉ COMPOSITE (0-100) ─────────────────────────────────────
// Remplace l'ancien confidence_score heuristique (0.6×Poisson + 0.4×PPG)
// Composantes :
//   35% — Volume Data   : fiabilité statistique (matchs joués)
//   35% — Stabilité xG  : étroitesse de l'IC over25 (IC large = incertitude élevée)
//   30% — Qualité Source: données réelles BSD/API vs simulées
// bd 1r14 — Expose components pour tooltip UI breakdown (sans break API legacy).
function computeReliabilityScore(uqd, isRealData, playedHome, playedAway) {
  const avgPlayed = ((playedHome || 5) + (playedAway || 5)) / 2;
  const volumeScore = Math.min(100, (avgPlayed / 20) * 100);           // 20+ matchs = max

  const icWidth = uqd && uqd.markets && uqd.markets.over25 ? uqd.markets.over25.width : 60;
  const stabilityScore = Math.max(0, 100 - icWidth * 1.8);             // IC large → score bas

  const qualityScore = isRealData ? 85 : 28;                           // Réel vs simulé

  const raw = 0.35 * volumeScore + 0.35 * stabilityScore + 0.30 * qualityScore;
  return Math.round(Math.max(0, Math.min(100, raw)));
}

// bd 1r14 — Wrapper retournant components breakdown pour tooltip UI.
// Décomposition transparente formula sans casser callers existants
// (number-only retourné par computeReliabilityScore).
function computeReliabilityComponents(uqd, isRealData, playedHome, playedAway) {
  const avgPlayed = ((playedHome || 5) + (playedAway || 5)) / 2;
  const volumeScore = Math.round(Math.min(100, (avgPlayed / 20) * 100));
  const icWidth = uqd && uqd.markets && uqd.markets.over25 ? uqd.markets.over25.width : 60;
  const stabilityScore = Math.round(Math.max(0, 100 - icWidth * 1.8));
  const qualityScore = isRealData ? 85 : 28;
  return {
    volume: { score: volumeScore, weight: 0.35, raw_input: { avg_played: Math.round(avgPlayed * 10) / 10, max_at: 20 } },
    stability: { score: stabilityScore, weight: 0.35, raw_input: { ic_width_over25: Math.round(icWidth * 10) / 10 } },
    quality: { score: qualityScore, weight: 0.30, raw_input: { is_real_data: !!isRealData } },
  };
}

// ── RÈGLE DE DÉCISION STRICTE — BET si EV>5% ET IC borne inf → EV>0% ────────
// Principe : même dans le scénario pessimiste (IC borne inférieure 90%),
//            l'edge reste positif → seulement alors recommander le pari.
function computeBetSignal(record, uqd) {
  const ev = record.best_edge && record.best_edge.edge != null ? record.best_edge.edge : null;
  const label = record.best_edge && record.best_edge.label;

  if (ev == null) return { recommended: false, reason: 'Aucun edge disponible' };
  if (!uqd) return { recommended: false, reason: 'UQD non calculé', ev_pct: ev };

  // Mapper le label du best_edge vers la clé marché UQD
  let marketKey = null;
  if (label === record.home_team) marketKey = 'homeWin';
  else if (label === record.away_team) marketKey = 'awayWin';
  else if (label === 'Nul') marketKey = 'draw';

  // Récupérer la borne inférieure IC du marché
  const icData = marketKey && uqd.markets[marketKey];
  if (!icData) {
    const reason = ev > 5
      ? `EV ${safeFixed(ev, 1)}% > 5% ✓ mais marché "${label}" non mappé UQD`
      : `EV ${safeFixed(ev, 1)}% ≤ seuil 5%`;
    return { recommended: false, reason, ev_pct: ev };
  }

  // Calculer l'EV avec la borne inférieure de l'IC (scénario pessimiste)
  const oddsKey = marketKey === 'homeWin' ? 'home' : marketKey === 'awayWin' ? 'away' : 'draw';
  const odds = record.odds && record.odds[oddsKey];
  const pLower = (icData.lower || 0) / 100;
  const evLower = odds ? parseFloat(((pLower * odds - 1) * 100).toFixed(1)) : null;

  // Kelly tier routing (Ren & Susnjak 2022): classify match difficulty → dynamic thresholds
  const kellyFrac = odds && odds > 1 ? ev / (odds - 1) : null;
  let evThr = 5, evLowerThr = 0, kellyTier = 'medium';
  if (kellyFrac !== null) {
    if (kellyFrac > 15)    { evThr = 3; evLowerThr = -2; kellyTier = 'easy'; }
    else if (kellyFrac < 8) { evThr = 8; evLowerThr = 2;  kellyTier = 'hard'; }
  }

  const cond1 = ev > evThr;
  const cond2 = evLower != null && evLower > evLowerThr;

  if (cond1 && cond2) {
    return {
      recommended: true,
      market: label,
      ev_pct: ev,
      ic_lower_pct: icData.lower,
      ic_lower_ev: evLower,
      kelly_tier: kellyTier,
      kelly_frac: kellyFrac !== null ? parseFloat(kellyFrac.toFixed(1)) : null,
      reason: `✓ EV ${safeFixed(ev, 1)}% > ${evThr}% [${kellyTier}] | ✓ EV pessimiste IC90% ${safeFixed(evLower, 1)}% > ${evLowerThr}%`,
    };
  } else if (cond1 && !cond2) {
    return {
      recommended: false,
      market: label,
      ev_pct: ev,
      ic_lower_pct: icData.lower,
      ic_lower_ev: evLower,
      kelly_tier: kellyTier,
      kelly_frac: kellyFrac !== null ? parseFloat(kellyFrac.toFixed(1)) : null,
      reason: `✓ EV ${safeFixed(ev, 1)}% > ${evThr}% [${kellyTier}] | ✗ EV pessimiste ${evLower != null ? safeFixed(evLower, 1) : '?'}% ≤ ${evLowerThr}% (incertitude trop haute)`,
    };
  } else {
    return {
      recommended: false,
      market: label,
      ev_pct: ev,
      kelly_tier: kellyTier,
      kelly_frac: kellyFrac !== null ? parseFloat(kellyFrac.toFixed(1)) : null,
      reason: `✗ EV ${safeFixed(ev, 1)}% ≤ seuil ${evThr}% [${kellyTier}]`,
    };
  }
}

// ── EV CALCULATOR — Expected Value avec cotes dévigées ───────────────────────

function calcEV(modelProb, marketOdds, fairProb) {
  // EV = (fairProb × odds) - 1
  // fairProb = probabilité dévigée du marché
  if (!modelProb || !marketOdds || !fairProb) return null;
  // Garde-fou cotes : une cote ≤ 1.01 ou aberrante = donnée invalide
  if (marketOdds <= 1.01 || marketOdds > 1000) return null;
  const ev = (fairProb * marketOdds - 1) * 100;
  // Sur un marché correctement dévigé, |EV| > 60% = donnée corrompue
  // (cote implicite fabriquée, fairProb hors borne). On rejette plutôt que d'afficher un faux signal.
  if (!isFinite(ev) || ev < -100 || ev > 60) return null;
  return parseFloat(ev.toFixed(1));
}

// Calcule l'EV pour tous les marchés d'un match
function calcAllEVs(blendedProbs, odds, fairProbs) {
  if (!blendedProbs || !odds || !fairProbs) return null;

  const evs = {};

  // 1X2
  if (odds.home && fairProbs.home) {
    evs.homeWin = calcEV(blendedProbs.homeWin / 100, odds.home, fairProbs.home);
  }
  if (odds.draw && fairProbs.draw) {
    evs.draw = calcEV(blendedProbs.draw / 100, odds.draw, fairProbs.draw);
  }
  if (odds.away && fairProbs.away) {
    evs.awayWin = calcEV(blendedProbs.awayWin / 100, odds.away, fairProbs.away);
  }

  // Over/Under (cotes non disponibles directement, on utilise les cotes 1X2 comme proxy)
  // Pour O2.5: cote implicite ≈ 1 / (probabilité fair du marché)
  // On estime la cote fair du marché via le devigage
  if (fairProbs.home && fairProbs.away) {
    // Proxy: si le marché pense que le match sera ouvert (faible proba de draw),
    // alors l'Over 2.5 est plus probable
    const marketOpenness = 1 - fairProbs.draw;
    const fairOver25 = blendedProbs.over25 / 100; // On utilise notre modèle comme référence
    // EV pour O2.5: on compare notre proba calibrée à la proba implicite du marché
    const impliedOver25 = marketOpenness * 0.65; // Heuristique: 65% de l'openness va en O2.5
    if (impliedOver25 > 0) {
      const impliedOdds = 1 / impliedOver25;
      evs.over25 = calcEV(fairOver25, impliedOdds, fairOver25);
    }
  }

  // BTTS
  if (blendedProbs.btts != null) {
    const fairBTTS = blendedProbs.btts / 100;
    const impliedBTTS = (fairProbs.home * 0.6 + fairProbs.away * 0.6) * 0.5; // Heuristique
    if (impliedBTTS > 0) {
      const impliedOdds = 1 / impliedBTTS;
      evs.btts = calcEV(fairBTTS, impliedOdds, fairBTTS);
    }
  }

  // Best EV — UNIQUEMENT marchés à cotes marché réelles (1X2).
  // over25/btts utilisent des cotes implicites heuristiques (×0.6×0.5) → EV non fiable,
  // exclus du "best" (cause du faux +EV 132.9%). Toujours exposés individuellement.
  const REAL_ODDS_MARKETS = ['homeWin', 'draw', 'awayWin'];
  let bestEV = null;
  let bestEVLabel = '';
  for (const key of REAL_ODDS_MARKETS) {
    const val = evs[key];
    if (val != null && (bestEV === null || val > bestEV)) {
      bestEV = val;
      bestEVLabel = key;
    }
  }
  evs.best = { label: bestEVLabel, value: bestEV };

  return evs;
}

// ═══════════════════════════════════════════════════════════════════════════════
//  SCÉNARIOS PRÉDICTIFS LIVE — Combine Poisson pré-match + momentum live + xG
// ═══════════════════════════════════════════════════════════════════════════════

function calcLiveAdjustedLambdas(match) {
  const minute = Math.min(match.live_minute || 0, 90);
  if (minute <= 0) return null;
  const eg = match.expectedGoals || {};
  const preLambdaH = eg.home || 1.3;
  const preLambdaA = eg.away || 1.1;
  const timeFactor = (90 - minute) / 90;
  const liveXgH = match.live_xg?.home;
  const liveXgA = match.live_xg?.away;
  if (liveXgH == null || liveXgA == null) {
    return { home: preLambdaH * timeFactor, away: preLambdaA * timeFactor };
  }
  const liveRateH = (liveXgH / minute) * 90;
  const liveRateA = (liveXgA / minute) * 90;
  const liveWeight = Math.min(0.8, minute / 60);
  const preWeight = 1 - liveWeight;
  let adjLambdaH = preLambdaH * preWeight + liveRateH * liveWeight;
  let adjLambdaA = preLambdaA * preWeight + liveRateA * liveWeight;
  if (match.live_momentum && Array.isArray(match.live_momentum) && match.live_momentum.length > 3) {
    const recent = match.live_momentum.slice(-6);
    const hMomentum = recent.filter(m => m.team === 'home').length / recent.length;
    const momentumBias = (hMomentum - 0.5) * 0.3;
    adjLambdaH *= (1 + momentumBias);
    adjLambdaA *= (1 - momentumBias);
  }
  const possession = match.live_possession;
  if (possession) {
    const pH = parseFloat(possession.home) || 0;
    const pA = parseFloat(possession.away) || 0;
    if (pH + pA > 0) {
      const possRatio = pH / (pH + pA);
      const possBias = (possRatio - 0.5) * 0.15;
      adjLambdaH *= (1 + possBias);
      adjLambdaA *= (1 - possBias);
    }
  }
  adjLambdaH = Math.max(0.1, adjLambdaH * timeFactor);
  adjLambdaA = Math.max(0.1, adjLambdaA * timeFactor);
  return { home: adjLambdaH, away: adjLambdaA };
}

function generateLiveScenarios(match) {
  const minute = Math.min(match.live_minute || 0, 90);
  if (minute <= 0 || !match.live_score) return [];
  const rawScore = match.live_score;
  let homeGoals, awayGoals;
  if (typeof rawScore === 'object' && rawScore !== null) {
    homeGoals = rawScore.home ?? 0;
    awayGoals = rawScore.away ?? 0;
  } else if (typeof rawScore === 'string' && rawScore.includes('-')) {
    const parts = rawScore.split('-').map(Number);
    homeGoals = parts[0] || 0;
    awayGoals = parts[1] || 0;
  } else {
    homeGoals = 0;
    awayGoals = 0;
  }
  const lambdas = calcLiveAdjustedLambdas(match);
  if (!lambdas) return [];
  const liveXgH = match.live_xg?.home || 0;
  const liveXgA = match.live_xg?.away || 0;
  const MAX = 7;
  const matrix = [];
  for (let h = 0; h < MAX; h++) {
    matrix[h] = [];
    for (let a = 0; a < MAX; a++) {
      matrix[h][a] = poissonPMF(lambdas.home, h) * poissonPMF(lambdas.away, a);
    }
  }
  const scenarios = [];
  let nextGoalHome = 0, nextGoalAway = 0, noMoreGoals = 0;
  for (let h = 0; h < MAX; h++) {
    for (let a = 0; a < MAX; a++) {
      const p = matrix[h][a];
      if (h > 0 && a === 0) nextGoalHome += p;
      if (h === 0 && a > 0) nextGoalAway += p;
      if (h === 0 && a === 0) noMoreGoals += p;
    }
  }
  const total = nextGoalHome + nextGoalAway + noMoreGoals;
  if (total > 0) {
    nextGoalHome /= total;
    nextGoalAway /= total;
    noMoreGoals /= total;
  }
  let over25FromNow = 0, over35FromNow = 0, bttsFromNow = 0, homeWinFromNow = 0, drawFromNow = 0, awayWinFromNow = 0;
  for (let h = 0; h < MAX; h++) {
    for (let a = 0; a < MAX; a++) {
      const p = matrix[h][a];
      const finalH = homeGoals + h;
      const finalA = awayGoals + a;
      const totalGoals = finalH + finalA;
      if (totalGoals > 2) over25FromNow += p;
      if (totalGoals > 3) over35FromNow += p;
      if (finalH > 0 && finalA > 0) bttsFromNow += p;
      if (finalH > finalA) homeWinFromNow += p;
      if (finalH === finalA) drawFromNow += p;
      if (finalH < finalA) awayWinFromNow += p;
    }
  }
  const topScores = [];
  for (let h = 0; h < MAX; h++) {
    for (let a = 0; a < MAX; a++) {
      topScores.push({
        score: `${homeGoals + h}-${awayGoals + a}`,
        prob: Math.round(matrix[h][a] * 100),
      });
    }
  }
  topScores.sort((a, b) => b.prob - a.prob);
  const powerScore = match.power_score || {};
  const powerDiff = (powerScore.home || 50) - (powerScore.away || 50);
  const dataQuality = minute >= 20 ? (minute >= 45 ? 0.9 : 0.75) : 0.55;
  if (nextGoalHome > 0.30) {
    scenarios.push({
      type: 'next_goal',
      label: `Prochain but — ${match.home_team}`,
      bet: `Next Goal: ${match.home_team}`,
      probability: Math.round(nextGoalHome * 100),
      confidence: Math.round(nextGoalHome * 100 * dataQuality),
      reason: nextGoalHome > 0.5
        ? `Domination écrasante (xG ${safeFixed(liveXgH, 1)}-${safeFixed(liveXgA, 1)}, momentum fort)`
        : `Avantage terrain + puissance offensive (${powerDiff > 10 ? 'Power Score supérieur' : 'xG favorable'})`,
      icon: '⚽',
      matchId: match.id,
    });
  }
  if (nextGoalAway > 0.30) {
    scenarios.push({
      type: 'next_goal',
      label: `Prochain but — ${match.away_team}`,
      bet: `Next Goal: ${match.away_team}`,
      probability: Math.round(nextGoalAway * 100),
      confidence: Math.round(nextGoalAway * 100 * dataQuality),
      reason: nextGoalAway > 0.5
        ? `Extérieur dominateur (xG ${safeFixed(liveXgA, 1)}-${safeFixed(liveXgH, 1)}, contre-attaques efficaces)`
        : `Bonne dynamique visiteur + faille défensive adverse`,
      icon: '⚽',
      matchId: match.id,
    });
  }
  const currentTotal = homeGoals + awayGoals;
  if (currentTotal < 2) {
    const overProb = over25FromNow;
    if (overProb > 0.35) {
      scenarios.push({
        type: 'over',
        label: `Over 2.5 buts (actu: ${currentTotal})`,
        bet: `Over 2.5`,
        probability: Math.round(overProb * 100),
        confidence: Math.round(overProb * 100 * dataQuality),
        reason: `Rythme élevé (xG combiné ${(liveXgH + liveXgA).toFixed(1)}, ${minute}e min)`,
        icon: '📈',
        matchId: match.id,
      });
    }
  }
  if (currentTotal < 3) {
    const overProb = over35FromNow;
    if (overProb > 0.30) {
      scenarios.push({
        type: 'over',
        label: `Over 3.5 buts (actu: ${currentTotal})`,
        bet: `Over 3.5`,
        probability: Math.round(overProb * 100),
        confidence: Math.round(overProb * 100 * dataQuality),
        reason: `Match très ouvert, deux équipes en mode offensif`,
        icon: '🔥',
        matchId: match.id,
      });
    }
  }
  const currentBTTS = homeGoals > 0 && awayGoals > 0;
  if (!currentBTTS && bttsFromNow > 0.35) {
    scenarios.push({
      type: 'btts',
      label: `BTTS — Les deux marquent`,
      bet: `BTTS: Oui`,
      probability: Math.round(bttsFromNow * 100),
      confidence: Math.round(bttsFromNow * 100 * dataQuality),
      reason: homeGoals === 0 && awayGoals === 0
        ? `Les deux équipes créent (xG ${(liveXgH + liveXgA).toFixed(1)}), but imminent des deux côtés`
        : homeGoals > 0
          ? `${match.away_team} pousse (xG ${safeFixed(liveXgA, 1)}), égalisation probable`
          : `${match.home_team} réagit (xG ${safeFixed(liveXgH, 1)}), réponse attendue`,
      icon: '🤝',
      matchId: match.id,
    });
  }
  if (homeWinFromNow > 0.40 && Math.abs(homeWinFromNow - awayWinFromNow) > 0.20) {
    scenarios.push({
      type: 'result',
      label: `Victoire ${match.home_team}`,
      bet: `1 (Victoire domicile)`,
      probability: Math.round(homeWinFromNow * 100),
      confidence: Math.round(homeWinFromNow * 100 * dataQuality),
      reason: `Contrôle du match (xG ${safeFixed(liveXgH, 1)}-${safeFixed(liveXgA, 1)}, score ${homeGoals}-${awayGoals})`,
      icon: '🏠',
      matchId: match.id,
    });
  }
  if (awayWinFromNow > 0.40 && Math.abs(awayWinFromNow - homeWinFromNow) > 0.20) {
    scenarios.push({
      type: 'result',
      label: `Victoire ${match.away_team}`,
      bet: `2 (Victoire extérieur)`,
      probability: Math.round(awayWinFromNow * 100),
      confidence: Math.round(awayWinFromNow * 100 * dataQuality),
      reason: `Performance extérieure solide (xG ${safeFixed(liveXgA, 1)}-${safeFixed(liveXgH, 1)})`,
      icon: '✈️',
      matchId: match.id,
    });
  }
  if (drawFromNow > 0.35 && Math.abs(homeGoals - awayGoals) <= 1) {
    scenarios.push({
      type: 'result',
      label: 'Match Nul',
      bet: 'N (Match nul)',
      probability: Math.round(drawFromNow * 100),
      confidence: Math.round(drawFromNow * 100 * dataQuality),
      reason: `Équilibre parfait, aucune équipe ne se détache`,
      icon: '🤝',
      matchId: match.id,
    });
  }
  const shotsH = match.live_shots?.home || 0;
  const shotsA = match.live_shots?.away || 0;
  const cornersH = match.live_corners?.home || 0;
  const cornersA = match.live_corners?.away || 0;
  const totalCorners = cornersH + cornersA;
  if (totalCorners < 8 && minute > 30) {
    const cornerRate = (totalCorners / minute) * 90;
    if (cornerRate > 8) {
      scenarios.push({
        type: 'corners',
        label: `Over 9.5 corners (actu: ${totalCorners})`,
        bet: `Over 9.5 Corners`,
        probability: Math.min(85, Math.round(cornerRate * 8)),
        confidence: Math.round(Math.min(85, cornerRate * 8) * dataQuality),
        reason: `Rythme corners élevé (${safeFixed(cornerRate, 1)}/90min, ${totalCorners} en ${minute}e)`,
        icon: '🚩',
        matchId: match.id,
      });
    }
  }
  if (shotsH + shotsA > 15 && minute < 70) {
    scenarios.push({
      type: 'shots',
      label: `Match intense — +1.5 buts restants`,
      bet: `Over 1.5 buts restants`,
      probability: Math.min(80, Math.round((shotsH + shotsA) / minute * 20)),
      confidence: Math.round(Math.min(80, (shotsH + shotsA) / minute * 20) * dataQuality),
      reason: `${shotsH + shotsA} tentations en ${minute}e, rythme soutenu`,
      icon: '💥',
      matchId: match.id,
    });
  }
  scenarios.forEach(s => {
    if (s.confidence > 75) s.tier = 'safe';
    else if (s.confidence > 55) s.tier = 'medium';
    else s.tier = 'value';
  });
  scenarios.sort((a, b) => b.confidence - a.confidence);
  return scenarios.slice(0, 8);
}

function getLivePredictionsTop5() {
  const now = Date.now();
  const liveMatches = db.matches.filter(m => {
    if (!m.live_score || !m.live_minute) return false;
    if (m.live_minute <= 5 || m.live_minute >= 85) return false;
    // v10.5: Ghost filter
    const minuteVal = parseInt(m.live_minute || 0);
    if (minuteVal > 130) return false;
    if (m.commence_time) {
      const hoursSince = (now - new Date(m.commence_time).getTime()) / (1000 * 60 * 60);
      if (hoursSince > 4) return false;
    }
    return true;
  });
  if (!liveMatches.length) return { predictions: [], message: 'Aucun match live éligible' };
  let allScenarios = [];
  for (const match of liveMatches) {
    const scenarios = generateLiveScenarios(match);
    allScenarios = allScenarios.concat(scenarios);
  }
  allScenarios.sort((a, b) => b.confidence - a.confidence);
  const top5 = allScenarios.slice(0, 5);
  for (const pred of top5) {
    const match = db.matches.find(m => m.id === pred.matchId);
    if (match) {
      pred.home_team = match.home_team;
      pred.away_team = match.away_team;
      pred.league = match.league;
      pred.score = match.live_score;
      pred.minute = match.live_minute;
      pred.odds = match.odds || null;
    }
  }
  return {
    predictions: top5,
    count: top5.length,
    total_live_matches: liveMatches.length,
    ts: Date.now(),
    minute_range: `${Math.min(...liveMatches.map(m => m.live_minute))}-${Math.max(...liveMatches.map(m => m.live_minute))}`,
  };
}

function buildSideStats(s) {
  // v9.9: ne JAMAIS diviser par un "played" fabriqué (=1) → sinon totaux saison
  // pris pour des moyennes. Résoudre le vrai nombre de matchs joués (alias multi-source).
  const playedRaw = s?.played ?? s?.matches_played ?? s?.games ?? s?.mp ?? s?.matchsPlayed ?? null;
  const played = (playedRaw != null && !isNaN(playedRaw) && +playedRaw > 0) ? +playedRaw : 0;
  if (!played) {
    // Données insuffisantes : renvoyer zéro (validateMatchIntegrity bloquera) plutôt
    // que des cumuls saison déguisés en moyennes.
    return { ppg: 0, wins: 0, draws: 0, losses: 0, scored: 0, conceded: 0,
             avgScored: 0, avgConceded: 0, played: 0 };
  }
  const w = s?.win || 0, d = s?.draw || 0, l = s?.lose || 0;

  // v9.2: Deep mapping — handle BOTH API-Football (nested) and BSD (flat) formats
  // API-Football: s.goals.for = { total: 15, average: "1.5" }
  // BSD: s.goals_for = 15 (flat number)
  const extractGoals = (obj) => {
    if (obj == null) return 0;
    if (typeof obj === 'number') return obj;
    if (typeof obj === 'object') {
      // API-Football nested format: { total: N, average: "N" }
      if (typeof obj.total === 'number') return obj.total;
      if (typeof obj.average === 'number') return obj.average;
      if (typeof obj.average === 'string') return parseFloat(obj.average) || 0;
    }
    return 0;
  };

  // Try nested first (API-Football), then flat (BSD)
  let gf = 0, ga = 0;
  if (s?.goals) {
    gf = extractGoals(s.goals.for);
    ga = extractGoals(s.goals.against);
  }
  // Fallback to flat properties (BSD format)
  if (gf === 0 && s?.goals_for != null) gf = extractGoals(s.goals_for);
  if (ga === 0 && s?.goals_against != null) ga = extractGoals(s.goals_against);

  const avgFor = played > 0 ? gf / played : 0;
  const avgAgainst = played > 0 ? ga / played : 0;

  return {
    ppg: parseFloat(((w * 3 + d) / played).toFixed(2)),
    wins: Math.round(w / played * 100),
    draws: Math.round(d / played * 100),
    losses: Math.round(l / played * 100),
    scored: Math.round(Math.min(95, (gf > 0 ? 1 : 0) / played * 100 || avgFor * 55)),
    conceded: Math.round(Math.min(95, (ga > 0 ? 1 : 0) / played * 100 || avgAgainst * 50)),
    avgScored: parseFloat(avgFor.toFixed(2)),
    avgConceded: parseFloat(avgAgainst.toFixed(2)),
    played,      // Conservé pour le Bootstrap UQD (P1 Quant)
  };
}

function simStats(name, isHome) {
  let h = 0;
  for (let i = 0; i < name.length; i++) h = ((h << 5) - h + name.charCodeAt(i)) & 0xffffffff;
  const r = (salt, min, max) => {
    const x = Math.abs(Math.sin(h + salt) * 43758.5453);
    return min + Math.floor((x - Math.floor(x)) * (max - min + 1));
  };
  const side = isHome ? 0 : 100;
  const wins = r(1 + side, isHome ? 35 : 22, isHome ? 72 : 58);
  const draws = r(2 + side, 8, 28);
  const losses = Math.max(0, 100 - wins - draws);
  const avgFor = parseFloat(((r(8 + side, 75, 240)) / 100).toFixed(2));
  const avgAg = parseFloat(((r(9 + side, 60, 200)) / 100).toFixed(2));
  return {
    ppg: parseFloat(((wins * 3 + draws) / 100).toFixed(2)),
    wins, draws, losses,
    scored: r(6 + side, 52, 93),
    conceded: r(7 + side, 40, 88),
    avgScored: avgFor,
    avgConceded: avgAg,
  };
}

function computeEdge(match) {
  const home = match.home_team, away = match.away_team;
  let bestH = null, bestN = null, bestA = null;
  let bestHbk = '', bestNbk = '', bestAbk = '';

  (match.bookmakers || []).forEach(bk => {
    const h2h = (bk.markets || []).find(m => m.key === 'h2h');
    if (!h2h) return;
    h2h.outcomes.forEach(o => {
      if (o.name === home && (!bestH || o.price > bestH)) { bestH = o.price; bestHbk = bk.title; }
      if (o.name === 'Draw' && (!bestN || o.price > bestN)) { bestN = o.price; bestNbk = bk.title; }
      if (o.name === away && (!bestA || o.price > bestA)) { bestA = o.price; bestAbk = bk.title; }
    });
  });

  if (!bestH || !bestA) return null;

  // v7.0: Dévigage Shin-Hurley (asymétrique, les favoris absorbent plus de marge)
  const fair = devig1X2(bestH, bestN, bestA, 'shin');
  if (!fair) return null;

  const edgeH = (bestH * fair.home - 1) * 100;
  const edgeN = bestN ? (bestN * fair.draw - 1) * 100 : null;
  const edgeA = (bestA * fair.away - 1) * 100;

  const edges = [
    { label: home, odds: bestH, edge: edgeH, bk: bestHbk, prob: fair.home },
    { label: 'Nul', odds: bestN, edge: edgeN, bk: bestNbk, prob: fair.draw },
    { label: away, odds: bestA, edge: edgeA, bk: bestAbk, prob: fair.away },
  ].filter(x => x.edge !== null);

  const best = edges.reduce((a, b) => b.edge > a.edge ? b : a);

  return {
    odds: { home: bestH, draw: bestN, away: bestA },
    bookmakers: { home: bestHbk, draw: bestNbk, away: bestAbk },
    fair: { home: fair.home, draw: fair.draw, away: fair.away },
    edgeValues: { home: edgeH, draw: edgeN, away: edgeA },
    best,
    margin: fair.margin,
    devigMethod: fair.method,
  };
}

// FIX v20.0 — Dérivation de forme depuis l'historique (dernier recours si db.teamStats absent)
// Scan db.matches + db.archive_matches pour reconstituer W/D/L récent d'une équipe
// Convention : forme[0] = match le plus ancien, forme[last] = plus récent (convention BSD/API-Football)
function deriveFormFromHistory(teamName, limit = 5) {
  const now = Date.now();
  const allMatches = [
    ...(db.matches || []),
    ...(db.archive_matches || [])
  ];
  const finished = allMatches
    .filter(m => {
      if (m.home_team !== teamName && m.away_team !== teamName) return false;
      const hasResult = !!(m.live_score || (m.goals?.home !== undefined && m.goals?.away !== undefined));
      const isPast = new Date(m.commence_time).getTime() < now;
      return hasResult && isPast;
    })
    .sort((a, b) => new Date(a.commence_time).getTime() - new Date(b.commence_time).getTime()) // plus ancien → plus récent
    .slice(-limit); // garder les N derniers

  if (finished.length < 2) return '';

  const formChars = [];
  for (const m of finished) {
    let hs, as;
    if (m.live_score) {
      [hs, as] = m.live_score.split('-').map(Number);
      if (isNaN(hs) || isNaN(as)) continue;
    } else if (m.goals?.home !== undefined && m.goals?.away !== undefined) {
      hs = m.goals.home;
      as = m.goals.away;
    } else {
      continue;
    }
    if (m.home_team === teamName) {
      formChars.push(hs > as ? 'W' : hs === as ? 'D' : 'L');
    } else {
      formChars.push(as > hs ? 'W' : as === hs ? 'D' : 'L');
    }
  }

  return formChars.join('');
}

// Level 5 — Synthèse forme depuis stats saison (PPG → W/D/L)
//   Ex: PPG 2.40 → "WWWWL", PPG 0.80 → "WDLLL"
function deriveFormFromStats(stats) {
  if (!stats || typeof stats.ppg !== 'number') return '';
  const ppg = stats.ppg;
  // Points totaux sur 5 matchs théoriques
  const ptsTotal = Math.round(ppg * 5);
  // Max de victoires possibles
  const wins = Math.min(5, Math.max(0, Math.floor(ptsTotal / 3)));
  const remainingPts = ptsTotal - wins * 3;
  const draws = Math.min(5 - wins, Math.max(0, remainingPts));
  const losses = 5 - wins - draws;
  // Construire la forme : W → D → L (du + récent au + ancien)
  let form = '';
  form += 'W'.repeat(wins);
  form += 'D'.repeat(draws);
  form += 'L'.repeat(losses);
  return form || 'LLLLL';
}

// H2H — Dernières 5 confrontations directes entre deux équipes (depuis history/archive)
// v9.8.4 fix : filter matchs FINIS (score connu) AVANT slice, sinon matchs futurs polluent le top 5
function computeH2H(homeTeam, awayTeam) {
  const hNorm = normName(homeTeam);
  const aNorm = normName(awayTeam);
  // Scan SEULEMENT sources avec score : history (kvGet archive verified) + db.archive_matches finis
  const histArr = (typeof history !== 'undefined' && Array.isArray(history)) ? history : [];
  const archived = (db.archive_matches || []);
  const pool = [
    ...histArr.map(h => ({
      home_team: h.home_team,
      away_team: h.away_team,
      commence_time: h.commence_time,
      score: h.realScore ? `${h.realScore.home}-${h.realScore.away}` : null,
      hs: h.realScore?.home,
      as: h.realScore?.away,
    })),
    ...archived.map(a => ({
      home_team: a.home_team,
      away_team: a.away_team,
      commence_time: a.commence_time,
      score: a.live_score || (a.goals ? `${a.goals.home}-${a.goals.away}` : null),
      hs: a.live_score ? Number(a.live_score.split('-')[0]) : a.goals?.home,
      as: a.live_score ? Number(a.live_score.split('-')[1]) : a.goals?.away,
    })),
  ].filter(m => m.score && typeof m.hs === 'number' && typeof m.as === 'number' && !isNaN(m.hs) && !isNaN(m.as));

  const h2hMatches = pool
    .filter(m => {
      const h = normName(m.home_team);
      const a = normName(m.away_team);
      return (h === hNorm && a === aNorm) || (h === aNorm && a === hNorm);
    })
    .sort((a, b) => new Date(b.commence_time) - new Date(a.commence_time))
    .slice(0, 5);

  if (h2hMatches.length === 0) return null;

  let w = 0, d = 0, l = 0;
  const formChars = [];
  const meetings = [];
  for (const m of [...h2hMatches].reverse()) {
    const isHome = normName(m.home_team) === hNorm;
    const hs = m.hs, as = m.as;
    const myScore = isHome ? hs : as;
    const oppScore = isHome ? as : hs;
    if (myScore > oppScore) { w++; formChars.push('W'); }
    else if (myScore === oppScore) { d++; formChars.push('D'); }
    else { l++; formChars.push('L'); }
    meetings.push({
      date: (m.commence_time || '').slice(0, 10),
      home: m.home_team,
      away: m.away_team,
      score: m.score,
      home_goals: hs,
      away_goals: as,
    });
  }

  return {
    summary: `${w}W-${d}D-${l}L`,
    form: formChars.join(''),
    wins: w, draws: d, losses: l, total: w + d + l,
    meetings,
    source: 'local',
  };
}

// Minimal record for odds-less fallback sources (P3 OpenFootball, P2bis Football-Data).
// Returns null if even fixture metadata is incomplete. No edge/odds/poisson — UI handles null.
function buildFallbackMatchRecord(raw) {
  if (!raw?.home_team || !raw?.away_team || !raw?.commence_time) return null;
  const hKey = normName(raw.home_team);
  const aKey = normName(raw.away_team);
  let hRaw = db.teamStats[hKey] || findFuzzy(hKey);
  let aRaw = db.teamStats[aKey] || findFuzzy(aKey);
  if (hRaw && aRaw && hRaw === aRaw) aRaw = null;
  const homeStats = hRaw?.home || simStats(raw.home_team, true);
  const awayStats = aRaw?.away || simStats(raw.away_team, false);
  const isReal = !!(hRaw?._real && aRaw?._real);

  // v10.7 — Patch fallback Poisson local : compute lambdas from cached stats
  // when no odds source available (OpenFootball/Football-Data) but real stats exist.
  // Skip if either team's avgScored is 0 (anti-zero guard) or stats are simulated.
  let poisson = null;
  let expectedGoals = null;
  if (isReal
      && Number.isFinite(homeStats?.avgScored) && homeStats.avgScored > 0
      && Number.isFinite(awayStats?.avgScored) && awayStats.avgScored > 0) {
    const LEAGUE_AVG = 1.35;
    const expHome = (homeStats.avgScored / LEAGUE_AVG) * (awayStats.avgConceded || LEAGUE_AVG);
    const expAway = (awayStats.avgScored / LEAGUE_AVG) * (homeStats.avgConceded || LEAGUE_AVG);
    if ((expHome > 0 || expAway > 0) && Number.isFinite(expHome) && Number.isFinite(expAway)
        && expHome <= 8 && expAway <= 8) {
      try {
        poisson = computePoisson(expHome, expAway);
        expectedGoals = { home: expHome, away: expAway };
      } catch (e) {
        console.warn(`[Fallback Poisson] ${raw.home_team} vs ${raw.away_team} — calcul échoué: ${e.message}`);
      }
    }
  }

  return {
    id: raw.id,
    sport: raw._sport || raw.sport_key || null,
    league: raw.sport_title || null,
    country: raw._league_country || raw.country || null,
    commence_time: raw.commence_time,
    home_team: raw.home_team,
    away_team: raw.away_team,
    home_rank: hRaw?.rank || null,
    away_rank: aRaw?.rank || null,
    odds: { home: null, draw: null, away: null },
    bookmakers: { home: null, draw: null, away: null },
    fair: null,
    edge: null,
    best_edge: null,
    poisson,
    expectedGoals,
    stats: { home: homeStats, away: awayStats, isReal },
    status: raw.status || 'scheduled',
    exotic: raw._exotic || (leaguesConfig.leagues.find(l => l.odds_key === (raw._sport || raw.sport_key))?.exotic) || false,
    home_score: raw.home_score ?? null,
    away_score: raw.away_score ?? null,
    referee_name: raw.referee_name || null,
    _source: raw._source,
    _fd_match_id: raw._fd_match_id || null,
    _fd_competition: raw._fd_competition || null,
    _no_odds: true,
    ...(_isNationalTeamMatch(raw) ? (() => {
      const hE = getNationalElo(raw.home_team), aE = getNationalElo(raw.away_team);
      return { elo_home: hE?.elo||null, elo_home_rank: hE?.rank||null, elo_away: aE?.elo||null, elo_away_rank: aE?.rank||null };
    })() : {}),
  };
}

const FALLBACK_NOODDS_SOURCES = new Set(['openfootball', 'football_data', 'rapidfree']);

// ── bd ParisScorebis-hb7 / BD-DATA-005 — Choke-O-Meter heuristique ──
// Approximation: "Favorite Win Rate" sur 90 jours par ligue.
// Si favori (odd_min <= 1.50) gagne, c'est OK. Si non, "choke".
// Limite: pas de "lead at 70'" stricte (pas de timeline stockee), mais
// signal valuable + utilisable comme proxy.
const _favWinRateCache = new Map(); // leagueKey → {sample, holdPct, ts}
const FAV_WIN_RATE_TTL_MS = 24 * 3600 * 1000;
const FAV_ODDS_THRESHOLD = 1.50;
const FAV_WIN_RATE_WINDOW_DAYS = 90;
const FAV_WIN_RATE_MIN_SAMPLE = 20;

function computeFavoriteWinRateForLeague(leagueKey) {
  if (!leagueKey) return null;
  const cached = _favWinRateCache.get(leagueKey);
  if (cached && (Date.now() - cached.ts) < FAV_WIN_RATE_TTL_MS) return cached;
  try {
    const cutoff = Date.now() - FAV_WIN_RATE_WINDOW_DAYS * 24 * 3600 * 1000;
    const archived = (db.archive_matches || []).filter(m => {
      if (!m || !m.live_score || (m.sport_key || m._sport || m.sport) !== leagueKey) return false;
      const ts = new Date(m.commence_time || 0).getTime();
      return ts >= cutoff;
    });
    let sample = 0;
    let holds = 0;
    for (const m of archived) {
      const oh = m.odds?.home, oa = m.odds?.away;
      if (typeof oh !== 'number' || typeof oa !== 'number') continue;
      const minOdd = Math.min(oh, oa);
      if (minOdd > FAV_ODDS_THRESHOLD) continue;
      const favSide = oh <= oa ? 'home' : 'away';
      const [hs, as] = String(m.live_score).split('-').map(Number);
      if (isNaN(hs) || isNaN(as)) continue;
      sample++;
      const favWon = (favSide === 'home' && hs > as) || (favSide === 'away' && as > hs);
      if (favWon) holds++;
    }
    const out = {
      sample,
      holdPct: sample >= FAV_WIN_RATE_MIN_SAMPLE ? Math.round((holds / sample) * 100) : null,
      ts: Date.now(),
    };
    _favWinRateCache.set(leagueKey, out);
    return out;
  } catch (e) {
    return null;
  }
}

function buildMatchRecord(raw) {
  const edge = computeEdge(raw);
  if (!edge) {
    if (raw?._source && FALLBACK_NOODDS_SOURCES.has(raw._source)) {
      return buildFallbackMatchRecord(raw);
    }
    return null;
  }

  const hKey = teamKey(raw.home_team);
  const aKey = teamKey(raw.away_team);
  let hRaw = db.teamStats[hKey] || findFuzzy(hKey);
  let aRaw = db.teamStats[aKey] || findFuzzy(aKey);

  // Fuzzy retry via xsTeamMatch — resolves cross-source name inconsistency (BSD "Aston Villa FC" vs API-Football "Aston Villa")
  if (!hRaw && raw.home_team) {
    for (const dbKey of Object.keys(db.teamStats)) {
      if (xsTeamMatch(raw.home_team, dbKey)) {
        hRaw = db.teamStats[dbKey];
        console.warn(`  [BuildMatch] Fuzzy retry via xsTeamMatch: "${raw.home_team}" → "${dbKey}" (home)`);
        break;
      }
    }
  }
  if (!aRaw && raw.away_team) {
    for (const dbKey of Object.keys(db.teamStats)) {
      if (xsTeamMatch(raw.away_team, dbKey)) {
        aRaw = db.teamStats[dbKey];
        console.warn(`  [BuildMatch] Fuzzy retry via xsTeamMatch: "${raw.away_team}" → "${dbKey}" (away)`);
        break;
      }
    }
  }

  // Si exact match retourne une entrée sans rank réel (ex: stub BSD fixtures sans standings),
  // tenter fuzzy en excluant cet exact pour préférer une entrée standings _real
  // (cas "Kyoto Sanga FC" → stub BSD rank=0 vs "Kyoto Sanga" API-Football rank=14)
  if (hRaw && (!hRaw._real || !hRaw.rank)) {
    const fuzz = findFuzzy(hKey, { skipExact: true, excludeEntry: hRaw });
    if (fuzz && fuzz._real && fuzz.rank) hRaw = fuzz;
  }
  if (aRaw && (!aRaw._real || !aRaw.rank)) {
    const fuzz = findFuzzy(aKey, { skipExact: true, excludeEntry: aRaw });
    if (fuzz && fuzz._real && fuzz.rank) aRaw = fuzz;
  }

  // Ligue couverte BSD → on rejette toute entrée `api-football` (plan gratuit
  // = classement saison N-1 TERMINÉE). Mieux vaut "chargement…" qu'un rang
  // périmé. Corrige le bug "colonne Clsst figée" (K League, Serie A…).
  if (isLeagueCoveredByBSD(raw._sport || raw.sport_key)) {
    if (hRaw && hRaw._source === 'api-football') hRaw = null;
    if (aRaw && aRaw._source === 'api-football') aRaw = null;
  }

  // H2H — 5 dernières confrontations
  const h2h = computeH2H(raw.home_team, raw.away_team);

  // ── Protocole double-check cohérence Home/Away ────────────────────────────
  // Guard 1 : cross-contamination — même objet DB pour les deux équipes
  if (hRaw && aRaw && hRaw === aRaw) {
    console.error(`  [Coherence] ⚠ CROSS-CONTAMINATION: "${raw.home_team}" et "${raw.away_team}" → même entrée DB. Away forcé simStats. Vérifier findFuzzy.`);
    aRaw = null;
  }
  // Guard 2 : fuzzy match ambigu — la clé matchée est plus proche de l'autre équipe
  if (hRaw && !db.teamStats[hKey]) {
    const hMatchedKey = Object.keys(db.teamStats).find(k => db.teamStats[k] === hRaw) || '';
    if (hMatchedKey && levenshtein(hMatchedKey, aKey) < levenshtein(hMatchedKey, hKey)) {
      console.error(`  [Coherence] ⚠ FUZZY AMBIGUË: "${raw.home_team}" → clé "${hMatchedKey}" plus proche de Away "${raw.away_team}". Home forcé simStats.`);
      hRaw = null;
    }
  }
  if (aRaw && !db.teamStats[aKey]) {
    const aMatchedKey = Object.keys(db.teamStats).find(k => db.teamStats[k] === aRaw) || '';
    if (aMatchedKey && levenshtein(aMatchedKey, hKey) < levenshtein(aMatchedKey, aKey)) {
      console.error(`  [Coherence] ⚠ FUZZY AMBIGUË: "${raw.away_team}" → clé "${aMatchedKey}" plus proche de Home "${raw.home_team}". Away forcé simStats.`);
      aRaw = null;
    }
  }
  // ─────────────────────────────────────────────────────────────────────────

  const homeStats = hRaw?.home || simStats(raw.home_team, true);
  const awayStats = aRaw?.away || simStats(raw.away_team, false);
  const isRealData = !!(hRaw?._real && aRaw?._real);

  if (!hRaw) console.warn(`  [BuildMatch] "${raw.home_team}" (Home) — stats simulées (non trouvé en DB)`);
  if (!aRaw) console.warn(`  [BuildMatch] "${raw.away_team}" (Away) — stats simulées (non trouvé en DB)`);

  // ── FIX v20.0 — getTeamForm() : Normalisateur Universel (symétrique Home/Away) ──
  // Niveaux : 1) DB exacte  2) Fuzzy  3) Prefix fallback  4) Historique de matchs
  const getTeamForm = (teamName, normKey, rawEntry, fallbackStats) => {
    // Niveau 1 — DB exacte (rawEntry passé par buildMatchRecord)
    if (rawEntry?.form && rawEntry.form.length >= 3) return rawEntry.form;
    // Niveau 2 — Fuzzy matching
    const fuzzy = findFuzzy(normKey);
    if (fuzzy?.form && fuzzy.form.length >= 3) return fuzzy.form;
    // Niveau 3 — Prefix fallback (premier mot, 4+ chars)
    const firstWord = normKey.split(' ')[0];
    if (firstWord.length >= 4) {
      for (const [k, v] of Object.entries(db.teamStats)) {
        if (k.startsWith(firstWord) && v?.form && v.form.length >= 3) {
          console.warn(`  [Forme] "${teamName}" → fallback forme depuis "${k}" (${v.form})`);
          return v.form;
        }
      }
    }
    // Niveau 4 — Dérivation depuis l'historique des matchs terminés (dernier recours)
    const derived = deriveFormFromHistory(teamName, 5);
    if (derived) {
      console.warn(`  [Forme] "${teamName}" → forme dérivée de l'historique (${derived})`);
      return derived;
    }
    // Niveau 5 — Synthèse forme depuis stats saison (PPG → W/D/L)
    const synForm = deriveFormFromStats(fallbackStats);
    if (synForm) {
      console.warn(`  [Forme] "${teamName}" → forme synthétisée depuis PPG (${synForm})`);
      return synForm;
    }
    return '';
  };
  const homeForm = getTeamForm(raw.home_team, hKey, hRaw, homeStats);
  const awayForm = getTeamForm(raw.away_team, aKey, aRaw, awayStats);

  // Expected goals (Poisson λ) : attaque dom × défense ext / ligue moyenne (~1.35)
  const LEAGUE_AVG = 1.35;
  // Home advantage dynamique (Benz & Lopez 2020): baseline 1.10 + ajustement forme L5
  const _formWinRate = (f) => {
    if (!f || !f.length) return 0.5;
    const g = String(f).split('').slice(-5);
    const pts = g.reduce((s, r) => s + (r === 'W' ? 3 : r === 'D' ? 1 : 0), 0);
    return pts / (g.length * 3);
  };
  const _hfr = _formWinRate(homeForm);
  const _afr = _formWinRate(awayForm);
  const ha_dynamic = Math.max(0.95, Math.min(1.25, 1.10 * (1 + 0.10 * (_hfr - _afr))));
  const expHome = (homeStats.avgScored / LEAGUE_AVG) * (awayStats.avgConceded || LEAGUE_AVG) * ha_dynamic;
  const expAway = (awayStats.avgScored / LEAGUE_AVG) * (homeStats.avgConceded || LEAGUE_AVG) / ha_dynamic;

  // v9.0/v9.9: Anti-Zero + Sanity λ — bloquer si moyennes à 0 OU λ aberrant
  // (cumuls saison pris pour moyennes → expHome≈136 → matrice Poisson sous-flow = 0%).
  let poisson;
  let dixonColes = null;
  const _lamBad = !Number.isFinite(expHome) || !Number.isFinite(expAway) ||
                  expHome > 8 || expAway > 8 || (expHome === 0 && expAway === 0);
  if (_lamBad) {
    console.error("\x1b[31m[POISSON] λ invalide (expHome=%s expAway=%s) pour %s vs %s — calcul bloqué\x1b[0m", expHome, expAway, raw.home_team, raw.away_team);
    poisson = { error: 'BAD_LAMBDA', message: 'Moyennes invalides — calcul Poisson impossible', over25: 0, btts: 0, homeWin: 0, draw: 0, awayWin: 0 };
  } else {
    poisson = computePoisson(expHome, expAway);
    // bd — Dixon-Coles: ajouté en parallèle du Poisson, stocké sur le record
    dixonColes = computeDixonColes(expHome, expAway);
  }

  // ── v7.0 BAYESIAN MODEL BLENDER ────────────────────────────────────────────

  // ── v7.0 BAYESIAN MODEL BLENDER ────────────────────────────────────────────
  const tempMatch = { stats: { home: homeStats, away: awayStats }, expectedGoals: { home: expHome, away: expAway } };
  const eloProbs = computeEloProbs(tempMatch);
  const xgProbs = computeXGLogisticProbs(tempMatch);

  // Blend: Poisson 50%, Elo 25%, xG Logistic 25%
  const blended = bayesianBlend(poisson, eloProbs, xgProbs);

  // Calibration via reliability diagram
  const calibrated = calibrateProbs(blended);

  // v7.0: EV calculations avec probabilités dévigées du marché
  const evs = calcAllEVs(calibrated, edge.odds, edge.fair);

  // v7.0: Edge Poisson recalculé avec probs calibrées (remplace l'ancien calcul brut)
  const pFairH = calibrated.homeWin / 100;
  const pFairN = calibrated.draw / 100;
  const pFairA = calibrated.awayWin / 100;
  const pEdgeH = edge.odds.home ? parseFloat(((edge.odds.home * pFairH - 1) * 100).toFixed(1)) : null;
  const pEdgeN = edge.odds.draw ? parseFloat(((edge.odds.draw * pFairN - 1) * 100).toFixed(1)) : null;
  const pEdgeA = edge.odds.away ? parseFloat(((edge.odds.away * pFairA - 1) * 100).toFixed(1)) : null;
  const pEdges = [
    { label: raw.home_team, edge: pEdgeH },
    { label: 'Nul', edge: pEdgeN },
    { label: raw.away_team, edge: pEdgeA },
  ].filter(x => x.edge !== null);
  const bestPoissonEdge = pEdges.length ? pEdges.reduce((a, b) => b.edge > a.edge ? b : a) : null;

  // PariScore Shield : convergence modèle blendé + Marché sur le même résultat
  const shield = !!(
    edge.best.edge > 5 &&
    bestPoissonEdge?.edge > 0 &&
    bestPoissonEdge?.label === edge.best.label
  );

  const leagueLabel = SPORT_LABELS[raw._sport || raw.sport_key] || raw.sport_title || '?';
  const recordCountry = detectCountryFromLeague(
    raw.sport_title || leagueLabel,
    raw._sport || raw.sport_key,
    raw.country || raw._league_country,
    raw._bsd_league_id
  );

  const record = {
    id: raw.id,
    sport: raw._sport || raw.sport_key,
    league: leagueLabel,
    country: recordCountry,
    commence_time: raw.commence_time,
    home_team: raw.home_team,
    away_team: raw.away_team,
    home_rank: hRaw?.rank || null,
    away_rank: aRaw?.rank || null,
    league_size: (() => {
      const lid = hRaw?.leagueId || aRaw?.leagueId;
      return lid ? (db._leagueSizes?.[lid] || null) : null;
    })(),
    _standings_loading: (!hRaw?.rank || !aRaw?.rank) && isLeagueCoveredByBSD(raw._sport || raw.sport_key),
    exotic: raw._exotic || (leaguesConfig.leagues.find(l => l.odds_key === (raw._sport || raw.sport_key))?.exotic) || false,
    status: raw.status || null,
    home_team_id: hRaw?.teamId || null,
    away_team_id: aRaw?.teamId || null,
    home_bsd_id: hRaw?.bsdTeamId || null,
    away_bsd_id: aRaw?.bsdTeamId || null,
    home_sofa_id: hRaw?.sofaTeamId || null,
    away_sofa_id: aRaw?.sofaTeamId || null,
    home_form: homeForm,
    away_form: awayForm,
    h2h,
    odds: edge.odds,
    bookmakers: edge.bookmakers,
    fair: edge.fair,
    edge: edge.edgeValues,
    best_edge: edge.best,
    poisson,
    dixonColes,
    blended,
    calibrated,
    evs,
    expectedGoals: { home: parseFloat(expHome.toFixed(2)), away: parseFloat(expAway.toFixed(2)) },
    poissonEdge: bestPoissonEdge,
    shield,
    elo: eloProbs,
    xgLogistic: xgProbs,
    margin: edge.margin,
    devigMethod: edge.devigMethod,
    stats: {
      home: homeStats,
      away: awayStats,
      isReal: isRealData,
    },
  };
  record.all_bookmakers = processAllBookmakers(raw.bookmakers, raw.home_team, raw.away_team);

  // ── P1 QUANT — Bootstrap UQD + Reliability Score + Bet Signal ───────────────
  const playedHome = homeStats.played || 10;
  const playedAway = awayStats.played || 10;

  // 1. Bootstrap UQD : IC 90% sur tous les marchés Poisson
  const uqd = (expHome > 0 && expAway > 0)
    ? computeBootstrapUQD(expHome, expAway, playedHome, playedAway, 500)
    : null;
  record.uqd = uqd;

  // 2. Score de Fiabilité Composite (remplace l'ancien confidence_score heuristique)
  record.reliability_score = computeReliabilityScore(uqd, isRealData, playedHome, playedAway);
  // bd 1r14 — Components breakdown pour tooltip UI transparence formula.
  record.reliability_components = computeReliabilityComponents(uqd, isRealData, playedHome, playedAway);

  // 3. Rétro-compatibilité : conserver confidence_score = reliability_score
  record.confidence_score = record.reliability_score;

  // 4. Règle de Décision Stricte : BET si EV>5% ET EV pessimiste IC>0%
  record.bet_signal = computeBetSignal(record, uqd);

  // Dropping Odds Tracker — time series (max 12 snapshots ≈ 24h à cron 2h)
  const snapKey = `odds_snap_${record.id}`;
  const history = kvGet(snapKey) || [];
  const prevSnap = Array.isArray(history) ? history[history.length - 1] : (history?.home != null ? history : null);
  if (prevSnap && prevSnap.home != null) {
    const dHome = record.odds?.home != null ? parseFloat((record.odds.home - prevSnap.home).toFixed(2)) : null;
    const dDraw = record.odds?.draw != null ? parseFloat((record.odds.draw - prevSnap.draw).toFixed(2)) : null;
    const dAway = record.odds?.away != null ? parseFloat((record.odds.away - prevSnap.away).toFixed(2)) : null;
    record.odds_delta = { home: dHome, draw: dDraw, away: dAway, ts: prevSnap.ts };
  } else {
    record.odds_delta = null;
  }
  if (record.odds?.home != null) {
    const arr = Array.isArray(history) ? history : (history?.home != null ? [history] : []);
    const snap = { home: record.odds.home, draw: record.odds.draw, away: record.odds.away, ts: Date.now() };
    kvSet(snapKey, [...arr, snap].slice(-12));
    // bd a8n — Post snapshot, check market divergence (delta+slope 15min) → SSE.
    // Debounce 30s per matchId garantit absence spam si fetchOdds cron tape.
    try { broadcastMarketDivergence(record.id); } catch (_) {}

    // bd 040 — Capture per-bookmaker snapshot pour steam detection.
    // record.all_bookmakers = rows processAllBookmakers (home/draw/away par bk).
    // Stocke compact pour steam detector fenêtre 5min.
    try {
      const bkRows = Array.isArray(record.all_bookmakers) ? record.all_bookmakers : [];
      if (bkRows.length >= 2) {
        const bkSnapKey = `odds_snap_bk_${record.id}`;
        const bkHistory = kvGet(bkSnapKey) || [];
        const bkArr = Array.isArray(bkHistory) ? bkHistory : [];
        const books = bkRows
          .filter(r => r && (r.key || r.title) && (r.home || r.away))
          .slice(0, 25) // cap bookmaker count par snapshot
          .map(r => ({
            bk: String(r.key || r.title || '').toLowerCase().slice(0, 32),
            home: Number.isFinite(r.home) ? r.home : null,
            draw: Number.isFinite(r.draw) ? r.draw : null,
            away: Number.isFinite(r.away) ? r.away : null,
          }));
        if (books.length >= 2) {
          kvSet(bkSnapKey, [...bkArr, { ts: Date.now(), books }].slice(-12));
          // Steam check post-snapshot. Debounce 30s géré par _pulseShouldBroadcast.
          broadcastSteamDetected(record.id);
        }
      }
    } catch (_) {}
  }

  // ── SPRINT 1 P0 — BD-DATA-001 — IC90 bornes sur best_edge (Normal-approx) ──
  // Use best.prob (no-vig fair prob) + sample size from played to compute IC90% on EV.
  // Z90 = 1.645. Real Bootstrap IC could replace later (record.uqd already exists).
  try {
    if (edge && edge.best && typeof edge.best.prob === 'number' && typeof edge.best.odds === 'number') {
      const z90 = 1.645;
      const playedH = (homeStats && typeof homeStats.played === 'number') ? homeStats.played : (playedHome || 30);
      const playedA = (awayStats && typeof awayStats.played === 'number') ? awayStats.played : (playedAway || 30);
      const nEff = Math.max(10, Math.min(playedH, playedA));
      const p = edge.best.prob;
      const stdP = Math.sqrt(Math.max(1e-9, p * (1 - p) / nEff));
      const pLow = Math.max(0, p - z90 * stdP);
      const pHigh = Math.min(1, p + z90 * stdP);
      const icLow = (edge.best.odds * pLow - 1) * 100;
      const icHigh = (edge.best.odds * pHigh - 1) * 100;
      record.best_edge = Object.assign({}, edge.best, {
        ic90: {
          low: parseFloat(icLow.toFixed(2)),
          high: parseFloat(icHigh.toFixed(2)),
          n_eff: nEff,
          method: 'normal_approx_v1'
        }
      });
    }
  } catch (e) {
    // never break record build on IC computation failure
  }

  // ── BD-DATA-005 — Favorite Win Rate (Choke-O-Meter proxy) ──
  try {
    const lk = raw._sport || raw.sport_key;
    if (lk) {
      const fav = computeFavoriteWinRateForLeague(lk);
      if (fav && fav.sample > 0) {
        record.favorite_winrate = {
          sample: fav.sample,
          hold_pct: fav.holdPct,
          threshold_odds: FAV_ODDS_THRESHOLD,
          window_days: FAV_WIN_RATE_WINDOW_DAYS,
        };
      }
    }
  } catch (e) { /* optional decoration */ }

  // ── SPRINT 1 P0 — BD-DATA-002 — Expose Fatigue Index (0-100) on record ──
  // computeFatigueIndex returns {hoursRest, level, score, matchesIn14d, upcomingIn72h}
  try {
    if (typeof computeFatigueIndex === 'function') {
      const fH = computeFatigueIndex(raw.home_team, raw.commence_time);
      const fA = computeFatigueIndex(raw.away_team, raw.commence_time);
      if (fH && typeof fH.score === 'number') {
        record.home_fatigue = fH.score;
        record.home_fatigue_level = fH.level;
        record.home_fatigue_meta = { hoursRest: fH.hoursRest, in14d: fH.matchesIn14d, upcoming: fH.upcomingIn72h };
      }
      if (fA && typeof fA.score === 'number') {
        record.away_fatigue = fA.score;
        record.away_fatigue_level = fA.level;
        record.away_fatigue_meta = { hoursRest: fA.hoursRest, in14d: fA.matchesIn14d, upcoming: fA.upcomingIn72h };
      }
    }
  } catch (e) {
    // fatigue is optional decoration
  }

  // ── BD-DATA-009 (bd kgd) — Travel Factor : distance + jet-lag + climat ──────
  // Modulateur xG visiteur (max -8% literature betting analytics).
  // Sport football uniquement (tennis/individuel hors scope).
  try {
    if (typeof computeTravelFactor === 'function') {
      const sport = raw._sport || raw.sport_key || '';
      const isFootball = !sport.startsWith('tennis_') && sport !== 'tennis';
      if (isFootball) {
        const lastAwayMatchISO = (typeof _lastMatchDateBeforeKickoff === 'function')
          ? _lastMatchDateBeforeKickoff(raw.away_team, raw.commence_time)
          : null;
        const tf = computeTravelFactor(raw.home_team, raw.away_team, raw.commence_time, lastAwayMatchISO);
        if (tf) {
          record.travel_factor = tf;
          // Modulateur xG sur visiteur (attaque dégradée) — n'applique que si score > 0 et non missing
          if (!tf.missing && typeof tf.xg_modulator === 'number' && tf.xg_modulator < 1) {
            const origXgAway = record.expectedGoals?.away;
            if (typeof origXgAway === 'number' && origXgAway > 0) {
              record.expectedGoals.away_raw = origXgAway;
              record.expectedGoals.away = parseFloat((origXgAway * tf.xg_modulator).toFixed(2));
            }
          }
        }
      }
    }
  } catch (e) {
    // travel factor is optional decoration
  }

  // Injuries — mappées directement depuis le flux BSD (unavailable_players)
  // Plus besoin d'appel API-Football dédié → économie de quota
  const bsdUnavailable = raw._source === 'bsd' ? raw.unavailable : null;
  if (bsdUnavailable) {
    record.injuries = {
      home: (bsdUnavailable.home || []).map(p => ({
        name: p.name || p.player?.name || '?',
        reason: p.reason || p.type || 'blessure',
      })),
      away: (bsdUnavailable.away || []).map(p => ({
        name: p.name || p.player?.name || '?',
        reason: p.reason || p.type || 'blessure',
      })),
    };
  } else {
    // Fallback: ancien mécanisme cache API-Football (si BSD non dispo)
    const homeKey = normName(record.home_team);
    const awayKey = normName(record.away_team);
    const homeTeamId = db.teamStats[homeKey]?.teamId;
    const awayTeamId = db.teamStats[awayKey]?.teamId;
    const homeInjCached = homeTeamId ? kvGet(`injuries_${homeTeamId}_${currentSeason()}`) : null;
    const awayInjCached = awayTeamId ? kvGet(`injuries_${awayTeamId}_${currentSeason()}`) : null;
    record.injuries = {
      home: homeInjCached?.data || [],
      away: awayInjCached?.data || [],
    };
  }
  const homeInjCount = Math.min((record.injuries.home || []).length, 6);
  const awayInjCount = Math.min((record.injuries.away || []).length, 6);
  record.injuryPenalty = {
    home: Math.min(homeInjCount * 5, 30),
    away: Math.min(awayInjCount * 5, 30),
  };

  // Corners Poisson — total attendu = (xG Dom + xG Ext) * ratio corners/buts (~3.0)
  const cornerTotal = Math.max(1.0, (expHome + expAway) * 3.0);
  let crCum = 0;
  for (let k = 0; k <= 6; k++) {
    let logP = -cornerTotal + k * Math.log(Math.max(cornerTotal, 0.001));
    for (let i = 1; i <= k; i++) logP -= Math.log(i);
    crCum += Math.exp(logP);
  }
  record.corners_poisson = { over_6_5: Math.round(Math.max(0, Math.min(99, (1 - crCum) * 100))) };

  // BSD metadata — xG réel, coaches, absences
  if (raw._source === 'bsd') {
    record._source = 'bsd';
    record._bsd_event_id = raw._bsd_event_id;
    // BUG-07 fix: guard against {home:null,away:null} truthy object
    const _rawXg = raw.bsd_xg || raw.xg;
    record.bsd_xg = (_rawXg && (_rawXg.home != null || _rawXg.away != null)) ? _rawXg : null;
    // BUG-05 fix: BSD real xG overrides Poisson expectedGoals when available
    if (record.bsd_xg) {
      if (!record.expectedGoals) record.expectedGoals = {};
      if (record.bsd_xg.home != null) {
        const _xgH = Number(record.bsd_xg.home);
        if (Number.isFinite(_xgH)) {
          record.expectedGoals.home = parseFloat(_xgH.toFixed(2));
          record.expectedGoals.home_source = 'bsd_real';
        }
      }
      if (record.bsd_xg.away != null) {
        const _xgA = Number(record.bsd_xg.away);
        if (Number.isFinite(_xgA)) {
          record.expectedGoals.away = parseFloat(_xgA.toFixed(2));
          record.expectedGoals.away_source = 'bsd_real';
        }
      }
    }
    record.bsd_coaches = raw.bsd_coaches || raw.coaches || null;
    record.bsd_unavailable = raw.unavailable || null;
  }

  // ── CatBoost — lookup cache (batch refresh après fetchOdds) ──────────────────
  // Fallback Poisson auto si CATBOOST_ENABLED=false ou cache vide (premier cycle).
  record.catboost = (typeof _catboostCache !== 'undefined' ? _catboostCache[record.id] : undefined) || null;
  if (record.catboost) {
    const cb = record.catboost;
    const po = record.poisson;
    // Blend 60% CatBoost + 40% Poisson (calibré vs non-calibré)
    record.blended_cb = {
      homeWin: Math.round(cb.home   * 100 * 0.6 + (po?.homeWin || 33) * 0.4),
      draw:    Math.round(cb.draw   * 100 * 0.6 + (po?.draw    || 33) * 0.4),
      awayWin: Math.round(cb.away   * 100 * 0.6 + (po?.awayWin || 33) * 0.4),
      over25:  Math.round(cb.over25 * 100 * 0.6 + (po?.over25  || 50) * 0.4),
      btts:    Math.round(cb.btts   * 100 * 0.6 + (po?.btts    || 45) * 0.4),
    };
  }

  // ── National Team Elo (eloratings.net) ────────────────────────────────────
  if (_isNationalTeamMatch(record)) {
    const hElo = getNationalElo(record.home_team);
    const aElo = getNationalElo(record.away_team);
    if (hElo) { record.elo_home = hElo.elo; record.elo_home_rank = hElo.rank; }
    if (aElo) { record.elo_away = aElo.elo; record.elo_away_rank = aElo.rank; }
  }

  return record;
}

// Enrichissement corners depuis BSD (donnees reelles par equipe, avec cache)
async function enrichCornersFromBSD(matches) {
  if (!BSD_API_KEY || !Object.keys(BSD_CONFIG_TO_BSD).length) {
    console.log('  [Corners] BSD non configure — conservation heuristique xG');
    return;
  }
  console.log('  [Corners] Enrichissement corners depuis BSD…');
  const teamCache = new Map(); // normName -> { totalCornersPerMatch }
  let enriched = 0;

  for (const m of matches) {
    if (m._source !== 'bsd' && !m._bsd_event_id) continue;
    const configLeague = leaguesConfig.leagues.find(l => l.name === m.league || l.odds_key === m.sport);
    const bsdLeagueId = configLeague ? configIdToBsd(configLeague.id) : null;
    if (!bsdLeagueId) continue;

    const homeKey = normName(m.home_team);
    const awayKey = normName(m.away_team);

    try {
      if (!teamCache.has(homeKey)) {
        const data = await fetchBSDTeamCornerHistory(m.home_team, bsdLeagueId, 5);
        teamCache.set(homeKey, data?.totalCornersPerMatch || null);
      }
      if (!teamCache.has(awayKey)) {
        const data = await fetchBSDTeamCornerHistory(m.away_team, bsdLeagueId, 5);
        teamCache.set(awayKey, data?.totalCornersPerMatch || null);
      }
    } catch (e) { continue; }

    const homeAvg = teamCache.get(homeKey);
    const awayAvg = teamCache.get(awayKey);
    if (homeAvg != null && awayAvg != null) {
      const cr = predictCorners(homeAvg, awayAvg, [6.5]);
      m.corners_poisson = {
        over_6_5: cr.probabilities.over_6_5,
        source: 'bsd',
        home_avg: Math.round(homeAvg * 10) / 10,
        away_avg: Math.round(awayAvg * 10) / 10,
      };
      enriched++;
    }
  }
  console.log(`  [Corners] ${enriched}/${matches.length} matchs enrichis via BSD`);
}

// ═══════════════════════════════════════════════════════════════════════════════
//  OPTION B — BACKTESTING (History + Accuracy)
// ═══════════════════════════════════════════════════════════════════════════════

const HISTORY_FILE = path.join(__dirname, 'history.json');
const HISTORIQUE_SEED_FILE = path.join(__dirname, 'historique_football.json'); // bd 9je ETL output
const HISTORIQUE_TENNIS_SEED_FILE = path.join(__dirname, 'historique_tennis.json'); // bd rxh ETL output
const HISTORIQUE_OPENFOOTBALL_FILE = path.join(__dirname, 'historique_openfootball.json'); // bd 6du6 ETL output
const HISTORIQUE_WIKIDATA_FILE = path.join(__dirname, 'historique_wikidata.json'); // bd 6du6 Phase 2 — Wikidata CC0 (GS singles + foot finals)
const HISTORIQUE_FBREF_FILE = path.join(__dirname, 'historique_fbref.json'); // bd 8lqf ETL output (RESEARCH ONLY)
const HISTORIQUE_ELOFOOTBALL_FILE = path.join(__dirname, 'historique_elofootball.json'); // bd 8lvf ETL output
const HISTORIQUE_BSD_TENNIS_FILE = path.join(__dirname, 'historique_bsd_tennis.json'); // bd rxh Phase 2 ETL output
let history = [];
let accuracy = { total: 0, over25_correct: 0, over25_total: 0, btts_correct: 0, btts_total: 0, edge_correct: 0, edge_total: 0 };

function loadHistory() {
  // Rétrocompat : migration one-shot depuis history.json
  if (fs.existsSync(HISTORY_FILE)) {
    try {
      const raw = JSON.parse(fs.readFileSync(HISTORY_FILE, 'utf8'));
      history = raw.matches || [];
      accuracy = raw.accuracy || accuracy;
      saveHistory();
      fs.renameSync(HISTORY_FILE, HISTORY_FILE + '.migrated');
      console.log(`  ✓ history.json migré vers SQLite (${history.length} matchs archivés)`);
      return;
    } catch (e) { console.warn('[History] Migration JSON→SQLite:', e.message); }
  }

  history = kvGet('history_matches', []);
  accuracy = kvGet('history_accuracy', accuracy);
  console.log(`  ✓ Historique SQLite chargé (${history.length} matchs archivés)`);

  // Charge l'historique tennis persisté (patch bd — était perdu au reboot)
  const persistedTennis = kvGet('tennis_history_matches', null);
  if (persistedTennis && Array.isArray(persistedTennis) && persistedTennis.length) {
    tennisHistory = persistedTennis;
    console.log(`  ✓ Historique Tennis SQLite chargé (${tennisHistory.length} matchs archivés)`);
  }

  // bd ParisScorebis-9je — Merge historique_football.json (ETL output) dans
  // db.archive_matches au boot. Dedup via id existant. Pas overwrite si match
  // deja present (live data prend priorite sur ETL backfill).
  if (fs.existsSync(HISTORIQUE_SEED_FILE)) {
    try {
      const seed = JSON.parse(fs.readFileSync(HISTORIQUE_SEED_FILE, 'utf8'));
      if (seed && seed.leagues && typeof seed.leagues === 'object') {
        let totalSeed = 0;
        let totalAdded = 0;
        const existingIds = new Set((db.archive_matches || []).map(m => String(m.id)));
        for (const leagueId of Object.keys(seed.leagues)) {
          const league = seed.leagues[leagueId];
          if (!league || !Array.isArray(league.matches)) continue;
          for (const m of league.matches) {
            totalSeed++;
            if (!m || !m.id || existingIds.has(String(m.id))) continue;
            // Map ETL shape → archive_matches shape (compat with runHistoryQuery)
            const archived = {
              id: m.id,
              sport: 'football',
              sport_key: m.source === 'api-football' && m.league_id ? `apif_${m.league_id}` : 'unknown',
              league: m.league_name,
              country: m.country,
              commence_time: m.date,
              home_team: m.home_team,
              away_team: m.away_team,
              home_score: m.home_score,
              away_score: m.away_score,
              live_score: (m.home_score != null && m.away_score != null) ? `${m.home_score}-${m.away_score}` : null,
              status: 'finished',
              venue: m.venue,
              referee: m.referee,
              season: m.season,
              round: m.round,
              halftime_score: m.halftime_score,
              extratime_score: m.extratime_score,
              penalty_score: m.penalty_score,
              _source: 'etl-seed',
              _etl_meta: { league_meta: league.meta, ingested_at: seed.generated_at },
              stats: m.stats || null,
            };
            (db.archive_matches = db.archive_matches || []).push(archived);
            existingIds.add(String(m.id));
            totalAdded++;
          }
        }
        if (totalSeed > 0) {
          console.log(`  ✓ ETL seed merge (foot): ${totalAdded}/${totalSeed} matchs ajoutes a db.archive_matches (dedup'd)`);
        }
      }
    } catch (e) {
      console.warn('[ETL Seed Load foot]', e.message);
    }
  }

  // bd ParisScorebis-rxh — Merge historique_tennis.json (ETL output) dans
  // db.archive_matches au boot. Schema: seasons.<year>.{atp,wta}[]
  if (fs.existsSync(HISTORIQUE_TENNIS_SEED_FILE)) {
    try {
      const seed = JSON.parse(fs.readFileSync(HISTORIQUE_TENNIS_SEED_FILE, 'utf8'));
      if (seed && seed.seasons && typeof seed.seasons === 'object') {
        let totalSeed = 0;
        let totalAdded = 0;
        const existingIds = new Set((db.archive_matches || []).map(m => String(m.id)));
        for (const seasonKey of Object.keys(seed.seasons)) {
          const seasonData = seed.seasons[seasonKey];
          if (!seasonData || typeof seasonData !== 'object') continue;
          for (const tour of ['atp', 'wta']) {
            const matches = Array.isArray(seasonData[tour]) ? seasonData[tour] : [];
            for (const m of matches) {
              totalSeed++;
              if (!m || !m.id || existingIds.has(String(m.id))) continue;
              // Map ETL tennis shape → archive_matches shape (compat with runHistoryQuery)
              const archived = {
                id: m.id,
                sport: 'tennis',
                sport_key: m.tour === 'ATP' ? 'tennis_atp' : 'tennis_wta',
                tour: m.tour,
                league: m.tournament || 'Tennis',
                country: 'International',
                surface: m.surface,
                round: m.round,
                commence_time: m.date,
                home_team: m.player1?.name,
                away_team: m.player2?.name,
                player1: m.player1,
                player2: m.player2,
                sets: m.sets,
                sets_won_p1: m.sets_won_p1,
                sets_won_p2: m.sets_won_p2,
                winner: m.winner,
                home_score: m.sets_won_p1,
                away_score: m.sets_won_p2,
                live_score: m.sets_won_p1 != null ? `${m.sets_won_p1}-${m.sets_won_p2}` : null,
                status: 'finished',
                season: parseInt(seasonKey, 10),
                _source: 'etl-seed-tennis',
                _etl_meta: { ingested_at: seed.generated_at, tour: m.tour },
              };
              (db.archive_matches = db.archive_matches || []).push(archived);
              // bd rxh Phase 4 fix: runHistoryQuery(sport='tennis') lit tennisHistory[],
              // pas db.archive_matches. Mirror dans tennisHistory pour exposer via /api/v1/history/query.
              tennisHistory.push(archived);
              existingIds.add(String(m.id));
              totalAdded++;
            }
          }
        }
        if (totalSeed > 0) {
          console.log(`  ✓ ETL seed merge (tennis ESPN): ${totalAdded}/${totalSeed} matchs ajoutes (db.archive_matches + tennisHistory)`);
          if (totalAdded > 0) saveHistory();
        }
      }
    } catch (e) {
      console.warn('[ETL Seed Load tennis]', e.message);
    }
  }

  // bd ParisScorebis-6du6 — Merge historique_openfootball.json (ETL ODbL) dans
  // db.archive_matches au boot. Schema: leagues.<key>.{meta, matches[]}
  if (fs.existsSync(HISTORIQUE_OPENFOOTBALL_FILE)) {
    try {
      const seed = JSON.parse(fs.readFileSync(HISTORIQUE_OPENFOOTBALL_FILE, 'utf8'));
      if (seed && seed.leagues && typeof seed.leagues === 'object') {
        let totalSeed = 0;
        let totalAdded = 0;
        const existingIds = new Set((db.archive_matches || []).map(m => String(m.id)));
        for (const key of Object.keys(seed.leagues)) {
          const leagueData = seed.leagues[key];
          if (!leagueData || !Array.isArray(leagueData.matches)) continue;
          for (const m of leagueData.matches) {
            totalSeed++;
            if (!m || !m.id || existingIds.has(String(m.id))) continue;
            const archived = {
              id: m.id,
              sport: 'football',
              sport_key: `of_${m.league_id}`,
              league: m.league_name,
              country: m.country,
              commence_time: m.date,
              home_team: m.home_team,
              away_team: m.away_team,
              home_score: m.home_score,
              away_score: m.away_score,
              live_score: (m.home_score != null && m.away_score != null) ? `${m.home_score}-${m.away_score}` : null,
              halftime_score: m.halftime_score,
              status: m.status || 'finished',
              season: m.season,
              round: m.round,
              _source: 'etl-seed-openfootball',
              _attribution: m._attribution || 'openfootball/football.json (ODbL)',
            };
            (db.archive_matches = db.archive_matches || []).push(archived);
            existingIds.add(String(m.id));
            totalAdded++;
          }
        }
        if (totalSeed > 0) {
          console.log(`  ✓ ETL seed merge (openfootball): ${totalAdded}/${totalSeed} matchs ajoutes a db.archive_matches (dedup'd, ODbL)`);
        }
      }
    } catch (e) {
      console.warn('[ETL Seed Load openfootball]', e.message);
    }
  }

  // bd ParisScorebis-6du6 Phase 2 — Merge historique_wikidata.json (CC0 1.0 Universal).
  // Schema: {tennis: {grand_slam_singles_winners[]}, football: {major_finals[]}}.
  // Winners-only records (single home_team = winner, no opponent). Commercial-safe (Wikidata CC0).
  if (fs.existsSync(HISTORIQUE_WIKIDATA_FILE)) {
    try {
      const seed = JSON.parse(fs.readFileSync(HISTORIQUE_WIKIDATA_FILE, 'utf8'));
      let totalSeed = 0;
      let totalAdded = 0;
      const existingIds = new Set((db.archive_matches || []).map(m => String(m.id)));

      const tennisRows = Array.isArray(seed?.tennis?.grand_slam_singles_winners)
        ? seed.tennis.grand_slam_singles_winners : [];
      for (const m of tennisRows) {
        totalSeed++;
        if (!m || !m.id || existingIds.has(String(m.id))) continue;
        const isMens = (m.class || '').toLowerCase().includes("men's singles")
          && !(m.class || '').toLowerCase().includes('women');
        const archived = {
          id: m.id,
          sport: 'tennis',
          sport_key: isMens ? 'tennis_atp' : 'tennis_wta',
          tour: isMens ? 'ATP' : 'WTA',
          league: m.edition || m.series || 'Grand Slam',
          country: 'International',
          surface: m.surface,
          round: m.round || 'F',
          commence_time: m.date,
          home_team: m.winner,
          away_team: null,
          winner: m.winner,
          status: 'finished',
          season: m.date ? parseInt(String(m.date).slice(0, 4), 10) : null,
          _source: 'etl-seed-wikidata',
          _attribution: m._attribution || 'Wikidata (CC0 1.0)',
          _wikidata: { series_qid: m.series_qid, edition_qid: m.edition_qid, winner_qid: m.winner_qid, class: m.class },
        };
        (db.archive_matches = db.archive_matches || []).push(archived);
        tennisHistory.push(archived);
        existingIds.add(String(m.id));
        totalAdded++;
      }

      const footRows = Array.isArray(seed?.football?.major_finals)
        ? seed.football.major_finals : [];
      for (const m of footRows) {
        totalSeed++;
        if (!m || !m.id || existingIds.has(String(m.id))) continue;
        const archived = {
          id: m.id,
          sport: 'football',
          sport_key: m.type_qid ? `wd_${m.type_qid}` : 'wd_football',
          league: m.event_label || m.type || 'Major Final',
          country: 'International',
          commence_time: m.date,
          home_team: m.winner || null,
          away_team: null,
          winner: m.winner || null,
          status: 'finished',
          season: m.date ? parseInt(String(m.date).slice(0, 4), 10) : null,
          round: m.round || 'F',
          _source: 'etl-seed-wikidata',
          _attribution: m._attribution || 'Wikidata (CC0 1.0)',
          _wikidata: { event_qid: m.event_qid, type_qid: m.type_qid, winner_qid: m.winner_qid, type: m.type },
        };
        (db.archive_matches = db.archive_matches || []).push(archived);
        existingIds.add(String(m.id));
        totalAdded++;
      }

      if (totalSeed > 0) {
        console.log(`  ✓ ETL seed merge (wikidata CC0): ${totalAdded}/${totalSeed} winners ajoutes (db.archive_matches${tennisRows.length ? ' + tennisHistory' : ''})`);
        if (totalAdded > 0) saveHistory();
      }
    } catch (e) {
      console.warn('[ETL Seed Load wikidata]', e.message);
    }
  }

  // bd ParisScorebis-8lqf — Merge historique_fbref.json (ETL via soccerdata).
  // ⚠️ RESEARCH ONLY: Sports Reference ToS interdit commercial display.
  // Gate via env: ETL_FBREF_LOAD=1 requis pour activer (defaut OFF prod commercial).
  // Marker research_only=true sur chaque record → UI doit skip.
  if (process.env.ETL_FBREF_LOAD === '1' && fs.existsSync(HISTORIQUE_FBREF_FILE)) {
    try {
      const seed = JSON.parse(fs.readFileSync(HISTORIQUE_FBREF_FILE, 'utf8'));
      if (seed && seed.leagues && typeof seed.leagues === 'object') {
        let totalSeed = 0;
        let totalAdded = 0;
        const existingIds = new Set((db.archive_matches || []).map(m => String(m.id)));
        for (const key of Object.keys(seed.leagues)) {
          const leagueData = seed.leagues[key];
          if (!leagueData || !Array.isArray(leagueData.matches)) continue;
          for (const m of leagueData.matches) {
            totalSeed++;
            if (!m || !m.id || existingIds.has(String(m.id))) continue;
            const archived = {
              id: m.id,
              sport: 'football',
              sport_key: `fbref_${m.league_id}`,
              league: m.league_name,
              country: 'International',
              commence_time: m.date,
              home_team: m.home_team,
              away_team: m.away_team,
              home_score: m.home_score,
              away_score: m.away_score,
              live_score: (m.home_score != null && m.away_score != null) ? `${m.home_score}-${m.away_score}` : null,
              status: 'finished',
              season: m.season,
              round: m.round,
              venue: m.venue,
              referee: m.referee,
              _source: 'etl-fbref-research',
              _research_only: true,
              _attribution: m._attribution || 'sports-reference.com via soccerdata (research only)',
            };
            (db.archive_matches = db.archive_matches || []).push(archived);
            existingIds.add(String(m.id));
            totalAdded++;
          }
        }
        if (totalSeed > 0) {
          console.log(`  ⚠️ ETL seed merge (fbref RESEARCH): ${totalAdded}/${totalSeed} matchs ajoutes — flag _research_only=true (ne pas display UI commercial)`);
        }
      }
    } catch (e) {
      console.warn('[ETL Seed Load fbref]', e.message);
    }
  }

  // bd ParisScorebis-8lvf — Merge historique_elofootball.json (community data)
  // v12.40 Phase 3: handles 3 schemas — clubs{}.matches[], recent_matches[],
  // rankings_current[] (last expose via db.elofootballRankings pour future UI).
  if (fs.existsSync(HISTORIQUE_ELOFOOTBALL_FILE)) {
    try {
      const seed = JSON.parse(fs.readFileSync(HISTORIQUE_ELOFOOTBALL_FILE, 'utf8'));
      if (seed && typeof seed === 'object') {
        let totalSeed = 0;
        let totalAdded = 0;
        const existingIds = new Set((db.archive_matches || []).map(m => String(m.id)));

        // Helper: map elofootball record → archive_matches shape (prob fields preserved)
        const mapElo = (m) => ({
          id: m.id,
          sport: 'football',
          sport_key: 'elofootball',
          league: m.league_name || 'Unknown',
          country: 'International',
          commence_time: m.date,
          home_team: m.home_team,
          away_team: m.away_team,
          home_score: m.home_score,
          away_score: m.away_score,
          live_score: (m.home_score != null && m.away_score != null) ? `${m.home_score}-${m.away_score}` : null,
          status: 'finished',
          season: m.season,
          elo_delta: m.elo_delta,
          // bd 8lvf Phase 3: probabilites elofootball preserves pour backtest/calibration
          elo_prediction: (m.prob_home != null || m.prob_draw != null || m.prob_away != null) ? {
            prob_home: m.prob_home,
            prob_draw: m.prob_draw,
            prob_away: m.prob_away,
          } : null,
          opponent_rating: m.opponent_rating || null,
          _source: 'etl-elofootball',
          _attribution: m._attribution || 'elofootball.com (community Elo ratings)',
        });

        // 1) Schema clubs{slug}.matches[] (v12.31 scaffold + v12.32 club-specific pull)
        if (seed.clubs && typeof seed.clubs === 'object') {
          for (const clubKey of Object.keys(seed.clubs)) {
            const clubData = seed.clubs[clubKey];
            if (!clubData || !Array.isArray(clubData.matches)) continue;
            for (const m of clubData.matches) {
              totalSeed++;
              if (!m || !m.id || existingIds.has(String(m.id))) continue;
              (db.archive_matches = db.archive_matches || []).push(mapElo(m));
              existingIds.add(String(m.id));
              totalAdded++;
            }
          }
        }

        // 2) Schema recent_matches[] (v12.32: index.php → 1902 matchs avec probas)
        if (Array.isArray(seed.recent_matches)) {
          for (const m of seed.recent_matches) {
            totalSeed++;
            if (!m || !m.id || existingIds.has(String(m.id))) continue;
            (db.archive_matches = db.archive_matches || []).push(mapElo(m));
            existingIds.add(String(m.id));
            totalAdded++;
          }
        }

        // 3) Schema rankings_current[] (v12.32: Top 50 Elo snapshot — pas archive
        //    matchs mais expose pour UI badge/widget Elo rankings)
        if (Array.isArray(seed.rankings_current)) {
          db.elofootballRankings = seed.rankings_current;
        }

        if (totalSeed > 0) {
          console.log(`  ✓ ETL seed merge (elofootball): ${totalAdded}/${totalSeed} matchs ajoutes (community attribution${Array.isArray(seed.rankings_current) ? `, rankings_current ${seed.rankings_current.length} clubs` : ''})`);
        }
      }
    } catch (e) {
      console.warn('[ETL Seed Load elofootball]', e.message);
    }
  }

  // bd ParisScorebis-rxh Phase 2 — Merge historique_bsd_tennis.json (BSD Sports
  // Addon settled predictions) dans db.archive_matches. Schema: predictions[]
  // avec match (tournament, players, sets_detail) + prediction probs + backtest
  // (actual_winner, was_winner_correct, confidence).
  if (fs.existsSync(HISTORIQUE_BSD_TENNIS_FILE)) {
    try {
      const seed = JSON.parse(fs.readFileSync(HISTORIQUE_BSD_TENNIS_FILE, 'utf8'));
      if (seed && Array.isArray(seed.predictions)) {
        let totalSeed = 0;
        let totalAdded = 0;
        const existingIds = new Set((db.archive_matches || []).map(m => String(m.id)));
        for (const p of seed.predictions) {
          totalSeed++;
          if (!p || !p.id || existingIds.has(String(p.id))) continue;
          // bd k3ex fix defensif: BSD tag souvent circuit='ATP' pour matchs feminins
          // (UTR Women, etc). On re-derive depuis gender + tournament name si conflit.
          let circuit = String(p.circuit || '').toUpperCase();
          const g1 = String(p.player1?.gender || '').toUpperCase();
          const g2 = String(p.player2?.gender || '').toUpperCase();
          const tNorm = String(p.tournament || '').toLowerCase();
          if (g1 === 'F' && g2 === 'F') circuit = 'WTA';
          else if (g1 === 'M' && g2 === 'M') circuit = 'ATP';
          else if ((g1 === 'F' && g2 === 'M') || (g1 === 'M' && g2 === 'F')) circuit = 'MIXED';
          else if (/\b(women|ladies|wta|female|girls)\b/.test(tNorm)) circuit = 'WTA';
          else if (/\bmixed\b/.test(tNorm)) circuit = 'MIXED';
          const sport_key = circuit === 'ATP' ? 'tennis_atp'
            : circuit === 'WTA' ? 'tennis_wta'
            : circuit === 'MIXED' ? 'tennis_mixed'
            : circuit === 'UTR' ? 'tennis_utr'
            : circuit === 'ITF' ? 'tennis_itf'
            : 'tennis_other';
          const seasonYear = p.date ? new Date(p.date).getUTCFullYear() : null;
          const winner = p.actual_winner === 1 ? 'p1' : (p.actual_winner === 2 ? 'p2' : null);
          const archived = {
            id: p.id,
            sport: 'tennis',
            sport_key,
            tour: circuit || null,
            league: p.tournament || 'Tennis',
            country: 'International',
            surface: p.surface || null,
            round: p.round || null,
            commence_time: p.date,
            home_team: p.player1?.name || null,
            away_team: p.player2?.name || null,
            player1: p.player1 || null,
            player2: p.player2 || null,
            sets: p.sets_detail || [],
            sets_won_p1: p.sets_won_p1,
            sets_won_p2: p.sets_won_p2,
            winner,
            home_score: p.sets_won_p1,
            away_score: p.sets_won_p2,
            live_score: p.sets_won_p1 != null ? `${p.sets_won_p1}-${p.sets_won_p2}` : null,
            status: p.status || 'finished',
            season: seasonYear,
            // BSD ML predictions (calibration source)
            bsd_prediction: {
              prob_p1_wins: p.prediction?.prob_p1_wins,
              prob_p2_wins: p.prediction?.prob_p2_wins,
              predicted_winner: p.prediction?.predicted_winner,
              confidence: p.prediction?.confidence,
              prob_over_2_5_sets: p.prediction?.prob_over_2_5_sets,
              prob_over_22_5_games: p.prediction?.prob_over_22_5_games,
              was_winner_correct: p.was_winner_correct,
            },
            _source: 'etl-bsd-tennis',
            _attribution: p._attribution || 'BSD Tennis (Bzzoiro Sports Addon)',
            _etl_meta: {
              ingested_at: seed.generated_at,
              bsd_prediction_id: p.bsd_prediction_id,
              bsd_match_id: p.bsd_match_id,
              api_id: p.api_id,
            },
          };
          (db.archive_matches = db.archive_matches || []).push(archived);
          // bd rxh Phase 4 fix: tennisHistory pour exposure via /api/v1/history/query
          tennisHistory.push(archived);
          existingIds.add(String(p.id));
          totalAdded++;
        }
        if (totalSeed > 0) {
          console.log(`  ✓ ETL seed merge (bsd-tennis): ${totalAdded}/${totalSeed} predictions ajoutees (db.archive_matches + tennisHistory, BSD attribution)`);
          if (totalAdded > 0) saveHistory();
        }
      }
    } catch (e) {
      console.warn('[ETL Seed Load bsd-tennis]', e.message);
    }
  }
}

function saveHistory() {
  kvSetBatch([
    ['history_matches', history],
    ['tennis_history_matches', tennisHistory],
    ['history_accuracy', accuracy],
  ]);
}

// ═══════════════════════════════════════════════════════════════════════════════
//  AI CACHE — analyses Power Score par match (ai_cache.json, TTL 24h)
// ═══════════════════════════════════════════════════════════════════════════════

let aiCache = {};  // { [matchKey]: { data, cachedAt } }

function loadAICache() {
  const now = Date.now();
  let kept = 0;

  // Rétrocompat : migration one-shot depuis ai_cache.json
  if (fs.existsSync(AI_CACHE_FILE)) {
    try {
      const raw = JSON.parse(fs.readFileSync(AI_CACHE_FILE, 'utf8'));
      for (const [key, entry] of Object.entries(raw)) {
        if (now - new Date(entry.cachedAt).getTime() < AI_CACHE_TTL) {
          aiCache[key] = entry;
          kvSet('ai_e_' + key, entry);
          kept++;
        }
      }
      fs.renameSync(AI_CACHE_FILE, AI_CACHE_FILE + '.migrated');
      console.log(`  ✓ ai_cache.json migré vers SQLite per-entry (${kept} analyses)`);
      return;
    } catch (e) { console.warn('[AICache] Migration JSON→SQLite:', e.message); }
  }

  // Migration one-shot depuis l'ancien blob monolithique 'ai_cache'
  const oldBlob = kvGet('ai_cache', null);
  if (oldBlob && typeof oldBlob === 'object') {
    for (const [key, entry] of Object.entries(oldBlob)) {
      if (now - new Date(entry.cachedAt).getTime() < AI_CACHE_TTL) {
        aiCache[key] = entry;
        kvSet('ai_e_' + key, entry);
        kept++;
      }
    }
    if (kept > 0) {
      sqldb.prepare("DELETE FROM kv WHERE key = 'ai_cache'").run();
      console.log(`  ✓ AI Cache blob migré vers per-entry (${kept} analyses)`);
      return;
    }
  }

  // Lecture per-entry (chemin nominal)
  try {
    const rows = sqldb.prepare("SELECT key, value FROM kv WHERE key LIKE 'ai_e_%'").all();
    for (const row of rows) {
      const matchKey = row.key.slice(5);
      try {
        const entry = JSON.parse(row.value);
        if (now - new Date(entry.cachedAt).getTime() < AI_CACHE_TTL) { aiCache[matchKey] = entry; kept++; }
        else sqldb.prepare("DELETE FROM kv WHERE key = ?").run(row.key);
      } catch { }
    }
  } catch (e) { console.warn('[AICache] Lecture per-entry:', e.message); }
  console.log(`  ✓ AI Cache chargé per-entry (${kept} analyses valides)`);
}

function saveAICache() { /* no-op — écriture per-entry dans saveAIAnalysisToCache */ }

// ─── FBref Advanced Stats — Pattern B Loader (P4) ────────────────────────────
// Lit les JSON produits par scripts/scrape_advanced_stats.py et merge dans
// db.fbrefStats keyed by normName(team). Réload toutes les 24h.
let _fbrefLastLoad = 0;
let _fbrefLoading = false;

function loadAdvancedFBrefStats() {
  if (_fbrefLoading) return;
  _fbrefLoading = true;
  try {
    if (!fs.existsSync(FBREF_ADVANCED_DIR)) {
      db.fbrefStats = db.fbrefStats || {};
      return;
    }
    const files = fs.readdirSync(FBREF_ADVANCED_DIR)
      .filter(f => f.endsWith('.json') && !f.startsWith('_'));
    if (!files.length) {
      db.fbrefStats = db.fbrefStats || {};
      _fbrefLastLoad = Date.now();
      return;
    }
    const merged = {};
    let totalRows = 0;
    let totalTeams = 0;
    for (const file of files) {
      try {
        const raw = fs.readFileSync(path.join(FBREF_ADVANCED_DIR, file), 'utf-8');
        const data = JSON.parse(raw);
        const meta = data._meta || {};
        const stats = data.team_season_stats || {};
        // Anchor on 'standard' rows to enumerate teams; other stat_types merge by team name.
        const standard = Array.isArray(stats.standard) ? stats.standard : [];
        for (const row of standard) {
          const teamName = row.team || row.Team || row.squad || row.Squad || null;
          if (!teamName) continue;
          const key = normName(teamName);
          if (!merged[key]) {
            merged[key] = {
              team: teamName,
              league: meta.league || null,
              season: meta.season || null,
              fetchedAt: meta.fetched_at || null,
              source: meta.source || 'fbref-soccerdata',
              stats: {},
            };
            totalTeams++;
          }
          merged[key].stats.standard = row;
          totalRows++;
        }
        // FBref 1.9.0 read_team_season_stats supported: standard/shooting/keeper/playing_time/misc
        for (const statType of ['shooting', 'keeper', 'playing_time', 'misc']) {
          const rows = Array.isArray(stats[statType]) ? stats[statType] : [];
          for (const row of rows) {
            const teamName = row.team || row.Team || row.squad || row.Squad || null;
            if (!teamName) continue;
            const key = normName(teamName);
            if (!merged[key]) continue;
            merged[key].stats[statType] = row;
            totalRows++;
          }
        }
      } catch (e) {
        console.warn(`  [FBref] ${file} parse erreur:`, e.message);
      }
    }
    db.fbrefStats = merged;
    _fbrefLastLoad = Date.now();
    console.log(`  ✓ FBref advanced stats : ${totalTeams} équipes (${totalRows} stat rows) depuis ${files.length} fichiers`);
  } catch (e) {
    console.warn('  [FBref] loadAdvancedFBrefStats erreur:', e.message);
  } finally {
    _fbrefLoading = false;
  }
}

function maybeReloadFBrefStats() {
  if (!_fbrefLastLoad || Date.now() - _fbrefLastLoad > FBREF_RELOAD_INTERVAL_MS) {
    loadAdvancedFBrefStats();
  }
}

function getFBrefStatsForTeam(teamName) {
  if (!teamName || !db.fbrefStats) return null;
  const key = normName(teamName);
  return db.fbrefStats[key] || null;
}

/**
 * Retourne l'analyse en cache si elle existe et est valide (< 24h).
 * @param {string} matchKey  Identifiant unique du match (m.id côté frontend)
 * @returns {object|null}    Réponse Gemini stockée, ou null si miss
 */
function getCachedAIAnalysis(matchKey) {
  if (!matchKey) return null;
  const entry = aiCache[matchKey];
  if (!entry) return null;
  if (Date.now() - new Date(entry.cachedAt).getTime() >= AI_CACHE_TTL) {
    delete aiCache[matchKey]; // éviction silencieuse
    return null;
  }
  return entry.data;
}

/**
 * Persiste une analyse Gemini dans le cache en mémoire et sur disque.
 * @param {string} matchKey  Identifiant unique du match
 * @param {object} data      Réponse Gemini complète (JSON déjà parsé)
 */
function saveAIAnalysisToCache(matchKey, data) {
  if (!matchKey) return;
  const entry = { data, cachedAt: new Date().toISOString() };
  aiCache[matchKey] = entry;
  kvSet('ai_e_' + matchKey, entry); // O(1) — une seule ligne SQLite
}

// BSD score lookup with per-call date cache — avoids redundant fetches within one archive pass
async function getBSDScoreForMatch(team1, team2, dateStr, bsdDateCache) {
  try {
    if (!bsdDateCache.has(dateStr)) {
      const results = await fetchBSDMatches(dateStr, dateStr);
      bsdDateCache.set(dateStr, results);
    }
    const bsdMatches = bsdDateCache.get(dateStr);
    const hNorm = normName(team1), aNorm = normName(team2);
    const found = bsdMatches.find(bm => {
      if (bm.home_score === null || bm.away_score === null) return false;
      if (bm.status === 'inprogress' || (bm.status && bm.status.includes('half'))) return false;
      const bh = normName(bm.home_team), ba = normName(bm.away_team);
      return (bh.includes(hNorm.split(' ')[0]) || hNorm.includes(bh.split(' ')[0])) &&
        (ba.includes(aNorm.split(' ')[0]) || aNorm.includes(ba.split(' ')[0]));
    });
    if (found) return { home: Number(found.home_score), away: Number(found.away_score), source: 'bsd' };
    return null;
  } catch (e) {
    return null;
  }
}

async function archivePastMatches() {
  if (!API_FOOTBALL_KEY && !BSD_BASE_URL) return;
  const now = Date.now();
  const bsdDateCache = new Map(); // shared cache across all archive passes this call

  // ── ÉTAPE 1 : Archiver les matchs terminés récents ──────────────────────────
  const past = db.matches.filter(m => new Date(m.commence_time).getTime() < now - 3 * 3600000);
  let archived = 0;

  if (past.length) {
    console.log(`  [Archive] ${past.length} matchs terminés à archiver…`);

    for (const match of past) {
      if (history.find(h => h.id === match.id)) continue;

      const dateStr = match.commence_time.split('T')[0];
      let realScore = null;

      // Phase 1 : BSD (gratuit, prioritaire)
      if (BSD_BASE_URL) {
        realScore = await getBSDScoreForMatch(match.home_team, match.away_team, dateStr, bsdDateCache);
        if (realScore) console.log(`  [Archive] BSD score OK: ${match.home_team} ${realScore.home}-${realScore.away} ${match.away_team}`);
      }

      // Phase 2 : API-Football fallback si BSD n'a pas le score
      if (!realScore && API_FOOTBALL_KEY) {
        try {
          const res = await httpsGet(
            `https://v3.football.api-sports.io/fixtures?date=${dateStr}&timezone=Europe/Paris&status=FT`,
            { 'x-apisports-key': API_FOOTBALL_KEY }
          );
          if (res.status === 200 && res.data.response) {
            const hNorm = normName(match.home_team), aNorm = normName(match.away_team);
            const found = res.data.response.find(f => {
              const fh = normName(f.teams.home.name), fa = normName(f.teams.away.name);
              return (fh.includes(hNorm.split(' ')[0]) || hNorm.includes(fh.split(' ')[0])) &&
                (fa.includes(aNorm.split(' ')[0]) || aNorm.includes(fa.split(' ')[0]));
            });
            if (found?.goals) realScore = { home: found.goals.home, away: found.goals.away, source: 'api-football' };
          }
        } catch (e) { _traceCatch('archive_score_lookup', e); /* score unavailable */ }
      }

      // H4 : tag stratégies IA qualifiées au moment de l'archive (snapshot prédictions)
      const strategiesQualified = [];
      try {
        for (const [key, strat] of Object.entries(STRATEGIES)) {
          const prob = strat.getProb?.(match);
          if (typeof prob === 'number' && prob >= 55) strategiesQualified.push(key);
        }
      } catch (e) { _traceCatch('strategies_qualified', e); /* STRATEGIES sont définies plus bas dans le fichier, garde-fou */ }

      const record = {
        id: match.id, home_team: match.home_team, away_team: match.away_team,
        league: match.league, commence_time: match.commence_time,
        predicted: {
          over25: match.poisson?.over25,
          btts: match.poisson?.btts,
          bestEdge: match.best_edge?.label,
          bestEdgeValue: match.best_edge?.edge,
          // H2 instrumentation : capture cote réelle bookmaker + cote no-vig fair
          bestEdgeOdds: match.best_edge?.odds ?? null,
          bestEdgeBk: match.best_edge?.bk ?? null,
          fair: match.fair ? { home: match.fair.home, draw: match.fair.draw, away: match.fair.away } : null,
          // H4 : stratégies IA tagguées au moment de l'archive
          strategies: strategiesQualified,
          // Snapshot des probas dérivées pour pouvoir évaluer win/loss par stratégie
          poisson_snapshot: match.poisson ? {
            over25: match.poisson.over25, btts: match.poisson.btts, over15: match.poisson.over15,
            cs00: match.poisson.cs00, homeWin: match.poisson.homeWin, draw: match.poisson.draw, awayWin: match.poisson.awayWin,
          } : null,
        },
        realScore, archived_at: new Date().toISOString(),
      };

      if (realScore !== null) {
        const totalGoals = realScore.home + realScore.away;
        const wasBTTS = realScore.home > 0 && realScore.away > 0;
        const wasOver25 = totalGoals > 2.5;
        if (match.poisson?.over25 > 55) { accuracy.over25_total++; if (wasOver25) accuracy.over25_correct++; }
        if (match.poisson?.btts > 55) { accuracy.btts_total++; if (wasBTTS) accuracy.btts_correct++; }
        if (match.best_edge?.edge > 5) {
          accuracy.edge_total++;
          const winner = realScore.home > realScore.away ? match.home_team : realScore.away > realScore.home ? match.away_team : 'Nul';
          if (winner === match.best_edge.label) accuracy.edge_correct++;
        }
        accuracy.total++;
        record.verified = true;
      } else { record.verified = false; }

      history.push(record);
      archived++;
      // Hook Mes Paris : flag les paris pending sur ce match pour suggestion settlement côté UI
      if (record.verified && record.realScore && sqldb) {
        try {
          sqldb.prepare(
            "UPDATE user_bets SET updated_at = strftime('%s','now') WHERE match_id = ? AND status = 'pending'"
          ).run(record.id);
        } catch (e) { _traceCatch('user_bets_update', e); /* table absente sur ancien deploy */ }
        // bd pbf — CLV per leg : si closing_odds capturé pour ce match, calcule CLV pour chaque pari
        // settled non-void (won/lost/half_won/half_lost) et pas encore évalué.
        try {
          const closing = getMatchClosingOdds(record.id);
          if (closing) {
            const bets = sqldb.prepare(
              "SELECT id, market, selection_label, odds FROM user_bets WHERE match_id = ? AND status IN ('won','lost','half_won','half_lost') AND clv_pct IS NULL"
            ).all(record.id);
            for (const bet of bets) {
              // Heuristique mapping selection → cote closing (1X2 only Phase 1, autres marchés future scope)
              const sel = String(bet.selection_label || '').toLowerCase().trim();
              let closingVal = null;
              if (sel === '1' || sel === 'home' || sel === record.home_team?.toLowerCase()) closingVal = closing.home;
              else if (sel === 'x' || sel === 'n' || sel === 'draw' || sel === 'nul') closingVal = closing.draw;
              else if (sel === '2' || sel === 'away' || sel === record.away_team?.toLowerCase()) closingVal = closing.away;
              const clv = computeCLV(bet.odds, closingVal);
              if (clv !== null) {
                sqldb.prepare("UPDATE user_bets SET clv_pct = ?, closing_odds = ? WHERE id = ?")
                  .run(clv, closingVal, bet.id);
              }
            }
          }
        } catch (e) { _traceCatch('clv_settle', e); }
      }
    }

    const archivedIds = new Set(past.map(m => m.id));
    db.matches = db.matches.filter(m => !archivedIds.has(m.id));
    // Sync vers db.archive_matches pour H2H et stats
    db.archive_matches = [...db.archive_matches, ...past];
    // Limiter a 1000 matchs archives pour performance
    if (db.archive_matches.length > 1000) {
      db.archive_matches = db.archive_matches.slice(-1000);
    }
  }

  // ── ÉTAPE 2 : Retry des matchs non vérifiés (API était down au moment de l'archive) ──
  const unverified = history.filter(h => !h.verified && h.realScore === null && new Date(h.archived_at).getTime() < now - 24 * 3600000);
  let retried = 0;

  if (unverified.length) {
    console.log(`  [Archive] ${unverified.length} matchs non vérifiés à re-tenter…`);

    for (const entry of unverified) {
      const dateStr = entry.commence_time.split('T')[0];
      let retryScore = null;

      // Phase 1 : BSD
      if (BSD_BASE_URL) {
        retryScore = await getBSDScoreForMatch(entry.home_team, entry.away_team, dateStr, bsdDateCache);
      }
      // Phase 2 : API-Football fallback
      if (!retryScore && API_FOOTBALL_KEY) {
        try {
          const res = await httpsGet(
            `https://v3.football.api-sports.io/fixtures?date=${dateStr}&timezone=Europe/Paris&status=FT`,
            { 'x-apisports-key': API_FOOTBALL_KEY }
          );
          if (res.status === 200 && res.data.response) {
            const hNorm = normName(entry.home_team), aNorm = normName(entry.away_team);
            const found = res.data.response.find(f => {
              const fh = normName(f.teams.home.name), fa = normName(f.teams.away.name);
              return (fh.includes(hNorm.split(' ')[0]) || hNorm.includes(fh.split(' ')[0])) &&
                (fa.includes(aNorm.split(' ')[0]) || aNorm.includes(fa.split(' ')[0]));
            });
            if (found?.goals) retryScore = { home: found.goals.home, away: found.goals.away, source: 'api-football' };
          }
        } catch (e) { /* still unavailable */ }
      }

      if (retryScore) {
        entry.realScore = retryScore;
        const totalGoals = entry.realScore.home + entry.realScore.away;
        const wasBTTS = entry.realScore.home > 0 && entry.realScore.away > 0;
        const wasOver25 = totalGoals > 2.5;
        if (entry.predicted?.over25 > 55) { accuracy.over25_total++; if (wasOver25) accuracy.over25_correct++; }
        if (entry.predicted?.btts > 55) { accuracy.btts_total++; if (wasBTTS) accuracy.btts_correct++; }
        if (entry.predicted?.bestEdgeValue > 5) {
          accuracy.edge_total++;
          const winner = entry.realScore.home > entry.realScore.away ? entry.home_team : entry.realScore.away > entry.realScore.home ? entry.away_team : 'Nul';
          if (winner === entry.predicted.bestEdge) accuracy.edge_correct++;
        }
        accuracy.total++;
        entry.verified = true;
        entry.retry_at = new Date().toISOString();
        retried++;
      }
    }
  }

  if (archived > 0 || retried > 0) {
    saveHistory(); saveDB();
    console.log(`  [Archive] ✓ ${archived} archivés + ${retried} re-vérifiés (${accuracy.total} vérifiés au total)`);
  }
}

// Backfill history depuis db.archive_matches : récupère les matchs qui ont été
// purgés sans passer par archivePastMatches() (race autoPurge vs archive).
// Idempotent — saute les matchs déjà présents dans history.
function backfillHistoryFromArchive() {
  if (!db.archive_matches || !db.archive_matches.length) {
    console.log(`  [Backfill] db.archive_matches vide — rien à récupérer`);
    return 0;
  }
  const knownIds = new Set(history.map(h => h.id));
  let added = 0;

  for (const m of db.archive_matches) {
    if (!m || !m.id || knownIds.has(m.id)) continue;

    // Extraction du score réel — supporte string "1-0", objet {home,away}, ou m.goals
    let realScore = null;
    if (typeof m.live_score === 'string' && /^\d+-\d+$/.test(m.live_score)) {
      const [h, a] = m.live_score.split('-').map(Number);
      if (Number.isFinite(h) && Number.isFinite(a)) {
        realScore = { home: h, away: a, source: 'archive_live' };
      }
    } else if (m.live_score && typeof m.live_score === 'object' &&
               Number.isFinite(m.live_score.home) && Number.isFinite(m.live_score.away)) {
      realScore = { home: m.live_score.home, away: m.live_score.away, source: 'archive_live' };
    } else if (m.goals && Number.isFinite(m.goals.home) && Number.isFinite(m.goals.away)) {
      realScore = { home: m.goals.home, away: m.goals.away, source: 'archive_goals' };
    }
    if (!realScore) continue;

    const record = {
      id: m.id,
      home_team: m.home_team,
      away_team: m.away_team,
      league: m.league,
      commence_time: m.commence_time,
      predicted: {
        over25: m.poisson?.over25,
        btts: m.poisson?.btts,
        bestEdge: m.best_edge?.label,
        bestEdgeValue: m.best_edge?.edge,
      },
      realScore,
      archived_at: m.archived_at || new Date().toISOString(),
      verified: true,
      backfilled: true,
    };

    const totalGoals = realScore.home + realScore.away;
    const wasBTTS = realScore.home > 0 && realScore.away > 0;
    const wasOver25 = totalGoals > 2.5;
    if (m.poisson?.over25 > 55) { accuracy.over25_total++; if (wasOver25) accuracy.over25_correct++; }
    if (m.poisson?.btts > 55) { accuracy.btts_total++; if (wasBTTS) accuracy.btts_correct++; }
    if (m.best_edge?.edge > 5) {
      accuracy.edge_total++;
      const winner = realScore.home > realScore.away ? m.home_team
                   : realScore.away > realScore.home ? m.away_team : 'Nul';
      if (winner === m.best_edge.label) accuracy.edge_correct++;
    }
    accuracy.total++;

    history.push(record);
    knownIds.add(m.id);
    added++;
  }

  if (added > 0) {
    saveHistory();
    console.log(`  [Backfill] ✓ ${added} matchs récupérés depuis db.archive_matches (history: ${history.length})`);
  } else {
    console.log(`  [Backfill] Aucun match exploitable dans db.archive_matches (${db.archive_matches.length} entrées scannées)`);
  }
  return added;
}

// Devig 2-way market : retourne probabilité fair en % (entier) de A vs B.
// bd b3b — Best edge 1X2 : meilleur EV parmi home/draw/away avec cotes marche
// et probas modele (Poisson teamStats prioritaire). Retourne { label, edge, odds, prob }.
function computeBest1X2Edge(homeOdds, drawOdds, awayOdds, modelProbs) {
  if (!Number.isFinite(homeOdds) || !Number.isFinite(awayOdds) || !modelProbs) return null;
  const dOdds = Number.isFinite(drawOdds) ? drawOdds : ((homeOdds + awayOdds) / 2);
  const ph = Number.isFinite(modelProbs.home) ? modelProbs.home : null;
  const pd = Number.isFinite(modelProbs.draw) ? modelProbs.draw : null;
  const pa = Number.isFinite(modelProbs.away) ? modelProbs.away : null;
  // Accept probas en pct (0..100) ou ratio (0..1) — normalise
  const norm = (p) => p == null ? null : (p > 1 ? p / 100 : p);
  const legs = [
    { label: 'home', odds: homeOdds, prob: norm(ph) },
    { label: 'draw', odds: dOdds,    prob: norm(pd) },
    { label: 'away', odds: awayOdds, prob: norm(pa) },
  ];
  let best = null;
  for (const l of legs) {
    if (!Number.isFinite(l.odds) || !Number.isFinite(l.prob) || l.odds <= 1 || l.prob <= 0) continue;
    const edge = (l.odds * l.prob - 1) * 100;
    if (!best || edge > best.edge) best = { label: l.label, edge: +edge.toFixed(2), odds: l.odds, prob: l.prob };
  }
  return best;
}

function devigTwoWay(oddsA, oddsB) {
  if (!Number.isFinite(oddsA) || !Number.isFinite(oddsB)) return null;
  if (oddsA <= 1 || oddsB <= 1) return null;
  const ia = 1 / oddsA, ib = 1 / oddsB;
  const total = ia + ib;
  if (total <= 0) return null;
  return Math.round((ia / total) * 100);
}

// Recompute global accuracy from current history. Idempotent.
function recomputeAccuracy() {
  accuracy = { total: 0, over25_correct: 0, over25_total: 0, btts_correct: 0, btts_total: 0, edge_correct: 0, edge_total: 0 };
  for (const h of history) {
    if (!h.verified || !h.realScore) continue;
    const rs = h.realScore;
    accuracy.total++;
    const wasOver25 = (rs.home + rs.away) > 2.5;
    const wasBTTS = rs.home > 0 && rs.away > 0;
    if (Number.isFinite(h.predicted?.over25) && h.predicted.over25 > 55) {
      accuracy.over25_total++;
      if (wasOver25) accuracy.over25_correct++;
    }
    if (Number.isFinite(h.predicted?.btts) && h.predicted.btts > 55) {
      accuracy.btts_total++;
      if (wasBTTS) accuracy.btts_correct++;
    }
    if (Number.isFinite(h.predicted?.bestEdgeValue) && h.predicted.bestEdgeValue > 5) {
      accuracy.edge_total++;
      const winner = rs.home > rs.away ? h.home_team
                   : rs.away > rs.home ? h.away_team : 'Nul';
      if (winner === h.predicted.bestEdge) accuracy.edge_correct++;
    }
  }
}

// Backfill via BSD : récupère N jours de matchs terminés et reconstruit `predicted`
// depuis les cotes BSD pré-match (devig over25/under25 ; 1/odds_btts_yes).
// opts.force = true → purge les records `backfilled:'bsd'` existants sans predicted valide,
// puis ré-injecte avec la nouvelle logique cotes.
async function backfillHistoryFromBSD(daysBack = 14, opts = {}) {
  if (typeof BSD_BASE_URL === 'undefined' || !BSD_BASE_URL) {
    console.warn('  [BackfillBSD] BSD_BASE_URL absent — skip');
    return 0;
  }
  const force = !!opts.force;

  if (force) {
    const before = history.length;
    history = history.filter(h => !(h.backfilled === 'bsd' && !Number.isFinite(h.predicted?.over25)));
    const purged = before - history.length;
    if (purged > 0) console.log(`  [BackfillBSD] force=true — purgé ${purged} records sans predicted`);
    recomputeAccuracy();
  }

  const now = Date.now();
  const knownIds = new Set(history.map(h => h.id));
  let added = 0, withPoisson = 0;
  const LEAGUE_AVG = 1.35;
  const finishedSet = new Set(['ended','finished','ft','aet','pen','ENDED','FINISHED','FT','AET','PEN']);

  for (let i = 1; i <= daysBack; i++) {
    const d = new Date(now - i * 86400000);
    const dateStr = d.toISOString().split('T')[0];
    let matches = [];
    try {
      matches = await fetchBSDMatches(dateStr, dateStr);
    } catch (e) {
      console.warn(`  [BackfillBSD] ${dateStr}:`, e.message);
      continue;
    }
    for (const m of matches) {
      if (!finishedSet.has(String(m.status || ''))) continue;
      if (!Number.isFinite(m.home_score) || !Number.isFinite(m.away_score)) continue;

      const id = m.id || `bsd_${m._bsd_event_id || ''}_${dateStr}`;
      if (knownIds.has(id)) continue;

      // STRATÉGIE 1 — predicted depuis cotes BSD pré-match (devig 2-way)
      let probOver25 = null, probBTTS = null;
      if (m.odds) {
        probOver25 = devigTwoWay(m.odds.over25, m.odds.under25);
        if (Number.isFinite(m.odds.btts) && m.odds.btts > 1) {
          probBTTS = Math.round((1 / m.odds.btts) * 100); // raw vig'd — BSD ne mappe que BTTS yes
        }
      }

      // STRATÉGIE 2 — fallback Poisson via teamStats fuzzy (si cotes absentes)
      // bd b3b — capture aussi probs 1X2 pour bestEdge ; couvre les deux cas
      // (Poisson dispo pour edge meme si over25 deja calc depuis cotes).
      let poisson1X2 = null;
      const hKey = normName(m.home_team);
      const aKey = normName(m.away_team);
      const hStats = (db.teamStats && (db.teamStats[hKey] || (typeof findFuzzy === 'function' ? findFuzzy(hKey) : null))) || null;
      const aStats = (db.teamStats && (db.teamStats[aKey] || (typeof findFuzzy === 'function' ? findFuzzy(aKey) : null))) || null;
      if (hStats && aStats &&
          Number.isFinite(hStats.avgScored) && Number.isFinite(aStats.avgConceded) &&
          Number.isFinite(aStats.avgScored) && Number.isFinite(hStats.avgConceded)) {
        const lh = (hStats.avgScored / LEAGUE_AVG) * aStats.avgConceded;
        const la = (aStats.avgScored / LEAGUE_AVG) * hStats.avgConceded;
        if (lh > 0 && la > 0) {
          try {
            const poisson = computePoisson(lh, la);
            if (probOver25 == null) probOver25 = poisson.over25;
            if (probBTTS == null)  probBTTS  = poisson.btts;
            // 1X2 probs pour computeBest1X2Edge (toujours capturees si Poisson OK)
            if (Number.isFinite(poisson.homeWin) && Number.isFinite(poisson.awayWin)) {
              poisson1X2 = { home: poisson.homeWin, draw: poisson.draw, away: poisson.awayWin };
            }
          } catch (e) { console.warn('[CATCH-04] computePoisson (buildValueBets):', e.message); }
        }
      }

      // Skip si aucune prédiction trouvée (ni cotes ni teamStats)
      if (probOver25 == null && probBTTS == null) continue;

      // bd b3b — bestEdge 1X2 quand cotes m.odds.home/draw/away + Poisson dispo
      let best1X2 = null;
      if (m.odds && Number.isFinite(m.odds.home) && Number.isFinite(m.odds.away) && poisson1X2) {
        best1X2 = computeBest1X2Edge(m.odds.home, m.odds.draw, m.odds.away, poisson1X2);
      }

      const realScore = { home: m.home_score, away: m.away_score, source: 'backfill_bsd' };
      const record = {
        id, home_team: m.home_team, away_team: m.away_team,
        league: m.league, commence_time: m.commence_time,
        predicted: {
          over25: probOver25,
          btts: probBTTS,
          bestEdge: best1X2 ? best1X2.label : null,
          bestEdgeValue: best1X2 ? best1X2.edge : null,
          bestEdgeOdds: best1X2 ? best1X2.odds : null,
          // Snapshot Poisson 1X2 pour audit + recompute futur
          homeWin: poisson1X2 ? poisson1X2.home : null,
          draw:    poisson1X2 ? poisson1X2.draw : null,
          awayWin: poisson1X2 ? poisson1X2.away : null,
        },
        odds_snapshot: m.odds || null,
        realScore,
        archived_at: new Date().toISOString(),
        verified: true,
        backfilled: 'bsd',
        predicted_source: (m.odds && (m.odds.over25 || m.odds.btts)) ? 'bsd_odds' : 'poisson_teamstats',
      };

      const wasOver25 = (realScore.home + realScore.away) > 2.5;
      const wasBTTS = realScore.home > 0 && realScore.away > 0;
      if (Number.isFinite(probOver25) && probOver25 > 55) {
        accuracy.over25_total++;
        if (wasOver25) accuracy.over25_correct++;
      }
      if (Number.isFinite(probBTTS) && probBTTS > 55) {
        accuracy.btts_total++;
        if (wasBTTS) accuracy.btts_correct++;
      }
      accuracy.total++;

      history.push(record);
      knownIds.add(id);
      added++;
      if (Number.isFinite(probOver25)) withPoisson++;
    }
    // BSD rate-limit safe pause
    await new Promise(r => setTimeout(r, 250));
  }

  if (added > 0) {
    saveHistory();
    console.log(`  [BackfillBSD] ✓ ${added} matchs récupérés sur ${daysBack}j (avec predicted: ${withPoisson}/${added} ; history: ${history.length} ; over25_total: ${accuracy.over25_total} ; btts_total: ${accuracy.btts_total})`);
  } else {
    console.log(`  [BackfillBSD] Aucun match exploitable sur ${daysBack}j`);
  }
  return added;
}

// Enrich history records sans predicted.over25 : 2 stratégies cascadées :
//   (1) cotes BSD stockées dans odds_snapshot (devig)
//   (2) Poisson rétrospectif via teamStats courants (fuzzy)
// Appelé après fetchStats() — non-destructif (skip si predicted déjà rempli).
function enrichHistoryPoisson() {
  if (!history.length) return 0;
  let enriched_odds = 0, enriched_poisson = 0, enriched_edge = 0, skipped = 0;
  const LEAGUE_AVG = 1.35;
  const hasTeamStats = db.teamStats && Object.keys(db.teamStats).length > 0;

  for (const h of history) {
    if (!h.verified || !h.realScore) continue;
    // bd b3b — process records meme si over25/btts deja remplis, pour compute bestEdge manquant
    const needsProbs = !Number.isFinite(h.predicted?.over25) || !Number.isFinite(h.predicted?.btts);
    const needsEdge = !Number.isFinite(h.predicted?.bestEdgeValue) || !h.predicted?.bestEdge;
    if (!needsProbs && !needsEdge) continue;

    let probOver25 = h.predicted?.over25;
    let probBTTS = h.predicted?.btts;
    let poisson1X2 = (Number.isFinite(h.predicted?.homeWin) && Number.isFinite(h.predicted?.awayWin))
      ? { home: h.predicted.homeWin, draw: h.predicted.draw, away: h.predicted.awayWin } : null;
    let source = null;

    // STRATÉGIE 1 — odds_snapshot
    if (h.odds_snapshot) {
      if (!Number.isFinite(probOver25)) {
        const p = devigTwoWay(h.odds_snapshot.over25, h.odds_snapshot.under25);
        if (Number.isFinite(p)) { probOver25 = p; source = 'odds'; }
      }
      if (!Number.isFinite(probBTTS) && Number.isFinite(h.odds_snapshot.btts) && h.odds_snapshot.btts > 1) {
        probBTTS = Math.round((1 / h.odds_snapshot.btts) * 100);
        source = source || 'odds';
      }
    }

    // STRATÉGIE 2 — Poisson teamStats fuzzy (+ bd b3b : capture aussi probs 1X2)
    if ((!Number.isFinite(probOver25) || !Number.isFinite(probBTTS) || !poisson1X2) && hasTeamStats) {
      const hKey = normName(h.home_team);
      const aKey = normName(h.away_team);
      const hStats = db.teamStats[hKey] || findFuzzy(hKey);
      const aStats = db.teamStats[aKey] || findFuzzy(aKey);
      if (hStats && aStats &&
          Number.isFinite(hStats.avgScored) && Number.isFinite(aStats.avgConceded) &&
          Number.isFinite(aStats.avgScored) && Number.isFinite(hStats.avgConceded)) {
        const lh = (hStats.avgScored / LEAGUE_AVG) * aStats.avgConceded;
        const la = (aStats.avgScored / LEAGUE_AVG) * hStats.avgConceded;
        if (lh > 0 && la > 0) {
          try {
            const poisson = computePoisson(lh, la);
            if (!Number.isFinite(probOver25)) { probOver25 = poisson.over25; source = source || 'poisson'; }
            if (!Number.isFinite(probBTTS))   { probBTTS  = poisson.btts;   source = source || 'poisson'; }
            if (!poisson1X2 && Number.isFinite(poisson.homeWin) && Number.isFinite(poisson.awayWin)) {
              poisson1X2 = { home: poisson.homeWin, draw: poisson.draw, away: poisson.awayWin };
            }
          } catch (e) { console.warn('[CATCH-05] computePoisson (backfill):', e.message); }
        }
      }
    }

    // bd b3b — bestEdge 1X2 si cotes odds_snapshot.home/draw/away + Poisson 1X2 dispos
    let best1X2 = null;
    const odds = h.odds_snapshot || {};
    if (Number.isFinite(odds.home) && Number.isFinite(odds.away) && poisson1X2) {
      best1X2 = computeBest1X2Edge(odds.home, odds.draw, odds.away, poisson1X2);
    }

    if (!Number.isFinite(probOver25) && !Number.isFinite(probBTTS) && !best1X2) { skipped++; continue; }

    h.predicted = h.predicted || {};
    if (Number.isFinite(probOver25)) h.predicted.over25 = probOver25;
    if (Number.isFinite(probBTTS))   h.predicted.btts = probBTTS;
    // Snapshot Poisson 1X2 pour audit + recompute futur
    if (poisson1X2) {
      if (!Number.isFinite(h.predicted.homeWin)) h.predicted.homeWin = poisson1X2.home;
      if (!Number.isFinite(h.predicted.draw))    h.predicted.draw    = poisson1X2.draw;
      if (!Number.isFinite(h.predicted.awayWin)) h.predicted.awayWin = poisson1X2.away;
    }
    if (best1X2) {
      h.predicted.bestEdge      = best1X2.label;
      h.predicted.bestEdgeValue = best1X2.edge;
      h.predicted.bestEdgeOdds  = best1X2.odds;
      enriched_edge++;
    }
    h.enriched = source;
    if (source === 'odds') enriched_odds++;
    else if (source === 'poisson') enriched_poisson++;

    const rs = h.realScore;
    const wasOver25 = (rs.home + rs.away) > 2.5;
    const wasBTTS = rs.home > 0 && rs.away > 0;
    if (Number.isFinite(probOver25) && probOver25 > 55) {
      accuracy.over25_total++;
      if (wasOver25) accuracy.over25_correct++;
    }
    if (Number.isFinite(probBTTS) && probBTTS > 55) {
      accuracy.btts_total++;
      if (wasBTTS) accuracy.btts_correct++;
    }
  }

  const enriched = enriched_odds + enriched_poisson + enriched_edge;
  if (enriched > 0) {
    saveHistory();
    console.log(`  [EnrichHistory] ✓ ${enriched_odds + enriched_poisson} matchs probs (odds: ${enriched_odds}, poisson: ${enriched_poisson}) + ${enriched_edge} bestEdge 1X2 enrichis (skipped: ${skipped}) — over25_total: ${accuracy.over25_total}, btts_total: ${accuracy.btts_total}`);
  } else {
    console.log(`  [EnrichHistory] 0 enrichis sur ${history.length} (skipped: ${skipped})`);
  }
  return enriched;
}

// Wrapper : archive AVANT purge — empêche autoPurge de wiper les matchs
// terminés avant qu'ils soient résolus et poussés dans history.
async function archiveThenPurge(label = 'cron') {
  try {
    await archivePastMatches();
  } catch (e) {
    console.warn(`  [Archive:${label}] erreur :`, e.message);
  }
  try {
    autoPurgeDatabase();
  } catch (e) {
    console.warn(`  [Purge:${label}] erreur :`, e.message);
  }
}

function getWeeklyAccuracyTrends(weeks = 12) {
  const getWeek = dateStr => {
    const d = new Date(dateStr);
    const y = d.getFullYear();
    const start = new Date(y, 0, 1);
    const diff = Math.floor((d - start + (start.getTimezoneOffset() - d.getTimezoneOffset()) * 60000) / 86400000);
    const w = Math.ceil((diff + start.getDay() + 1) / 7);
    return `${y}-W${String(w).padStart(2, '0')}`;
  };

  const weeksMap = {}; // déclaration correcte de la variable

  for (const h of history) {
    if (!h.verified || !h.realScore || !h.commence_time) continue;
    const wk = getWeek(h.commence_time);
    if (!weeksMap[wk]) weeksMap[wk] = { over25c: 0, over25t: 0, bttsc: 0, bttst: 0, total: 0 };
    weeksMap[wk].total++;
    const rs = h.realScore;
    const wasOver25 = (rs.home + rs.away) > 2.5;
    const wasBTTS = rs.home > 0 && rs.away > 0;
    if (h.predicted?.over25 > 55) { weeksMap[wk].over25t++; if (wasOver25) weeksMap[wk].over25c++; }
    if (h.predicted?.btts > 55) { weeksMap[wk].bttst++; if (wasBTTS) weeksMap[wk].bttsc++; }
  }

  return Object.entries(weeksMap)
    .sort(([a], [b]) => a.localeCompare(b))
    .slice(-weeks)
    .map(([week, d]) => ({
      week,
      total: d.total,
      over25: d.over25t > 0 ? Math.round(d.over25c / d.over25t * 100) : null,
      btts: d.bttst > 0 ? Math.round(d.bttsc / d.bttst * 100) : null,
      over25_bets: d.over25t,
      btts_bets: d.bttst,
    }));
}


function getAccuracyReport() {
  const pct = (c, t) => t > 0 ? Math.round(c / t * 100) : null;

  // ── Global ──────────────────────────────────────────────────────────────────
  const global = {
    total_verified: accuracy.total,
    over25: { rate: pct(accuracy.over25_correct, accuracy.over25_total), sample: accuracy.over25_total },
    btts: { rate: pct(accuracy.btts_correct, accuracy.btts_total), sample: accuracy.btts_total },
    edge: { rate: pct(accuracy.edge_correct, accuracy.edge_total), sample: accuracy.edge_total },
    history_size: history.length,
  };

  // ── Calibration: Brier + Log-Loss (Walsh & Joshi 2023 — accuracy seule trompeuse) ──
  {
    const eps = 1e-7;
    let bO25 = 0, bBtts = 0, llO25 = 0, llBtts = 0, nO25 = 0, nBtts = 0;
    for (const h of history) {
      if (!h.verified || !h.realScore) continue;
      const rs = h.realScore;
      const o25 = ((rs.home + rs.away) > 2.5) ? 1 : 0;
      const btts = (rs.home > 0 && rs.away > 0) ? 1 : 0;
      if (h.predicted?.over25 != null) {
        const p = Math.max(eps, Math.min(1 - eps, h.predicted.over25 / 100));
        bO25  += (p - o25) ** 2;
        llO25 += -(o25 * Math.log(p) + (1 - o25) * Math.log(1 - p));
        nO25++;
      }
      if (h.predicted?.btts != null) {
        const p = Math.max(eps, Math.min(1 - eps, h.predicted.btts / 100));
        bBtts  += (p - btts) ** 2;
        llBtts += -(btts * Math.log(p) + (1 - btts) * Math.log(1 - p));
        nBtts++;
      }
    }
    global.calibration = {
      over25: nO25 ? { brier: parseFloat((bO25 / nO25).toFixed(4)), logloss: parseFloat((llO25 / nO25).toFixed(4)), sample: nO25 } : null,
      btts:   nBtts ? { brier: parseFloat((bBtts / nBtts).toFixed(4)), logloss: parseFloat((llBtts / nBtts).toFixed(4)), sample: nBtts } : null,
    };
  }

  // ── Rolling window (30 derniers matchs vérifiés) ────────────────────────────
  const recent = history.filter(h => h.verified).slice(-30);
  let rOver25c = 0, rOver25t = 0, rBttsc = 0, rBttst = 0, rEdgec = 0, rEdget = 0;
  for (const h of recent) {
    const rs = h.realScore;
    if (!rs) continue;
    const wasOver25 = (rs.home + rs.away) > 2.5;
    const wasBTTS = rs.home > 0 && rs.away > 0;
    if (h.predicted?.over25 > 55) { rOver25t++; if (wasOver25) rOver25c++; }
    if (h.predicted?.btts > 55) { rBttst++; if (wasBTTS) rBttsc++; }
    if (h.predicted?.bestEdgeValue > 5) {
      rEdget++;
      const winner = rs.home > rs.away ? h.home_team : rs.away > rs.home ? h.away_team : 'Nul';
      if (winner === h.predicted.bestEdge) rEdgec++;
    }
  }
  global.rolling30 = {
    sample: recent.length,
    over25: { rate: pct(rOver25c, rOver25t), sample: rOver25t },
    btts: { rate: pct(rBttsc, rBttst), sample: rBttst },
    edge: { rate: pct(rEdgec, rEdget), sample: rEdget },
  };

  // ── Auto-alerte rolling20 ────────────────────────────────────────────────────
  const last20 = history.filter(h => h.verified).slice(-20);
  let aOver25c = 0, aOver25t = 0, aBttsc = 0, aBttst = 0;
  for (const h of last20) {
    if (!h.realScore) continue;
    const rs = h.realScore;
    if (h.predicted?.over25 > 55) { aOver25t++; if ((rs.home + rs.away) > 2.5) aOver25c++; }
    if (h.predicted?.btts > 55) { aBttst++; if (rs.home > 0 && rs.away > 0) aBttsc++; }
  }
  const allBets = aOver25t + aBttst;
  const allCorrect = aOver25c + aBttsc;
  global.alert = allBets >= 10 ? {
    combined: pct(allCorrect, allBets),
    over25: pct(aOver25c, aOver25t),
    over25_bets: aOver25t,
    btts: pct(aBttsc, aBttst),
    btts_bets: aBttst,
    total: allBets,
    triggered: pct(allCorrect, allBets) < 45,
    threshold: 45,
  } : null;

  // ── Per-league breakdown ────────────────────────────────────────────────────
  const byLeague = {};
  for (const h of history) {
    if (!h.verified || !h.realScore) continue;
    const lg = h.league || 'Unknown';
    if (!byLeague[lg]) byLeague[lg] = { over25c: 0, over25t: 0, bttsc: 0, bttst: 0, edgec: 0, edget: 0, total: 0 };
    const rs = h.realScore;
    const wasOver25 = (rs.home + rs.away) > 2.5;
    const wasBTTS = rs.home > 0 && rs.away > 0;
    byLeague[lg].total++;
    if (h.predicted?.over25 > 55) { byLeague[lg].over25t++; if (wasOver25) byLeague[lg].over25c++; }
    if (h.predicted?.btts > 55) { byLeague[lg].bttst++; if (wasBTTS) byLeague[lg].bttsc++; }
    if (h.predicted?.bestEdgeValue > 5) {
      byLeague[lg].edget++;
      const winner = rs.home > rs.away ? h.home_team : rs.away > rs.home ? h.away_team : 'Nul';
      if (winner === h.predicted.bestEdge) byLeague[lg].edgec++;
    }
  }
  global.leagues = {};
  for (const [lg, d] of Object.entries(byLeague)) {
    global.leagues[lg] = {
      total: d.total,
      over25: { rate: pct(d.over25c, d.over25t), sample: d.over25t },
      btts: { rate: pct(d.bttsc, d.bttst), sample: d.bttst },
      edge: { rate: pct(d.edgec, d.edget), sample: d.edget },
    };
  }

  // ── Confidence tier stratification ─────────────────────────────────────────
  const tiers = { '55-65': { c: 0, t: 0 }, '65-75': { c: 0, t: 0 }, '75+': { c: 0, t: 0 } };
  for (const h of history) {
    if (!h.verified || !h.realScore) continue;
    const rs = h.realScore;
    const wasOver25 = (rs.home + rs.away) > 2.5;
    const wasBTTS = rs.home > 0 && rs.away > 0;
    const pred = h.predicted?.over25;
    if (pred > 55) {
      let tier;
      if (pred <= 65) tier = '55-65';
      else if (pred <= 75) tier = '65-75';
      else tier = '75+';
      tiers[tier].t++;
      if (wasOver25) tiers[tier].c++;
    }
  }
  global.confidence_tiers = {};
  for (const [label, d] of Object.entries(tiers)) {
    global.confidence_tiers[label] = { rate: pct(d.c, d.t), sample: d.t };
  }

  return global;
}

// ═══════════════════════════════════════════════════════════════════════════════
//  DATA HUB HISTORIQUE — /api/v1/history/query
//  Filtre + agrège + pagine history[] (foot v10.78+). Tennis brancé en Phase H3.
// ═══════════════════════════════════════════════════════════════════════════════

// Edge raisonnable : [5%, 50%]. Au-delà = données legacy corrompues (bug ancien archive),
// on les exclut du backtest pour ne pas polluer les KPIs.
const HISTORY_EDGE_MIN = 5;
const HISTORY_EDGE_MAX = 50;

// Décompose un record archivé en picks-par-marché (1 entrée par pick).
function _historyPicksOf(h) {
  if (!h.verified || !h.realScore) return [];
  const rs = h.realScore;
  const wasOver25 = (rs.home + rs.away) > 2.5;
  const wasBTTS = rs.home > 0 && rs.away > 0;
  const winnerLabel = rs.home > rs.away ? h.home_team : rs.away > rs.home ? h.away_team : 'Nul';
  const out = [];
  if (h.predicted?.over25 > 55 && h.predicted.over25 <= 100) {
    out.push({ id: h.id, market: 'over25', t: new Date(h.commence_time).getTime(), won: wasOver25 ? 1 : 0, proba: h.predicted.over25, league: h.league });
  }
  if (h.predicted?.btts > 55 && h.predicted.btts <= 100) {
    out.push({ id: h.id, market: 'btts', t: new Date(h.commence_time).getTime(), won: wasBTTS ? 1 : 0, proba: h.predicted.btts, league: h.league });
  }
  const ev = h.predicted?.bestEdgeValue;
  if (typeof ev === 'number' && ev >= HISTORY_EDGE_MIN && ev <= HISTORY_EDGE_MAX) {
    out.push({
      id: h.id, market: 'edge', t: new Date(h.commence_time).getTime(),
      won: winnerLabel === h.predicted.bestEdge ? 1 : 0,
      ev, league: h.league,
      odds: typeof h.predicted.bestEdgeOdds === 'number' ? h.predicted.bestEdgeOdds : null, // H2
    });
  }
  return out;
}

// H4 : évaluation win/loss par stratégie sur record archivé foot.
// Renvoie 1/0/null (null = pas de réponse définissable depuis les données disponibles).
function _strategyWonOf(strategyKey, h) {
  if (!h.realScore) return null;
  const rs = h.realScore;
  const total = rs.home + rs.away;
  switch (strategyKey) {
    case 'BTTS_YES':  return (rs.home > 0 && rs.away > 0) ? 1 : 0;
    case 'OVER_2_5':  return total > 2.5 ? 1 : 0;
    case 'OVER_1_5':  return total > 1.5 ? 1 : 0;
    case 'UNDER_2_5': return total < 2.5 ? 1 : 0;
    case 'HOME_WIN':  return rs.home > rs.away ? 1 : 0;
    case 'AWAY_WIN':  return rs.away > rs.home ? 1 : 0;
    case 'DRAW':      return rs.home === rs.away ? 1 : 0;
    case 'CS_00':     return (rs.home === 0 && rs.away === 0) ? 1 : 0;
    // Stratégies sans data dans le record archivé (corners, cartons, etc.) → null
    default: return null;
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// bd cty — BD-DATA-006 : CLV (Closing Line Value) par stratégie 30 jours
// CLV = (cote_pari_pris / cote_clôture - 1) × 100
// Métrique gold-standard sharp vs square : CLV+ = sharp, CLV~0 = flat, CLV- = square
// ─────────────────────────────────────────────────────────────────────────────

// Infère un tag stratégie depuis (market, selection_label) quand bet POST ne fournit pas
// d'explicite `strategy`. Mapping conservateur — null si ambigu (pas de pollution data).
function inferStrategyTag(market, selectionLabel) {
  if (!market || typeof market !== 'string') return null;
  const m = market.toUpperCase().replace(/[\s\-\.]/g, '_');
  const sl = (selectionLabel || '').toLowerCase();
  // Match direct sur les clés STRATEGIES si déjà au bon format
  if (typeof STRATEGIES === 'object' && STRATEGIES && Object.prototype.hasOwnProperty.call(STRATEGIES, m)) return m;
  // Heuristiques marchés courants
  if (m.includes('BTTS') || m === 'GG' || m === 'GGNG') return sl.includes('non') || sl === 'no' ? null : 'BTTS_YES';
  if (m.includes('OVER_2_5') || m === 'O25' || m === 'PLUS_2_5') return 'OVER_2_5';
  if (m.includes('OVER_1_5') || m === 'O15') return 'OVER_1_5';
  if (m.includes('UNDER_2_5') || m === 'U25' || m === 'MOINS_2_5') return 'UNDER_2_5';
  if (m === '1X2' || m === '1N2') {
    if (sl === '1' || sl.includes('home') || sl.includes('domicile')) return 'HOME_WIN';
    if (sl === '2' || sl.includes('away') || sl.includes('exterieur') || sl.includes('extérieur')) return 'AWAY_WIN';
    if (sl === 'x' || sl === 'n' || sl.includes('nul') || sl.includes('draw')) return 'DRAW';
  }
  if (m.includes('HOME_WIN') || m === 'HOME') return 'HOME_WIN';
  if (m.includes('AWAY_WIN') || m === 'AWAY') return 'AWAY_WIN';
  if (m.includes('DRAW') || m === 'NUL') return 'DRAW';
  if (m.includes('CS_0_0') || m === 'SCORE_00' || m === '0_0') return 'CS_00';
  return null;
}

// Clip outliers CLV pour robustesse stats : [-90%, +300%]
// CLV < -90% = bet sur 100x outsider qui clos 10x = ratio non-informatif (bug data)
// CLV > 300% = artefact closing line non-snapshoté (cote stale)
function _clipCLV(pct) {
  if (!Number.isFinite(pct)) return null;
  return Math.max(-90, Math.min(300, pct));
}

// Median d'un array de nombres (sans dep)
function _medianOf(arr) {
  if (!arr || !arr.length) return 0;
  const sorted = arr.slice().sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}

// Helper bas-niveau : CLV moyen pour une stratégie spécifique sur fenêtre N jours
// userId : null = aggregate cross-users (anonymized public mode)
// Returns: { strategy, n_bets, clv_mean_pct, clv_median_pct, win_rate_pct, roi_pct, sparkline }
function computeStrategyCLV(userId, strategy, periodDays = 30) {
  if (!sqldb) return null;
  const periodSec = Math.max(1, Math.min(365, periodDays | 0)) * 86400;
  const sinceTs = Math.floor(Date.now() / 1000) - periodSec;

  // Where clause : bets settled (non-pending, non-void), strategy match, closing_odds disponible
  const whereParts = [
    "strategy = ?",
    "closing_odds IS NOT NULL",
    "closing_odds > 1.01",
    "odds > 1.01",
    "status IN ('won','lost','half_won','half_lost','cashout')",
    "settled_at >= ?",
  ];
  const params = [strategy, sinceTs];
  if (userId != null) {
    whereParts.push("user_id = ?");
    params.push(userId);
  }
  const sql = `SELECT odds, closing_odds, stake_cents, payout_cents, status, settled_at
               FROM user_bets WHERE ${whereParts.join(' AND ')} ORDER BY settled_at ASC`;
  let rows;
  try { rows = sqldb.prepare(sql).all(...params); }
  catch (e) { _traceCatch('clv_query', e); return null; }
  if (!rows.length) return { strategy, n_bets: 0, clv_mean_pct: null, clv_median_pct: null, win_rate_pct: null, roi_pct: null, sparkline: [] };

  const clvs = [];
  let wins = 0, totalStake = 0, totalPayout = 0;
  for (const r of rows) {
    const clv = _clipCLV(((r.odds / r.closing_odds) - 1) * 100);
    if (clv != null) clvs.push({ clv, ts: r.settled_at });
    if (r.status === 'won' || r.status === 'half_won') wins++;
    totalStake += (r.stake_cents || 0);
    totalPayout += (r.payout_cents || 0);
  }
  const clvOnly = clvs.map(c => c.clv);
  const mean = clvOnly.reduce((s, v) => s + v, 0) / clvOnly.length;
  // Sparkline : moyenne glissante par bucket de 3 jours (max 10 points)
  const bucketSec = Math.max(1, Math.floor(periodSec / 10));
  const buckets = new Map();
  for (const { clv, ts } of clvs) {
    const k = Math.floor(ts / bucketSec);
    if (!buckets.has(k)) buckets.set(k, []);
    buckets.get(k).push(clv);
  }
  const sparkline = Array.from(buckets.entries())
    .sort((a, b) => a[0] - b[0])
    .map(([k, vs]) => ({ ts: k * bucketSec, clv: +(vs.reduce((s, v) => s + v, 0) / vs.length).toFixed(2) }));

  return {
    strategy,
    n_bets: rows.length,
    clv_mean_pct: +mean.toFixed(2),
    clv_median_pct: +(_medianOf(clvOnly)).toFixed(2),
    win_rate_pct: +(100 * wins / rows.length).toFixed(1),
    roi_pct: totalStake > 0 ? +(100 * (totalPayout / totalStake)).toFixed(2) : null,
    sparkline,
  };
}

// Top-level : balaye toutes les stratégies présentes en DB pour user (ou global) sur N jours
function computeAllStrategyCLV(userId, periodDays = 30) {
  if (!sqldb) return [];
  const periodSec = Math.max(1, Math.min(365, periodDays | 0)) * 86400;
  const sinceTs = Math.floor(Date.now() / 1000) - periodSec;
  const params = [sinceTs];
  let where = "strategy IS NOT NULL AND closing_odds IS NOT NULL AND settled_at >= ? AND status IN ('won','lost','half_won','half_lost','cashout')";
  if (userId != null) {
    where += " AND user_id = ?";
    params.push(userId);
  }
  let strats;
  try {
    strats = sqldb.prepare(`SELECT DISTINCT strategy FROM user_bets WHERE ${where}`).all(...params);
  } catch (e) { _traceCatch('clv_distinct', e); return []; }
  return strats
    .map(r => computeStrategyCLV(userId, r.strategy, periodDays))
    .filter(r => r && r.n_bets > 0)
    .sort((a, b) => (b.clv_mean_pct || 0) - (a.clv_mean_pct || 0));
}

// H3 : décompose un record tennis en picks-par-marché.
// Schema attendu (rempli progressivement par cron tennis post-release) :
//   { id, p1, p2, tournament, surface, commence_time,
//     predicted: { ml, set1, set1_p1, score_sets, geq1_set_dog, total_games, total_games_thr,
//                  aces_total, aces_thr, tie_break,
//                  ml_odds, set1_odds, total_games_odds, ... }, // odds H2 instrumentation
//     realResult: { sets: [{p1,p2}], winner, total_games, aces_p1, aces_p2, had_tiebreak },
//     archived_at, verified }
function _tennisPicksOf(h) {
  if (!h.verified || !h.realResult) return [];
  const r = h.realResult;
  const out = [];
  const t = h.commence_time ? new Date(h.commence_time).getTime() : 0;
  // Bridge: entries ETL stockent sous bsd_prediction, pas predicted. Unifier.
  const p = h.predicted || h.bsd_prediction ? {
    // Si bsd_prediction présent mais pas predicted, dériver
    ...(h.predicted || {}),
    ...(h.bsd_prediction ? {
      ml: h.bsd_prediction.prob_p1_wins > 0.50 ? h.p1 : (h.bsd_prediction.prob_p1_wins < 0.50 ? h.p2 : null),
      ml_odds: h.bsd_prediction.prob_p1_wins > 0.50
        ? parseFloat((1 / Math.max(0.01, h.bsd_prediction.prob_p1_wins)).toFixed(2))
        : (h.bsd_prediction.prob_p1_wins < 0.50
          ? parseFloat((1 / Math.max(0.01, 1 - h.bsd_prediction.prob_p1_wins)).toFixed(2))
          : null),
    } : {}),
  } : {};
  const tournament = h.tournament || h.league || null;

  // Marché 1 : Moneyline (ML)
  if (p.ml && (p.ml === h.p1 || p.ml === h.p2)) {
    out.push({
      id: h.id, market: 'ml', t,
      won: r.winner === p.ml ? 1 : 0,
      odds: typeof p.ml_odds === 'number' ? p.ml_odds : null,
      league: tournament,
    });
  }
  // Marché 2 : Set 1 winner
  if (p.set1 && r.sets?.length) {
    const s1 = r.sets[0];
    const set1Winner = s1.p1 > s1.p2 ? h.p1 : h.p2;
    out.push({
      id: h.id, market: 'set1', t,
      won: set1Winner === p.set1 ? 1 : 0,
      odds: typeof p.set1_odds === 'number' ? p.set1_odds : null,
      league: tournament,
    });
  }
  // Marché 3 : ≥1 set pour l'outsider
  if (p.geq1_set_dog && r.sets?.length) {
    const dog = p.geq1_set_dog;
    const setsWonByDog = r.sets.filter(s =>
      (dog === h.p1 ? s.p1 > s.p2 : s.p2 > s.p1)
    ).length;
    out.push({
      id: h.id, market: 'geq1_set', t,
      won: setsWonByDog >= 1 ? 1 : 0,
      odds: typeof p.geq1_set_odds === 'number' ? p.geq1_set_odds : null,
      league: tournament,
    });
  }
  // Marché 4 : Total jeux Over/Under
  if (typeof p.total_games_thr === 'number' && typeof r.total_games === 'number') {
    const direction = p.total_games_over ? 'over' : 'under';
    const won = direction === 'over' ? (r.total_games > p.total_games_thr ? 1 : 0)
                                     : (r.total_games < p.total_games_thr ? 1 : 0);
    out.push({
      id: h.id, market: 'total_games', t, won,
      odds: typeof p.total_games_odds === 'number' ? p.total_games_odds : null,
      league: tournament,
    });
  }
  // Marché 5 : Aces total Over
  if (typeof p.aces_thr === 'number' && (typeof r.aces_p1 === 'number' || typeof r.aces_p2 === 'number')) {
    const totalAces = (r.aces_p1 || 0) + (r.aces_p2 || 0);
    out.push({
      id: h.id, market: 'aces', t,
      won: totalAces > p.aces_thr ? 1 : 0,
      odds: typeof p.aces_odds === 'number' ? p.aces_odds : null,
      league: tournament,
    });
  }
  // Marché 6 : Tie-break présent (oui/non)
  if (typeof p.tie_break === 'boolean' && typeof r.had_tiebreak === 'boolean') {
    out.push({
      id: h.id, market: 'tie_break', t,
      won: p.tie_break === r.had_tiebreak ? 1 : 0,
      odds: typeof p.tie_break_odds === 'number' ? p.tie_break_odds : null,
      league: tournament,
    });
  }
  return out;
}

// KPIs tennis : reprend la structure foot mais sur _tennisPicksOf
function computeTennisKpis(entries) {
  const allPicks = [];
  for (const h of entries) allPicks.push(..._tennisPicksOf(h));
  allPicks.sort((a, b) => a.t - b.t);

  // Guard-fou: dataset vide → retourne zéros explicites, pas undefined/NaN
  if (!allPicks.length) {
    console.log('  [DEBUG HISTORIQUE TENNIS] computeTennisKpis: 0 picks → retour zéro');
    const zeroMkt = { sample: 0, wins: 0, losses: 0, winrate: 0, winrate_ic95: [0, 0], ic_method: 'wilson', longest_winning_streak: 0, longest_losing_streak: 0 };
    return {
      total_picks: 0, verified_matches: 0,
      max_drawdown_units: 0, final_pl_units: 0,
      ml: { ...zeroMkt },
      set1: { ...zeroMkt },
      geq1_set: { ...zeroMkt },
      total_games: { ...zeroMkt },
      aces: { ...zeroMkt },
      tie_break: { ...zeroMkt },
    };
  }

  const markets = ['ml', 'set1', 'geq1_set', 'total_games', 'aces', 'tie_break'];
  const out = {
    total_picks: allPicks.length,
    verified_matches: entries.filter(h => h.verified && h.realResult).length,
    max_drawdown_units: 0,
    final_pl_units: 0,
  };

  let cumul = 0, peak = 0, ddMax = 0;
  for (const p of allPicks) {
    cumul += p.won ? 1 : -1;
    if (cumul > peak) peak = cumul;
    if (peak - cumul > ddMax) ddMax = peak - cumul;
  }
  out.max_drawdown_units = ddMax;
  out.final_pl_units = cumul;

  for (const mkt of markets) {
    const xs = allPicks.filter(p => p.market === mkt);
    const sample = xs.length;
    const wins = xs.reduce((s, p) => s + p.won, 0);
    const seq = xs.map(p => p.won);
    const [lo, hi] = _bootstrapCI95(seq);
    const yieldStats = _yieldStats(xs);
    out[mkt] = {
      sample,
      wins,
      losses: sample - wins,
      winrate: sample ? wins / sample : null,
      winrate_ic95: [lo, hi],
      ic_method: sample >= 30 ? 'bootstrap_500' : 'wilson',
      longest_winning_streak: _maxStreak(seq, 1),
      longest_losing_streak: _maxStreak(seq, 0),
      ...yieldStats,
    };
  }
  out.global_yield = _yieldStats(allPicks);
  return out;
}

function computeTennisBreakdown(entries) {
  const byTournament = {};
  for (const h of entries) {
    if (!h.verified || !h.realResult) continue;
    const key = h.tournament || h.league || 'Unknown';
    if (!byTournament[key]) byTournament[key] = { sample: 0, picks: [] };
    byTournament[key].sample++;
    byTournament[key].picks.push(..._tennisPicksOf(h));
  }
  const tournaments = Object.entries(byTournament).map(([name, d]) => {
    const wins = d.picks.reduce((s, p) => s + p.won, 0);
    const total = d.picks.length;
    const wr = total ? wins / total : null;
    const [lo, hi] = _bootstrapCI95(d.picks.map(p => p.won));
    const yieldStats = _yieldStats(d.picks);
    return {
      league: name,
      matches: d.sample,
      picks: total,
      wins,
      winrate: wr,
      winrate_ic95: [lo, hi],
      yield: yieldStats.yield,
      avg_odds: yieldStats.avg_odds,
    };
  });
  tournaments.sort((a, b) => b.picks - a.picks);

  const markets = ['ml', 'set1', 'geq1_set', 'total_games', 'aces', 'tie_break'].map(mkt => {
    const xs = entries.flatMap(h => _tennisPicksOf(h)).filter(p => p.market === mkt);
    const wins = xs.reduce((s, p) => s + p.won, 0);
    const [lo, hi] = _bootstrapCI95(xs.map(p => p.won));
    const yieldStats = _yieldStats(xs);
    return {
      market: mkt,
      sample: xs.length,
      wins,
      winrate: xs.length ? wins / xs.length : null,
      winrate_ic95: [lo, hi],
      yield: yieldStats.yield,
      avg_odds: yieldStats.avg_odds,
      break_even: yieldStats.break_even,
    };
  });

  return { by_league: tournaments, by_market: markets, by_strategy: [], trap_teams: [], heatmap: [] };
}

function computeTennisSeries(entries) {
  const verified = entries.filter(h => h.verified && h.realResult)
    .filter(h => h.commence_time) // skip entries sans date
    .slice()
    .sort((a, b) => new Date(a.commence_time) - new Date(b.commence_time));
  const plCumulative = [], ddCurve = [];
  let cumul = 0, peak = 0;
  for (const h of verified) {
    let delta = 0;
    for (const p of _tennisPicksOf(h)) delta += (p.won ? 1 : -1);
    if (delta !== 0) cumul += delta;
    if (cumul > peak) peak = cumul;
    const dateKey = h.commence_time ? h.commence_time.split('T')[0] : 'unknown';
    plCumulative.push({ date: dateKey, units: cumul });
    ddCurve.push({ date: dateKey, dd: peak - cumul });
  }
  const allPicks = [];
  for (const h of verified) allPicks.push(..._tennisPicksOf(h));
  allPicks.sort((a, b) => a.t - b.t);
  const rolling30 = [];
  const W = 30;
  for (let i = W - 1; i < allPicks.length; i++) {
    const window = allPicks.slice(i - W + 1, i + 1);
    const w = window.reduce((s, p) => s + p.won, 0);
    rolling30.push({ date: new Date(window[window.length - 1].t).toISOString().split('T')[0], wr: w / W });
  }
  return { pl_cumulative: plCumulative, drawdown_curve: ddCurve, rolling30_wr: rolling30 };
}

function _wilsonCI95(wins, total) {
  if (!total) return [null, null];
  const z = 1.96, p = wins / total, n = total;
  const denom = 1 + z * z / n;
  const center = p + z * z / (2 * n);
  const margin = z * Math.sqrt(p * (1 - p) / n + z * z / (4 * n * n));
  return [(center - margin) / denom, (center + margin) / denom];
}

// Bootstrap 500 iter, retourne [p2.5, p97.5] sur winrate.
// Plus précis que Wilson pour samples >= 30 ; pour <30 garde Wilson (Wilson plus robuste sur petits N).
function _bootstrapCI95(seq, iters = 500) {
  const n = seq.length;
  if (!n) return [null, null];
  if (n < 30) {
    const wins = seq.reduce((s, v) => s + (v ? 1 : 0), 0);
    return _wilsonCI95(wins, n);
  }
  const wrs = new Array(iters);
  for (let i = 0; i < iters; i++) {
    let w = 0;
    for (let j = 0; j < n; j++) w += seq[(Math.random() * n) | 0] ? 1 : 0; // nosemgrep: insecure-random — bootstrap resampling
    wrs[i] = w / n;
  }
  wrs.sort((a, b) => a - b);
  return [wrs[Math.floor(iters * 0.025)], wrs[Math.floor(iters * 0.975)]];
}

// Yield (rendement %) : moyenne (won ? (odds-1) : -1) par pick.
// Avg Odds : moyenne arithmétique des cotes des picks ayant odds.
// Break-even Strike Rate : 1 / avg_odds → WR minimum pour rentabilité.
function _yieldStats(picks) {
  const withOdds = picks.filter(p => typeof p.odds === 'number' && p.odds > 1);
  if (!withOdds.length) return { yield: null, avg_odds: null, break_even: null, sample_with_odds: 0 };
  const ret = withOdds.reduce((s, p) => s + (p.won ? p.odds - 1 : -1), 0);
  const sumOdds = withOdds.reduce((s, p) => s + p.odds, 0);
  const avgOdds = sumOdds / withOdds.length;
  return {
    yield: ret / withOdds.length,
    avg_odds: avgOdds,
    break_even: 1 / avgOdds,
    sample_with_odds: withOdds.length,
  };
}

function _maxStreak(arr, target) {
  let cur = 0, max = 0;
  for (const v of arr) {
    if (v === target) { cur++; if (cur > max) max = cur; }
    else { cur = 0; }
  }
  return max;
}

function computeHistoryKpis(entries) {
  const allPicks = [];
  for (const h of entries) allPicks.push(..._historyPicksOf(h));
  allPicks.sort((a, b) => a.t - b.t);

  const agg = (mkt) => {
    const xs = allPicks.filter(p => p.market === mkt);
    const sample = xs.length;
    const wins = xs.reduce((s, p) => s + p.won, 0);
    const wr = sample ? wins / sample : null;
    const seq = xs.map(p => p.won);
    // H2 : bootstrap IC pour samples >= 30, Wilson sinon (fallback robuste)
    const [lo, hi] = _bootstrapCI95(seq);
    const probas = xs.map(p => p.proba).filter(x => typeof x === 'number');
    const avgProba = probas.length ? probas.reduce((s, v) => s + v, 0) / probas.length : null;
    const evs = xs.map(p => p.ev).filter(x => typeof x === 'number');
    const avgEv = evs.length ? evs.reduce((s, v) => s + v, 0) / evs.length : null;
    // H2 : Yield / Avg Odds / Break-even Strike Rate (sur picks avec odds capturées)
    const yieldStats = _yieldStats(xs);
    return {
      sample,
      wins,
      losses: sample - wins,
      winrate: wr,
      winrate_ic95: [lo, hi],
      ic_method: sample >= 30 ? 'bootstrap_500' : 'wilson',
      avg_proba: avgProba,
      avg_ev: avgEv,
      longest_winning_streak: _maxStreak(seq, 1),
      longest_losing_streak: _maxStreak(seq, 0),
      ...yieldStats, // yield, avg_odds, break_even, sample_with_odds
    };
  };

  // Drawdown sur P/L cumul tous picks confondus (1u flat)
  let cumul = 0, peak = 0, ddMax = 0;
  for (const p of allPicks) {
    cumul += p.won ? 1 : -1;
    if (cumul > peak) peak = cumul;
    const dd = peak - cumul;
    if (dd > ddMax) ddMax = dd;
  }

  // H2 : Yield global tous marchés confondus (sur picks avec odds)
  const globalYield = _yieldStats(allPicks);

  return {
    total_picks: allPicks.length,
    verified_matches: entries.filter(h => h.verified && h.realScore).length,
    over25: agg('over25'),
    btts: agg('btts'),
    edge: agg('edge'),
    max_drawdown_units: ddMax,
    final_pl_units: cumul,
    global_yield: globalYield, // { yield, avg_odds, break_even, sample_with_odds }
  };
}

function computeHistoryBreakdown(entries) {
  const byLeague = {};
  for (const h of entries) {
    if (!h.verified || !h.realScore) continue;
    const lg = h.league || 'Unknown';
    if (!byLeague[lg]) byLeague[lg] = { sample: 0, picks: [] };
    byLeague[lg].sample++;
    byLeague[lg].picks.push(..._historyPicksOf(h));
  }
  const leagues = Object.entries(byLeague).map(([name, d]) => {
    const wins = d.picks.reduce((s, p) => s + p.won, 0);
    const total = d.picks.length;
    const wr = total ? wins / total : null;
    const [lo, hi] = _bootstrapCI95(d.picks.map(p => p.won));
    const yieldStats = _yieldStats(d.picks);
    return {
      league: name,
      matches: d.sample,
      picks: total,
      wins,
      winrate: wr,
      winrate_ic95: [lo, hi],
      yield: yieldStats.yield,
      avg_odds: yieldStats.avg_odds,
    };
  });
  leagues.sort((a, b) => b.picks - a.picks);

  // Per-market breakdown
  const markets = ['over25', 'btts', 'edge'].map(mkt => {
    const xs = entries.flatMap(h => _historyPicksOf(h)).filter(p => p.market === mkt);
    const wins = xs.reduce((s, p) => s + p.won, 0);
    const [lo, hi] = _bootstrapCI95(xs.map(p => p.won));
    const yieldStats = _yieldStats(xs);
    return {
      market: mkt,
      sample: xs.length,
      wins,
      winrate: xs.length ? wins / xs.length : null,
      winrate_ic95: [lo, hi],
      yield: yieldStats.yield,
      avg_odds: yieldStats.avg_odds,
      break_even: yieldStats.break_even,
    };
  });

  // H4 : Strategy breakdown depuis tag predicted.strategies posé à l'archive
  const stratPicks = {};
  for (const h of entries) {
    if (!h.verified || !h.realScore) continue;
    const strats = h.predicted?.strategies;
    if (!Array.isArray(strats) || !strats.length) continue;
    for (const sk of strats) {
      const won = _strategyWonOf(sk, h);
      if (won === null) continue;
      if (!stratPicks[sk]) stratPicks[sk] = [];
      stratPicks[sk].push({ won, t: new Date(h.commence_time).getTime() });
    }
  }
  const strategies = Object.entries(stratPicks).map(([key, picks]) => {
    picks.sort((a, b) => a.t - b.t);
    const wins = picks.reduce((s, p) => s + p.won, 0);
    const total = picks.length;
    const wr = total ? wins / total : null;
    const [lo, hi] = _bootstrapCI95(picks.map(p => p.won));
    // Trend : différence WR last-half vs first-half (proxy "edge dégradé / amélioré")
    let trend = null;
    if (total >= 10) {
      const mid = Math.floor(total / 2);
      const firstHalfWR = picks.slice(0, mid).reduce((s, p) => s + p.won, 0) / mid;
      const lastHalfWR  = picks.slice(mid).reduce((s, p) => s + p.won, 0) / (total - mid);
      trend = lastHalfWR - firstHalfWR;
    }
    // Sparkline data : WR cumulé tous les 5 picks
    const sparkline = [];
    let cumW = 0;
    for (let i = 0; i < total; i++) {
      cumW += picks[i].won;
      if ((i + 1) % 5 === 0 || i === total - 1) {
        sparkline.push(cumW / (i + 1));
      }
    }
    return {
      strategy: key,
      sample: total,
      wins,
      winrate: wr,
      winrate_ic95: [lo, hi],
      trend,
      sparkline,
    };
  });
  strategies.sort((a, b) => b.sample - a.sample);

  // R3 : Heatmap WR ligue × marché (cellules : WR + sample par croisement)
  const heatmap = [];
  for (const [name, d] of Object.entries(byLeague)) {
    const cells = ['over25', 'btts', 'edge'].map(mkt => {
      const xs = d.picks.filter(p => p.market === mkt);
      const total = xs.length;
      const wins = xs.reduce((s, p) => s + p.won, 0);
      return { market: mkt, sample: total, winrate: total ? wins / total : null };
    });
    heatmap.push({ league: name, total_picks: d.picks.length, cells });
  }
  heatmap.sort((a, b) => b.total_picks - a.total_picks);

  // H6 : Matchs Pièges — équipes où nos picks historiques sous-performent.
  // Pour chaque équipe (dom OU ext), agrège picks et calcule WR.
  // Trap = sample >= 5 picks ET winrate < 40%.
  const byTeam = {};
  for (const h of entries) {
    if (!h.verified || !h.realScore) continue;
    const picks = _historyPicksOf(h);
    if (!picks.length) continue;
    for (const team of [h.home_team, h.away_team]) {
      if (!team) continue;
      if (!byTeam[team]) byTeam[team] = { picks: [], leagues: new Set() };
      byTeam[team].picks.push(...picks);
      if (h.league) byTeam[team].leagues.add(h.league);
    }
  }
  const trapTeams = Object.entries(byTeam)
    .map(([team, d]) => {
      const total = d.picks.length;
      const wins = d.picks.reduce((s, p) => s + p.won, 0);
      const wr = total ? wins / total : null;
      const [lo, hi] = _bootstrapCI95(d.picks.map(p => p.won));
      return {
        team,
        leagues: Array.from(d.leagues).slice(0, 3),
        picks: total,
        wins,
        winrate: wr,
        winrate_ic95: [lo, hi],
      };
    })
    .filter(t => t.picks >= 5 && t.winrate !== null && t.winrate < 0.4)
    .sort((a, b) => a.winrate - b.winrate)
    .slice(0, 12);

  return { by_league: leagues, by_market: markets, by_strategy: strategies, trap_teams: trapTeams, heatmap };
}

// R8 — Backtesting Simulator : exécute filtres + applique staking system
function runBacktestSimulation(filters, opts = {}) {
  const staking = opts.staking || 'flat_1u'; // flat_1u | kelly_full | kelly_half | pct_1 | pct_2 | pct_5
  const startBankroll = opts.startBankroll || 100;
  // Reuse runHistoryQuery to get filtered pool
  const queryParams = { ...filters, page: 1, pageSize: 10000, sort: 'date_asc' };
  const data = runHistoryQuery(queryParams);
  const sport = data.sport;
  const pool = data.matches;
  const allPicks = [];
  for (const h of pool) {
    const picks = sport === 'tennis' ? _tennisPicksOf(h) : _historyPicksOf(h);
    for (const p of picks) allPicks.push(p);
  }
  allPicks.sort((a, b) => a.t - b.t);

  let bankroll = startBankroll;
  let peak = startBankroll;
  let maxDD = 0;
  let totalStaked = 0;
  let wins = 0, losses = 0;
  const curve = [];
  const returns = [];

  for (const pk of allPicks) {
    // Calcul stake selon staking system
    let stake = 0;
    const odds = typeof pk.odds === 'number' && pk.odds > 1 ? pk.odds : null;
    const proba = typeof pk.proba === 'number' ? pk.proba / 100
      : (odds ? 1 / odds : null); // bd fix: tennis derive pseudo-proba from odds
    if (staking === 'flat_1u') {
      stake = 1;
    } else if (staking === 'pct_1') {
      stake = bankroll * 0.01;
    } else if (staking === 'pct_2') {
      stake = bankroll * 0.02;
    } else if (staking === 'pct_5') {
      stake = bankroll * 0.05;
    } else if ((staking === 'kelly_full' || staking === 'kelly_half') && odds && proba) {
      const b = odds - 1;
      const q = 1 - proba;
      const kellyFrac = Math.max(0, (b * proba - q) / b);
      const mult = staking === 'kelly_full' ? 1 : 0.5;
      stake = bankroll * Math.min(kellyFrac * mult, 0.25); // cap 25%
    } else {
      stake = 1; // fallback flat
    }
    if (stake <= 0) continue;
    totalStaked += stake;

    // Apply outcome
    if (pk.won === 1) {
      const payout = odds ? stake * (odds - 1) : stake; // flat profit 1u for no-odds picks
      bankroll += payout;
      wins++;
      returns.push(payout / stake);
    } else {
      bankroll -= stake;
      losses++;
      returns.push(-1);
    }
    if (bankroll > peak) peak = bankroll;
    const dd = (peak - bankroll) / peak;
    if (dd > maxDD) maxDD = dd;
    curve.push({ t: new Date(pk.t).toISOString().split('T')[0], bankroll: Math.round(bankroll * 100) / 100 });
  }

  // KPIs
  const sample = wins + losses;
  const winrate = sample ? wins / sample : null;
  const yieldPct = totalStaked ? (bankroll - startBankroll) / totalStaked : null;
  const roi = startBankroll ? (bankroll - startBankroll) / startBankroll : null;
  // Sharpe-like : mean / stddev of returns
  let meanRet = 0, varRet = 0;
  if (returns.length) {
    meanRet = returns.reduce((s, v) => s + v, 0) / returns.length;
    varRet = returns.reduce((s, v) => s + (v - meanRet) ** 2, 0) / returns.length;
  }
  const sharpe = varRet > 0 ? meanRet / Math.sqrt(varRet) : null;
  const calmar = maxDD > 0 ? roi / maxDD : null;

  return {
    staking,
    start_bankroll: startBankroll,
    final_bankroll: Math.round(bankroll * 100) / 100,
    pl_units: Math.round((bankroll - startBankroll) * 100) / 100,
    total_staked: Math.round(totalStaked * 100) / 100,
    sample, wins, losses,
    winrate,
    yield_pct: yieldPct,
    roi_pct: roi,
    max_drawdown_pct: maxDD,
    sharpe,
    calmar,
    curve,
  };
}

// R7 — Bad Beat Detector + Variance Tracker
// Unluck score (proxy sans xG) :
//   pour pick perdu : unluck = (predicted_proba - 50) / 50 ∈ [0, 1]
//   pour pick gagné : unluck = 0 (peut être enrichi avec "luck" inverse plus tard)
// Bad Beat = pick perdu AVEC predicted_proba >= 65 (proxy raisonnable).
function computeBadBeats(entries) {
  const lostBadBeats = [];
  const allPicks = [];
  for (const h of entries) {
    if (!h.verified || !h.realScore) continue;
    const rs = h.realScore;
    const picks = _historyPicksOf(h);
    for (const pk of picks) {
      allPicks.push(pk);
      if (pk.won === 1) continue;
      // Only over25/btts have proba (edge has ev, treated differently)
      const proba = pk.proba;
      if (typeof proba !== 'number' || proba < 65) continue;
      const unluck = Math.min((proba - 50) / 50, 1);
      lostBadBeats.push({
        match_id: h.id,
        home_team: h.home_team,
        away_team: h.away_team,
        league: h.league,
        market: pk.market,
        predicted_proba: proba,
        unluck_score: unluck,
        real_score: rs.home + '-' + rs.away,
        commence_time: h.commence_time,
      });
    }
  }
  lostBadBeats.sort((a, b) => b.unluck_score - a.unluck_score);

  // Bankroll comparison : actual vs "without bad beats"
  const sorted = allPicks.slice().sort((a, b) => a.t - b.t);
  let cumReal = 0, cumNoBB = 0, peakReal = 0, peakNoBB = 0, ddReal = 0, ddNoBB = 0;
  const seriesReal = [], seriesNoBB = [];
  const badBeatIds = new Set(lostBadBeats.map(b => b.match_id + '|' + b.market));
  for (const pk of sorted) {
    const k = pk.id + '|' + pk.market;
    cumReal += pk.won ? 1 : -1;
    cumNoBB += (badBeatIds.has(k) && pk.won === 0) ? 1 : (pk.won ? 1 : -1);
    if (cumReal > peakReal) peakReal = cumReal;
    if (cumNoBB > peakNoBB) peakNoBB = cumNoBB;
    if (peakReal - cumReal > ddReal) ddReal = peakReal - cumReal;
    if (peakNoBB - cumNoBB > ddNoBB) ddNoBB = peakNoBB - cumNoBB;
    seriesReal.push({ date: new Date(pk.t).toISOString().split('T')[0], units: cumReal });
    seriesNoBB.push({ date: new Date(pk.t).toISOString().split('T')[0], units: cumNoBB });
  }

  return {
    total_picks_lost: sorted.filter(p => p.won === 0).length,
    bad_beats_count: lostBadBeats.length,
    bad_beats_top: lostBadBeats.slice(0, 10),
    pl_actual_units: cumReal,
    pl_without_bad_beats_units: cumNoBB,
    delta_units: cumNoBB - cumReal,
    max_drawdown_actual: ddReal,
    max_drawdown_no_bad_beats: ddNoBB,
    series_actual: seriesReal,
    series_no_bad_beats: seriesNoBB,
  };
}

// R6 — Calibration plot : predicted proba bucket vs realized winrate
function computeCalibration(entries) {
  const buckets = {};
  for (const h of entries) {
    const picks = _historyPicksOf(h);
    for (const p of picks) {
      if (p.market !== 'over25' && p.market !== 'btts') continue;
      const proba = p.proba;
      if (typeof proba !== 'number' || proba < 0 || proba > 100) continue;
      const bucket = Math.min(Math.floor(proba / 10) * 10, 90);
      const key = `${bucket}-${bucket + 10}`;
      if (!buckets[key]) buckets[key] = { pred_sum: 0, sample: 0, wins: 0, mid: bucket + 5 };
      buckets[key].pred_sum += proba;
      buckets[key].sample++;
      buckets[key].wins += p.won;
    }
  }
  return Object.entries(buckets).map(([range, d]) => ({
    bucket: range,
    bucket_mid: d.mid,
    predicted_avg: d.sample ? d.pred_sum / d.sample : null,
    realized_rate: d.sample ? d.wins / d.sample * 100 : null,
    sample: d.sample,
  })).sort((a, b) => a.bucket_mid - b.bucket_mid);
}

// R6 — Calibration tennis: buckets déciles via proba implicite (1/odds)
function computeTennisCalibration(entries) {
  const buckets = {};
  for (const h of entries) {
    const picks = _tennisPicksOf(h);
    for (const p of picks) {
      if (!p.odds || typeof p.odds !== 'number' || p.odds <= 1) continue;
      const proba = (1 / p.odds) * 100; // probabilité implicite
      if (proba < 0 || proba > 100) continue;
      const bucket = Math.min(Math.floor(proba / 10) * 10, 90);
      const key = `${bucket}-${bucket + 10}`;
      if (!buckets[key]) buckets[key] = { pred_sum: 0, sample: 0, wins: 0, mid: bucket + 5 };
      buckets[key].pred_sum += proba;
      buckets[key].sample++;
      buckets[key].wins += p.won;
    }
  }
  return Object.entries(buckets).map(([range, d]) => ({
    bucket: range,
    bucket_mid: d.mid,
    predicted_avg: d.sample ? d.pred_sum / d.sample : null,
    realized_rate: d.sample ? d.wins / d.sample * 100 : null,
    sample: d.sample,
  })).sort((a, b) => a.bucket_mid - b.bucket_mid);
}

// R4 — Profit Attribution : décompose P/L total par dim (marché × ligue × stratégie)
function computeProfitAttribution(entries) {
  const allPicks = [];
  for (const h of entries) allPicks.push(..._historyPicksOf(h));
  const totalPL = allPicks.reduce((s, p) => s + (p.won ? 1 : -1), 0);

  const byMarket = ['over25', 'btts', 'edge'].map(mkt => {
    const xs = allPicks.filter(p => p.market === mkt);
    const wins = xs.reduce((s, p) => s + p.won, 0);
    const pl = wins - (xs.length - wins);
    return { dim: mkt, sample: xs.length, wins, losses: xs.length - wins, pl_units: pl };
  }).filter(x => x.sample > 0);

  const byLeague = {};
  for (const p of allPicks) {
    const k = p.league || 'Unknown';
    if (!byLeague[k]) byLeague[k] = { sample: 0, wins: 0 };
    byLeague[k].sample++;
    byLeague[k].wins += p.won;
  }
  const leagueAttr = Object.entries(byLeague).map(([dim, d]) => ({
    dim,
    sample: d.sample,
    wins: d.wins,
    losses: d.sample - d.wins,
    pl_units: d.wins - (d.sample - d.wins),
  })).sort((a, b) => Math.abs(b.pl_units) - Math.abs(a.pl_units));

  // Stratégies — depuis predicted.strategies tagging
  const byStrategy = {};
  for (const h of entries) {
    if (!h.verified || !h.realScore) continue;
    const strats = h.predicted?.strategies;
    if (!Array.isArray(strats) || !strats.length) continue;
    for (const sk of strats) {
      const won = _strategyWonOf(sk, h);
      if (won === null) continue;
      if (!byStrategy[sk]) byStrategy[sk] = { sample: 0, wins: 0 };
      byStrategy[sk].sample++;
      byStrategy[sk].wins += won;
    }
  }
  const strategyAttr = Object.entries(byStrategy).map(([dim, d]) => ({
    dim,
    sample: d.sample,
    wins: d.wins,
    losses: d.sample - d.wins,
    pl_units: d.wins - (d.sample - d.wins),
  })).sort((a, b) => Math.abs(b.pl_units) - Math.abs(a.pl_units));

  return {
    total_pl_units: totalPL,
    total_picks: allPicks.length,
    by_market: byMarket,
    by_league: leagueAttr.slice(0, 15),
    by_strategy: strategyAttr.slice(0, 12),
  };
}

// R2 — Alertes Executive : drift / bad beat streak / cohort divergence
function computeHistoryAlerts(entries) {
  const verified = entries.filter(h => h.verified && h.realScore)
    .slice().sort((a, b) => new Date(a.commence_time) - new Date(b.commence_time));
  if (!verified.length) return [];

  const alerts = [];

  // 1. Drift detection — WR rolling 30 picks vs all-time, par marché
  const allPicks = [];
  for (const h of verified) allPicks.push(..._historyPicksOf(h));
  allPicks.sort((a, b) => a.t - b.t);
  for (const mkt of ['over25', 'btts', 'edge']) {
    const xs = allPicks.filter(p => p.market === mkt);
    if (xs.length < 30) continue;
    const recent30 = xs.slice(-30);
    const wrAll = xs.reduce((s, p) => s + p.won, 0) / xs.length;
    const wr30 = recent30.reduce((s, p) => s + p.won, 0) / 30;
    const delta = wr30 - wrAll;
    if (delta <= -0.10) {
      alerts.push({
        kind: 'drift',
        severity: delta <= -0.20 ? 'red' : 'amber',
        market: mkt,
        wr_all: wrAll,
        wr_recent30: wr30,
        delta,
        msg: `${mkt} : WR rolling 30 = ${Math.round(wr30 * 100)}% vs ${Math.round(wrAll * 100)}% all-time (${Math.round(delta * 100)}pts)`,
      });
    }
  }

  // 2. Bad beat streak — N consecutive losses sur edge picks (proxy)
  const edgePicks = allPicks.filter(p => p.market === 'edge');
  let curStreak = 0, maxStreakRecent = 0;
  for (let i = edgePicks.length - 1; i >= 0; i--) {
    if (edgePicks[i].won === 0) {
      curStreak++;
      maxStreakRecent = Math.max(maxStreakRecent, curStreak);
    } else break;
  }
  if (curStreak >= 5) {
    alerts.push({
      kind: 'losing_streak',
      severity: curStreak >= 8 ? 'red' : 'amber',
      streak: curStreak,
      market: 'edge',
      msg: `${curStreak} edge picks perdants consécutifs (en cours)`,
    });
  }

  // 3. Cohort divergence — WR last 30j vs prior 90j window (sliding)
  const now = Date.now();
  const last30 = allPicks.filter(p => now - p.t <= 30 * 86400e3);
  const prior90 = allPicks.filter(p => now - p.t > 30 * 86400e3 && now - p.t <= 120 * 86400e3);
  if (last30.length >= 15 && prior90.length >= 30) {
    const wr30 = last30.reduce((s, p) => s + p.won, 0) / last30.length;
    const wr90 = prior90.reduce((s, p) => s + p.won, 0) / prior90.length;
    const delta = wr30 - wr90;
    if (Math.abs(delta) >= 0.10) {
      alerts.push({
        kind: 'cohort_divergence',
        severity: delta >= 0 ? 'green' : (delta <= -0.20 ? 'red' : 'amber'),
        sample_30: last30.length,
        sample_90: prior90.length,
        wr_30: wr30,
        wr_90: wr90,
        delta,
        msg: `Dernier mois ${Math.round(wr30 * 100)}% vs 90j précédents ${Math.round(wr90 * 100)}% (${delta >= 0 ? '+' : ''}${Math.round(delta * 100)}pts)`,
      });
    }
  }

  return alerts;
}

function computeHistorySeries(entries) {
  const verified = entries.filter(h => h.verified && h.realScore)
    .slice()
    .sort((a, b) => new Date(a.commence_time) - new Date(b.commence_time));

  const plCumulative = [];
  const ddCurve = [];
  let cumul = 0, peak = 0;
  for (const h of verified) {
    let delta = 0;
    for (const p of _historyPicksOf(h)) delta += (p.won ? 1 : -1);
    if (delta !== 0) cumul += delta;
    if (cumul > peak) peak = cumul;
    const dateKey = h.commence_time.split('T')[0];
    plCumulative.push({ date: dateKey, units: cumul });
    ddCurve.push({ date: dateKey, dd: peak - cumul });
  }

  // Rolling 30-pick winrate
  const allPicks = [];
  for (const h of verified) allPicks.push(..._historyPicksOf(h));
  allPicks.sort((a, b) => a.t - b.t);
  const rolling30 = [];
  const W = 30;
  for (let i = W - 1; i < allPicks.length; i++) {
    const window = allPicks.slice(i - W + 1, i + 1);
    const w = window.reduce((s, p) => s + p.won, 0);
    rolling30.push({ date: new Date(window[window.length - 1].t).toISOString().split('T')[0], wr: w / W });
  }

  return { pl_cumulative: plCumulative, drawdown_curve: ddCurve, rolling30_wr: rolling30 };
}

function runHistoryQuery(p) {
  const sport = p.sport === 'tennis' ? 'tennis' : 'football';
  // H3 : Tennis activé sur tennisHistory[] (rempli par cron tennis post-release)
  let pool = sport === 'football' ? history.slice() : tennisHistory.slice();
  // Surface filter (tennis-specific)
  if (sport === 'tennis' && p.surfaces?.length) {
    const set = new Set(p.surfaces.map(s => s.toLowerCase()));
    pool = pool.filter(h => set.has(String(h.surface || '').toLowerCase()));
  }

  // ── Filters ────────────────────────────────────────────────────────────────
  if (p.leagues?.length) {
    const set = new Set(p.leagues.map(s => s.toLowerCase()));
    pool = pool.filter(h => set.has(String(h.league || '').toLowerCase()));
  }
  if (p.teams?.length) {
    const norm = p.teams.map(t => normName(t));
    pool = pool.filter(h => {
      const hN = normName(h.home_team || ''), aN = normName(h.away_team || '');
      return norm.some(t => hN.includes(t) || aN.includes(t) || t.includes(hN) || t.includes(aN));
    });
  }
  if (p.markets?.length) {
    const wants = new Set(p.markets);
    // Tennis markets: décomposition via _tennisPicksOf (≠ football predicted fields)
    if (sport === 'tennis') {
      pool = pool.filter(h => {
        const picks = _tennisPicksOf(h);
        return picks.some(pk => wants.has(pk.market));
      });
    } else {
      pool = pool.filter(h => {
        if (!h.predicted) return false;
        if (wants.has('over25') && h.predicted.over25 > 55 && h.predicted.over25 <= 100) return true;
        if (wants.has('btts') && h.predicted.btts > 55 && h.predicted.btts <= 100) return true;
        if (wants.has('edge')) {
          const ev = h.predicted.bestEdgeValue;
          if (typeof ev === 'number' && ev >= HISTORY_EDGE_MIN && ev <= HISTORY_EDGE_MAX) return true;
        }
        return false;
      });
    }
  }

  // bd debug — log le nombre de matchs dans le pool après filtres
  if (sport === 'tennis') {
    console.log(`  [DEBUG HISTORIQUE TENNIS] Pool après filtres: ${pool.length} matchs (marchés: ${(p.markets||[]).join(',') || 'tous'}, surfaces: ${(p.surfaces||[]).join(',') || 'toutes'})`);
  }
  // H4 : Filtre stratégies (matche si record a au moins 1 stratégie active)
  if (sport === 'football' && p.strategies?.length) {
    const wants = new Set(p.strategies);
    pool = pool.filter(h => {
      const strats = h.predicted?.strategies;
      return Array.isArray(strats) && strats.some(s => wants.has(s));
    });
  }
  if (p.fromDate) {
    const ts = Date.UTC(...p.fromDate.split('-').map((v, i) => i === 1 ? +v - 1 : +v));
    if (!Number.isNaN(ts)) pool = pool.filter(h => new Date(h.commence_time).getTime() >= ts);
  }
  if (p.toDate) {
    const parts = p.toDate.split('-').map((v, i) => i === 1 ? +v - 1 : +v);
    const ts = Date.UTC(...parts) + 86400000;
    if (!Number.isNaN(ts)) pool = pool.filter(h => new Date(h.commence_time).getTime() < ts);
  }
  if (p.minProba != null && !Number.isNaN(p.minProba)) {
    if (sport === 'tennis') {
      // Tennis: minProba n'est pas applicable (pas de over25/btts)
      // skip — les KPIs de confiance sont dans _tennisPicksOf
    } else {
      pool = pool.filter(h => {
        const probs = [h.predicted?.over25, h.predicted?.btts].filter(x => typeof x === 'number');
        return probs.some(x => x >= p.minProba);
      });
    }
  }
  if (p.minEV != null && !Number.isNaN(p.minEV)) {
    if (sport !== 'tennis') {
      pool = pool.filter(h => (h.predicted?.bestEdgeValue || 0) >= p.minEV);
    }
  }
  if (p.outcome === 'won' || p.outcome === 'lost') {
    pool = pool.filter(h => {
      const picks = sport === 'tennis' ? _tennisPicksOf(h) : _historyPicksOf(h);
      if (!picks.length) return false;
      const allWon = picks.every(x => x.won === 1);
      const anyLost = picks.some(x => x.won === 0);
      return p.outcome === 'won' ? allWon : anyLost;
    });
  }
  if (p.confidence?.length && sport !== 'tennis') {
    const wants = new Set(p.confidence);
    pool = pool.filter(h => {
      const probs = [h.predicted?.over25, h.predicted?.btts].filter(x => typeof x === 'number');
      const max = probs.length ? Math.max(...probs) : 0;
      const tier = max >= 75 ? 'high' : max >= 65 ? 'medium' : 'low';
      return wants.has(tier);
    });
  }
  // R1 — Plage de cotes (sur bestEdgeOdds quand dispo)
  if (sport === 'football' && (p.minOdds != null || p.maxOdds != null)) {
    const lo = p.minOdds != null ? p.minOdds : 1.0;
    const hi = p.maxOdds != null ? p.maxOdds : 100;
    pool = pool.filter(h => {
      const o = h.predicted?.bestEdgeOdds;
      // Si aucune cote captée (entry legacy), on garde par défaut quand range = défaut total.
      if (typeof o !== 'number') return (lo <= 1.1 && hi >= 10);
      return o >= lo && o <= hi;
    });
  }
  // R1 — Venue filter (Edge picks = label home_team / away_team / Nul)
  if (sport === 'football' && p.venue && p.venue !== 'all') {
    pool = pool.filter(h => {
      const lbl = h.predicted?.bestEdge;
      if (!lbl) return false;
      if (p.venue === 'home') return lbl === h.home_team;
      if (p.venue === 'away') return lbl === h.away_team;
      if (p.venue === 'draw') return lbl === 'Nul' || lbl === 'Draw';
      return true;
    });
  }
  // R1 — Weekday filter (0=dim..6=sam)
  if (p.weekdays?.length) {
    const wantsD = new Set(p.weekdays.map(d => parseInt(d)).filter(d => d >= 0 && d <= 6));
    if (wantsD.size) {
      pool = pool.filter(h => {
        const d = new Date(h.commence_time).getDay();
        return wantsD.has(d);
      });
    }
  }
  // R9 — Weather filter (predicted.weather.condition) — data dépendante de l'enrichissement
  // archive externe (open-meteo via venue lat/lon). Tant que pipeline absent, filtre opère sur
  // entries déjà tagguées seulement, sinon retourne pool inchangé si aucune entrée taggée.
  if (p.weather?.length) {
    const wants = new Set(p.weather.map(w => w.toLowerCase()));
    const hasTaggedEntries = pool.some(h => h.predicted?.weather?.condition);
    if (hasTaggedEntries) {
      pool = pool.filter(h => {
        const cond = h.predicted?.weather?.condition;
        return cond && wants.has(String(cond).toLowerCase());
      });
    }
    // Sinon : pool inchangé + frontend affichera bandeau "data météo absente"
  }

  // ── Aggregations PRE-pagination (branchées sport) ──────────────────────────
  const kpis = sport === 'tennis' ? computeTennisKpis(pool) : computeHistoryKpis(pool);
  const breakdown = sport === 'tennis' ? computeTennisBreakdown(pool) : computeHistoryBreakdown(pool);
  const series = sport === 'tennis' ? computeTennisSeries(pool) : computeHistorySeries(pool);
  const alerts = sport === 'football' ? computeHistoryAlerts(pool) : []; // R2 Executive
  const attribution = sport === 'football' ? computeProfitAttribution(pool) : null; // R4
  const calibration = sport === 'football' ? computeCalibration(pool) : computeTennisCalibration(pool); // R6
  const badbeats = sport === 'football' ? computeBadBeats(pool) : null; // R7

  // Exclude low-WR leagues (BetMines-style)
  if (p.excludeLowLeagues) {
    const low = new Set(
      breakdown.by_league
        .filter(l => l.winrate !== null && l.picks >= 5 && l.winrate < 0.5)
        .map(l => l.league)
    );
    pool = pool.filter(h => !low.has(h.league));
  }

  // ── Sort ───────────────────────────────────────────────────────────────────
  const sort = p.sort || 'date_desc';
  pool.sort((a, b) => {
    if (sort === 'date_asc') return new Date(a.commence_time) - new Date(b.commence_time);
    if (sort === 'ev_desc') return (b.predicted?.bestEdgeValue || 0) - (a.predicted?.bestEdgeValue || 0);
    if (sort === 'proba_desc') {
      const ap = Math.max(a.predicted?.over25 || 0, a.predicted?.btts || 0);
      const bp = Math.max(b.predicted?.over25 || 0, b.predicted?.btts || 0);
      return bp - ap;
    }
    return new Date(b.commence_time) - new Date(a.commence_time); // default date_desc
  });

  // ── Paginate ───────────────────────────────────────────────────────────────
  const total = pool.length;
  const pageSize = Math.max(10, Math.min(200, p.pageSize || 50));
  const page = Math.max(1, p.page || 1);
  const matches = pool.slice((page - 1) * pageSize, page * pageSize);

  return { sport, matches, total, page, pageSize, kpis, breakdown, series, alerts, attribution, calibration, badbeats };
}

// ═══════════════════════════════════════════════════════════════════════════════
//  OPTION C — AI SCOUT (Top Value Bets → Gemini)
// ═══════════════════════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════════════════════
//  STATS AVANCÉES — /teams/statistics (cache 24h, ~1 req/équipe/jour max)
// ═══════════════════════════════════════════════════════════════════════════════

/**
 * Récupère les statistiques agrégées de saison d'une équipe via /teams/statistics.
 * Budget : 1 requête API-Football par équipe par jour (cache 24h dans db.advancedTeamStats).
 *
 * @param {string} teamKey   Clé normalisée (normName) — sert de clé de cache
 * @param {number} teamId    ID numérique API-Football (stocké dans db.teamStats[key].teamId)
 * @param {number} leagueId  ID ligue API-Football
 * @param {number} season    Saison (ex: 2025)
 * @returns {object|null}    Objet stats avancées, ou null si indisponible
 */
async function fetchTeamAdvancedStats(teamKey, teamId, leagueId, season) {
  if (!API_FOOTBALL_KEY || !teamId || !leagueId) return null;

  // ── Cache hit ────────────────────────────────────────────────────────────────
  const cached = db.advancedTeamStats[teamKey];
  // Invalide le cache si les champs v4.0 sont absents (migration shots/cards/clean_sheet)
  if (cached && cached.data && cached.data.shots_on_total === undefined) {
    delete db.advancedTeamStats[teamKey];
  } else if (cached && (Date.now() - new Date(cached.fetchedAt).getTime() < ADV_STATS_TTL)) {
    return cached.data;
  }

  // ── Appel API ────────────────────────────────────────────────────────────────
  try {
    const res = await httpsGet(
      `https://v3.football.api-sports.io/teams/statistics?league=${leagueId}&team=${teamId}&season=${season}`,
      { 'x-apisports-key': API_FOOTBALL_KEY }
    );

    if (res.status === 429) {
      console.warn(`  [AdvStats] Quota épuisé — ${teamKey}`);
      return null;
    }
    if (res.status !== 200) {
      console.warn(`  [AdvStats] HTTP ${res.status} — team=${teamId} league=${leagueId}`);
      return null;
    }

    const raw = res.data?.response;
    if (!raw) return null;

    // ── Extraction des 5 piliers du Scientific Mode ───────────────────────────
    const data = {
      // Pilier 1 — Stabilité offensive / défensive
      goals_scored_home_avg: parseFloat(raw.goals?.for?.average?.home || 0),
      goals_scored_away_avg: parseFloat(raw.goals?.for?.average?.away || 0),
      goals_conceded_home_avg: parseFloat(raw.goals?.against?.average?.home || 0),
      goals_conceded_away_avg: parseFloat(raw.goals?.against?.average?.away || 0),

      // Pilier 2 — Croissance de forme (5 derniers matchs)
      form: raw.form || '',

      // Pilier 3 — Résultats à domicile / extérieur (différentiel)
      played_home: raw.fixtures?.played?.home || 0,
      played_away: raw.fixtures?.played?.away || 0,
      wins_home: raw.fixtures?.wins?.home || 0,
      wins_away: raw.fixtures?.wins?.away || 0,
      draws_home: raw.fixtures?.draws?.home || 0,
      draws_away: raw.fixtures?.draws?.away || 0,
      losses_home: raw.fixtures?.losses?.home || 0,
      losses_away: raw.fixtures?.losses?.away || 0,

      // Pilier 4 — Indice spéculatif (pénaltys, biggest wins, streaks)
      penalties_scored: raw.penalty?.scored?.total || 0,
      penalties_missed: raw.penalty?.missed?.total || 0,
      biggest_win_home: raw.biggest?.wins?.home || '',
      biggest_win_away: raw.biggest?.wins?.away || '',
      biggest_loss_home: raw.biggest?.loses?.home || '',
      biggest_loss_away: raw.biggest?.loses?.away || '',
      streak_wins: raw.biggest?.streak?.wins || 0,
      streak_draws: raw.biggest?.streak?.draws || 0,
      streak_losses: raw.biggest?.streak?.loses || 0,

      // Pilier 2 — Tirs (disponibles dans /teams/statistics)
      shots_on_home: raw.shots?.on?.home || 0,
      shots_on_away: raw.shots?.on?.away || 0,
      shots_on_total: raw.shots?.on?.total || 0,
      shots_total_home: raw.shots?.total?.home || 0,
      shots_total_away: raw.shots?.total?.away || 0,

      // Pilier 5 — Schéma tactique (formation dominante)
      main_formation: raw.lineups?.[0]?.formation || 'N/A',

      // Pilier 6 — Discipline (cartons — somme de toutes les tranches horaires)
      cards_yellow_total: Object.values(raw.cards?.yellow || {}).reduce((s, v) => s + (v.total || 0), 0),
      cards_red_total: Object.values(raw.cards?.red || {}).reduce((s, v) => s + (v.total || 0), 0),

      // Pilier 7 — Clean Sheets
      clean_sheet_home: raw.clean_sheet?.home || 0,
      clean_sheet_away: raw.clean_sheet?.away || 0,
      clean_sheet_total: raw.clean_sheet?.total || 0,

      // Moyennes globales (pour le classement mode "Global")
      goals_scored_total_avg: parseFloat(raw.goals?.for?.average?.total || 0),
      goals_conceded_total_avg: parseFloat(raw.goals?.against?.average?.total || 0),
    };

    // ── Mise en cache ─────────────────────────────────────────────────────────
    db.advancedTeamStats[teamKey] = {
      data,
      fetchedAt: new Date().toISOString(),
      teamId,
      leagueId,
    };
    saveDB();

    console.log(`  [AdvStats] ✓ ${teamKey} (team=${teamId}, league=${leagueId})`);
    return data;

  } catch (e) {
    console.warn(`  [AdvStats] Erreur ${teamKey}:`, e.message);
    return null;
  }
}

// Fallback stats avancées équipe SANS API-Football : dérivé des standings
// BSD déjà en mémoire (db.teamStats[key]._raw + form). Zéro réseau. Champs
// sans source libre (tirs/cartons/penalties/formation/clean sheets) = null
// HONNÊTE (jamais inventé) → l'UI affiche « N/A ». Même shape que l'AF.
function buildAdvancedStatsFromStandings(ts) {
  if (!ts || !ts._raw) return null;
  const R = ts._raw, h = R.home || {}, a = R.away || {};
  const div = (n, d) => (d && d > 0 ? Math.round((n / d) * 100) / 100 : 0);
  const form = String(ts.form || '');
  let sw = 0, sd = 0, sl = 0;
  if (form) {
    const last = form.slice(-1).toUpperCase();
    for (let i = form.length - 1; i >= 0; i--) {
      if (form[i].toUpperCase() !== last) break;
      if (last === 'W') sw++; else if (last === 'D') sd++; else if (last === 'L') sl++;
    }
  }
  return {
    goals_scored_home_avg: div(h.gf, h.played),
    goals_scored_away_avg: div(a.gf, a.played),
    goals_conceded_home_avg: div(h.ga, h.played),
    goals_conceded_away_avg: div(a.ga, a.played),
    form,
    played_home: h.played || 0, played_away: a.played || 0,
    wins_home: h.wins || 0, wins_away: a.wins || 0,
    draws_home: h.draws || 0, draws_away: a.draws || 0,
    losses_home: h.losses || 0, losses_away: a.losses || 0,
    penalties_scored: null, penalties_missed: null,
    biggest_win_home: '', biggest_win_away: '', biggest_loss_home: '', biggest_loss_away: '',
    streak_wins: sw, streak_draws: sd, streak_losses: sl,
    shots_on_home: null, shots_on_away: null, shots_on_total: null,
    shots_total_home: null, shots_total_away: null,
    main_formation: 'N/A',
    cards_yellow_total: null, cards_red_total: null,
    clean_sheet_home: null, clean_sheet_away: null, clean_sheet_total: null,
    goals_scored_total_avg: div(R.gf, R.played),
    goals_conceded_total_avg: div(R.ga, R.played),
    xg_for: ts.xgFor != null ? ts.xgFor : null,
    xg_against: ts.xgAgainst != null ? ts.xgAgainst : null,
    _source: 'bsd-standings' + (h._estimated ? '-est' : ''),
  };
}

// Stats avancées avec fallback : API-Football si dispo, sinon BSD standings.
async function getTeamAdvancedStats(teamKey, meta, leagueId, season) {
  let adv = (meta && meta.teamId && leagueId)
    ? await fetchTeamAdvancedStats(teamKey, meta.teamId, leagueId, season)
    : null;
  if (adv) return adv;
  const fb = buildAdvancedStatsFromStandings(db.teamStats[teamKey] || meta);
  if (fb) {
    db.advancedTeamStats[teamKey] = {
      data: fb, fetchedAt: new Date().toISOString(),
      teamId: (meta && meta.teamId) || null, leagueId: leagueId || null, _fallback: 'bsd',
    };
  }
  return fb;
}

// ─── HELPER GEMINI (appel synchrone one-shot) ────────────────────────────────
async function callGemini(prompt, maxTokens = 600) {
  if (!GEMINI_API_KEY) throw new Error('Cle Gemini non configuree');
  const res = await Promise.race([
    httpsPost(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_API_KEY}`,
      {
        contents: [{ parts: [{ text: prompt }] }],
        generationConfig: { temperature: 0.7, maxOutputTokens: maxTokens },
        safetySettings: GEMINI_SAFETY_SETTINGS,
      }
    ),
    new Promise((_, reject) => setTimeout(() => reject(new Error('Gemini timeout (12s)')), 12000)),
  ]);
  if (res.status === 429) throw new Error('GEMINI_QUOTA');
  const text = res.data?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  if (!text && res.status !== 200) throw new Error(`GEMINI_ERR_${res.status}`);
  return text;
}

// ─── INJURIES PAR ÉQUIPE — SUPPRIMÉ (données mappées via flux BSD) ─────────
// fetchTeamInjuries() removed — injuries now sourced from BSD unavailable_players
// in buildMatchRecord(). API-Football /injuries endpoint no longer called.

// ─── AF ENRICHMENTS — predictions + transfers (cache 6h/24h) ──────────────
// Active des endpoints API-Football PRO inexploités (7500 req/jour budget).
// Apport: 2e source AI-prediction indépendante de BSD (cross-check Poisson)
// + transferts hivernaux pour contexte tactique.
const AF_BASE_URL = 'https://v3.football.api-sports.io';
const AF_PREDICTIONS_TTL_MS = 6 * 3600 * 1000;
const AF_TRANSFERS_TTL_MS   = 24 * 3600 * 1000;

async function fetchAFPredictions(fixtureId) {
  if (!API_FOOTBALL_KEY || !fixtureId) return null;
  const cacheKey = `af_pred_${fixtureId}`;
  const cached = apiCacheGet(cacheKey, 'apif_predictions');
  if (cached !== null && cached !== undefined) {
    return cached === '__NEG__' ? null : cached;
  }
  try {
    const r = await httpsGet(
      `${AF_BASE_URL}/predictions?fixture=${encodeURIComponent(fixtureId)}`,
      { 'x-apisports-key': API_FOOTBALL_KEY }
    );
    const arr = r?.data?.response;
    if (!Array.isArray(arr) || arr.length === 0) {
      apiCacheSet(cacheKey, '__NEG__', 'apif_predictions', AF_PREDICTIONS_TTL_MS);
      return null;
    }
    const p = arr[0]?.predictions || {};
    const cleaned = {
      winner_id:      p.winner?.id ?? null,
      winner_name:    p.winner?.name ?? null,
      winner_comment: p.winner?.comment ?? null,
      win_or_draw:    !!p.win_or_draw,
      under_over:     p.under_over ?? null,
      goals_home:     p.goals?.home ?? null,
      goals_away:     p.goals?.away ?? null,
      advice:         p.advice ?? null,
      percent_home:   p.percent?.home ?? null,
      percent_draw:   p.percent?.draw ?? null,
      percent_away:   p.percent?.away ?? null,
      fetched_at:     Date.now(),
      source:         'api-football',
    };
    apiCacheSet(cacheKey, cleaned, 'apif_predictions', AF_PREDICTIONS_TTL_MS);
    return cleaned;
  } catch (e) {
    console.warn(`  [AF/predictions] fixture=${fixtureId} erreur:`, e.message);
    return null;
  }
}

async function fetchAFTransfers(teamId, sinceDays = 180) {
  if (!API_FOOTBALL_KEY || !teamId) return null;
  const cacheKey = `af_trans_${teamId}_${sinceDays}`;
  const cached = apiCacheGet(cacheKey, 'apif_transfers');
  if (cached !== null && cached !== undefined) {
    return cached === '__NEG__' ? null : cached;
  }
  try {
    const r = await httpsGet(
      `${AF_BASE_URL}/transfers?team=${encodeURIComponent(teamId)}`,
      { 'x-apisports-key': API_FOOTBALL_KEY }
    );
    const arr = r?.data?.response;
    if (!Array.isArray(arr) || arr.length === 0) {
      apiCacheSet(cacheKey, '__NEG__', 'apif_transfers', AF_TRANSFERS_TTL_MS);
      return null;
    }
    const cutoff = Date.now() - (sinceDays * 24 * 3600 * 1000);
    const transfers = [];
    for (const player of arr) {
      const playerName = player?.player?.name || null;
      const playerId   = player?.player?.id   || null;
      for (const t of player?.transfers || []) {
        const ts = t.date ? new Date(t.date).getTime() : 0;
        if (!Number.isFinite(ts) || ts < cutoff) continue;
        transfers.push({
          player_id:   playerId,
          player_name: playerName,
          date:        t.date,
          type:        t.type ?? null,
          team_in:     t.teams?.in?.name  ?? null,
          team_out:    t.teams?.out?.name ?? null,
        });
      }
    }
    transfers.sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    apiCacheSet(cacheKey, transfers, 'apif_transfers', AF_TRANSFERS_TTL_MS);
    return transfers;
  } catch (e) {
    console.warn(`  [AF/transfers] team=${teamId} erreur:`, e.message);
    return null;
  }
}

// ─── Transfermarkt — cache (voie D : felipeall self-host, cf. fetchTransfermarkt) ─
// Cache 24h (data carrière/valeurs peu volatile). Scaffold Apify retiré
// (actor payant) au profit du sidecar felipeall/transfermarkt-api.
const TM_TTL_MS = 24 * 3600 * 1000;
const _tmCache = new Map();

// ─── Option A : felipeall/transfermarkt-api auto-hébergé (sidecar Docker) ────
// Microservice Python/FastAPI MIT déployé en conteneur ; Node l'appelle en
// HTTP clé-zéro (zero-dep préservé, https natif). Schéma JSON propre (schemas
// Pydantic). Endpoints : /players/{id}/{profile|market_value|transfers|injuries}.
// ⚠ Pas d'endpoint « rumeurs » côté felipeall → transferts CONFIRMÉS + valeurs
// uniquement (rumeurs = follow-up : route custom /geruechte ou RapidAPI apidojo).
const TM_API_URL = (process.env.TRANSFERMARKT_API_URL || 'http://127.0.0.1:8000').replace(/\/+$/, '');
const _TM_PATHS = { profile: 'profile', market_value: 'market_value', transfers: 'transfers', injuries: 'injuries' };

async function fetchTransfermarkt(kind, id, slug) {
  if (!_TM_PATHS[kind]) throw new Error(`kind invalide: ${kind}`);
  const pid = String(id || '').replace(/\D/g, '');
  if (!pid) throw new Error('id Transfermarkt numérique requis');
  const ck = `tm_${kind}_${pid}`;
  const cached = _tmCache.get(ck);
  if (cached && Date.now() - cached.ts < TM_TTL_MS) return cached.data;
  const url = `${TM_API_URL}/players/${pid}/${_TM_PATHS[kind]}`;
  let res;
  try {
    res = await httpsGet(url, { Accept: 'application/json' });
  } catch (e) {
    throw new Error(`transfermarkt-api injoignable (${TM_API_URL}) : ${e.message}`);
  }
  if (res.status === 404) throw new Error('joueur introuvable Transfermarkt');
  if (res.status !== 200) throw new Error(`transfermarkt-api HTTP ${res.status}`);
  const body = (res.data && typeof res.data === 'object') ? res.data : null;
  if (!body) throw new Error('réponse transfermarkt-api invalide');
  const data = {
    source: 'transfermarkt',
    via: 'felipeall/transfermarkt-api (self-host)',
    kind,
    tm_id: pid,
    fetched_at: new Date().toISOString(),
    data: body,
  };
  _tmCache.set(ck, { ts: Date.now(), data });
  return data;
}

// Résolveur nom → id Transfermarkt (felipeall /players/search/{name}).
// Désambiguïse via indices club puis âge ; fallback 1er résultat. Cache 24h.
async function tmResolvePlayerId(name, hints = {}) {
  const q = String(name || '').trim();
  if (!q) return null;
  const ck = `tm_search_${(normName ? normName(q) : q.toLowerCase())}`;
  const cached = _tmCache.get(ck);
  if (cached && Date.now() - cached.ts < TM_TTL_MS) return cached.data;
  let res;
  try {
    res = await httpsGet(`${TM_API_URL}/players/search/${encodeURIComponent(q)}?page_number=1`, { Accept: 'application/json' });
  } catch (e) { return null; }
  const results = (res && res.status === 200 && res.data && Array.isArray(res.data.results)) ? res.data.results : [];
  if (!results.length) { _tmCache.set(ck, { ts: Date.now(), data: null }); return null; }
  const nClub = (hints.club && normName) ? normName(hints.club) : null;
  let pick = null;
  if (nClub) pick = results.find(r => r.club && r.club.name && normName(r.club.name) &&
    (normName(r.club.name).includes(nClub) || nClub.includes(normName(r.club.name))));
  if (!pick && hints.age) pick = results.find(r => r.age && Math.abs(r.age - hints.age) <= 1);
  if (!pick) pick = results[0];
  const id = (pick && pick.id) ? String(pick.id) : null;
  _tmCache.set(ck, { ts: Date.now(), data: id });
  return id;
}

// Bio + blessure 100% via Transfermarkt (felipeall sidecar). Orphelin
// API-Football : profil (la bible) + blessure en cours (until_date null).
async function getTransfermarktBio(name, hints = {}) {
  const id = await tmResolvePlayerId(name, hints);
  if (!id) return null;
  let prof = null, inj = null;
  try { prof = await fetchTransfermarkt('profile', id); } catch (_) {}
  try { inj = await fetchTransfermarkt('injuries', id); } catch (_) {}
  const p = (prof && prof.data) ? prof.data : null;
  const out = { tm_id: id };
  if (p) {
    out.full_name = p.full_name || p.name || null;
    out.birthdate = p.date_of_birth || null;
    if (p.age != null) out.age = p.age;
    else if (p.date_of_birth) {
      const d = new Date(p.date_of_birth);
      if (!isNaN(d.getTime())) out.age = Math.floor((Date.now() - d.getTime()) / 31557600000);
    }
    out.nationality = Array.isArray(p.citizenship) ? (p.citizenship[0] || null)
      : (p.citizenship || (p.place_of_birth && p.place_of_birth.country) || null);
    out.height = p.height || null;
    out.foot = p.foot || null;
    out.position = (p.position && (p.position.main || (typeof p.position === 'string' ? p.position : null))) || null;
    out.photo = p.image_url || null;
  }
  const injs = (inj && inj.data && Array.isArray(inj.data.injuries)) ? inj.data.injuries : [];
  const today = new Date().toISOString().slice(0, 10);
  const cur = injs.find(x => x && (!x.until_date || String(x.until_date) >= today));
  out.injured = !!cur;
  out.current_injury = cur ? { injury: cur.injury, since: cur.from_date, until: cur.until_date || null, days: cur.days } : null;
  out.injury_history = injs.slice(0, 5);
  return out;
}

