// Envoyer alertes pour les value bets avec edge > seuil

function escTg(s) {
  return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

// Croise proba modèle (%) + EV+ (ratio value en %, ex: 125 = cote*prob = 1.25)
function computeConfidenceStars(probaPct, evPlusPct) {
  const p = Number(probaPct) || 0;
  const ev = Number(evPlusPct) || 0;
  if (p > 65 && ev > 125) return { stars: 5, label: 'Ultra Safe / Énorme Value', glyph: '⭐⭐⭐⭐⭐' };
  if (p > 55 && ev > 115) return { stars: 4, label: 'Confiance Forte',          glyph: '⭐⭐⭐⭐☆' };
  if (p > 50 || ev > 105) return { stars: 3, label: 'Value Intéressante',       glyph: '⭐⭐⭐☆☆' };
  return { stars: 0, label: 'Sous seuil', glyph: '' };
}

// Parse score live "2-1" → { h, a, total } ; null si invalide
function parseLiveScore(s) {
  const mt = String(s || '').match(/^\s*(\d+)\s*[-:]\s*(\d+)\s*$/);
  if (!mt) return null;
  const h = parseInt(mt[1], 10), a = parseInt(mt[2], 10);
  if (!Number.isFinite(h) || !Number.isFinite(a)) return null;
  return { h, a, total: h + a };
}

// Extrait LE meilleur pari prédictif (1X2 vs Over2.5 vs BTTS) par EV+ croisé proba.
// En contexte LIVE : exclut tout marché déjà tranché par le score courant
// (Over2.5 si ≥3 buts, BTTS si les 2 ont marqué, 1X2 pré-match invalide en live).
function pickPredictiveBet(m) {
  const p = m.poisson || {};
  const fair = m.fair || {};
  const minute = parseInt(m.live_minute || 0, 10) || 0;
  const ls = parseLiveScore(m.live_score);
  const isLive = !!(ls && minute > 0 && minute < 130);

  const cands = [];

  // 1X2 — fair pré-match : valide UNIQUEMENT hors live (pas de modèle live ici)
  if (!isLive && m.best_edge && m.best_edge.odds) {
    const probMap = { 'Domicile': fair.home, 'Nul': fair.draw, 'Extérieur': fair.away };
    const lbl = m.best_edge.label;
    const pick = lbl === 'Domicile' ? `Victoire ${m.home_team}`
               : lbl === 'Extérieur' ? `Victoire ${m.away_team}`
               : 'Match nul';
    cands.push({ pick, prob: (probMap[lbl] ?? 0) * 100, odds: m.best_edge.odds, bk: m.best_edge.bk });
  }

  // Over 2.5 — exclu en live si déjà ≥ 3 buts (pari déjà gagné = non prédictif)
  if (p.over25 && !(isLive && ls.total >= 3)) {
    cands.push({ pick: 'Plus de 2.5 buts', prob: p.over25, odds: +(100 / p.over25).toFixed(2), bk: 'Poisson' });
  }

  // BTTS — exclu en live si les 2 équipes ont déjà marqué (déjà OUI = non prédictif)
  if (p.btts && !(isLive && ls.h > 0 && ls.a > 0)) {
    cands.push({ pick: 'Les deux équipes marquent', prob: p.btts, odds: +(100 / p.btts).toFixed(2), bk: 'Poisson' });
  }

  if (!cands.length) return null;
  cands.forEach(c => { c.evPlus = (c.prob / 100) * c.odds * 100; });
  return cands.sort((a, b) => b.evPlus - a.evPlus)[0];
}

/* -------------------------------------------------
   Bet prédictif LIVE — modèle Poisson CONDITIONNEL sur le temps restant.
   Contrôle long terme score↔bet : ne propose QUE des marchés encore OUVERTS
   (jamais déjà tranchés par le score), proba recalculée minute par minute.
   ------------------------------------------------- */
function pickLivePredictiveBet(m) {
  const ls = parseLiveScore(m.live_score);
  const minute = parseInt(m.live_minute || 0, 10) || 0;
  if (!ls || minute <= 0 || minute >= 130) return null; // pas de contexte live exploitable

  const minutesLeft = Math.max(1, Math.min(90, 90 - minute));
  const frac = minutesLeft / 90;

  // Expected goals plein-match (source réelle si dispo, sinon moyenne ligue ~2.6)
  const eg = m.expectedGoals || {};
  const egH = Number.isFinite(eg.home) ? eg.home : 1.3;
  const egA = Number.isFinite(eg.away) ? eg.away : 1.3;
  const lamH = Math.max(0.01, egH * frac); // buts restants attendus domicile
  const lamA = Math.max(0.01, egA * frac); // buts restants attendus extérieur
  const lamT = lamH + lamA;

  const pAtLeast1 = lam => 1 - Math.exp(-lam);
  const pAtLeast2 = lam => 1 - Math.exp(-lam) * (1 + lam);

  const cands = [];

  // 1) Over ligne suivante — toujours OUVERT (seuil = total actuel + 0.5 → besoin ≥1 but de plus)
  {
    const line = ls.total + 0.5;
    const prob = pAtLeast1(lamT) * 100;
    cands.push({ pick: `Plus de ${line} buts`, prob });
  }
  // 2) Over +1 ligne — alternative plus haute cote (besoin ≥2 buts de plus)
  {
    const line = ls.total + 1.5;
    const prob = pAtLeast2(lamT) * 100;
    cands.push({ pick: `Plus de ${line} buts`, prob });
  }
  // 3) BTTS — seulement si PAS encore résolu (les 2 ont déjà marqué = OUI tranché → exclu)
  if (!(ls.h > 0 && ls.a > 0)) {
    let prob;
    if (ls.h === 0 && ls.a === 0)      prob = pAtLeast1(lamH) * pAtLeast1(lamA) * 100;
    else if (ls.h === 0)               prob = pAtLeast1(lamH) * 100; // manque but domicile
    else                               prob = pAtLeast1(lamA) * 100; // manque but extérieur
    cands.push({ pick: 'Les deux équipes marquent', prob });
  }

  // proba bornée [5,95], cote = juste 100/proba (pas de book live), EV+ neutre
  const valid = cands
    .map(c => ({ ...c, prob: Math.round(Math.max(5, Math.min(95, c.prob))) }))
    .map(c => ({ ...c, odds: +(100 / c.prob).toFixed(2), bk: 'Modèle live', evPlus: 100 }));
  if (!valid.length) return null;
  return valid.sort((a, b) => b.prob - a.prob)[0]; // le plus probable parmi marchés ouverts
}

function matchUrl(m) {
  return m && m.id ? `https://pariscore.fr/?match=${encodeURIComponent(m.id)}` : 'https://pariscore.fr';
}

// Liste groupée — retourne null si aucun pari ≥ 3★ (ne pas envoyer)
function buildAlertMessage(valueBets, label = 'Value Bets') {
  const dt = new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
  const blocks = [];

  for (const m of valueBets) {
    const bet = pickPredictiveBet(m);
    if (!bet) continue;
    const conf = computeConfidenceStars(bet.prob, bet.evPlus);
    if (conf.stars < 3) continue; // gate canal principal

    const ko = new Date(m.commence_time).toLocaleString('fr-FR',
      { weekday: 'short', day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
    const evDisplay = (bet.evPlus - 100).toFixed(1);

    const args = [];
    if (m.poisson?.over25) args.push(`Modèle Poisson : ${m.poisson.over25}% buts > 2.5`);
    if (m.poisson?.btts)   args.push(`Probabilité BTTS : ${m.poisson.btts}%`);
    if (m.best_edge)       args.push(`Cote ${bet.odds} détectée vs marché (${escTg(bet.bk)})`);
    while (args.length < 3) args.push('Convergence Poisson + Edge no-vig positive');

    blocks.push(
      `🚨 <b>ALERTE HAUTE VALUE - PARISCORE</b> 🚨\n` +
      `⚽ <b>${escTg(m.league)} : ${escTg(m.home_team)} 🆚 ${escTg(m.away_team)}</b>\n` +
      `⏱ <i>Coup d'envoi : ${ko}</i>\n\n` +
      `🎯 <b>LE BET PRÉDICTIF :</b> <b>${escTg(bet.pick)}</b>\n` +
      `🔥 <b>Indice de Confiance :</b> ${conf.glyph} <i>(${conf.label})</i>\n` +
      `📈 <b>Avantage (EV+) :</b> <b>+${evDisplay}%</b> <i>(Cote ${safeFixed(bet.odds, 2)} vs Bookmakers)</i>\n\n` +
      `📊 <b>L'ŒIL DE L'IA (Data Express) :</b>\n` +
      args.slice(0, 3).map(a => `• ${escTg(a)}`).join('\n') + `\n\n` +
      `⚡ <i>Prenez l'avantage sur les books en 2 secondes chrono !</i>\n` +
      `👉 <b>Voir le match :</b> ${matchUrl(m)}`
    );
  }

  if (!blocks.length) return null;

  return `🎯 <b>PariScore — ${escTg(label)} du ${dt}</b>\n\n`
    + blocks.join('\n\n━━━━━━━━━━━━━━━\n\n')
    + `\n\n⚠️ Pariez de manière responsable. 18+`;
}

// Dedup value alerts — évite ré-envoi du même (match,marché) à chaque tick scheduler.
// TTL long (odds cron 12h) : on n'alerte qu'une fois par bet sur la fenêtre.
const _VALUE_ALERT_TTL_MS = parseInt(process.env.VALUE_ALERT_TTL_MS || String(6 * 60 * 60 * 1000), 10);
const _valueAlertCooldowns = new Map(); // `${scope}:${matchId}:${label}` → lastSentMs
function _vaKey(scope, m) { return `${scope}:${m.id}:${m.best_edge?.label || ''}`; }
function _vaOnCooldown(scope, m) { return Date.now() - (_valueAlertCooldowns.get(_vaKey(scope, m)) || 0) < _VALUE_ALERT_TTL_MS; }
function _vaMark(scope, m) { _valueAlertCooldowns.set(_vaKey(scope, m), Date.now()); }
function _vaUnmark(scope, m) { _valueAlertCooldowns.delete(_vaKey(scope, m)); }

async function sendValueBetAlerts() {
  if (!automatedAlertsAllowed()) { console.log('  [TG] skip value alerts (instance non-prod)'); return; }
  const threshold = parseFloat(process.env.ALERT_EDGE_THRESHOLD || '8');
  const allBets = db.matches
    .filter(m => (m.best_edge?.edge || 0) >= threshold)
    .sort((a, b) => b.best_edge.edge - a.best_edge.edge);
  if (!allBets.length) return;

  const topBets = allBets.slice(0, 5);

  // ── Broadcast global (admin — TELEGRAM_CHAT_IDS du .env) ─────────────────
  if (TELEGRAM_BOT_TOKEN && TELEGRAM_CHAT_IDS.size) {
    const fresh = topBets.filter(m => !_vaOnCooldown('bcast', m));
    if (fresh.length) {
      fresh.forEach(m => _vaMark('bcast', m)); // mark AVANT await (anti-doublon concurrent)
      const msg = buildAlertMessage(fresh);
      if (msg) await broadcastTelegramAlert(msg);
      else fresh.forEach(m => _vaUnmark('bcast', m)); // rien ≥3★ → libère pour retry
    }
  }

  // ── Alertes personnalisées par utilisateur ────────────────────────────────
  if (TELEGRAM_BOT_TOKEN) {
    const userPrefs = kvScan('alert_prefs_');
    for (const { value: prefs } of userPrefs) {
      if (!prefs.enabled || !prefs.chatId) continue;
      const edgeMin = prefs.edgeMin ?? 8;
      const probaMin = prefs.probaMin ?? 55;
      const markets = prefs.markets || [];
      const leagues = prefs.leagues || [];

      let userBets = allBets.filter(m => {
        if ((m.best_edge?.edge || 0) < edgeMin) return false;
        if (leagues.length && !leagues.includes(m.sport)) return false;
        // filtre marché : au moins une stratégie matchée
        if (markets.length) {
          const p = m.poisson || {};
          const matchMkt = markets.some(mkt => {
            if (mkt === 'BTTS_YES' && (p.btts || 0) >= probaMin) return true;
            if (mkt === 'OVER_2_5' && (p.over25 || 0) >= probaMin) return true;
            if (mkt === 'OVER_1_5' && (p.over15 || 0) >= probaMin) return true;
            if (mkt === 'HOME_WIN' && (p.homeWin || 0) >= probaMin) return true;
            if (mkt === 'AWAY_WIN' && (p.awayWin || 0) >= probaMin) return true;
            return false;
          });
          if (!matchMkt) return false;
        }
        return true;
      }).slice(0, 5);

      const userScope = 'u:' + prefs.chatId;
      userBets = userBets.filter(m => !_vaOnCooldown(userScope, m));
      if (!userBets.length) continue;
      userBets.forEach(m => _vaMark(userScope, m)); // mark AVANT await
      const userMsg = buildAlertMessage(userBets, 'Vos Alertes');
      if (!userMsg) { userBets.forEach(m => _vaUnmark(userScope, m)); continue; }
      const ok = await sendTelegramAlert(prefs.chatId, userMsg);
      if (ok) console.log(`  [TG:User] Alerte envoyée → chat ${prefs.chatId} (${userBets.length} matchs)`);
      else userBets.forEach(m => _vaUnmark(userScope, m)); // échec → retry prochain tick
    }
  }

  // ── Historique global des alertes ─────────────────────────────────────────
  const existing = kvGet('alert_history') || [];
  const entry = {
    ts: Date.now(),
    count: topBets.length,
    matches: topBets.map(m => ({
      home_team: m.home_team, away_team: m.away_team,
      league: m.league, sport: m.sport,
      edge: m.best_edge?.edge, odds: m.best_edge?.odds, label: m.best_edge?.label,
    })),
  };
  kvSet('alert_history', [...existing, entry].slice(-50));
}

// ── Alertes Tennis Prematch (Elo Gap >= 100) & Live (|DR| >= 0.20) ──────────
const _TENNIS_ALERT_TTL_MS = 6 * 60 * 60 * 1000; // cooldown 6h prematch
const _TENNIS_LIVE_ALERT_TTL_MS = 5 * 60 * 1000; // cooldown 5min live
const _tennisAlertSent = new Map(); // `${scope}:${matchId}` → lastSentMs
const _tennisDrAbsSent = new Map(); // `tndr_${scope}:${matchId}` → drGapSnapshot (dedup)
const _tennisDRSetHist = new Map(); // matchId → { [setNum]: { dr, ts, src } } pour variance DR/set

function _tnAlertOnCooldown(key, ttl) {
  return Date.now() - (_tennisAlertSent.get(key) || 0) < (ttl || _TENNIS_ALERT_TTL_MS);
}
function _tnAlertMark(key) { _tennisAlertSent.set(key, Date.now()); }

// Lookup Elo par nom joueur dans tennis_players_elo (LIKE tolérant)
function _lookupTennisElo(playerName) {
  if (!playerName || !tennisEloCalculator) return null;
  const clean = String(playerName).trim();
  if (!clean) return null;
  // Essai 1 : exact match LOWER dans SQLite
  let row = sqldb.prepare(
    `SELECT player_id, player_name, elo_rating, circuit FROM tennis_players_elo WHERE LOWER(player_name) = LOWER(?) LIMIT 1`
  ).get(clean);
  // Essai 2 : contain match (nom complet contient le terme BSD)
  if (!row) {
    row = sqldb.prepare(
      `SELECT player_id, player_name, elo_rating, circuit FROM tennis_players_elo WHERE LOWER(player_name) LIKE ? LIMIT 1`
    ).get('%' + clean.toLowerCase() + '%');
  }
  if (!row || !row.elo_rating) return null;
  return { id: row.player_id, name: row.player_name, elo: row.elo_rating, circuit: row.circuit };
}

async function pollTennisPrematchEloAlerts() {
  if (!automatedAlertsAllowed()) return;
  if (!tennisEloCalculator) return;

  try {
    let upcoming = [];
    if (BSD_TENNIS_ENABLED) {
      try {
        const res = await bsdTennisFetch('/api/v2/matches/?status=scheduled&limit=200');
        if (res && res.status === 200) {
          const arr = Array.isArray(res.data) ? res.data : (res.data?.results || []);
          upcoming = arr.map(_normalizeBSDTennisMatch).filter(Boolean);
        }
      } catch (e) { /* fallback silencieux — pas de matchs BSD */ }
    }

    if (!upcoming.length) return;

    const alerts = [];
    for (const m of upcoming) {
      if (m.is_live) continue;
      const matchKey = `elo:${m.id}`;
      if (_tnAlertOnCooldown(matchKey)) continue;

      const p1Name = m.player1?.name;
      const p2Name = m.player2?.name;
      if (!p1Name || !p2Name) continue;

      const eloP1 = _lookupTennisElo(p1Name);
      const eloP2 = _lookupTennisElo(p2Name);
      if (!eloP1 || !eloP2) continue;

      const gap = eloP1.elo - eloP2.elo;
      if (Math.abs(gap) < 100) continue;

      const fav = gap > 0 ? eloP1 : eloP2;
      const dog = gap > 0 ? eloP2 : eloP1;
      const prob = tennisEloCalculator.computeWinProbability(fav.elo, dog.elo);

      alerts.push({
        matchId: m.id, tournament: m.tournament, court: m.court,
        discipline: m.discipline, startTime: m.start_time,
        p1Name, p2Name, gap: Math.round(gap), favName: fav.name,
        favElo: Math.round(fav.elo), dogElo: Math.round(dog.elo),
        prob: Math.round(prob * 100),
      });
    }

    if (!alerts.length) return;

    for (const a of alerts) {
      const msgHtml = [
        `🎾 <b>ALERTE ELO TENNIS</b> — Écart significatif`,
        ``,
        `${escTg(a.tournament)} | ${escTg(a.court)} | ${escTg(a.discipline)}`,
        `${escTg(a.p1Name)} (Elo: ${a.gap > 0 ? a.favElo : a.dogElo}) vs ${escTg(a.p2Name)} (Elo: ${a.gap > 0 ? a.dogElo : a.favElo})`,
        `Écart: <b>${Math.abs(a.gap)} pts</b> — Favori: ${escTg(a.favName)} (${a.prob}%)`,
        a.startTime ? `Début: ${new Date(a.startTime).toLocaleString('fr-FR', { timeZone: 'Europe/Paris' })}` : '',
        `Surface: ${a.discipline || 'N/A'}`,
      ].filter(Boolean).join('\n');

      const discordEmbed = {
        title: `🎾 Alerte Elo Tennis — ${a.tournament}`,
        color: 0x1DB954,
        fields: [
          { name: 'Match', value: `${a.p1Name} vs ${a.p2Name}`, inline: false },
          { name: 'Écart Elo', value: `${Math.abs(a.gap)} pts`, inline: true },
          { name: 'Favori', value: `${a.favName} (${a.prob}%)`, inline: true },
          { name: 'Surface', value: a.discipline || 'N/A', inline: true },
          { name: 'Tour', value: a.court || 'N/A', inline: true },
          { name: 'Début', value: a.startTime ? new Date(a.startTime).toLocaleString('fr-FR', { timeZone: 'Europe/Paris' }) : 'N/A', inline: true },
        ],
        footer: { text: `Elo: ${a.favElo} vs ${a.dogElo} | ${a.tournament}` },
        timestamp: new Date().toISOString(),
      };

      await broadcastAlert(msgHtml, discordEmbed);
      _tnAlertMark(`elo:${a.matchId}`);
    }

    console.log(`  [TennisEloAlert] ${alerts.length} alerte(s) envoyée(s)`);
    // Nettoyage périodique du cooldown (>1000 entrées)
    if (_tennisAlertSent.size > 1000) {
      const cutoff = Date.now() - _TENNIS_ALERT_TTL_MS * 2;
      for (const [k, v] of _tennisAlertSent) { if (v < cutoff) _tennisAlertSent.delete(k); }
    }
  } catch (e) {
    console.warn('  [TennisEloAlert]', e.message);
  }
}

// ─── /api/v1/arbitrage — scanner de surebets multi-bookmakers ───────────────
function computeArbitrage() {
  const results = [];
  for (const m of db.matches) {
    if (!m.odds?.home || !m.odds?.away) continue;
    const h = m.odds.home, d = m.odds.draw, a = m.odds.away;
    const invSum = (1 / h) + (d ? 1 / d : 0) + (1 / a);
    const margin = parseFloat(((1 - invSum) * 100).toFixed(2));

    // Mises optimales pour 100€ investis au total (méthode Kelly-Arbitrage)
    const stakeH = parseFloat((100 / (h * invSum)).toFixed(2));
    const stakeD = d ? parseFloat((100 / (d * invSum)).toFixed(2)) : 0;
    const stakeA = parseFloat((100 / (a * invSum)).toFixed(2));

    results.push({
      id: m.id,
      home_team: m.home_team,
      away_team: m.away_team,
      league: m.league,
      commence_time: m.commence_time,
      odds: m.odds,
      bookmakers: m.bookmakers,
      margin,
      stakes_for_100: { home: stakeH, draw: stakeD, away: stakeA },
      is_surebet: margin > 0,
      guaranteed_profit: margin > 0 ? parseFloat((margin).toFixed(2)) : 0,
    });
  }
  return results.sort((a, b) => b.margin - a.margin).slice(0, 10);
}

// ─── /api/v1/top-matches — Top 10 matchs du jour / semaine ──────────────────
function computeTopPick(m) {
  const p = m.poisson || {};
  const candidates = [
    { key: 'over25', label: 'Over 2.5', val: p.over25 || 0 },
    { key: 'btts', label: 'BTTS', val: p.btts || 0 },
    { key: 'over15', label: 'Over 1.5', val: p.over15 || 0 },
    { key: 'homeWin', label: 'Victoire Dom.', val: p.homeWin || 0 },
    { key: 'awayWin', label: 'Victoire Ext.', val: p.awayWin || 0 },
    { key: 'over35', label: 'Over 3.5', val: p.over35 || 0 },
    { key: 'under15', label: 'Under 1.5', val: p.under15 || 0 },
    { key: 'cs00', label: 'CS Domicile', val: p.cs00 || 0 },
  ];
  return candidates.reduce((best, c) => c.val > best.val ? c : best, { val: 0, label: '—', key: '' });
}
function matchEngagementScore(m) {
  const pick = computeTopPick(m);
  const edge = Math.max(0, m.best_edge?.edge || 0);
  return pick.val + edge * 0.5;
}
function getTopMatchesByTimeframe(timeframe, limit) {
  const now = Date.now();
  let matches = db.matches.filter(m => new Date(m.commence_time).getTime() > now);
  if (timeframe === 'today') {
    const todayEnd = new Date(); todayEnd.setHours(23, 59, 59, 999);
    matches = matches.filter(m => new Date(m.commence_time) <= todayEnd);
  } else {
    const weekEnd = new Date(now + 7 * 24 * 3600000);
    matches = matches.filter(m => new Date(m.commence_time) <= weekEnd);
  }
  return matches
    .map(m => ({ ...m, topPick: computeTopPick(m), _score: matchEngagementScore(m) }))
    .sort((a, b) => b._score - a._score)
    .slice(0, limit)
    .map(m => { delete m._score; return m; });
}

// ─── /api/v1/league-hub/:oddsKey — Standings + Top scorer pour hub ligue ─────
function getLeagueHub(oddsKey) {
  const leagueCfg = leaguesConfig.leagues.find(l => l.odds_key === oddsKey);
  if (!leagueCfg) return null;
  const lid = leagueCfg.id;
  // Récupérer toutes les équipes de cette ligue, triées par rank
  const teams = Object.entries(db.teamStats)
    .filter(([, v]) => v.leagueId === lid && v._real)
    .map(([name, v]) => ({
      name, rank: v.rank, ppg: v.home?.ppg ?? 0, form: v.form || '',
      wins: v.home?.wins ?? 0, draws: v.home?.draws ?? 0, losses: v.home?.losses ?? 0,
      scored: v.home?.scored ?? 0
    }))
    .sort((a, b) => a.rank - b.rank)
    .slice(0, 8);
  // Top scorer de la ligue
  const scorerKey = `${lid}_${currentSeason()}`;
  const scorersData = db.topScorers[scorerKey];
  const topScorer = scorersData?.data?.[0] || null;
  return {
    leagueId: lid,
    leagueName: leagueCfg.name,
    oddsKey,
    teams,
    topScorer: topScorer ? {
      name: topScorer.player?.name || '?',
      team: topScorer.statistics?.[0]?.team?.name || '?',
      goals: topScorer.statistics?.[0]?.goals?.total || 0,
      photo: topScorer.player?.photo || null,
    } : null,
  };
}

// ─── /api/v1/top-strategy — Top matchs par stratégie ────────────────────────
// Config centralisée : ajouter une stratégie = 1 entrée ici (zéro autre changement)
// ── Intégration modèles ML dans le scoring stratégies (bd he1t) ─────────────
// Résout la MEILLEURE probabilité modèle (%) disponible pour un marché donné,
// avec repli gracieux sur Poisson. Priorité par type de marché :
//   1X2         → CatBoost blend (blended_cb) > bayésien calibré > Poisson
//   over25/btts → CatBoost blend > Dixon-Coles > Poisson
//   totals/CS   → Dixon-Coles (correction faibles scores) > Poisson
// Toutes les sorties sont sur la même échelle (% 0-100). Jamais throw.
function bestModelProb(m, market) {
  if (!m) return null;
  const cb = m.blended_cb, dc = m.dixonColes, ca = m.calibrated, po = m.poisson || {};
  switch (market) {
    case 'homeWin': case 'draw': case 'awayWin':
      if (cb && cb[market] != null) return cb[market];
      if (ca && ca[market] != null) return ca[market];
      return po[market] != null ? po[market] : null;
    case 'over25': case 'btts':
      if (cb && cb[market] != null) return cb[market];
      if (dc && dc[market] != null) return dc[market];
      return po[market] != null ? po[market] : null;
    case 'over05': case 'over15': case 'over35': case 'under15': case 'cs00':
      if (dc && dc[market] != null) return dc[market];
      return po[market] != null ? po[market] : null;
    default:
      return po[market] != null ? po[market] : null;
  }
}
// Source modèle utilisée pour un marché (transparence UI + tag backtest).
function modelSourceFor(m, market) {
  if (!m) return 'poisson';
  const cb = m.blended_cb, dc = m.dixonColes, ca = m.calibrated;
  switch (market) {
    case 'homeWin': case 'draw': case 'awayWin':
      if (cb && cb[market] != null) return 'ml-catboost';
      if (ca && ca[market] != null) return 'calibrated';
      return 'poisson';
    case 'over25': case 'btts':
      if (cb && cb[market] != null) return 'ml-catboost';
      if (dc && dc[market] != null) return 'dixon-coles';
      return 'poisson';
    case 'over05': case 'over15': case 'over35': case 'under15': case 'cs00':
      if (dc && dc[market] != null) return 'dixon-coles';
      return 'poisson';
    default: return 'poisson';
  }
}
// Marché primaire par stratégie → résolution model_source dans les picks.
const STRAT_MARKET = {
  BTTS_YES: 'btts', OVER_2_5: 'over25', OVER_1_5: 'over15', UNDER_2_5: 'over25',
  HOME_WIN: 'homeWin', AWAY_WIN: 'awayWin', DRAW: 'draw', CS_00: 'cs00',
  VERROU_TACTIQUE: 'over35', DC_HOME: 'homeWin', DC_AWAY: 'awayWin',
  HT_HOME_FT_HOME: 'homeWin', HT_UNDER_FT_OVER: 'over25', GOLDEN_PPG_GAP: 'homeWin',
};

