const TENNIS_LIVE_TTL_MS = 30 * 1000;
const TENNIS_ESPN_ENDPOINTS = [
  { tour: 'ATP', url: 'https://site.api.espn.com/apis/site/v2/sports/tennis/atp/scoreboard' },
  { tour: 'WTA', url: 'https://site.api.espn.com/apis/site/v2/sports/tennis/wta/scoreboard' }
];
let _tennisLiveCache = { ts: 0, data: [] };
let _isFetchingTennis = false;

function _tennisStateLabel(state, detail, period) {
  const s = String(state || '').toLowerCase();
  if (s === 'pre') return 'À VENIR';
  if (s === 'post') return 'TERMINÉ';
  if (s === 'in') {
    if (period > 0) return `SET ${period}`;
    return 'EN COURS';
  }
  return String(detail || state || '').toUpperCase() || 'INCONNU';
}

// Détermine le circuit (ATP / WTA / MIXED / autre) en croisant la grouping ESPN
// (mens-singles / womens-doubles / mixed-doubles) avec l'endpoint d'origine.
// La grouping est source de vérité — l'endpoint n'est qu'un fallback puisque le
// scoreboard ATP renvoie aussi les tableaux WTA lors des tournois combinés.
function _resolveTennisTour(grouping, endpointTour) {
  const slug = String(grouping?.slug || '').toLowerCase();
  const label = String(grouping?.displayName || '').toLowerCase();
  const text = `${slug} ${label}`;
  if (/mixed/.test(text)) return 'MIXED';
  if (/women|ladies|female|\bwta\b|wom-/.test(text)) return 'WTA';
  if (/\bmen\b|mens|male|gentlemen|\batp\b/.test(text)) return 'ATP';
  // Fallback : origine de l'endpoint (rare — slugs ESPN couvrent tous les cas connus)
  return endpointTour || 'ATP';
}

function _normalizeESPNTennisCompetition(comp, tour, tournamentName, groupingMeta) {
  if (!comp || !Array.isArray(comp.competitors) || comp.competitors.length < 2) return null;
  const status = comp.status || {};
  const stype = status.type || {};
  const state = stype.state;
  // Trie homeAway: 'home' = player1, 'away' = player2 (fallback : order)
  const p1Raw = comp.competitors.find(c => c.homeAway === 'home') || comp.competitors[0];
  const p2Raw = comp.competitors.find(c => c.homeAway === 'away') || comp.competitors[1];
  const ls1 = Array.isArray(p1Raw.linescores) ? p1Raw.linescores : [];
  const ls2 = Array.isArray(p2Raw.linescores) ? p2Raw.linescores : [];
  const maxSets = Math.max(ls1.length, ls2.length);
  const sets = [];
  for (let i = 0; i < maxSets; i++) {
    sets.push({
      p1: Number(ls1[i]?.value ?? 0),
      p2: Number(ls2[i]?.value ?? 0)
    });
  }
  const player1_sets = sets.filter(s => s.p1 > s.p2).length;
  const player2_sets = sets.filter(s => s.p2 > s.p1).length;
  return {
    id: String(comp.id || comp.uid || ''),
    tour,
    discipline: groupingMeta?.displayName || groupingMeta?.slug || '',
    tournament: tournamentName || '',
    court: comp.venue?.court || '',
    surface: comp.venue?.fullName || '',
    status: _tennisStateLabel(state, stype.detail, status.period),
    is_live: state === 'in',
    player1: {
      name: p1Raw.athlete?.displayName || p1Raw.athlete?.shortName || '?',
      country: p1Raw.athlete?.flag?.alt || '',
      flag: p1Raw.athlete?.flag?.href || null
    },
    player2: {
      name: p2Raw.athlete?.displayName || p2Raw.athlete?.shortName || '?',
      country: p2Raw.athlete?.flag?.alt || '',
      flag: p2Raw.athlete?.flag?.href || null
    },
    player1_sets,
    player2_sets,
    sets,
    current_set_index: sets.length > 0 ? sets.length - 1 : 0,
    current_point: null, // ESPN public scoreboard ne livre pas le point en cours
    serving: null,
    notes: Array.isArray(comp.notes) && comp.notes.length ? String(comp.notes[0].text || '') : '',
    start_time: comp.startDate || comp.date || null,
    last_update_ts: Date.now(),
    _espn_competition_id: String(comp.id || '')
  };
}

// Parse une réponse scoreboard ESPN tennis dans byId (muté). Factorisé : réutilisé
// par le poll live (sans date) ET le fetch schedule (par date). Dédup par
// competition id — un match en tournoi mixte apparaît sur les 2 scoreboards.
function _ingestESPNTennisEvents(resData, epTour, byId) {
  const events = Array.isArray(resData && resData.events) ? resData.events : [];
  for (const ev of events) {
    const tournamentName = ev.name || ev.shortName || '';
    const groupings = Array.isArray(ev.groupings) ? ev.groupings : [];
    for (const g of groupings) {
      const resolvedTour = _resolveTennisTour(g.grouping, epTour);
      const comps = Array.isArray(g.competitions) ? g.competitions : [];
      for (const c of comps) {
        const norm = _normalizeESPNTennisCompetition(c, resolvedTour, tournamentName, g.grouping);
        if (!norm) continue;
        if (!norm.id) { byId.set(`${tournamentName}-${norm.player1.name}-${norm.player2.name}`, norm); continue; }
        // Garde la 1re entrée (grouping résoud déjà le bon tour ; doublon WTA identique).
        if (!byId.has(norm.id)) byId.set(norm.id, norm);
      }
    }
  }
}

async function fetchESPNTennisLive() {
  const byId = new Map();
  for (const ep of TENNIS_ESPN_ENDPOINTS) {
    try {
      const res = await httpsGet(ep.url);
      if (res.status !== 200 || !res.data) continue;
      _ingestESPNTennisEvents(res.data, ep.tour, byId);
    } catch (e) {
      console.warn(`  [Tennis] ESPN ${ep.tour} fetch failed: ${e.message}`);
    }
  }
  return Array.from(byId.values());
}

// ── Option C : schedule ESPN par date (J → J+N). Gratuit, zéro quota. Fait
// remonter les matchs PROGRAMMÉS (state=pre) que le scoreboard live n'expose
// pas. Source de matchs tennis quand BSD off + Odds API quota épuisé.
const TENNIS_SCHEDULE_TTL_MS = 15 * 60 * 1000;
const TENNIS_SCHEDULE_DAYS = 3;
let _tennisScheduleCache = { ts: 0, data: [] };

function _tennisYmd(d) {
  return d.getUTCFullYear() * 1e4 + (d.getUTCMonth() + 1) * 100 + d.getUTCDate();
}

async function fetchESPNTennisSchedule(days = TENNIS_SCHEDULE_DAYS) {
  const byId = new Map();
  const now = new Date();
  for (let i = 0; i < days; i++) {
    const d = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + i));
    const ymd = _tennisYmd(d);
    for (const ep of TENNIS_ESPN_ENDPOINTS) {
      try {
        const res = await httpsGet(`${ep.url}?dates=${ymd}`);
        if (res.status !== 200 || !res.data) continue;
        _ingestESPNTennisEvents(res.data, ep.tour, byId);
      } catch (e) {
        console.warn(`  [Tennis] ESPN schedule ${ep.tour} ${ymd} failed: ${e.message}`);
      }
    }
  }
  return Array.from(byId.values());
}

async function getTennisScheduleCached() {
  if (Date.now() - _tennisScheduleCache.ts < TENNIS_SCHEDULE_TTL_MS && _tennisScheduleCache.data.length) {
    return _tennisScheduleCache.data;
  }
  try {
    const data = await fetchESPNTennisSchedule();
    if (data.length) _tennisScheduleCache = { ts: Date.now(), data };
  } catch (e) {
    console.warn('  [Tennis] schedule fetch error:', e.message);
  }
  return _tennisScheduleCache.data;
}

// ── BSD Tennis (Sports Addon actif) — source PRIMAIRE, ESPN en complément ──────
// Normalise un match BSD tennis vers la forme interne unifiée (= shape ESPN
// consommée par la route /tennis/api/v2/matches/live/ + onglet Tennis).
function _normalizeBSDTennisMatch(m) {
  if (!m || !m.player1 || !m.player2) return null;
  const st = String(m.status || '').toLowerCase();
  const finishedRx = /finish|complete|ended|cancel|walkover|retired|abandon|w_?o|post/;
  const isLive = (/progress|live|playing|in_play|inplay|set/.test(st) && !finishedRx.test(st))
    || (m.current_set != null && !finishedRx.test(st));
  const sets = Array.isArray(m.sets_detail)
    ? m.sets_detail.map(s => ({ p1: s.p1 ?? s.player1 ?? null, p2: s.p2 ?? s.player2 ?? null }))
    : [];
  const tn = m.tournament || {};
  return {
    id: `bsd_t_${m.id}`,
    tour: tn.circuit || '',
    discipline: tn.category || '',
    tournament: tn.name || '',
    court: m.round_name || '',
    status: m.status || '',
    is_live: !!isLive,
    player1: { name: m.player1.name || m.player1.short_name || '?', country: m.player1.country_name || m.player1.country_code || '', flag: null },
    player2: { name: m.player2.name || m.player2.short_name || '?', country: m.player2.country_name || m.player2.country_code || '', flag: null },
    player1_sets: m.player1_sets ?? 0,
    player2_sets: m.player2_sets ?? 0,
    sets,
    current_set_index: m.current_set != null ? Math.max(0, (parseInt(m.current_set, 10) || 1) - 1) : (sets.length ? sets.length - 1 : 0),
    current_point: m.current_point || '',
    serving: (() => {
      // bd patch BSD 29 mai — is_serving_p1 n'est PLUS inversé/absent,
      // la synchro list↔detail est corrigée côté BSD. Valeur fiable prioritaire.
      // Verrouillage: la valeur du flux détaillé (/matches/{id}/) ne touche
      // PAS serving (seul _mergeDetailStats s'applique → champs _bsd_stats).
      // Ce champ est la source unique de vérité pour le service en cours.
      if (m.is_serving_p1 === true) return 1;
      if (m.is_serving_p1 === false) return 2;
      // bd c5i: inference par parite jeux depuis _tennisServeHist si snapshot connu
      try {
        const g1 = (m.player1_games_current || 0) + (Array.isArray(m.sets_detail) ? m.sets_detail.reduce((a, s) => a + (s.p1 || 0), 0) : 0);
        const g2 = (m.player2_games_current || 0) + (Array.isArray(m.sets_detail) ? m.sets_detail.reduce((a, s) => a + (s.p2 || 0), 0) : 0);
        const inferred = inferTennisServingFromHistory(m.id, g1, g2);
        if (inferred === 1 || inferred === 2) return inferred;
      } catch (_) { /* defensive */ }
      return null;
    })(),
    notes: m.round_name || '',
    start_time: m.start_time || m.commence_time || m.match_date || m.scheduled || m.event_date || m.start_date || m.date || null,
    last_update_ts: Date.now(),
    // bd patch BSD 30 mai — cotes directes vainqueur du match (décimal)
    odds_player1: m.odds_player1 != null ? parseFloat(m.odds_player1) : null,
    odds_player2: m.odds_player2 != null ? parseFloat(m.odds_player2) : null,
    _bsd_match_id: m.id,
    _bsd_stats: {
      p1_aces: m.p1_aces ?? null, p2_aces: m.p2_aces ?? null,
      p1_df: m.p1_double_faults ?? null, p2_df: m.p2_double_faults ?? null,
      p1_first_pct: m.p1_first_serve_pct ?? null, p2_first_pct: m.p2_first_serve_pct ?? null,
      // Extended — BSD may expose these depending on match detail level; null if absent
      p1_first_won: m.p1_first_serve_won_pct ?? m.p1_first_serve_points_won_pct ?? null,
      p2_first_won: m.p2_first_serve_won_pct ?? m.p2_first_serve_points_won_pct ?? null,
      p1_bp_saved: m.p1_break_points_saved ?? null, p2_bp_saved: m.p2_break_points_saved ?? null,
      p1_ret_won: m.p1_return_points_won_pct ?? m.p1_return_games_won_pct ?? null,
      p2_ret_won: m.p2_return_points_won_pct ?? m.p2_return_games_won_pct ?? null,
      p1_total_pts: m.p1_total_points_won_pct ?? null, p2_total_pts: m.p2_total_points_won_pct ?? null,
    },
  };
}

// ── BSD Tennis detailed stats enrichment (new fields: first_won, bp_saved, ret_won, total_pts)
const _bsdTennisDetailCache = new Map(); // bsd_match_id → {ts, data}
const BSD_TENNIS_DETAIL_TTL_MS = 60_000; // 60s — aligned with live poll cadence

async function _fetchBSDTennisMatchDetail(bsdMatchId) {
  const cid = String(bsdMatchId);
  const cached = _bsdTennisDetailCache.get(cid);
  if (cached && Date.now() - cached.ts < BSD_TENNIS_DETAIL_TTL_MS) return cached.data;
  const res = await bsdTennisFetch(`/api/v2/matches/${cid}/`, 0);
  if (res && res.status === 200 && res.data) {
    _bsdTennisDetailCache.set(cid, { ts: Date.now(), data: res.data });
    return res.data;
  }
  return null;
}

function _needsDetailEnrich(stats) {
  return stats && (
    stats.p1_first_won === null || stats.p1_bp_saved === null ||
    stats.p1_ret_won  === null || stats.p1_total_pts === null
  );
}

function _mergeDetailStats(match, detail) {
  if (!match._bsd_stats || !detail) return match;
  const s = match._bsd_stats;
  s.p1_first_won = s.p1_first_won ?? detail.p1_first_serve_won_pct ?? detail.p1_first_serve_points_won_pct ?? null;
  s.p2_first_won = s.p2_first_won ?? detail.p2_first_serve_won_pct ?? detail.p2_first_serve_points_won_pct ?? null;
  s.p1_bp_saved  = s.p1_bp_saved  ?? detail.p1_break_points_saved  ?? null;
  s.p2_bp_saved  = s.p2_bp_saved  ?? detail.p2_break_points_saved  ?? null;
  s.p1_ret_won   = s.p1_ret_won   ?? detail.p1_return_points_won_pct ?? null;
  s.p2_ret_won   = s.p2_ret_won   ?? detail.p2_return_points_won_pct ?? null;
  s.p1_total_pts = s.p1_total_pts ?? detail.p1_total_points_won_pct  ?? null;
  s.p2_total_pts = s.p2_total_pts ?? detail.p2_total_points_won_pct  ?? null;
  return match;
}

async function fetchBSDTennisLive() {
  const res = await bsdTennisFetch('/api/v2/matches/live/');
  if (!res || res.status !== 200) return [];
  const arr = Array.isArray(res.data)
    ? res.data
    : (res.data && Array.isArray(res.data.results) ? res.data.results : []);
  const normalized = arr.map(_normalizeBSDTennisMatch).filter(Boolean);
  // bd patch BSD 29 mai — Verrou serving: le détail (/matches/{id}/) enrichit
  // uniquement _bsd_stats, mais par sécurité on préserve le serving original.
  // La valeur `is_serving_p1` du flux list est désormais fiable (bug BSD corrigé).
  const _servingBackup = new Map();
  for (const m of normalized) {
    if (m._bsd_match_id != null && (m.serving === 1 || m.serving === 2)) {
      _servingBackup.set(m._bsd_match_id, m.serving);
    }
  }
  // Enrich live matches with extended stats from BSD detailed endpoint (parallel, non-blocking)
  const results = await Promise.allSettled(
    normalized.map(async (m) => {
      if (!m.is_live || !m._bsd_match_id || !_needsDetailEnrich(m._bsd_stats)) return m;
      try {
        const detail = await Promise.race([
          _fetchBSDTennisMatchDetail(m._bsd_match_id),
          new Promise(r => setTimeout(() => r(null), 3000)),
        ]);
        const enriched = _mergeDetailStats(m, detail);
        // bd patch BSD 29 mai — Restaure le serving original après enrichissement
        // détail (le flux détaillé ne doit jamais écraser is_serving_p1 du flux list).
        const savedSrv = _servingBackup.get(m._bsd_match_id);
        if (savedSrv != null && enriched.serving !== savedSrv) {
          enriched.serving = savedSrv;
        }
        return enriched;
      } catch (_) { return m; }
    })
  );
  return results.map(r => r.status === 'fulfilled' ? r.value : null).filter(Boolean);
}

function _tennisPairKey(m) {
  const a = normName(m && m.player1 && m.player1.name);
  const b = normName(m && m.player2 && m.player2.name);
  return [a, b].sort().join('|');
}
// Fusion : BSD prioritaire (stats/service/point), ESPN ajoute les matchs absents.
function _mergeTennisLive(primary, secondary) {
  const out = primary.slice();
  const seen = new Set(primary.map(_tennisPairKey));
  for (const m of secondary) {
    const k = _tennisPairKey(m);
    if (k && k !== '|' && !seen.has(k)) { seen.add(k); out.push(m); }
  }
  return out;
}

// ── SPRINT 3 — Serve Momentum Live + lean modèle in-play ────────────────────
// Snapshot par poll (30s) : jeux cumulés + qui sert. Dérive les 5 derniers
// jeux (hold/break) + tendance. Aucune dépendance point-par-point fiable →
// on infère break = jeu gagné par le NON-serveur entre 2 snapshots.
const _tennisServeHist = new Map(); // id → [{ts,g1,g2,serving}]
// bd 6xw — Map id → { p1, p2, missing, ts } pour détecter Δ BPPI > 20pts entre 2 polls.
const _tennisBPPIPrev = new Map();
function _tennisGamesFromSets(m) {
  let g1 = 0, g2 = 0;
  for (const s of (Array.isArray(m.sets) ? m.sets : [])) {
    g1 += Number(s.p1) || 0; g2 += Number(s.p2) || 0;
  }
  return { g1, g2 };
}
// bd c5i — Cross-source merge : si BSD/ESPN serving=null, cherche dans aiscoreMatchCache
// par normName des joueurs (déjà chauffé via warmer ou requêtes utilisateur). Mutation
// in-place : copie serving 1|2 dans le match live. Retourne nb d'enrichissements.
function enrichServingFromAiscoreCache(liveData, sourceTag) {
  if (!Array.isArray(liveData) || liveData.length === 0) return 0;
  const _srcTag = sourceTag || 'aiscore_cache';
  // Index aiscore cache par paire de joueurs normalisée
  const aiIdx = new Map();
  try {
    for (const [, entry] of aiscoreMatchCache) {
      const d = entry && entry.data;
      if (!d || !Array.isArray(d.players) || d.players.length !== 2) continue;
      if (d.serving !== 1 && d.serving !== 2) continue;
      const a = normName(d.players[0].name);
      const b = normName(d.players[1].name);
      if (!a || !b) continue;
      const k = [a, b].sort().join('|');
      // Conserve uniquement entrée la plus récente
      const cur = aiIdx.get(k);
      if (!cur || entry.ts > cur.ts) aiIdx.set(k, { ts: entry.ts, players: [a, b], serving: d.serving });
    }
  } catch (_) { return 0; }
  if (aiIdx.size === 0) return 0;

  let enriched = 0;
  for (const m of liveData) {
    if (!m || !m.is_live || m.serving === 1 || m.serving === 2) continue;
    const a = normName(m.player1 && m.player1.name);
    const b = normName(m.player2 && m.player2.name);
    if (!a || !b) continue;
    const k = [a, b].sort().join('|');
    const hit = aiIdx.get(k);
    if (!hit) continue;
    // Réaligne serving aiscore (basé sur ordre [a,b] trié) vers ordre m.player1/player2
    // Si tri inversé l'ordre, swap : aiscore p1 = m.player2 → swap serving
    const aiP1Norm = hit.players[0];
    const mP1Norm = a;
    const aligned = (aiP1Norm === mP1Norm) ? hit.serving : (hit.serving === 1 ? 2 : 1);
    m.serving = aligned;
    m._serving_source = _srcTag;
    enriched++;
  }
  return enriched;
}

// ═══════════════════════════════════════════════════════════════════════════════
// bd zckt — Helper générique `withOnDemandThrottle()` (innovation backlog)
//
// Extrait pattern de `fetchAiscoreServingOnDemand` (bd c5i Phase 3) en helper
// réutilisable pour tout fetcher coûteux sur data gap conditionnel :
//   • Cap N fetches par invocation (throttle global pollwide)
//   • Cooldown M ms par key ratée (anti-retry-storm sur miss prévisible)
//   • State Map réutilisable cross-poll (caller fournit pour persist)
//
// Use cases extensibles (cf CLAUDE.md innovation §3) :
//   - fetchAiscoreLineupsOnDemand (lineups BSD/ESPN missing)
//   - fetchSofascoreEditorialOnDemand (bd 6jro Plan H)
//   - fetchOddsPapiPinnacleOnDemand (anchor sharp ad-hoc)
//
// SIGNATURE :
//   await withOnDemandThrottle({
//     candidates,         // array<item> à processer
//     candidateKey,       // (item) => string (key pour tracking cooldown)
//     resolver,           // async (item) => target|null (lookup léger, ex sitemap index)
//     fetcher,            // async (item, target) => * (fetch coûteux, peut throw)
//     maxPerInvocation,   // default 5
//     cooldownMs,         // default 10 min
//     state,              // Map<key, ts> (fournie par caller, persisted cross-call)
//     name                // string debug-only
//   })
//   → number (fetches réussis)
//
// CONTRAT :
//   • Skip item si state.has(key) && (now - state.get(key)) <= cooldownMs
//   • Marque state.set(key, now) AVANT fetcher() (compte tentative, pas success — anti-retry)
//   • Stoppe loop quand fetched >= maxPerInvocation (cap throttle)
//   • Swallow errors fetcher individuels (cooldown évite spam, suite continue)
// ═══════════════════════════════════════════════════════════════════════════════
async function withOnDemandThrottle({
  candidates,
  candidateKey,
  resolver,
  fetcher,
  maxPerInvocation = 5,
  cooldownMs = 10 * 60 * 1000,
  state,
  name = 'ondemand',
}) {
  if (!Array.isArray(candidates) || candidates.length === 0) return 0;
  if (!state || typeof state.has !== 'function') return 0;
  if (typeof candidateKey !== 'function' || typeof fetcher !== 'function') return 0;

  const now = Date.now();
  const eligible = candidates.filter(item => {
    const k = candidateKey(item);
    if (!k) return false;
    const lastTs = state.get(k);
    return lastTs == null || (now - lastTs) > cooldownMs;
  });
  if (eligible.length === 0) return 0;

  let fetched = 0;
  for (const item of eligible) {
    if (fetched >= maxPerInvocation) break;
    const k = candidateKey(item);
    state.set(k, now);  // marque AVANT fetcher (compte tentative, pas success)
    let target = item;
    if (typeof resolver === 'function') {
      try {
        target = await resolver(item);
        if (target == null) continue;  // resolver ko = skip, mais cooldown déjà set
      } catch (_) {
        continue;  // resolver throw = skip, cooldown set évite retry storm
      }
    }
    try {
      await fetcher(item, target);
      fetched++;
    } catch (_) { /* fetcher swallow — cooldown active évite spam */ }
  }
  return fetched;
}

// bd c5i Phase 3 — On-demand aiscore fetch throttle pour matchs serving=null
// & aiscore cache miss. Resout via sitemap index (player last-name match dans slug).
// Throttle: max 5 fetches par poll + cooldown 10min par matchId raté.
// bd zckt — refactor pour utiliser helper générique withOnDemandThrottle().
const _aiscoreOndemandSeenIds = new Map();
const AISCORE_ONDEMAND_COOLDOWN_MS = 10 * 60 * 1000;
const AISCORE_ONDEMAND_MAX_PER_POLL = 5;
async function fetchAiscoreServingOnDemand(liveData) {
  if (!Array.isArray(liveData) || liveData.length === 0) return 0;
  // Filter pre-resolver : skip matchs déjà résolus (serving set) ou data incomplète.
  const targets = liveData.filter(m =>
    m && m.is_live && m.serving !== 1 && m.serving !== 2
    && m.player1 && m.player1.name && m.player2 && m.player2.name
  );
  if (targets.length === 0) return 0;
  // Resolver utilise un index partagé : on lazy-load une seule fois pour tous les candidats.
  let _idxCache = null;
  const getIdx = async () => {
    if (_idxCache != null) return _idxCache;
    try { _idxCache = await getAiscoreTennisIndex() || { matches: [] }; }
    catch (_) { _idxCache = { matches: [] }; }
    return _idxCache;
  };
  return await withOnDemandThrottle({
    name: 'aiscore_serving',
    candidates: targets,
    candidateKey: (m) => m && m.id != null ? String(m.id) : null,
    resolver: async (m) => {
      const idx = await getIdx();
      if (!idx || !Array.isArray(idx.matches) || idx.matches.length === 0) return null;
      const p1n = normName(m.player1.name);
      const p2n = normName(m.player2.name);
      if (!p1n || !p2n) return null;
      const p1Last = p1n.split(/\s+/).filter(Boolean).pop();
      const p2Last = p2n.split(/\s+/).filter(Boolean).pop();
      if (!p1Last || !p2Last || p1Last.length < 3 || p2Last.length < 3) return null;
      return idx.matches.find(am => {
        const s = String(am.slug || '').toLowerCase();
        return s.includes(p1Last) && s.includes(p2Last);
      }) || null;
    },
    fetcher: async (_m, hit) => {
      await getAiscoreMatch(hit.id, hit.slug);
    },
    maxPerInvocation: AISCORE_ONDEMAND_MAX_PER_POLL,
    cooldownMs: AISCORE_ONDEMAND_COOLDOWN_MS,
    state: _aiscoreOndemandSeenIds,
  });
}

// ═══════════════════════════════════════════════════════════════════════════════
// bd mpg — BD-DATA-010 PBP point-by-point streaming tennis live
// ═══════════════════════════════════════════════════════════════════════════════
// Source: aiscore.com HTML (BSD /api/v2/matches/{id}/ n'expose PAS point_by_point).
// Pattern: reuse `getAiscoreMatch` cache + extends on-demand fetch throttle.
// Diff detection: compare `last_point_idx` poll-over-poll → SSE `pbp_update` broadcast.
// Debounce 30s per matchId (anti-spam SSE). Cache 30s aligné avec aiscore match TTL.
//
// Schema sortie /api/v1/tennis/pbp/:matchId :
//   {
//     match_id: "0xabc123",
//     source: "aiscore",
//     player1, player2,
//     points: [{ idx, set, game, score, server, winner, shot_type, minute }, ...],
//     last_point_idx,
//     counters: { p1_aces, p2_aces, p1_df, p2_df },
//     updated_at
//   }
const _tennisPBPPrev = new Map(); // matchId → { last_point_idx, ts }
const _tennisPBPSSEDebounce = new Map(); // matchId → last broadcast ts
const PBP_SSE_DEBOUNCE_MS = Math.max(5000, parseInt(process.env.PBP_SSE_DEBOUNCE_MS || '30000', 10));

// Convertit aiscore.point_by_point (groupé par set/jeu) en flat points[] avec idx croissant.
function _normalizePBPFromAiscore(am) {
  if (!am || !Array.isArray(am.point_by_point)) {
    return { points: [], last_point_idx: -1, counters: { p1_aces: 0, p2_aces: 0, p1_df: 0, p2_df: 0 } };
  }
  const points = [];
  let idx = 0;
  for (let si = 0; si < am.point_by_point.length; si++) {
    const setBox = am.point_by_point[si];
    const setNum = si + 1;
    const games = Array.isArray(setBox.game_score) ? setBox.game_score : [];
    const pointsArr = Array.isArray(setBox.points) ? setBox.points : [];
    for (let gi = 0; gi < pointsArr.length; gi++) {
      const gamePts = Array.isArray(pointsArr[gi]) ? pointsArr[gi] : [];
      const gameMeta = games[gi] || {};
      const gameWinner = gameMeta.winner ? 1 : 2; // approx : colorGreen sur ligne p1
      const server = (gi % 2 === 0) ? 1 : 2; // server alterne chaque jeu
      for (let pi = 0; pi < gamePts.length; pi++) {
        const sc = gamePts[pi];
        const isLast = pi === gamePts.length - 1;
        points.push({
          idx: idx++,
          set: setNum,
          game: gi + 1,
          score: String(sc || ''),
          server,
          winner: isLast ? gameWinner : null,
          shot_type: null,
          minute: null,
        });
      }
    }
  }
  const counters = { p1_aces: 0, p2_aces: 0, p1_df: 0, p2_df: 0 };
  if (am.stats && typeof am.stats === 'object') {
    const acesEntry = am.stats['Aces'] || am.stats['aces'] || null;
    const dfEntry = am.stats['Double Faults'] || am.stats['Double faults'] || am.stats['double_faults'] || null;
    if (acesEntry) {
      counters.p1_aces = parseInt(acesEntry.p1, 10) || 0;
      counters.p2_aces = parseInt(acesEntry.p2, 10) || 0;
    }
    if (dfEntry) {
      counters.p1_df = parseInt(dfEntry.p1, 10) || 0;
      counters.p2_df = parseInt(dfEntry.p2, 10) || 0;
    }
  }
  return { points, last_point_idx: idx - 1, counters };
}

// Résout matchId interne (bsd_t_<id> / espn / aiscore) → aiscore match (cache + index).
async function _resolveAiscoreMatchForPBP(matchId, liveData) {
  if (!matchId) return null;
  const mid = String(matchId);
  const directCached = aiscoreMatchCache.get(mid);
  if (directCached && directCached.data) return directCached.data;
  if (/^[0-9a-z]+$/.test(mid) && mid.length <= 24) {
    try { return await getAiscoreMatch(mid); } catch (_) { /* fallback */ }
  }
  const m = Array.isArray(liveData) ? liveData.find(x => x && String(x.id) === mid) : null;
  if (!m || !m.player1 || !m.player2) return null;
  const p1n = normName(m.player1.name);
  const p2n = normName(m.player2.name);
  if (!p1n || !p2n) return null;
  const p1Last = p1n.split(/\s+/).filter(Boolean).pop();
  const p2Last = p2n.split(/\s+/).filter(Boolean).pop();
  if (!p1Last || !p2Last || p1Last.length < 3 || p2Last.length < 3) return null;
  for (const [, entry] of aiscoreMatchCache) {
    const d = entry && entry.data;
    if (!d || !Array.isArray(d.players) || d.players.length < 2) continue;
    const an = normName(d.players[0].name);
    const bn = normName(d.players[1].name);
    if ((an.includes(p1Last) && bn.includes(p2Last)) || (an.includes(p2Last) && bn.includes(p1Last))) {
      return d;
    }
  }
  try {
    const idx = await getAiscoreTennisIndex();
    const hit = idx && Array.isArray(idx.matches) ? idx.matches.find(am => {
      const s = String(am.slug || '').toLowerCase();
      return s.includes(p1Last) && s.includes(p2Last);
    }) : null;
    if (!hit) return null;
    return await getAiscoreMatch(hit.id, hit.slug);
  } catch (_) { return null; }
}

// bd mpg Phase 2 — On-demand fetch aiscore PBP pour matchs live sans cache.
// Refactor pattern : utilise helper générique withOnDemandThrottle (bd zckt).
// Coverage step-up : sans cette fonction, detectAndBroadcastPBPUpdates skip
// silencieusement les matchs sans aiscore cache préchargé via serving fetch.
const _pbpOndemandSeenIds = new Map();
const PBP_ONDEMAND_COOLDOWN_MS = 10 * 60 * 1000;
const PBP_ONDEMAND_MAX_PER_POLL = 3;  // Plus conservateur que serving (5) — PBP HTML payload plus lourd
async function fetchAiscorePBPOnDemand(liveData) {
  if (!Array.isArray(liveData) || liveData.length === 0) return 0;
  // Filter pre-resolver : live matchs sans aiscore cache + data joueurs complète
  const targets = liveData.filter(m => {
    if (!m || !m.is_live) return false;
    if (!m.player1 || !m.player1.name || !m.player2 || !m.player2.name) return false;
    // Skip si déjà en cache aiscore (PBP sera capté par detectAndBroadcastPBPUpdates)
    for (const [, entry] of aiscoreMatchCache) {
      const d = entry && entry.data;
      if (!d || !Array.isArray(d.players) || d.players.length < 2) continue;
      const an = normName(d.players[0].name);
      const bn = normName(d.players[1].name);
      const p1n = normName(m.player1.name);
      const p2n = normName(m.player2.name);
      const p1Last = p1n.split(/\s+/).filter(Boolean).pop();
      const p2Last = p2n.split(/\s+/).filter(Boolean).pop();
      if (p1Last && p2Last && ((an.includes(p1Last) && bn.includes(p2Last)) || (an.includes(p2Last) && bn.includes(p1Last)))) {
        return false;  // déjà cache
      }
    }
    return true;
  });
  if (targets.length === 0) return 0;
  // Lazy single-fetch sitemap index (réutilisé entre candidats)
  let _idxCache = null;
  const getIdx = async () => {
    if (_idxCache != null) return _idxCache;
    try { _idxCache = await getAiscoreTennisIndex() || { matches: [] }; }
    catch (_) { _idxCache = { matches: [] }; }
    return _idxCache;
  };
  return await withOnDemandThrottle({
    name: 'aiscore_pbp',
    candidates: targets,
    candidateKey: (m) => m && m.id != null ? String(m.id) : null,
    resolver: async (m) => {
      const idx = await getIdx();
      if (!idx || !Array.isArray(idx.matches) || idx.matches.length === 0) return null;
      const p1n = normName(m.player1.name);
      const p2n = normName(m.player2.name);
      if (!p1n || !p2n) return null;
      const p1Last = p1n.split(/\s+/).filter(Boolean).pop();
      const p2Last = p2n.split(/\s+/).filter(Boolean).pop();
      if (!p1Last || !p2Last || p1Last.length < 3 || p2Last.length < 3) return null;
      return idx.matches.find(am => {
        const s = String(am.slug || '').toLowerCase();
        return s.includes(p1Last) && s.includes(p2Last);
      }) || null;
    },
    fetcher: async (_m, hit) => {
      await getAiscoreMatch(hit.id, hit.slug);  // populate cache → next poll detectAndBroadcast triggers PBP SSE
    },
    maxPerInvocation: PBP_ONDEMAND_MAX_PER_POLL,
    cooldownMs: PBP_ONDEMAND_COOLDOWN_MS,
    state: _pbpOndemandSeenIds,
  });
}

// Helper public : récupère PBP normalisé pour un matchId (lazy fetch + cache aiscore).
async function fetchTennisPBP(matchId) {
  const liveData = _tennisLiveCache && Array.isArray(_tennisLiveCache.data) ? _tennisLiveCache.data : [];
  const am = await _resolveAiscoreMatchForPBP(matchId, liveData);
  if (!am) return null;
  const norm = _normalizePBPFromAiscore(am);
  return {
    match_id: String(matchId),
    source: 'aiscore',
    source_url: am.source_url || null,
    player1: (am.players && am.players[0]) ? { name: am.players[0].name, country: am.players[0].country } : null,
    player2: (am.players && am.players[1]) ? { name: am.players[1].name, country: am.players[1].country } : null,
    tournament: am.tournament || null,
    status: am.status || null,
    points: norm.points,
    last_point_idx: norm.last_point_idx,
    counters: norm.counters,
    updated_at: am.fetched_at || new Date().toISOString(),
  };
}

// Diff detection par poll : compare last_point_idx avec _tennisPBPPrev → SSE broadcast.
function detectAndBroadcastPBPUpdates(liveData) {
  if (!Array.isArray(liveData) || liveData.length === 0) return 0;
  const now = Date.now();
  let broadcasts = 0;
  for (const m of liveData) {
    if (!m || !m.is_live) continue;
    const p1n = m.player1 && normName(m.player1.name);
    const p2n = m.player2 && normName(m.player2.name);
    if (!p1n || !p2n) continue;
    const p1Last = p1n.split(/\s+/).filter(Boolean).pop();
    const p2Last = p2n.split(/\s+/).filter(Boolean).pop();
    if (!p1Last || !p2Last) continue;
    let am = null;
    for (const [, entry] of aiscoreMatchCache) {
      const d = entry && entry.data;
      if (!d || !Array.isArray(d.players) || d.players.length < 2) continue;
      const an = normName(d.players[0].name);
      const bn = normName(d.players[1].name);
      if ((an.includes(p1Last) && bn.includes(p2Last)) || (an.includes(p2Last) && bn.includes(p1Last))) {
        am = d; break;
      }
    }
    if (!am) continue;
    const norm = _normalizePBPFromAiscore(am);
    const prev = _tennisPBPPrev.get(m.id) || null;
    const lastIdx = norm.last_point_idx;
    if (prev && prev.last_point_idx === lastIdx) continue;
    _tennisPBPPrev.set(m.id, { last_point_idx: lastIdx, ts: now });
    const lastBroadcast = _tennisPBPSSEDebounce.get(m.id) || 0;
    if (now - lastBroadcast < PBP_SSE_DEBOUNCE_MS) continue;
    _tennisPBPSSEDebounce.set(m.id, now);
    try {
      const newPointsCount = prev ? Math.max(0, lastIdx - prev.last_point_idx) : Math.min(5, norm.points.length);
      const newPoints = norm.points.slice(-newPointsCount);
      broadcastSSE('pbp_update', {
        match_id: m.id,
        source: 'aiscore',
        last_point_idx: lastIdx,
        new_points: newPoints,
        counters: norm.counters,
        ts: now,
      });
      broadcasts++;
    } catch (_) { /* SSE non bloquant */ }
  }
  const liveIds = new Set(liveData.filter(mm => mm && mm.is_live).map(mm => mm.id));
  for (const k of _tennisPBPPrev.keys()) if (!liveIds.has(k)) _tennisPBPPrev.delete(k);
  for (const k of _tennisPBPSSEDebounce.keys()) if (!liveIds.has(k)) _tennisPBPSSEDebounce.delete(k);
  return broadcasts;
}

// bd c5i — Inference serveur par parite des jeux quand source omet l'info.
// Tennis: serveur alterne CHAQUE jeu. Si on a connu serveur a un snapshot
// passe, on derive current serveur depuis (totalGames_now - totalGames_then)
// parite. Retourne null si pas d'info historique.
function inferTennisServingFromHistory(matchId, currentG1, currentG2) {
  if (!matchId) return null;
  const hist = _tennisServeHist.get(matchId) || [];
  // Cherche le snapshot le plus recent avec serving connu
  let lastKnown = null;
  for (let i = hist.length - 1; i >= 0; i--) {
    if (hist[i].serving === 1 || hist[i].serving === 2) { lastKnown = hist[i]; break; }
  }
  if (!lastKnown) return null;
  const totalThen = (lastKnown.g1 || 0) + (lastKnown.g2 || 0);
  const totalNow = (currentG1 || 0) + (currentG2 || 0);
  const elapsed = totalNow - totalThen;
  if (elapsed < 0 || elapsed > 30) return null; // sanity: 30 jeux d'ecart = nouveau set, defiance
  // Pair = meme serveur, impair = oppose
  return (elapsed % 2 === 0) ? lastKnown.serving : (lastKnown.serving === 1 ? 2 : 1);
}

function recordTennisServe(m) {
  if (!m || !m.id || !m.is_live) return null;
  const { g1, g2 } = _tennisGamesFromSets(m);
  const serving = m.serving === 1 ? 1 : m.serving === 2 ? 2 : null;
  let hist = _tennisServeHist.get(m.id) || [];
  const last = hist[hist.length - 1];
  if (!last || last.g1 !== g1 || last.g2 !== g2 || last.serving !== serving) {
    hist.push({ ts: Date.now(), g1, g2, serving });
    if (hist.length > 14) hist = hist.slice(-14);
    _tennisServeHist.set(m.id, hist);
  }
  // Dérive jeux récents : qui a pris chaque jeu + break si non-serveur gagne.
  const games = [];
  for (let i = 1; i < hist.length; i++) {
    const a = hist[i - 1], b = hist[i];
    const d1 = b.g1 - a.g1, d2 = b.g2 - a.g2;
    if (d1 + d2 !== 1) continue; // saute si >1 jeu entre snapshots (poll lent)
    const winner = d1 === 1 ? 1 : 2;
    const srv = a.serving;
    const isBreak = srv != null && winner !== srv;
    games.push({ w: winner, brk: isBreak });
  }
  const recent = games.slice(-5);
  const breaks = recent.filter(g => g.brk).length;
  let streakW = 0, streakP = null;
  for (let i = recent.length - 1; i >= 0; i--) {
    if (streakP == null) { streakP = recent[i].w; streakW = 1; }
    else if (recent[i].w === streakP) streakW++;
    else break;
  }
  const trend = streakW >= 3 ? (streakP === 1 ? 'p1' : 'p2') : 'even';
  return { games: recent, breaks_recent: breaks, run: { player: streakP, len: streakW }, trend, snapshots: hist.length };
}

// ── bd 6xw — BREAK POINT PRESSURE INDEX (BPPI) ──────────────────────────────
// Indicateur quant tennis live 0-100 par joueur mesurant pression sur set/match.
// Composantes (pondérations) :
//   30% clutch_score   = % holds défensifs (1 - break rate quand on sert)
//   30% offense_score  = % conversion offensive (breaks réalisés / opps retour)
//   20% serve_pressure = % 1ère balle in (proxy pression sous service)
//   20% momentum_5     = forme courte (run + breaks récents pondérés)
// × context_weight     = 1.0 (régulier) à 1.30 (balle de match / égalité dans set décisif)
//
// Sources live exposées par BSD/ESPN :
//   - m.serve_momentum.games[] (qui sert / qui gagne / break flag) → drive clutch + offense + momentum
//   - m._bsd_stats.p1_first_pct / p2_first_pct → serve_pressure direct
//   - m.sets, m.player1_sets/player2_sets, m.current_point ("AD", "40-40") → context
//
// Fallback gracieux : missing=true + valeurs 50 neutres si match non-live ou data absente.
// Performance : O(1) par match (boucles bornées à 5 jeux récents). Pas d'I/O.
function computeBPPI(m) {
  const out = {
    p1: 50, p2: 50,
    components: {
      p1: { clutch: 50, offense: 50, serve: 50, momentum: 50 },
      p2: { clutch: 50, offense: 50, serve: 50, momentum: 50 },
    },
    context_weight: 1.0,
    context_flags: [],
    missing: false,
  };
  if (!m || !m.is_live) { out.missing = true; return out; }
  const _clampPct = v => {
    const n = Number(v);
    if (!Number.isFinite(n)) return 50;
    if (n < 0) return 0;
    if (n > 100) return 100;
    return n;
  };

  const sm = m.serve_momentum || null;
  const games = (sm && Array.isArray(sm.games)) ? sm.games : [];
  // games[i] = { w: 1|2, brk: bool } — provient de recordTennisServe (5 jeux récents dérivés
  // des snapshots à partir de l'historique des polls 30s).
  // brk=true ⇒ winner = returner (non-serveur). brk=false ⇒ winner = serveur (hold).

  // Compte holds/breaks par joueur (proxy clutch + offense conversion).
  let p1Served = 0, p1Holds = 0;
  let p2Served = 0, p2Holds = 0;
  let p1BreakOpp = 0, p1Breaks = 0;
  let p2BreakOpp = 0, p2Breaks = 0;
  for (const g of games) {
    if (!g || (g.w !== 1 && g.w !== 2)) continue;
    if (g.brk) {
      // Returner gagne : winner = returner, serveur = opposé.
      const returner = g.w;
      const server = returner === 1 ? 2 : 1;
      if (server === 1) { p1Served++; p2BreakOpp++; p2Breaks++; }
      else              { p2Served++; p1BreakOpp++; p1Breaks++; }
    } else {
      // Hold : winner = serveur.
      const server = g.w;
      if (server === 1) { p1Served++; p1Holds++; p2BreakOpp++; /* opportunity, no conversion */ }
      else              { p2Served++; p2Holds++; p1BreakOpp++; }
    }
  }
  // Clutch défensif : % de holds quand on sert. Si 0 service observé → fallback 50.
  const clutch_p1 = p1Served > 0 ? (p1Holds / p1Served) * 100 : 50;
  const clutch_p2 = p2Served > 0 ? (p2Holds / p2Served) * 100 : 50;
  // Offense conversion : breaks réalisés / opportunités (jeux où l'adversaire sert).
  const offense_p1 = p1BreakOpp > 0 ? (p1Breaks / p1BreakOpp) * 100 : 50;
  const offense_p2 = p2BreakOpp > 0 ? (p2Breaks / p2BreakOpp) * 100 : 50;

  // Serve pressure proxy : % 1ères balles in (BSD expose p1_first_serve_pct).
  const bsdStats = m._bsd_stats || {};
  const serve_p1 = _clampPct(bsdStats.p1_first_pct != null ? bsdStats.p1_first_pct : 50);
  const serve_p2 = _clampPct(bsdStats.p2_first_pct != null ? bsdStats.p2_first_pct : 50);

  // Momentum 5 jeux : combine run (streak en cours) + ratio jeux gagnés sur 5.
  let p1Won5 = 0, p2Won5 = 0;
  for (const g of games) {
    if (g && g.w === 1) p1Won5++;
    else if (g && g.w === 2) p2Won5++;
  }
  const total5 = Math.max(1, games.length);
  let momentum_p1 = (p1Won5 / total5) * 100;
  let momentum_p2 = (p2Won5 / total5) * 100;
  // Bonus run : streak 3+ → +10pts, streak 4+ → +15pts (cappé à 100).
  if (sm && sm.run && sm.run.len >= 3) {
    const bonus = sm.run.len >= 4 ? 15 : 10;
    if (sm.run.player === 1) momentum_p1 = Math.min(100, momentum_p1 + bonus);
    else if (sm.run.player === 2) momentum_p2 = Math.min(100, momentum_p2 + bonus);
  }
  // Si pas de games observés (snapshot 0/1) → fallback neutre 50 plutôt que 0.
  if (games.length === 0) { momentum_p1 = 50; momentum_p2 = 50; }

  // Context weight : importance jeu courant. Heuristique conservatrice.
  let ctxW = 1.0;
  const ctxFlags = [];
  const cp = String(m.current_point || '').toUpperCase().trim();
  if (cp === 'AD' || cp === '40-40' || cp === 'DEUCE' || cp === 'A' || cp === 'A-40' || cp === '40-A') {
    ctxW += 0.10; ctxFlags.push('deuce');
  }
  const sets = Array.isArray(m.sets) ? m.sets : [];
  const lastSet = sets[sets.length - 1] || null;
  const p1Sets = Number(m.player1_sets || 0);
  const p2Sets = Number(m.player2_sets || 0);
  // Set point heuristique : un joueur a 5+ jeux dans set courant ET >=1 jeu d'avance.
  if (lastSet) {
    const g1 = Number(lastSet.p1 || 0);
    const g2 = Number(lastSet.p2 || 0);
    if ((g1 >= 5 && g1 - g2 >= 1) || (g2 >= 5 && g2 - g1 >= 1)) {
      ctxW += 0.10; ctxFlags.push('set_point');
      // Match point heuristique : leader sets à 1 set d'écart sur best-of-3 ou 2 sur best-of-5.
      if ((p1Sets === 1 && p2Sets === 0 && g1 >= 5 && g1 > g2) ||
          (p2Sets === 1 && p1Sets === 0 && g2 >= 5 && g2 > g1) ||
          (p1Sets === 2 && p2Sets <= 1 && g1 >= 5 && g1 > g2) ||
          (p2Sets === 2 && p1Sets <= 1 && g2 >= 5 && g2 > g1)) {
        ctxW += 0.10; ctxFlags.push('match_point');
      }
    }
  }
  // Cap context weight à 1.30 (max +30% pression contextuelle).
  if (ctxW > 1.30) ctxW = 1.30;

  // Combine composantes (pondérations 30/30/20/20) puis applique context weight.
  const base_p1 = 0.30 * clutch_p1 + 0.30 * offense_p1 + 0.20 * serve_p1 + 0.20 * momentum_p1;
  const base_p2 = 0.30 * clutch_p2 + 0.30 * offense_p2 + 0.20 * serve_p2 + 0.20 * momentum_p2;
  const bppi_p1 = Math.round(Math.max(0, Math.min(100, base_p1 * ctxW)));
  const bppi_p2 = Math.round(Math.max(0, Math.min(100, base_p2 * ctxW)));

  // Détecte si on a au moins UN signal informatif (pas tout par défaut 50).
  const hasSignal = games.length > 0
    || bsdStats.p1_first_pct != null
    || bsdStats.p2_first_pct != null
    || ctxFlags.length > 0;

  out.p1 = bppi_p1;
  out.p2 = bppi_p2;
  out.components = {
    p1: {
      clutch: Math.round(clutch_p1),
      offense: Math.round(offense_p1),
      serve: Math.round(serve_p1),
      momentum: Math.round(momentum_p1),
    },
    p2: {
      clutch: Math.round(clutch_p2),
      offense: Math.round(offense_p2),
      serve: Math.round(serve_p2),
      momentum: Math.round(momentum_p2),
    },
  };
  out.context_weight = Math.round(ctxW * 100) / 100;
  out.context_flags = ctxFlags;
  out.missing = !hasSignal;
  return out;
}

// bd c8zp — Archive tennis finished matches detectes dans live cache vers
// tennisHistory (alimente onglet Historique tennis comme foot via archivePastMatches).
// Idempotent: dedup par m.id contre tennisHistory existant + db.archive_matches.
function archiveFinishedTennisFromLiveCache(liveData) {
  if (!Array.isArray(liveData) || !liveData.length) return 0;
  const existingTennisIds = new Set((tennisHistory || []).map(h => String(h.id)));
  const existingArchiveIds = new Set((db.archive_matches || []).map(m => String(m.id)));
  let added = 0;
  for (const m of liveData) {
    if (!m || !m.id) continue;
    const isFinished = m.is_live === false && (
      String(m.status || '').toLowerCase().includes('finish') ||
      String(m.status || '').toLowerCase().includes('end') ||
      String(m.status || '').toLowerCase() === 'ft' ||
      (m.player1_sets != null && m.player2_sets != null && (m.player1_sets >= 2 || m.player2_sets >= 2))
    );
    if (!isFinished) continue;
    const idStr = String(m.id);
    if (existingTennisIds.has(idStr) || existingArchiveIds.has(idStr)) continue;
    // Map live tennis shape → archive shape compat runHistoryQuery
    const sw1 = Number(m.player1_sets ?? 0);
    const sw2 = Number(m.player2_sets ?? 0);
    const winner = sw1 > sw2 ? 'p1' : (sw2 > sw1 ? 'p2' : null);
    const archived = {
      id: m.id,
      sport: 'tennis',
      sport_key: m.tour === 'WTA' ? 'tennis_wta' : (m.tour === 'MIXED' ? 'tennis_mixed' : 'tennis_atp'),
      tour: m.tour || null,
      league: m.tournament || 'Tennis',
      country: 'International',
      surface: m.surface || null,
      round: m.notes || null,
      commence_time: m.start_time || new Date().toISOString(),
      home_team: m.player1?.name || null,
      away_team: m.player2?.name || null,
      p1: m.player1?.name || null,
      p2: m.player2?.name || null,
      player1: m.player1 || null,
      player2: m.player2 || null,
      sets: m.sets || [],
      sets_won_p1: sw1,
      sets_won_p2: sw2,
      winner,
      home_score: sw1,
      away_score: sw2,
      live_score: `${sw1}-${sw2}`,
      status: 'finished',
      verified: true,
      _source: 'cron-tennis-live-archive',
      _archived_at: new Date().toISOString(),
      // bd fix — realResult + predicted pour alimenter _tennisPicksOf et les KPIs
      realResult: {
        winner: winner === 'p1' ? m.player1?.name : (winner === 'p2' ? m.player2?.name : null),
        sets: (m.sets || []).map(s => ({ p1: s.p1 ?? 0, p2: s.p2 ?? 0 })),
        total_games: (m.sets || []).reduce((s, set) => s + (set.p1 || 0) + (set.p2 || 0), 0),
        aces_p1: m._bsd_stats?.p1_aces ?? null,
        aces_p2: m._bsd_stats?.p2_aces ?? null,
        had_tiebreak: (m.sets || []).some(s => {
          return (s.p1 >= 6 && s.p2 >= 6) || (s.p1 === 7 && s.p2 === 6) || (s.p1 === 6 && s.p2 === 7);
        }) || false,
      },
      // Prédictions BSD (stockées sur m._bsd_prediction) pour alimenter ML/Set1/Total Games
      predicted: m._bsd_prediction ? {
        ml: m.bsd_prediction.prob_p1_wins > 0.50 ? m.player1?.name : (m.bsd_prediction.prob_p2_wins > 0.50 ? m.player2?.name : null),
        ml_odds: m.bsd_prediction.prob_p1_wins > 0.50
          ? parseFloat((1 / Math.max(0.01, m.bsd_prediction.prob_p1_wins)).toFixed(2))
          : parseFloat((1 / Math.max(0.01, 1 - m.bsd_prediction.prob_p1_wins)).toFixed(2)),
        set1: null, // BSD ne prédit pas le set1 individuellement
        total_games_thr: m.bsd_prediction.expected_total_games ?? null,
        total_games_over: true,
      } : {},
    };
    tennisHistory.push(archived);
    (db.archive_matches = db.archive_matches || []).push(archived);
    existingTennisIds.add(idStr);
    existingArchiveIds.add(idStr);
    added++;
  }
  if (added > 0) {
    saveHistory();
    console.log(`  [Tennis Archive] ${added} matchs finished archives vers tennisHistory (+db.archive_matches) — persisté`);
  }
  return added;
}

// bd — Challenger ATP supplement: BSD/The Odds API/MatchStat ne couvrent pas.
// Tennis Explorer scraper (déjà intégré) couvre tous les niveaux ATP/WTA.
const _MS_CHALLENGER_CACHE_TTL = 5 * 60 * 1000;
let _msChallengerCache = { ts: 0, data: [] };

async function _fetchMSChallengerMatches() {
  const now = Date.now();
  if (_msChallengerCache.data.length && (now - _msChallengerCache.ts) < _MS_CHALLENGER_CACHE_TTL) {
    return _msChallengerCache.data;
  }
  try {
    const matches = [];

    // Source 1: The Odds API — les Challengers sont listés comme sports actifs
    if (ODDS_API_KEY) {
      try {
        const sportsRes = await httpsGet(`https://api.the-odds-api.com/v4/sports/?apiKey=${ODDS_API_KEY}&all=false`);
        if (sportsRes && sportsRes.status === 200 && Array.isArray(sportsRes.data)) {
          const challengerSports = sportsRes.data.filter(s =>
            s && s.group === 'Tennis' && s.active === true &&
            /challenger|itf/.test(String(s.key || '').toLowerCase())
          );
          if (challengerSports.length) {
            // Fetch odds for each Challenger sport
            const now2 = new Date();
            for (const cs of challengerSports) {
              try {
                const query = new URLSearchParams({
                  apiKey: ODDS_API_KEY,
                  regions: process.env.ODDS_REGIONS || 'eu',
                  markets: 'h2h',
                  oddsFormat: 'decimal',
                  dateFormat: 'iso',
                  commenceTimeFrom: formatIsoTimestamp(now2),
                  commenceTimeTo: formatIsoTimestamp(new Date(now2.getTime() + 7 * 24 * 3600 * 1000)),
                }).toString();
                const oddsRes = await httpsGet(`https://api.the-odds-api.com/v4/sports/${cs.key}/odds/?${query}`);
                if (oddsRes && oddsRes.status === 200 && Array.isArray(oddsRes.data)) {
                  for (const od of oddsRes.data) {
                    const tnName = od.sport_title || cs.title || cs.key.replace(/tennis_(atp|wta|itf)_/, '').replace(/_/g, ' ');
                    matches.push({
                      id: `odds_ch_${od.id || Math.random()}`,
                      tour: cs.key.includes('wta') ? 'WTA' : 'ATP',
                      discipline: tnName,
                      tournament: tnName,
                      court: '',
                      surface: 'Hard',
                      status: 'notstarted',
                      is_live: false,
                      player1: { name: od.home_team || '?', country: '', flag: null },
                      player2: { name: od.away_team || '?', country: '', flag: null },
                      player1_sets: 0,
                      player2_sets: 0,
                      sets: [],
                      serving: null,
                      start_time: od.commence_time || null,
                      _source: 'odds_api_challenger',
                      _bsd_match_id: null,
                      _bsd_stats: {},
                    });
                  }
                }
              } catch (_) { /* skip un sport */ }
            }
          }
        }
      } catch (_) { /* The Odds API fail → fallback MatchStat */ }
    }

    // Source 2: Tennis Explorer — couvre tous les niveaux ATP/WTA y compris Challengers
    if (!matches.length) {
      try {
        const cal = await fetchTexCalendar('atp');
        const items = cal && cal.tournaments || [];
        const challengers = items.filter(t => {
          const name = String(t.name || t.short || '').toLowerCase();
          return name.includes('challenger') || name.includes('chall') || name.includes('little');
        });
        if (challengers.length) {
          // Pour chaque Challenger, fetch la page du tournoi et parse les matchs
          for (const t of challengers.slice(0, 5)) {
            try {
              const tournPage = await _texFetchHtml(t.url.replace(TEX_BASE, ''));
              // Parse les matchs depuis la page tournoi (même structure que /matches/)
              const parsed = _texParseMatchesPage(tournPage);
              for (const p of parsed) {
                // Init Elo Challenger: nom du joueur comme ID (pas de BSD player ID)
                const p1Id = `ch_${(p.player1?.name || '?').toLowerCase().replace(/\s+/g, '_')}`;
                const p2Id = `ch_${(p.player2?.name || '?').toLowerCase().replace(/\s+/g, '_')}`;
                let elo1 = 1500, elo2 = 1500;
                if (tennisEloCalculator) {
                  try {
                    elo1 = tennisEloCalculator.getPlayer(p1Id).elo;
                    elo2 = tennisEloCalculator.getPlayer(p2Id).elo;
                  } catch (_) {
                    tennisEloCalculator.initializePlayer(p1Id, 1500);
                    tennisEloCalculator.initializePlayer(p2Id, 1500);
                  }
                }
                matches.push({
                  id: p.id,
                  tour: 'ATP',
                  discipline: t.name || 'Challenger',
                  tournament: t.name || t.short || 'Challenger',
                  court: '',
                  surface: t.surface || 'Hard',
                  status: 'notstarted',
                  is_live: false,
                  player1: { name: p.player1?.name || '?', country: '', flag: null },
                  player2: { name: p.player2?.name || '?', country: '', flag: null },
                  player1_sets: 0,
                  player2_sets: 0,
                  sets: [],
                  serving: null,
                  start_time: null,
                  _source: 'tex_challenger',
                  _bsd_match_id: null,
                  _bsd_stats: {},
                  elo_p1: Math.round(elo1),
                  elo_p2: Math.round(elo2),
                  elo_gap: Math.round(elo1 - elo2),
                });
              }
            } catch (_) { /* skip ce tournoi */ }
          }
        }
      } catch (_) { /* Tennis Explorer fail */ }
    }

    _msChallengerCache = { ts: now, data: matches };
    if (matches.length) {
      console.log(`  [Challenger ATP] ${matches.length} matchs chargés (The Odds API + Tennis Explorer)`);
    }
    return matches;
  } catch (e) {
    console.warn('  [Challenger ATP]', e.message);
    return [];
  }
}

async function pollTennisLive() {
  if (_isFetchingTennis) return;
  _isFetchingTennis = true;
  try {
    let bsd = [];
    if (BSD_TENNIS_ENABLED) {
      try {
        bsd = await fetchBSDTennisLive();
      } catch (e) {
        if (e && e.code === 'ADDON_REQUIRED') console.warn('  [Tennis] BSD addon requis — fallback ESPN');
        else console.warn('  [Tennis] BSD live error:', e.message);
      }
    }
    let espn = [];
    try { espn = await fetchESPNTennisLive(); } catch (e) { console.warn('  [Tennis] ESPN live error:', e.message); }
    const data = _mergeTennisLive(bsd, espn);
    // bd — Merge MatchStat Challenger matches (BSD ne couvre pas Challengers ATP)
    try { const msCh = await _fetchMSChallengerMatches(); if (msCh.length) data.push(...msCh); } catch (_) {}
    // bd c5i — Cross-source serving enrichment (aiscore cache hit) AVANT recordTennisServe
    // pour que l'historique parite ait la donnée fraîche.
    let _aiEnriched = 0, _aiOndemand = 0, _aiEnrichedOndemand = 0;
    try { _aiEnriched = enrichServingFromAiscoreCache(data, 'aiscore_cache'); } catch (_) {}
    // bd c5i Phase 3 — on-demand aiscore fetch throttled (5/poll) pour matchs
    // serving=null & cache miss. Re-merge apres fetch pour propager au payload courant.
    try { _aiOndemand = await fetchAiscoreServingOnDemand(data); } catch (_) {}
    if (_aiOndemand > 0) {
      try { _aiEnrichedOndemand = enrichServingFromAiscoreCache(data, 'aiscore_ondemand'); } catch (_) {}
    }
    // S3 : serve momentum par match live + purge des ids disparus.
    const _liveIds = new Set();
    for (const m of data) {
      if (m && m.is_live) { _liveIds.add(m.id); try { m.serve_momentum = recordTennisServe(m); } catch (_) { m.serve_momentum = null; } }
      // bd — K-Flow + SM Momentum tracker: feed point data per match
      if (m && m.is_live && tennisMomentumTracker) {
        try {
          const pWinner = m.current_point ? (m.current_point.includes('40') || m.serving === 1 ? 0 : 1) : (m.serving === 1 ? 0 : 1);
          tennisMomentumTracker.addPoint(m.id, {
            winner: m.serving === 1 ? 0 : 1, // heuristic: server wins point by default (will improve with real point data)
            server: m.serving === 1 ? 0 : m.serving === 2 ? 1 : null,
            rallyCount: 4, // default rally count (will improve with real data)
            gamePoint: false,
            ts: Date.now(),
          });
          m.momentum = tennisMomentumTracker.getMomentum(m.id);
          // Attach Glicko-2 ratings to match for frontend display
          if (tennisGlicko2) {
            try {
              const p1Id = m.player1?.name?.toLowerCase().replace(/\s+/g, '_') || '';
              const p2Id = m.player2?.name?.toLowerCase().replace(/\s+/g, '_') || '';
              tennisGlicko2.serveCalc.getPlayer(p1Id); // ensure initialized
              tennisGlicko2.serveCalc.getPlayer(p2Id);
              m.glicko2 = {
                p1_serve: Math.round(tennisGlicko2.serveCalc.getPlayer(p1Id).rating),
                p1_return: Math.round(tennisGlicko2.returnCalc.getPlayer(p1Id).rating),
                p2_serve: Math.round(tennisGlicko2.serveCalc.getPlayer(p2Id).rating),
                p2_return: Math.round(tennisGlicko2.returnCalc.getPlayer(p2Id).rating),
              };
            } catch (_) { m.glicko2 = null; }
          }
        } catch (_) { m.momentum = null; }
      }
    }
    for (const k of _tennisServeHist.keys()) if (!_liveIds.has(k)) _tennisServeHist.delete(k);
    // bd 6xw — Break Point Pressure Index par match live + SSE bppi_spike (Δ>20pts).
    for (const m of data) {
      if (!m || !m.is_live) continue;
      try {
        const prev = _tennisBPPIPrev.get(m.id) || null;
        const cur = computeBPPI(m);
        m.bppi = cur;
        if (prev && cur && !cur.missing && !prev.missing) {
          const d1 = Math.abs((cur.p1 || 0) - (prev.p1 || 0));
          const d2 = Math.abs((cur.p2 || 0) - (prev.p2 || 0));
          if (d1 >= 20 || d2 >= 20) {
            const side = d1 >= d2 ? 'p1' : 'p2';
            try {
              broadcastSSE('bppi_spike', {
                match_id: m.id,
                tournament: m.tournament,
                player1: m.player1 && m.player1.name,
                player2: m.player2 && m.player2.name,
                side,
                delta: side === 'p1' ? (cur.p1 - prev.p1) : (cur.p2 - prev.p2),
                bppi: { p1: cur.p1, p2: cur.p2 },
                context_flags: cur.context_flags || [],
                ts: Date.now(),
              });
            } catch (_) { /* SSE non bloquant */ }
          }
        }
        _tennisBPPIPrev.set(m.id, { p1: cur.p1, p2: cur.p2, missing: cur.missing, ts: Date.now() });
      } catch (_) { m.bppi = null; }
    }
    // Purge BPPI prev pour matchs disparus
    for (const k of _tennisBPPIPrev.keys()) if (!_liveIds.has(k)) _tennisBPPIPrev.delete(k);
    // bd 6v0 — DR Spike detection on every poll for live tennis matches.
    // Compare DR_set_courant vs DR_match → si |delta|/dr_match > seuil → SSE.
    // Fire-and-forget, debounce 30s per matchId garantit pas de spam.
    try {
      for (const m of data) {
        if (!m || !m.is_live) continue;
        const curSet = (Array.isArray(m.sets) && m.sets.length) ? m.sets.length
          : (Number.isFinite(m.current_set_index) ? m.current_set_index + 1 : null);
        const drBase = getSofascoreDRCached(m.player1?.name, m.player2?.name);
        if (!drBase || !Number.isFinite(drBase.dr)) continue;
        const drEnriched = _drAttachCurrentSet(drBase, curSet);
        const drSetCur = drEnriched?.dr_set_courant;
        if (!drSetCur || !Number.isFinite(drSetCur.dr) || drSetCur.reliable === false) continue;
        // DR favorise J1 si DR > 1 → DR=p1/p2 ratio (déjà p1-centric côté Sofa).
        // Spike side = celui qui voit son DR augmenter (=dominant set en cours).
        const side = drSetCur.dr >= drBase.dr ? 'p1' : 'p2';
        broadcastTennisDRSpike(m.id, drBase.dr, drSetCur.dr, side);
      }
      // DR-DIFF — Alerte Discord Différence DR entre les 2 joueurs
      // Métrique : |DR_ratio - 1.0| = écart normalisé P1 vs P2 (DR = p1_total / p2_total)
      //            Affichage : DR individuels serve+return de chaque joueur
      // Dedup : cooldown time-based 5 min par match (via _tnAlertOnCooldown)
      // Seuil : TENNIS_DR_DIFF_THRESHOLD env (défaut 0.20)
      try {
        const _DR_DIFF_THR = parseFloat(process.env.TENNIS_DR_DIFF_THRESHOLD || '0.20');
        for (const m of data) {
          if (!m || !m.is_live) continue;
          const curSet2 = (Array.isArray(m.sets) && m.sets.length) ? m.sets.length
            : (Number.isFinite(m.current_set_index) ? m.current_set_index + 1 : null);
          // DR multi-source : Sofascore (lookup par nom, riche dr_by_set) en priorité,
          // sinon calcul inline depuis stats BSD (clé match id → robuste aux noms).
          let drBase2 = getSofascoreDRCached(m.player1?.name, m.player2?.name);
          let _drSrc = (drBase2 && Number.isFinite(drBase2.dr)) ? 'sofa' : null;
          if (!_drSrc) {
            drBase2 = computeTennisDRFromMatch(m);
            _drSrc = (drBase2 && drBase2.source) || 'none';
          }
          if (process.env.DEBUG_DR === 'true') {
            const st = m._bsd_stats || {};
            console.log(`  [DR DEBUG] "${m.player1?.name}" vs "${m.player2?.name}" | dr=${drBase2 ? drBase2.dr : 'NULL'} src=${_drSrc} | bsd p1S=${st.p1_first_won} p1R=${st.p1_ret_won} p2S=${st.p2_first_won} p2R=${st.p2_ret_won} p1T=${st.p1_total_pts} p2T=${st.p2_total_pts}`);
          }
          if (!drBase2 || !Number.isFinite(drBase2.dr)) continue;

          // ── VARIANCE DR PAR SET ──────────────────────────────────────────
          // Snapshot du DR par set → variance inter-sets. Alerte si le DR oscille
          // fort d'un set à l'autre (match en dents de scie / bascule momentum).
          // Affichage "par joueur par set" : DR + dominant pour chaque set.
          // Indépendant de l'alerte diff (pas de continue avant ce bloc).
          try {
            if (curSet2) {
              let setHist = _tennisDRSetHist.get(m.id);
              if (!setHist) { setHist = {}; _tennisDRSetHist.set(m.id, setHist); }
              // Source DR/set : Sofascore dr_by_set (vrai per-set) si dispo,
              // sinon snapshot du DR match courant attribué au set en cours.
              const bySet = drBase2.dr_by_set || {};
              const bySetKeys = Object.keys(bySet);
              if (bySetKeys.length) {
                for (const sn of bySetKeys) {
                  const v = bySet[sn];
                  if (v && Number.isFinite(v.dr)) setHist[sn] = { dr: v.dr, ts: Date.now(), src: 'sofa' };
                }
              } else {
                setHist[curSet2] = { dr: drBase2.dr, ts: Date.now(), src: _drSrc };
              }
              const setEntries = Object.keys(setHist)
                .map(k => ({ set: parseInt(k, 10), dr: setHist[k].dr }))
                .filter(e => Number.isFinite(e.set) && Number.isFinite(e.dr))
                .sort((a, b) => a.set - b.set);
              if (setEntries.length >= 2) {
                const vals = setEntries.map(e => e.dr);
                const mean = vals.reduce((a, b) => a + b, 0) / vals.length;
                const variance = vals.reduce((a, b) => a + (b - mean) * (b - mean), 0) / vals.length;
                const stdev = Math.sqrt(variance);
                const _VAR_THR = parseFloat(process.env.TENNIS_DR_VAR_THRESHOLD || '0.08');
                // Clé cooldown inclut le nb de sets → re-fire quand un nouveau set complète
                const varKey = `tndr_var:${m.id}:${setEntries.length}`;
                if (variance >= _VAR_THR && !_tnAlertOnCooldown(varKey, 5 * 60 * 1000)) {
                  _tnAlertMark(varKey);
                  const p1n = m.player1?.name || 'J1', p2n = m.player2?.name || 'J2';
                  const swingLvl = variance >= 0.15 ? '🔴 TRÈS INSTABLE' : '📈 INSTABLE';
                  const setLines = setEntries.map(e => `Set ${e.set}: DR ${e.dr.toFixed(2)} → ${e.dr >= 1 ? p1n : p2n}`);
                  const varMsg = [
                    `📈 <b>VARIANCE DR PAR SET — ${swingLvl}</b>`,
                    ``,
                    `${escTg(m.tournament)} | ${escTg(m.court)}`,
                    `${escTg(p1n)} vs ${escTg(p2n)} (${m.player1_sets || 0}-${m.player2_sets || 0})`,
                    ``,
                    ...setLines.map(l => escTg(l)),
                    ``,
                    `Variance: <b>${variance.toFixed(3)}</b> | Écart-type: <b>${stdev.toFixed(3)}</b>`,
                    `→ Domination en dents de scie sur ${setEntries.length} sets`,
                  ].join('\n');
                  const varEmbed = {
                    title: `📈 Variance DR par Set — ${swingLvl}`,
                    description: `**${p1n}** vs **${p2n}** · ${setEntries.length} sets analysés`,
                    color: variance >= 0.15 ? 0xFF2200 : 0x9B59B6,
                    fields: [
                      ...setEntries.slice(0, 5).map(e => ({
                        name: `Set ${e.set}`,
                        value: `DR **${e.dr.toFixed(2)}**\n→ ${e.dr >= 1 ? p1n : p2n}`,
                        inline: true,
                      })),
                      { name: '📊 Variance', value: `**${variance.toFixed(3)}**`, inline: true },
                      { name: '📐 Écart-type', value: `**${stdev.toFixed(3)}**`, inline: true },
                    ],
                    footer: { text: `Variance DR/set | src:${_drSrc} | Seuil ${_VAR_THR} | ${m.tournament}` },
                    timestamp: new Date().toISOString(),
                  };
                  broadcastTennisLiveAlert(varMsg, varEmbed).catch(() => {});
                  console.log(`  [Tennis DR Var] ${m.id} sets=${setEntries.length} var=${variance.toFixed(3)} stdev=${stdev.toFixed(3)}`);
                }
              }
            }
          } catch (eVar) { if (process.env.DEBUG_DR === 'true') console.warn('  [Tennis DR Var]', eVar.message); }
          // ─────────────────────────────────────────────────────────────────

          // ── Alerte DOMINATION REELLE : DR_individuel = ret% / (100-serve%) >= 1.2 + cote <= 1.30 ──
          // Scope : RG + ATP/WTA Challengers + UTR. Independant du gate drGapAbs ci-dessous.
          try {
            const _p1sN = Number(drBase2?.p1_serve);
            const _p1rN = Number(drBase2?.p1_ret);
            const _p2sN = Number(drBase2?.p2_serve);
            const _p2rN = Number(drBase2?.p2_ret);
            // DR individuel = (% pts gagnes en retour) / (% pts perdus au service)
            //               = ret_won% / (100 - serve_won%)
            const _drI_p1 = (Number.isFinite(_p1sN) && Number.isFinite(_p1rN) && _p1sN < 100)
              ? _p1rN / (100 - _p1sN) : null;
            const _drI_p2 = (Number.isFinite(_p2sN) && Number.isFinite(_p2rN) && _p2sN < 100)
              ? _p2rN / (100 - _p2sN) : null;
            const _DOM_REAL_THR = 1.5;
            const _p1Dom = _drI_p1 != null && _drI_p1 >= _DOM_REAL_THR;
            const _p2Dom = _drI_p2 != null && _drI_p2 >= _DOM_REAL_THR;
            if (_p1Dom || _p2Dom) {
              const _tnTour2 = (m.tour       || '').toUpperCase();
              const _tnDisc2 = (m.discipline || '').toUpperCase();
              const _tnName2 = (m.tournament || '').toUpperCase();
              const _inScope = (
                /ROLAND.?GARROS|FRENCH.?OPEN/.test(_tnName2)               ||
                /CHALLENGER/.test(_tnDisc2) || /CHALLENGER/.test(_tnTour2) ||
                /CHALLENGER/.test(_tnName2) || /UTR/.test(_tnName2)        ||
                /UTR/.test(_tnTour2)        || /UTR/.test(_tnDisc2)        ||
                (/GRAND.?SLAM/.test(_tnDisc2) && /ATP|WTA/.test(_tnTour2))
              );
              if (_inScope) {
                const _dSide = (_p1Dom && (!_p2Dom || (_drI_p1 ?? 0) >= (_drI_p2 ?? 0))) ? 'p1' : 'p2';
                const _dName = _dSide === 'p1' ? (m.player1?.name || 'J1') : (m.player2?.name || 'J2');
                const _dOdds = _dSide === 'p1' ? m.odds_player1 : m.odds_player2;
                const _dDR   = _dSide === 'p1' ? _drI_p1 : _drI_p2;
                if (_dOdds != null && Number.isFinite(_dOdds) && _dOdds >= 1.2 && _dOdds <= 1.8) {
                  const _ok = `tndr_odds13:${m.id}`;
                  if (!_tnAlertOnCooldown(_ok, 20 * 60 * 1000)) {
                    _tnAlertMark(_ok);
                    const _ls   = `${m.player1_sets || 0}-${m.player2_sets || 0}`;
                    const _p1sS = Number.isFinite(_p1sN) ? _p1sN.toFixed(1) + '%' : '--';
                    const _p1rS = Number.isFinite(_p1rN) ? _p1rN.toFixed(1) + '%' : '--';
                    const _p2sS = Number.isFinite(_p2sN) ? _p2sN.toFixed(1) + '%' : '--';
                    const _p2rS = Number.isFinite(_p2rN) ? _p2rN.toFixed(1) + '%' : '--';
                    const _d1S  = _drI_p1 != null ? _drI_p1.toFixed(3) : '--';
                    const _d2S  = _drI_p2 != null ? _drI_p2.toFixed(3) : '--';
                    const _dDRS = Number.isFinite(_dDR)  ? _dDR.toFixed(3)  : '--';
                    const _emb  = {
                      title: `🎯 DOMINATION REELLE DR>=1.50 + COTE 1.20-1.80`,
                      description: `**${m.player1?.name || 'J1'}** vs **${m.player2?.name || 'J2'}** · Sets ${_ls}`,
                      color: 0xFFD700,
                      fields: [
                        { name: `🎯 ${m.player1?.name || 'J1'}`, value: `Serve: **${_p1sS}** | Return: **${_p1rS}**
DR = **${_d1S}**${_p1Dom ? ' ✅ >=1.50' : ''}`, inline: true },
                        { name: `🎯 ${m.player2?.name || 'J2'}`, value: `Serve: **${_p2sS}** | Return: **${_p2rS}**
DR = **${_d2S}**${_p2Dom ? ' ✅ >=1.50' : ''}`, inline: true },
                        { name: '​', value: '​', inline: true },
                        { name: '🏆 Dominant',   value: `**${_dName}**`,                      inline: true },
                        { name: '💰 Cote match', value: `**${_dOdds.toFixed(2)}** [1.20-1.80] ✅`, inline: true },
                        { name: '📐 DR reel',    value: `**${_dDRS}** >=1.50 ✅`,           inline: true },
                        { name: '🎾 Court',      value: m.court      || 'N/A',                 inline: true },
                        { name: '🏟 Tournoi',    value: m.tournament || 'N/A',                 inline: true },
                        { name: '📡 Src DR',     value: _drSrc,                               inline: true },
                      ],
                      footer: { text: `DR=ret%/(100-serv%) | seuil >=1.50 + cote 1.20-1.80 | Cooldown 20min (~4 jeux) | ${m.tournament}` },
                      timestamp: new Date().toISOString(),
                    };
                    if (DISCORD_TENNIS_DOMINATION_ODDS_URL) {
                      httpsPost(DISCORD_TENNIS_DOMINATION_ODDS_URL, { embeds: [_emb] })
                        .catch(e => console.warn('  [Tennis:DomOdds13]', e.message));
                    }
                    console.log(`  [Tennis:DomOdds13] ${m.id} dominant=${_dName} DR=${_dDRS} cote=${_dOdds.toFixed(2)}`);
                  }
                }
              }
            }
          } catch (_eDom) { /* swallow */ }

          // ── Alerte DR Break Set — DR set en cours ≥2 + 2 jeux d'écart + dominant mène ────
          // Bets : Under 12.5 jeux (cote fair ≥1.20) ET/OU Gagne le set (cote ≥1.15)
          try {
            // 1. Score set en cours — dernier entry de m.sets[]
            const _mSets     = Array.isArray(m.sets) ? m.sets : [];
            const _curSS     = _mSets.length ? _mSets[_mSets.length - 1] : null;
            if (!_curSS) throw new Error('skip');
            const _g1        = parseInt(_curSS.p1) || 0;
            const _g2        = parseInt(_curSS.p2) || 0;
            const _gap       = _g1 - _g2; // >0 → P1 devant
            if (Math.abs(_gap) < 2) throw new Error('skip'); // 2 jeux d'écart minimum
            // 2. DR set en cours — dr_by_set[setNum] priorité, fallback match DR
            const _bySetBrk  = drBase2.dr_by_set || {};
            const _drSetBrk  = _bySetBrk[_mSets.length]?.dr;
            const _drAvgSet  = Number.isFinite(_drSetBrk) ? _drSetBrk : (Number.isFinite(drBase2.dr) ? drBase2.dr : null);
            if (!_drAvgSet || (_drAvgSet < 1.5 && (1 / _drAvgSet) < 1.5)) throw new Error('skip'); // DR set < 1.5
            // 3. Aligner dominant DR set avec leader du set
            const _domSideBrk  = _drAvgSet >= 1 ? 'p1' : 'p2';
            const _domLeads    = (_domSideBrk === 'p1' && _gap > 0) || (_domSideBrk === 'p2' && _gap < 0);
            if (!_domLeads) throw new Error('skip');
            const _domNameBrk  = _domSideBrk === 'p1' ? (m.player1?.name || 'J1') : (m.player2?.name || 'J2');
            const _domOddsBrk  = _domSideBrk === 'p1' ? m.odds_player1 : m.odds_player2;
            if (!Number.isFinite(_domOddsBrk) || _domOddsBrk <= 1.15) throw new Error('skip');
            // 4. Cooldown 20min
            const _ckBrk = `tndr_break_set:${m.id}`;
            if (_tnAlertOnCooldown(_ckBrk, 20 * 60 * 1000)) throw new Error('skip');
            _tnAlertMark(_ckBrk);
            // 5. Confiances
            const _tot       = _g1 + _g2;
            const _gAhead    = Math.abs(_gap);
            const _confU125  = _tot <= 6 ? 82 : _tot <= 8 ? 75 : 68;
            const _iU125     = parseFloat((100 / _confU125).toFixed(2));
            const _confSet   = Math.min(88, Math.round(65 + (_drAvgSet - 2.0) * 8 + _gAhead * 3));
            const _iSet      = parseFloat((100 / _confSet).toFixed(2));
            const _setStr    = _mSets.map((s, i) => `S${i + 1}: ${s.p1}-${s.p2}`).join(' | ');
            const _curSetNum = _mSets.length;
            const _emb2      = {
              title:       `🎾 BREAK ALERT — DR Set ${_curSetNum}: ${_drAvgSet.toFixed(2)} + 2J écart | Set ${_curSetNum}`,
              description: `**${m.player1?.name || 'J1'}** vs **${m.player2?.name || 'J2'}** · Set ${_curSetNum}: **${_g1}-${_g2}**`,
              color:       0x00b4d8,
              fields: [
                { name: '🏆 Dominant',                value: `**${_domNameBrk}**`,                                                                                  inline: true },
                { name: `📐 DR set ${_curSetNum}`,    value: `**${_drAvgSet.toFixed(2)}** ≥2.0 ✅${Number.isFinite(_drSetBrk) ? '' : ' (fallback match)'}`,         inline: true },
                { name: '💰 Cote match',              value: `**${_domOddsBrk.toFixed(2)}** >1.15 ✅`,                                                               inline: true },
                { name: '🎾 Score set',               value: `**${_g1}-${_g2}** (${_gAhead} jeu(x) écart)`,                                                         inline: true },
                { name: '📊 Sets',                    value: _setStr || `Set 1 en cours`,                                                                            inline: true },
                { name: '📡 Src DR',                  value: _drSrc,                                                                                                 inline: true },
                { name: '🎯 BET 1 — Under 12.5 jeux', value: `Conf **${_confU125}%** · Cote fair **${_iU125}**\nDR set ≥2 + 2J écart → set rapide attendu`,        inline: false },
                { name: '🎯 BET 2 — Gagne le set',    value: `**${_domNameBrk}** · Conf **${_confSet}%** · Cote fair **${_iSet}**\nVérifier cote bookie ≥1.15`,    inline: false },
              ],
              footer:      { text: `DR set en cours ≥2.0 + 2 jeux écart + dominant mène + cote >1.15 | Cooldown 20min | ${m.tournament}` },
              timestamp:   new Date().toISOString(),
            };
            if (DISCORD_TENNIS_BREAK_SET_URL) {
              httpsPost(DISCORD_TENNIS_BREAK_SET_URL, { embeds: [_emb2] })
                .catch(e => console.warn('  [Tennis:BreakSet]', e.message));
            }
            saveTennisAlert({ alert_type:'break_set', match_id:m.id, player1:m.player1?.name, player2:m.player2?.name, tournament:m.tournament, set_num:_curSetNum, dr_set:_drAvgSet, bet_type:'under_12.5', bet_conf:_confU125, score_at_alert:`${_g1}-${_g2}` });
            saveTennisAlert({ alert_type:'break_set', match_id:m.id, player1:m.player1?.name, player2:m.player2?.name, tournament:m.tournament, set_num:_curSetNum, dr_set:_drAvgSet, bet_type:'gagne_set', bet_conf:_confSet, score_at_alert:`${_g1}-${_g2}` });
            console.log(`  [Tennis:BreakSet] ${m.id} dom=${_domNameBrk} drAvg=${_drAvgSet} set=${_g1}-${_g2} cote=${_domOddsBrk.toFixed(2)}`);
          } catch (_eBrk) { if (process.env.DEBUG_DR === 'true') console.warn('  [Tennis:BreakSet]', _eBrk.message); }

          // ── Alerte Under 7.5/8.5 jeux — Score 1-1 (2 tenues service) ───────────────────
          // Trigger : score EXACT 1-1 dans le set en cours (les 2 joueurs ont tenu leur 1er jeu de service)
          // Calcul : P(Under 7.5) et P(Under 8.5) via Poisson depuis DR → cote implicite
          // Fire si : au moins un under a cote calculée ≤1.20
          try {
            const _mSetsU  = Array.isArray(m.sets) ? m.sets : [];
            const _curSSU  = _mSetsU.length ? _mSetsU[_mSetsU.length - 1] : null;
            if (!_curSSU) throw new Error('skip');
            const _g1u = parseInt(_curSSU.p1) || 0;
            const _g2u = parseInt(_curSSU.p2) || 0;
            if (_g1u !== 1 || _g2u !== 1) throw new Error('skip'); // 1-1 exact seulement
            // p_dom : probabilité de gagner chaque jeu pour le joueur dominant (DR set en cours)
            const _bySetU   = drBase2.dr_by_set || {};
            const _drSetCur = _bySetU[_mSetsU.length]?.dr;
            const _drU      = Number.isFinite(_drSetCur) ? _drSetCur : (Number.isFinite(drBase2.dr) ? drBase2.dr : 1);
            if (_drU < 1.5 && (1 / _drU) < 1.5) throw new Error('skip'); // DR set en cours < 1.5 → pas de domination suffisante
            const _drDom = Math.max(_drU, 1 / _drU); // toujours >= 1
            const _pDom  = Math.min(0.95, 0.63 + (_drDom - 1) * 0.14);
            const _pSub  = 1 - _pDom;
            // P(Under 7.5 | 1-1) = P(5-0 restants) — set fini 6-1 dans un sens
            const _pU75  = Math.pow(_pDom, 5) + Math.pow(_pSub, 5);
            const _oU75  = parseFloat((1 / Math.max(_pU75, 0.01)).toFixed(2));
            // P(Under 8.5 | 1-1) = P(5-0) + P(5-1 restants) — set fini 6-1 ou 6-2
            const _pU85  = _pU75
              + 5 * Math.pow(_pDom, 5) * _pSub
              + 5 * Math.pow(_pSub, 5) * _pDom;
            const _oU85  = parseFloat((1 / Math.max(_pU85, 0.01)).toFixed(2));
            // Gate : au moins un under à cote ≤1.20
            const _hasU75 = _oU75 <= 1.20;
            const _hasU85 = _oU85 <= 1.20;
            if (!_hasU75 && !_hasU85) throw new Error('skip');
            // Cooldown 30min par match + set (évite re-fire si score reste 1-1)
            const _setNumU = _mSetsU.length;
            const _ckU = `tndr_under_games:${m.id}:s${_setNumU}`;
            if (_tnAlertOnCooldown(_ckU, 30 * 60 * 1000)) throw new Error('skip');
            _tnAlertMark(_ckU);
            const _domSideU = _drU >= 1 ? 'p1' : 'p2';
            const _domNameU = _domSideU === 'p1' ? (m.player1?.name || 'J1') : (m.player2?.name || 'J2');
            const _domOddsU = Number.isFinite(_domSideU === 'p1' ? m.odds_player1 : m.odds_player2)
              ? (_domSideU === 'p1' ? m.odds_player1 : m.odds_player2) : null;
            // Gate cote Winner Match : doit être dans [1.10 ; 1.25]
            if (!_domOddsU || _domOddsU < 1.10 || _domOddsU > 1.25) throw new Error('skip');
            const _emb3 = {
              title:       `🎾 UNDER JEU ALERT — ${_hasU75 ? 'Under 7.5 🔥' : 'Under 8.5'} | Set ${_setNumU}`,
              description: `**${m.player1?.name || 'J1'}** vs **${m.player2?.name || 'J2'}** · Score **1-1** (2 tenues service)`,
              color:       0x7209b7,
              fields: [
                { name: `📐 DR set ${_setNumU}`,   value: `**${_drU.toFixed(2)}** — ${_domNameU} domine${Number.isFinite(_drSetCur) ? '' : ' (fallback match)'}`,  inline: true },
                { name: '🎯 P/jeu dom', value: `**${(_pDom * 100).toFixed(1)}%**`,                                             inline: true },
                { name: '🏆 Dominant',  value: `**${_domNameU}**${_domOddsU ? ` @ **${_domOddsU.toFixed(2)}**` : ''}`,        inline: true },
                ...(_hasU75 ? [{ name: '✅ Under 7.5 jeux', value: `Cote calc. **${_oU75}** ≤1.20 · Conf **${Math.round(_pU75 * 100)}%**\nSet expédié 6-1`, inline: false }] : []),
                ...(_hasU85 ? [{ name: `${_hasU75 ? '➕' : '✅'} Under 8.5 jeux`, value: `Cote calc. **${_oU85}** ≤1.20 · Conf **${Math.round(_pU85 * 100)}%**\nSet fini ≤8 jeux (6-1 ou 6-2)`, inline: false }] : []),
                { name: '🏟 Tournoi',  value: m.tournament || '?',  inline: true },
                { name: '📡 Src DR',   value: _drSrc,               inline: true },
              ],
              footer:    { text: `Score 1-1 (2 holds) → Under 7.5/8.5 set | Cote winner [1.10-1.25] | DR Poisson | Cooldown 30min | ${m.tournament}` },
              timestamp: new Date().toISOString(),
            };
            if (DISCORD_TENNIS_BREAK_SET_URL) {
              httpsPost(DISCORD_TENNIS_BREAK_SET_URL, { embeds: [_emb3] })
                .catch(e => console.warn('  [Tennis:UnderGames]', e.message));
            }
            if (_hasU75) saveTennisAlert({ alert_type:'under_jeu', match_id:m.id, player1:m.player1?.name, player2:m.player2?.name, tournament:m.tournament, set_num:_setNumU, dr_set:_drU, bet_type:'under_7.5', bet_odds:_oU75, bet_conf:Math.round(_pU75*100), score_at_alert:'1-1' });
            if (_hasU85) saveTennisAlert({ alert_type:'under_jeu', match_id:m.id, player1:m.player1?.name, player2:m.player2?.name, tournament:m.tournament, set_num:_setNumU, dr_set:_drU, bet_type:'under_8.5', bet_odds:_oU85, bet_conf:Math.round(_pU85*100), score_at_alert:'1-1' });
            console.log(`  [Tennis:UnderGames] ${m.id} 1-1 DR=${_drU.toFixed(2)} pDom=${(_pDom*100).toFixed(0)}% U75_odd=${_oU75} U85_odd=${_oU85}`);
          } catch (_eUG) { if (process.env.DEBUG_DR === 'true') console.warn('  [Tennis:UnderGames]', _eUG.message); }

          // ── Alerte OddsPapi LIVE — Score 2-0 ou 0-2 dans le set ──────────────
          // Trigger : score EXACT 2-0 ou 0-2 dans le set en cours (début de dominance)
          // Check : cotes OddsPapi in-play Over 7.5 / Over 8.5 / Under 12.5 ∈ [1.10-1.30]
          // Intérêt : signal combiné score + Pinnacle confirme set rapide
          if (ODDSPAPI_V4_KEY() && DISCORD_TENNIS_BREAK_SET_URL) {
            try {
              const _mSetsLO = Array.isArray(m.sets) ? m.sets : [];
              const _curSSLO = _mSetsLO.length ? _mSetsLO[_mSetsLO.length - 1] : null;
              if (!_curSSLO) throw new Error('skip');
              const _g1lo = parseInt(_curSSLO.p1) || 0;
              const _g2lo = parseInt(_curSSLO.p2) || 0;
              const _is20 = _g1lo === 2 && _g2lo === 0;
              const _is02 = _g1lo === 0 && _g2lo === 2;
              if (!_is20 && !_is02) throw new Error('skip');
              const _setNumLO = _mSetsLO.length;
              const _scoreLO  = `${_g1lo}-${_g2lo}`;
              // Cooldown 30min par match + set + score (évite re-fire si score reste 2-0)
              const _ckLO = `oddspapi_live_setal:${m.id}:s${_setNumLO}:${_scoreLO}`;
              if (_tnAlertOnCooldown(_ckLO, 30 * 60 * 1000)) throw new Error('skip');
              // Résoudre fixture OddsPapi (cache — cherche index avant appel réseau)
              const _fxCached = _oddspapiFxIndex.get(String(m.id));
              const _hasFxCache = _fxCached && (Date.now() - _fxCached.ts) < ODDSPAPI_V4_TTL;
              if (!_hasFxCache && !m.tournament) throw new Error('skip'); // skip si pas de tournoi sans cache
              // Construire matchData compatible avec _oddspapiResolveFixtureId
              const _mdLO = {
                id: m.id,
                player1: m.player1 || {},
                player2: m.player2 || {},
                tournament: { name: m.tournament || '' },
                circuit: m.circuit || '',
              };
              // Async : ne bloque pas le poll principal
              (async () => {
                try {
                  const _fxId = await _oddspapiResolveFixtureId(_mdLO);
                  if (!_fxId) return;
                  const _odds = await fetchOddspapiTennisSetOdds(_fxId);
                  if (!_odds || (!_odds.set1.length && !_odds.set2.length)) return;
                  // Vérifier critères sur le set en cours
                  const _setLines = _setNumLO === 1 ? _odds.set1 : _odds.set2;
                  if (!_setLines || !_setLines.length) return;
                  const _hits = [];
                  for (const cfg of ODDSPAPI_ALERT_LINES) {
                    const _sl = _setLines.find(s => s.line === cfg.line);
                    if (!_sl) continue;
                    const _pr = _sl[cfg.field];
                    if (!_pr || _pr < ODDSPAPI_ALERT_MIN || _pr > ODDSPAPI_ALERT_MAX) continue;
                    _hits.push({ ...cfg, price: _pr, bookmaker: _sl.bookmaker });
                  }
                  if (!_hits.length) return;
                  _tnAlertMark(_ckLO); // armer cooldown maintenant (après vérification)
                  const _leaderLO = _is20 ? (m.player1?.name || 'J1') : (m.player2?.name || 'J2');
                  const _hitsStr  = _hits.map(h => `**${h.label}** @ **${h.price.toFixed(2)}** [${h.bookmaker}]`).join('\n');
                  const _h2hStr   = _odds.h2h ? `P1 **${_odds.h2h.p1?.toFixed(2) || '?'}** · P2 **${_odds.h2h.p2?.toFixed(2) || '?'}** [${_odds.h2h.bookmaker}]` : '—';
                  const _embLO = {
                    title:       `🎾 LIVE SET ALERT — Score ${_scoreLO} · Set ${_setNumLO} · OddsPapi ✅`,
                    description: `**${m.player1?.name || 'J1'}** vs **${m.player2?.name || 'J2'}**`,
                    color:       0xffa500,
                    fields: [
                      { name: '🏆 Mène',        value: `**${_leaderLO}** mène **${_scoreLO}** Set ${_setNumLO}`,  inline: true  },
                      { name: '🏟 Tournoi',     value: m.tournament || '?',                                        inline: true  },
                      { name: '🎲 H2H Pinnacle',value: _h2hStr,                                                    inline: false },
                      { name: '📊 Signaux OddsPapi', value: _hitsStr,                                              inline: false },
                    ],
                    footer:    { text: `Score ${_scoreLO} LIVE + OddsPapi ∈ [${ODDSPAPI_ALERT_MIN}-${ODDSPAPI_ALERT_MAX}] | Cooldown 30min | ${m.id}` },
                    timestamp: new Date().toISOString(),
                  };
                  httpsPost(DISCORD_TENNIS_BREAK_SET_URL, { embeds: [_embLO] })
                    .catch(e => console.warn('  [OddsPapi:LiveSet]', e.message));
                  console.log(`  [OddsPapi:LiveSet] ${m.id} score ${_scoreLO} S${_setNumLO} hits:${_hits.map(h=>h.label+'@'+h.price).join(',')}`);
                } catch (_e2) { /* silencieux */ }
              })();
            } catch (_eLO) { /* skip silencieux */ }
          }

          // Écart DR entre les 2 joueurs (DR = p1_total/p2_total → |DR-1| = avantage relatif)
          const drGapSigned = drBase2.dr - 1.0;
          const drGapAbs    = Math.abs(drGapSigned);
          if (drGapAbs < _DR_DIFF_THR) continue;

          // Cooldown 5 min par match — time-based, pas value-based (alert re-fire si DR stable)
          if (_tnAlertOnCooldown(`tndr_diff:${m.id}`, 5 * 60 * 1000)) continue;

          // Côtés dominant / dominé
          const side      = drGapSigned > 0 ? 'p1' : 'p2';
          const dominant  = side === 'p1' ? (m.player1?.name || 'J1') : (m.player2?.name || 'J2');
          const dominated = side === 'p1' ? (m.player2?.name || 'J2') : (m.player1?.name || 'J1');

          // DR individuels joueurs : serve + return séparément (p1_serve / p1_ret / p2_serve / p2_ret)
          const p1Serve = Number.isFinite(drBase2.p1_serve) ? drBase2.p1_serve.toFixed(2) : '–';
          const p1Ret   = Number.isFinite(drBase2.p1_ret)   ? drBase2.p1_ret.toFixed(2)   : '–';
          const p2Serve = Number.isFinite(drBase2.p2_serve) ? drBase2.p2_serve.toFixed(2) : '–';
          const p2Ret   = Number.isFinite(drBase2.p2_ret)   ? drBase2.p2_ret.toFixed(2)   : '–';

          // Bonus DR set courant si fiable (min 6 pts retour)
          const drEnriched2 = _drAttachCurrentSet(drBase2, curSet2);
          const drSetCur2   = drEnriched2?.dr_set_courant;
          const setGapAbs   = (drSetCur2 && Number.isFinite(drSetCur2.dr)) ? Math.abs(drSetCur2.dr - 1.0) : null;
          const setBonus    = (drSetCur2 && Number.isFinite(drSetCur2.dr) && drSetCur2.reliable !== false)
            ? `\nDR Set ${curSet2 || '?'}: ${drSetCur2.dr.toFixed(2)} (écart ${setGapAbs.toFixed(2)})`
            : '';

          const liveScore = `${m.player1_sets || 0}-${m.player2_sets || 0}`;
          const lastSet   = [].concat(m.sets || []).slice(-1)[0];
          const setLabel  = lastSet ? ` · Set ${curSet2 || '?'}: ${lastSet.p1}-${lastSet.p2}` : '';
          const intensity = drGapAbs >= 0.35 ? '🔴 FORTE DOMINATION' : '⚠️ DOMINATION';

          const msgHtml = [
            `🎾 <b>DIFF DR LIVE — ${intensity}</b>`,
            ``,
            `${escTg(m.tournament)} | ${escTg(m.court)} (${liveScore} sets${setLabel})`,
            `${escTg(m.player1?.name || 'J1')} vs ${escTg(m.player2?.name || 'J2')}`,
            ``,
            `DR ${escTg(m.player1?.name || 'J1')}: Serve <b>${p1Serve}</b> | Ret <b>${p1Ret}</b>`,
            `DR ${escTg(m.player2?.name || 'J2')}: Serve <b>${p2Serve}</b> | Ret <b>${p2Ret}</b>`,
            `Ratio DR: <b>${Number.isFinite(drBase2?.dr) ? drBase2.dr.toFixed(2) : '–'}</b> | Écart: <b>${Number.isFinite(drGapAbs) ? drGapAbs.toFixed(2) : '–'}</b>`,
            `→ <b>${escTg(dominant)}</b> domine ${escTg(dominated)}${setBonus}`,
          ].filter(Boolean).join('\n');

          const discordEmbed = {
            title: `🎾 Diff DR Live — ${intensity}`,
            description: `**${m.player1?.name || 'J1'}** vs **${m.player2?.name || 'J2'}** · Sets ${liveScore}`,
            color: drGapAbs >= 0.35 ? 0xFF2200 : 0xFF8C00,
            fields: [
              { name: `🎯 ${m.player1?.name || 'J1'}`, value: `Serve: **${p1Serve}**\nReturn: **${p1Ret}**`, inline: true },
              { name: `🎯 ${m.player2?.name || 'J2'}`, value: `Serve: **${p2Serve}**\nReturn: **${p2Ret}**`, inline: true },
              { name: '​', value: '​', inline: true },
              { name: '📊 Ratio DR', value: `**${drBase2.dr.toFixed(2)}**`, inline: true },
              { name: '⚡ Écart DR', value: `**${drGapAbs.toFixed(2)}**`, inline: true },
              { name: '🏆 Dominant', value: dominant, inline: true },
              { name: '🎾 Court', value: m.court || 'N/A', inline: true },
              { name: '🏟️ Tournoi', value: m.tournament || 'N/A', inline: true },
            ],
            footer: { text: `Diff DR Joueurs | src:${_drSrc} | Seuil ${_DR_DIFF_THR} | Cooldown 5min | ${m.tournament}` },
            timestamp: new Date().toISOString(),
          };

          _tnAlertMark(`tndr_diff:${m.id}`); // arme le cooldown (sinon spam chaque poll)
          broadcastTennisLiveAlert(msgHtml, discordEmbed).catch(() => {});
          console.log(`  [Tennis DR Diff] ${m.id} gap=${drGapAbs.toFixed(2)} dominant=${dominant} ratio=${drBase2.dr.toFixed(2)}`);
        }
        // Purge historique DR/set (cap mémoire — matchs terminés)
        if (_tennisDRSetHist.size > 300) _tennisDRSetHist.clear();
      } catch (e) { console.warn('  [Tennis DR Diff alert]', e.message); }
    } catch (e) { /* swallow — pulse best-effort */ }
    const _aiTotal = _aiEnriched + _aiEnrichedOndemand;
    console.log(`  [TennisLive] BSD=${bsd.length} ESPN=${espn.length} merged=${data.length} live=${_liveIds.size}${_aiTotal ? ` serving+${_aiTotal}aiscore` : ''}${_aiOndemand ? ` fetched+${_aiOndemand}aiscore_ondemand` : ''}${BSD_TENNIS_ENABLED ? '' : ' (BSD off)'}`);
    _tennisLiveCache = { ts: Date.now(), data };
    try { verifyPendingTennisAlerts(data); } catch (e) { console.warn('  [TennisAlerts] verifyPending:', e.message); }
    try { verifyPendingFootAlerts(); } catch (e) { console.warn('  [FootAlerts] verifyPending:', e.message); }
    // bd c8zp: cron capture tennis score finals → tennisHistory
    try { archiveFinishedTennisFromLiveCache(data); } catch (e) { console.warn('  [Tennis Archive]', e.message); }
    // bd mpg Phase 2 — On-demand fetch aiscore PBP pour matchs live sans cache.
    // Trigger populate cache → next poll detectAndBroadcastPBPUpdates broadcast SSE.
    try {
      const pbpFetched = await fetchAiscorePBPOnDemand(data);
      if (pbpFetched > 0) console.log(`  [TennisPBP] fetched+${pbpFetched}aiscore_ondemand`);
    } catch (_) { /* swallow */ }
    // bd mpg — Detect & broadcast PBP updates depuis aiscore cache (debounce 30s/matchId).
    try {
      const pbpBroadcasts = detectAndBroadcastPBPUpdates(data);
      if (pbpBroadcasts > 0) console.log(`  [TennisPBP] SSE pbp_update broadcast x${pbpBroadcasts}`);
    } catch (e) { /* swallow — best-effort */ }
    // Warmer background : remplit les caches BSD (pred/calib/rank) HORS chemin
    // requête /tennis/value-bets. Les builders s'auto-gatent (cache 6h/30min)
    // → fetch réel rare. Fire-and-forget, ne bloque jamais le poll.
    if (BSD_TENNIS_ENABLED) {
      // [FIX bug 5o0] Résolution via pont globalThis.__tnWarmers (les symboles
      // directs ne sont pas liés dans ce scope). typeof = safe sur identifiant
      // non déclaré (ne throw pas). Warmer fire-and-forget : ne casse jamais le poll.
      const _w = (globalThis.__tnWarmers) || {};
      const _call = (fn) => { try { return (typeof fn === 'function') ? fn() : Promise.resolve(); } catch (_) { return Promise.resolve(); } };
      Promise.allSettled([
        (_w.fetchBSDTennisPredictions ? _w.fetchBSDTennisPredictions('') : Promise.resolve()),
        _call(_w.buildBSDTennisCalibration),
        _call(_w.buildBSDTennisRankIndex),
        _call(_w._buildTennisSurfaceIndex), // warm index surface TE hors chemin requête
      ]).catch(() => {});
    }
  } catch (e) {
    console.warn('  [Tennis] poll error:', e.message);
  } finally {
    _isFetchingTennis = false;
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
//  TENNIS ODDS — The Odds API (h2h pre-match, ATP/WTA tournaments)
//  Budget cible : free tier 500 credits/mois. 1 credit = 1 market × 1 region par call.
//  Stratégie : discovery /v4/sports (gratuite) + fetch h2h+eu sur sports actifs.
// ═══════════════════════════════════════════════════════════════════════════════

const TENNIS_ODDS_TTL_MS = 4 * 60 * 60 * 1000; // 4h
const TENNIS_ODDS_DISCOVERY_TTL_MS = 24 * 60 * 60 * 1000; // 24h
// Quota Odds API = mensuel : un 429/401 = épuisé. Sans circuit-breaker, le
// cache n'est pas re-stampé → getTennisOddsCache() refire à chaque match →
// spam 429. Cooldown : on coupe les tentatives 6h après un quota hit.
const TENNIS_ODDS_QUOTA_COOLDOWN_MS = 6 * 60 * 60 * 1000; // 6h
// v11.10 — Rate-limit prédictif : quand remaining < 50 → fetch fenêtre J+1
// au lieu de J+7 + n'interroge plus les sports off-season.
const TENNIS_ODDS_LOW_QUOTA_THRESHOLD = 50;
// Alerte Telegram quand quota < 10% du quota mensuel par défaut (500 free / 20k pro)
const TENNIS_ODDS_ALERT_THRESHOLD_RATIO = 0.10;
let _tennisOddsCache = { ts: 0, data: {} };          // { sportKey: [rawMatch...] }
let _activeTennisSports = [];                         // ['tennis_atp_french_open', ...]
let _activeTennisSportsTs = 0;
let _isFetchingTennisOdds = false;
let _tennisOddsQuotaUntil = 0;                        // epoch ms — skip fetch si Date.now() < lui
let _tennisOddsQuotaRemaining = null;                 // null = unknown, sinon int
let _tennisOddsAlertSent = false;                     // anti-spam alerte Telegram

// Discover currently active tennis sport keys from The Odds API.
// /v4/sports is a free endpoint (does not consume request credits).
async function discoverActiveTennisSports() {
  if (!ODDS_API_KEY) return [];
  try {
    const res = await httpsGet(`https://api.the-odds-api.com/v4/sports/?apiKey=${ODDS_API_KEY}&all=false`);
    if (!res || res.status !== 200 || !Array.isArray(res.data)) return [];
    return res.data
      .filter(s => s && s.group === 'Tennis' && s.active === true && !s.has_outrights)
      .map(s => s.key);
  } catch (e) {
    console.warn('  [Tennis Odds] Discovery failed:', e.message);
    return [];
  }
}

async function fetchTennisOddsAPI() {
  if (!ODDS_API_KEY) return {};
  if (_isFetchingTennisOdds) return _tennisOddsCache.data || {};
  // Circuit-breaker quota : tant que le cooldown court, on ne retente pas
  // (zéro HTTP, zéro log). On re-stampe le cache pour que le gate TTL de
  // getTennisOddsCache() ne re-déclenche pas en boucle.
  if (Date.now() < _tennisOddsQuotaUntil) {
    _tennisOddsCache.ts = Date.now();
    return _tennisOddsCache.data || {};
  }
  _isFetchingTennisOdds = true;

  try {
    // Refresh discovery cache once per 24h
    if (_activeTennisSports.length === 0 || Date.now() - _activeTennisSportsTs > TENNIS_ODDS_DISCOVERY_TTL_MS) {
      _activeTennisSports = await discoverActiveTennisSports();
      _activeTennisSportsTs = Date.now();
      if (_activeTennisSports.length > 0) {
        console.log(`  [Tennis Odds] Discovered ${_activeTennisSports.length} active tennis sports: ${_activeTennisSports.join(', ')}`);
      } else {
        console.log('  [Tennis Odds] No active tennis sports right now (off-season or quota issue).');
      }
    }

    const out = {};
    const now = new Date();
    let quotaHit = false;

    // v11.10 — Fenêtre réduite à J+1 en mode low-quota pour économiser
    // les requêtes (matchs lointains rarement utiles vs matchs du jour).
    const lowQuotaMode = (_tennisOddsQuotaRemaining != null && _tennisOddsQuotaRemaining < TENNIS_ODDS_LOW_QUOTA_THRESHOLD);
    const windowDays = lowQuotaMode ? 1 : 7;
    if (lowQuotaMode) {
      console.log(`  [Tennis Odds] ⚠️ Mode low-quota actif (remaining ${_tennisOddsQuotaRemaining}) — fenêtre réduite à J+${windowDays}.`);
    }

    for (const sport of _activeTennisSports) {
      try {
        const query = new URLSearchParams({
          apiKey: ODDS_API_KEY,
          regions: process.env.ODDS_REGIONS || 'eu',
          markets: 'h2h',
          oddsFormat: 'decimal',
          dateFormat: 'iso',
          commenceTimeFrom: formatIsoTimestamp(now),
          commenceTimeTo: formatIsoTimestamp(new Date(now.getTime() + windowDays * 24 * 60 * 60 * 1000)),
        }).toString();

        const res = await httpsGet(`https://api.the-odds-api.com/v4/sports/${sport}/odds/?${query}`);
        if (!res) continue;

        // v11.10 — Capture quota remaining (header x-requests-remaining)
        if (res.headers && res.headers['x-requests-remaining']) {
          const remain = parseInt(res.headers['x-requests-remaining'], 10);
          if (!isNaN(remain)) {
            _tennisOddsQuotaRemaining = remain;
            // Alerte Telegram one-shot quand quota < 10%
            const total = parseInt(res.headers['x-requests-used'], 10) + remain;
            if (!isNaN(total) && total > 0 && (remain / total) < TENNIS_ODDS_ALERT_THRESHOLD_RATIO && !_tennisOddsAlertSent) {
              _tennisOddsAlertSent = true;
              const msg = `⚠️ PariScore — Odds API quota faible : ${remain}/${total} restants (<${Math.round(TENNIS_ODDS_ALERT_THRESHOLD_RATIO * 100)}%). Fetch tennis basculera en mode low-quota (fenêtre J+1).`;
              console.warn(`  [Tennis Odds] ${msg}`);
              try { if (typeof sendTelegramAlert === 'function') sendTelegramAlert(msg); } catch (_) {}
            }
          }
        }

        if (res.status === 401 || res.status === 429) {
          quotaHit = true;
          break;
        }

        if (res.status === 200 && Array.isArray(res.data)) {
          out[sport] = res.data.map(m => ({ ...m, _sport: sport }));
          console.log(`  [Tennis Odds] ${sport} → ${res.data.length} matches`);
        }
      } catch (e) {
        console.warn(`  [Tennis Odds] ${sport} error: ${e.message}`);
      }
    }

    if (!quotaHit) {
      _tennisOddsCache = { ts: Date.now(), data: out };
    } else {
      // Quota épuisé : arme le cooldown 6h + re-stampe le cache (sinon le
      // gate TTL refire à chaque match → spam 429). Log UNE fois par fenêtre.
      const firstHit = Date.now() >= _tennisOddsQuotaUntil;
      _tennisOddsQuotaUntil = Date.now() + TENNIS_ODDS_QUOTA_COOLDOWN_MS;
      const merged = Object.keys(out).length > 0
        ? { ...(_tennisOddsCache.data || {}), ...out }
        : (_tennisOddsCache.data || {});
      _tennisOddsCache = { ts: Date.now(), data: merged };
      if (firstHit) {
        console.warn(`  [Tennis Odds] ⚠️ Quota Odds API épuisé. Fetch tennis suspendu ${TENNIS_ODDS_QUOTA_COOLDOWN_MS / 3600000}h (cotes marché → fallback cote équitable).`);
      }
    }
    return _tennisOddsCache.data || {};
  } finally {
    _isFetchingTennisOdds = false;
  }
}

// Lazy accessor : déclenche un fetch en arrière-plan si cache > TTL.
function getTennisOddsCache() {
  if (Date.now() - _tennisOddsCache.ts > TENNIS_ODDS_TTL_MS) {
    fetchTennisOddsAPI().catch(() => {});
  }
  return _tennisOddsCache.data || {};
}

// Extract best h2h quotes across bookmakers for one match record returned
// by /v4/sports/{tennis_xxx}/odds. Returns { p1:{odds,book}, p2:{odds,book} } or null.
function extractBestTennisH2H(match) {
  if (!match || !Array.isArray(match.bookmakers) || !match.home_team || !match.away_team) return null;
  const p1Name = normName(match.home_team);
  const p2Name = normName(match.away_team);
  let bestP1 = { odds: 0, book: null };
  let bestP2 = { odds: 0, book: null };

  for (const bk of match.bookmakers) {
    const markets = Array.isArray(bk.markets) ? bk.markets : [];
    const h2h = markets.find(m => m && m.key === 'h2h');
    if (!h2h || !Array.isArray(h2h.outcomes)) continue;
    for (const o of h2h.outcomes) {
      if (!o || !o.name || typeof o.price !== 'number') continue;
      const n = normName(o.name);
      if (n === p1Name && o.price > bestP1.odds) bestP1 = { odds: o.price, book: bk.title || bk.key };
      else if (n === p2Name && o.price > bestP2.odds) bestP2 = { odds: o.price, book: bk.title || bk.key };
    }
  }
  if (!bestP1.odds || !bestP2.odds) return null;
  return { p1: bestP1, p2: bestP2 };
}

// Helper : retrouve un match Odds API par paires de joueurs normalisés.
// Utilisé par buildTennisMatchRecord (T2) pour merger BSD + Odds API.
function findTennisOddsForPlayers(player1Name, player2Name) {
  if (!player1Name || !player2Name) return null;
  const cache = getTennisOddsCache();
  const p1 = normName(player1Name);
  const p2 = normName(player2Name);
  for (const sport of Object.keys(cache)) {
    const matches = cache[sport] || [];
    for (const m of matches) {
      const mh = normName(m.home_team);
      const ma = normName(m.away_team);
      if ((mh === p1 && ma === p2) || (mh === p2 && ma === p1)) {
        return { match: m, swapped: mh === p2 };
      }
    }
  }
  return null;
}

