// ── GET /api/v1/live-dashboard/:matchId — Modal V2 data source (BSD sr_stats + Sofa enrichment + momentum synthétique) ──
if (pathname.startsWith('/api/v1/live-dashboard/')) {
  const id = pathname.slice('/api/v1/live-dashboard/'.length);
  if (!id || id === 'undefined') return jsonResponse(res, 400, { error: 'ID invalide' });
  const match = (mockActive && testMatch && testMatch.id === id)
    ? testMatch
    : (db.matches.find(m => m.id === id) || null);
  if (!match) return jsonResponse(res, 404, { error: 'Match non trouvé', id });
  const bsdId = match._bsd_event_id || (id.startsWith('bsd_') ? id.slice(4) : null);
  // bd qe5 Phase 1.5 — incidents fetch parallèle (cache 60s) pour markers SVG momentum
  const [detail, sofaEnrich, incRes] = await Promise.all([
    bsdId ? fetchBSDEventDetail(bsdId) : Promise.resolve(null),
    fetchSofaMicroserviceEnrichment(match).catch(() => null),
    bsdId ? _bsdEnrichFetch('incidents', bsdId).catch(() => null) : Promise.resolve(null),
  ]);
  const payload = buildLiveDashboardPayload(match, detail);
  // Normalisation events[] : minute + type + side (home|away|neutral) + player + score_after
  if (incRes?.data) {
    const raw = incRes.data?.results || incRes.data?.incidents || incRes.data || [];
    if (Array.isArray(raw) && raw.length) {
      payload.events = raw
        .filter(ev => ev && (ev.minute != null || ev.time != null))
        .map(ev => {
          const minute = parseInt(ev.minute ?? ev.time ?? 0, 10) || 0;
          const teamRaw = (ev.team || '').toString().toLowerCase();
          const side = teamRaw === 'home' ? 'home' : (teamRaw === 'away' ? 'away' : 'neutral');
          const type = (ev.type || ev.incident_type || ev.event_type || '').toLowerCase();
          // Classifier en catégories visuelles : goal | card_yellow | card_red | shot_on_target | substitution | other
          let kind = 'other';
          if (/goal|but/.test(type) && !/own_goal|csc/.test(type)) kind = 'goal';
          else if (/own_goal|csc/.test(type)) kind = 'own_goal';
          else if (/yellow|jaune/.test(type)) kind = 'card_yellow';
          else if (/red|rouge/.test(type)) kind = 'card_red';
          else if (/shot_on_target|sot|tir cadre/.test(type)) kind = 'shot_on_target';
          else if (/sub|remplacement/.test(type)) kind = 'substitution';
          return {
            minute,
            kind,
            side,
            type,
            player: ev.player?.name || ev.player_name || null,
            score_after: ev.score ? `${ev.score.home ?? '?'}-${ev.score.away ?? '?'}` : null,
          };
        })
        .filter(ev => ev.minute > 0 && ev.minute <= 130)
        .sort((a, b) => a.minute - b.minute);
    } else {
      payload.events = [];
    }
  } else {
    payload.events = [];
  }
  // Sofa overrides : si Sofa a la donnée, elle prime sur BSD synthétique
  if (sofaEnrich) {
    if (sofaEnrich.possession)        payload.possession        = sofaEnrich.possession;
    if (sofaEnrich.shots)             payload.shots             = sofaEnrich.shots;
    if (sofaEnrich.shots_on_target)   payload.shots_on_target   = sofaEnrich.shots_on_target;
    if (sofaEnrich.shots_off_target)  payload.shots_off_target  = sofaEnrich.shots_off_target;
    if (sofaEnrich.shots_blocked)     payload.shots_blocked     = sofaEnrich.shots_blocked;
    if (sofaEnrich.corners)           payload.corners           = sofaEnrich.corners;
    if (sofaEnrich.fouls)             payload.fouls             = sofaEnrich.fouls;
    if (sofaEnrich.offsides)          payload.offsides          = sofaEnrich.offsides;
    if (sofaEnrich.passes)            payload.passes            = sofaEnrich.passes;
    if (sofaEnrich.key_passes)        payload.key_passes        = sofaEnrich.key_passes;
    if (sofaEnrich.crosses)           payload.crosses           = sofaEnrich.crosses;
    if (sofaEnrich.long_balls)        payload.long_balls        = sofaEnrich.long_balls;
    if (sofaEnrich.tackles)           payload.tackles           = sofaEnrich.tackles;
    if (sofaEnrich.interceptions)     payload.interceptions     = sofaEnrich.interceptions;
    if (sofaEnrich.clearances)        payload.clearances        = sofaEnrich.clearances;
    if (sofaEnrich.saves)             payload.saves             = sofaEnrich.saves;
    if (sofaEnrich.penalties)         payload.penalties         = sofaEnrich.penalties;
    if (sofaEnrich.cards)             payload.cards             = sofaEnrich.cards;
    if (sofaEnrich.xg)                payload.xg                = sofaEnrich.xg;
    if (sofaEnrich.momentum && sofaEnrich.momentum.length) payload.momentum = sofaEnrich.momentum;
    if (sofaEnrich.shotmap && sofaEnrich.shotmap.length)   payload.shotmap  = sofaEnrich.shotmap;
    payload._sofa_event_id = sofaEnrich.sofa_event_id;
    payload._source = `${payload._source || 'bsd'}+sofa`;
  }
  return jsonResponse(res, 200, payload);
}

