// POST /api/v1/admin/backtest-bsd (protégé auth — admin ou premium)
if (pathname === '/api/v1/admin/backtest-bsd' && req.method === 'POST') {
  const user = getAuthUser(req);
  if (!user || (user.role !== 'admin' && user.role !== 'premium')) return jsonResponse(res, 403, { error: 'Accès refusé — Premium requis' });
  if (!BSD_BASE_URL) return jsonResponse(res, 503, { error: 'BSD non configuré' });

  readBodyLimited(req, MAX_BODY_SIZE).then(async body => {
    try {
      const parsed = JSON.parse(body || '{}');
      const days = Math.min(Math.max(parseInt(parsed.days) || 7, 1), 30);
      const now = Date.now();
      const bsdDateCache = new Map();
      let newVerified = 0, alreadyVerified = 0, noScore = 0;
      const report = [];

      for (let d = 1; d <= days; d++) {
        const dateMs = now - d * 86400000;
        const dateStr = formatDateOnly(new Date(dateMs));

        // Fetch BSD matches for this date (cached)
        if (!bsdDateCache.has(dateStr)) {
          const bsdResults = await fetchBSDMatches(dateStr, dateStr);
          bsdDateCache.set(dateStr, bsdResults);
        }
        const bsdDay = bsdDateCache.get(dateStr);
        const finished = bsdDay.filter(bm =>
          bm.home_score !== null && bm.away_score !== null &&
          bm.status !== 'inprogress' && !(bm.status && bm.status.includes('half'))
        );

        for (const bm of finished) {
          const hNorm = normName(bm.home_team), aNorm = normName(bm.away_team);

          // Check if already in history
          const existing = history.find(h => {
            const hh = normName(h.home_team), ha = normName(h.away_team);
            return h.commence_time?.startsWith(dateStr) &&
              (hh.includes(hNorm.split(' ')[0]) || hNorm.includes(hh.split(' ')[0])) &&
              (ha.includes(aNorm.split(' ')[0]) || aNorm.includes(ha.split(' ')[0]));
          });

          if (existing) {
            if (!existing.verified && existing.realScore === null) {
              // Fill missing real score
              existing.realScore = { home: Number(bm.home_score), away: Number(bm.away_score), source: 'bsd' };
              const totalGoals = existing.realScore.home + existing.realScore.away;
              const wasBTTS = existing.realScore.home > 0 && existing.realScore.away > 0;
              const wasOver25 = totalGoals > 2.5;
              if (existing.predicted?.over25 > 55) { accuracy.over25_total++; if (wasOver25) accuracy.over25_correct++; }
              if (existing.predicted?.btts > 55) { accuracy.btts_total++; if (wasBTTS) accuracy.btts_correct++; }
              if (existing.predicted?.bestEdgeValue > 5) {
                accuracy.edge_total++;
                const winner = existing.realScore.home > existing.realScore.away ? existing.home_team : existing.realScore.away > existing.realScore.home ? existing.away_team : 'Nul';
                if (winner === existing.predicted.bestEdge) accuracy.edge_correct++;
              }
              accuracy.total++;
              existing.verified = true;
              existing.retry_at = new Date().toISOString();
              newVerified++;
              report.push({ match: `${bm.home_team} ${bm.home_score}-${bm.away_score} ${bm.away_team}`, date: dateStr, action: 'verified' });
            } else {
              alreadyVerified++;
            }
          } else {
            noScore++;
            // Match in BSD but not in our history — no stored prediction, skip
          }
        }
      }

      if (newVerified > 0) saveHistory();

      return jsonResponse(res, 200, {
        ok: true,
        days_scanned: days,
        new_verified: newVerified,
        already_verified: alreadyVerified,
        bsd_only: noScore,
        accuracy: getAccuracyReport(),
        sample: report.slice(0, 20),
      });
    } catch (e) { return jsonResponse(res, 500, { error: e.message }); }
  }).catch(() => jsonResponse(res, 413, { error: 'Payload trop volumineux' }));
  return;
}
// POST /api/v1/admin/change-password (protégé JWT admin)
if (pathname === '/api/v1/admin/change-password' && req.method === 'POST') {
  const user = getAuthUser(req);
  if (!user || user.role !== 'admin') return jsonResponse(res, 403, { error: 'Accès refusé' });
  readBodyLimited(req, MAX_BODY_SIZE).then(body => {
    try {
      const parsed = JSON.parse(body);
      if (!parsed.current || !parsed.new) return jsonResponse(res, 400, { error: 'current et new requis' });
      if (!verifyPasswordSync(parsed.current, user.hash, user.salt)) return jsonResponse(res, 401, { error: 'Mot de passe actuel incorrect' });
      if (parsed.new.length < 8) return jsonResponse(res, 400, { error: 'Minimum 8 caractères' });
      const { hash, salt } = hashPasswordSync(parsed.new);
      user.hash = hash;
      user.salt = salt;
      user.forceChange = false;
      jsonResponse(res, 200, { ok: true, message: 'Mot de passe modifié' });
    } catch (e) { jsonResponse(res, 400, { error: 'JSON invalide' }); }
  }).catch(() => jsonResponse(res, 413, { error: 'Payload trop volumineux' }));
  return;
}

// ── AFFILIATION ROUTES ──────────────────────────────────────────────
// GET /api/v1/affiliates — Liste des bookmakers affiliés actifs (public)
// Fix E ParisScorebis-amc : wrap try/catch + 200 [] fallback. Sans cela, si
// la query throw (colonne manquante post-migration, sqldb undefined race
// init, …), le handler async ne `return` jamais → nginx attend → 504 Gateway
// Timeout côté client. Cf. front bug bd-6cv « tv-channel + affiliates 504 ».
if (pathname === '/api/v1/affiliates' && req.method === 'GET') {
  try {
    if (!sqldb) return jsonResponse(res, 503, { error: 'DB not ready', items: [] });
    const affiliates = sqldb.prepare(
      'SELECT id, bookmaker, name, affiliate_link, deeplink_template, promo_code, commission_type, commission_rate, priority FROM affiliates WHERE active = 1 ORDER BY priority DESC'
    ).all();
    return jsonResponse(res, 200, affiliates);
  } catch (e) {
    console.error('[/api/v1/affiliates GET]', e.message);
    return jsonResponse(res, 200, []);
  }
}

// POST /api/v1/affiliates — Créer un affilié (admin)
if (pathname === '/api/v1/affiliates' && req.method === 'POST') {
  const user = getAuthUser(req);
  if (!user || user.role !== 'admin') return jsonResponse(res, 403, { error: 'Accès refusé' });
  readBodyLimited(req, MAX_BODY_SIZE).then(body => {
    try {
      const d = JSON.parse(body);
      if (!d.bookmaker || !d.name || !d.affiliate_link) return jsonResponse(res, 400, { error: 'bookmaker, name, affiliate_link requis' });
      const result = sqldb.prepare(`INSERT INTO affiliates (bookmaker, name, affiliate_link, deeplink_template, promo_code, commission_type, commission_rate, active, priority)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`).run(
        d.bookmaker, d.name, d.affiliate_link, d.deeplink_template || null, d.promo_code || null,
        d.commission_type || 'revshare', d.commission_rate || 30, d.active !== undefined ? d.active : 1, d.priority || 0
      );
      return jsonResponse(res, 201, { id: result.lastInsertRowid, ok: true });
    } catch (e) { jsonResponse(res, 400, { error: e.message }); }
  }).catch(() => jsonResponse(res, 413, { error: 'Payload trop volumineux' }));
  return;
}

// PUT /api/v1/affiliates/:id — Modifier un affilié (admin)
if (pathname.match(/^\/api\/v1\/affiliates\/\d+$/) && req.method === 'PUT') {
  const user = getAuthUser(req);
  if (!user || user.role !== 'admin') return jsonResponse(res, 403, { error: 'Accès refusé' });
  const id = parseInt(pathname.split('/').pop());
  readBodyLimited(req, MAX_BODY_SIZE).then(body => {
    try {
      const d = JSON.parse(body);
      const fields = [];
      const values = [];
      for (const [k, v] of Object.entries(d)) {
        if (['bookmaker', 'name', 'affiliate_link', 'deeplink_template', 'promo_code', 'commission_type', 'commission_rate', 'active', 'priority'].includes(k)) {
          fields.push(`${k} = ?`);
          values.push(v);
        }
      }
      if (fields.length === 0) return jsonResponse(res, 400, { error: 'Aucun champ valide' });
      values.push(id);
      sqldb.prepare(`UPDATE affiliates SET ${fields.join(', ')} WHERE id = ?`).run(...values);
      return jsonResponse(res, 200, { ok: true });
    } catch (e) { jsonResponse(res, 400, { error: e.message }); }
  }).catch(() => jsonResponse(res, 413, { error: 'Payload trop volumineux' }));
  return;
}

// DELETE /api/v1/affiliates/:id — Supprimer un affilié (admin)
if (pathname.match(/^\/api\/v1\/affiliates\/\d+$/) && req.method === 'DELETE') {
  const user = getAuthUser(req);
  if (!user || user.role !== 'admin') return jsonResponse(res, 403, { error: 'Accès refusé' });
  const id = parseInt(pathname.split('/').pop());
  sqldb.prepare('DELETE FROM affiliates WHERE id = ?').run(id);
  return jsonResponse(res, 200, { ok: true });
}

// POST /api/v1/affiliate/click — Track un clic affilié
if (pathname === '/api/v1/affiliate/click' && req.method === 'POST') {
  readBodyLimited(req, MAX_BODY_SIZE).then(body => {
    try {
      const d = JSON.parse(body);
      if (!d.affiliate_id || !d.match_id) return jsonResponse(res, 400, { error: 'affiliate_id, match_id requis' });
      const ip = req.socket?.remoteAddress || 'unknown';
      const ua = req.headers['user-agent'] || '';
      sqldb.prepare('INSERT INTO affiliate_clicks (affiliate_id, match_id, user_ip, user_agent) VALUES (?, ?, ?, ?)').run(
        d.affiliate_id, d.match_id, ip, ua
      );
      return jsonResponse(res, 200, { ok: true });
    } catch (e) { jsonResponse(res, 400, { error: e.message }); }
  }).catch(() => jsonResponse(res, 413, { error: 'Payload trop volumineux' }));
  return;
}

// GET /api/v1/affiliate/stats — Stats d'affiliation (admin)
if (pathname === '/api/v1/affiliate/stats') {
  const user = getAuthUser(req);
  if (!user || user.role !== 'admin') return jsonResponse(res, 403, { error: 'Accès refusé' });
  const totalClicks = sqldb.prepare('SELECT COUNT(*) as c FROM affiliate_clicks').get();
  const clicksByAffiliate = sqldb.prepare('SELECT a.bookmaker, a.name, COUNT(c.id) as clicks, MAX(c.clicked_at) as last_click FROM affiliates a LEFT JOIN affiliate_clicks c ON a.id = c.affiliate_id GROUP BY a.id ORDER BY clicks DESC').all();
  const clicksByDay = sqldb.prepare(`SELECT DATE(clicked_at, 'unixepoch') as day, COUNT(*) as clicks FROM affiliate_clicks WHERE clicked_at > strftime('%s','now','-30 days') GROUP BY day ORDER BY day`).all();
  return jsonResponse(res, 200, {
    totalClicks: totalClicks.c,
    byAffiliate: clicksByAffiliate,
    byDay: clicksByDay,
  });
}

// GET /api/v1/affiliate/link/:matchId — Génère le meilleur lien affilié pour un match
if (pathname.startsWith('/api/v1/affiliate/link/') && req.method === 'GET') {
  const matchId = decodeURIComponent(pathname.slice('/api/v1/affiliate/link/'.length));
  let match = db.matches.find(m => m.id === matchId);
  if (!match) match = cachedMatches.find(m => m.id === matchId);
  if (!match) match = cachedMatches.find(m => m.fixture_id == matchId);
  if (!match) return jsonResponse(res, 200, { link: FINAL_FALLBACK });
  const bestAffiliate = sqldb.prepare('SELECT * FROM affiliates WHERE active = 1 ORDER BY priority DESC LIMIT 1').get();
  if (!bestAffiliate) return jsonResponse(res, 404, { error: 'Aucun affilié actif' });
  // Remplacer les placeholders dans deeplink_template
  let link = bestAffiliate.affiliate_link;
  if (bestAffiliate.deeplink_template) {
    const slugify = (s) => s.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
    link = bestAffiliate.deeplink_template
      .replace('{sport}', match.sport || 'soccer')
      .replace('{event_id}', match.id || '')
      .replace('{home}', bestAffiliate.bookmaker === 'coteur' ? slugify(match.home_team) : encodeURIComponent(match.home_team))
      .replace('{away}', bestAffiliate.bookmaker === 'coteur' ? slugify(match.away_team) : encodeURIComponent(match.away_team));
  }
  return jsonResponse(res, 200, {
    id: bestAffiliate.id,
    bookmaker: bestAffiliate.bookmaker,
    name: bestAffiliate.name,
    link: link,
    promo_code: bestAffiliate.promo_code,
  });
}

// ─── bd l9vk Phase 1+5 — affiliate_id-based click route (vs /r/ bookmaker-based) ───
// GET /api/v1/affiliate/click/:affiliateId?source=X&campaign=Y&content=Z
// Effet: lookup affiliate id → INSERT click_id UUID + UTM tags → 302 vers affiliate_link (+ UTM injectés)
// Use-case: CTAs hors-match (banner landing, email, Telegram channel) — pas besoin de matchId.
// Cookie ps_aff_click posé 90j (first-party, GDPR-safe) pour réconciliation Stripe checkout.
const affClickMatch = pathname.match(/^\/api\/v1\/affiliate\/click\/(\d+)$/);
if (affClickMatch && req.method === 'GET') {
  // Sanitize affiliate_id : regex /^\d+$/ déjà appliquée via match. Cap à uint32.
  const affiliateId = parseInt(affClickMatch[1], 10);
  if (!Number.isFinite(affiliateId) || affiliateId < 1 || affiliateId > 2147483647) {
    res.writeHead(400, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('invalid affiliate id');
  }
  let aff;
  try {
    aff = sqldb.prepare('SELECT * FROM affiliates WHERE id = ? AND active = 1').get(affiliateId);
  } catch (e) {
    console.error('[/api/v1/affiliate/click/:id] DB lookup failed:', e.message);
    res.writeHead(500, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('lookup failed');
  }
  if (!aff) {
    res.writeHead(404, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('affiliate not found or inactive');
  }
  const clickId = (crypto.randomUUID ? crypto.randomUUID() : genClickId());
  const source   = String(query.source   || '').slice(0, 60);
  const campaign = String(query.campaign || '').slice(0, 60);
  const content  = String(query.content  || '').slice(0, 60);
  const user = getAuthUser(req);
  // Inject UTM dans URL finale (utm_source/campaign/medium/content)
  let targetUrl = injectAffiliateUTM(aff.affiliate_link, aff.id, source || 'direct', campaign || 'click', content);
  // Append cid pour postback iGaming compat
  try {
    const u2 = new URL(targetUrl);
    if (!u2.searchParams.has('cid')) u2.searchParams.set('cid', clickId);
    targetUrl = u2.toString();
  } catch { /* noop */ }
  // INSERT click best-effort, non-bloquant
  try {
    sqldb.prepare(`INSERT INTO affiliate_clicks
      (affiliate_id, match_id, user_ip, user_agent, click_id, context, utm_source, utm_campaign, user_id)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`).run(
      aff.id,
      query.mid || 'direct',
      req.socket && req.socket.remoteAddress || 'unknown',
      String(req.headers['user-agent'] || '').slice(0, 256),
      clickId,
      `${source || 'direct'}_${campaign || 'click'}`.slice(0, 64),
      source || null,
      campaign || null,
      user && user.userId || null
    );
  } catch (e) {
    console.error('[/api/v1/affiliate/click/:id] INSERT failed:', e.message);
  }
  // Cookie first-party 90j : Stripe checkout pourra lire et envoyer affiliate_click_id en metadata
  const cookieMaxAge = 90 * 24 * 3600;
  res.writeHead(302, {
    'Location': targetUrl,
    'Set-Cookie': `ps_aff_click=${clickId}; Max-Age=${cookieMaxAge}; Path=/; SameSite=Lax; HttpOnly`,
    'Cache-Control': 'no-store, no-cache, must-revalidate',
    'Pragma': 'no-cache',
  });
  return res.end();
}

// ─── bd l9vk Phase 5 — opt-out RGPD tracking affiliate (clear cookie) ───
if (pathname === '/api/v1/affiliate/optout' && (req.method === 'POST' || req.method === 'DELETE')) {
  res.writeHead(200, {
    'Content-Type': 'application/json; charset=utf-8',
    'Set-Cookie': 'ps_aff_click=; Max-Age=0; Path=/; SameSite=Lax; HttpOnly',
  });
  return res.end(JSON.stringify({ optout: true, message: 'Cookie tracking affiliate effacé. Vous ne serez plus tracé.' }));
}

// ─── bd l9vk Phase 5 — admin stats dashboard par affiliate × période ───
// GET /api/v1/admin/affiliate/stats?affiliate_id=X&period=30d
// Réponse: { clicks, conversions, conv_rate, ltv_total, payout_total, roi_pct, by_day[], top_contexts[] }
if (pathname === '/api/v1/admin/affiliate/stats' && req.method === 'GET') {
  const user = getAuthUser(req);
  if (!user || user.role !== 'admin') return jsonResponse(res, 403, { error: 'Accès refusé (admin only)' });
  // Parse period (1d/7d/30d/90d/all) → seconds offset
  const periodRaw = String(query.period || '30d');
  const periodMatch = periodRaw.match(/^(\d{1,3})d$/);
  let sinceClause = '';
  if (periodMatch) {
    const days = Math.min(365, parseInt(periodMatch[1], 10));
    sinceClause = `AND clicked_at >= strftime('%s','now','-${days} days')`;
  } else if (periodRaw !== 'all') {
    return jsonResponse(res, 400, { error: 'period invalide (attendu: 1d-365d ou "all")' });
  }
  // Affiliate filter optionnel
  const affIdRaw = query.affiliate_id;
  let affClause = '';
  if (affIdRaw !== undefined && affIdRaw !== null && affIdRaw !== '') {
    if (!/^\d+$/.test(String(affIdRaw))) {
      return jsonResponse(res, 400, { error: 'affiliate_id invalide (entier requis)' });
    }
    affClause = `AND affiliate_id = ${parseInt(affIdRaw, 10)}`;
  }
  try {
    const summary = sqldb.prepare(`SELECT
        COUNT(*) AS clicks,
        SUM(CASE WHEN converted_at IS NOT NULL THEN 1 ELSE 0 END) AS conversions,
        COALESCE(SUM(payout_cents), 0) AS payout_cents_total,
        COUNT(DISTINCT customer_id) AS unique_customers
      FROM affiliate_clicks
      WHERE 1=1 ${sinceClause} ${affClause}`).get();
    const clicks = summary?.clicks || 0;
    const conversions = summary?.conversions || 0;
    const convRate = clicks > 0 ? (conversions / clicks) * 100 : 0;
    const payoutTotal = (summary?.payout_cents_total || 0) / 100;
    const ltvRow = sqldb.prepare(`SELECT COALESCE(SUM(payout_cents), 0) AS ltv_cents
      FROM affiliate_clicks
      WHERE converted_at IS NOT NULL ${sinceClause} ${affClause}`).get();
    const ltvTotal = (ltvRow?.ltv_cents || 0) / 100;
    const roiPct = payoutTotal > 0 ? ((ltvTotal - payoutTotal) / payoutTotal) * 100 : null;
    const byDay = sqldb.prepare(`SELECT
        DATE(clicked_at, 'unixepoch') AS day,
        COUNT(*) AS clicks,
        SUM(CASE WHEN converted_at IS NOT NULL THEN 1 ELSE 0 END) AS conversions,
        COALESCE(SUM(payout_cents), 0) / 100.0 AS payout_eur
      FROM affiliate_clicks
      WHERE 1=1 ${sinceClause} ${affClause}
      GROUP BY day
      ORDER BY day DESC
      LIMIT 90`).all();
    const topContexts = sqldb.prepare(`SELECT
        COALESCE(context, 'unknown') AS context,
        COUNT(*) AS clicks,
        SUM(CASE WHEN converted_at IS NOT NULL THEN 1 ELSE 0 END) AS conversions
      FROM affiliate_clicks
      WHERE 1=1 ${sinceClause} ${affClause}
      GROUP BY context
      ORDER BY clicks DESC
      LIMIT 10`).all();
    return jsonResponse(res, 200, {
      affiliate_id: affClause ? parseInt(affIdRaw, 10) : null,
      period: periodRaw,
      clicks,
      conversions,
      conv_rate: Math.round(convRate * 100) / 100,
      ltv_total: ltvTotal,
      payout_total: payoutTotal,
      unique_customers: summary?.unique_customers || 0,
      roi_pct: roiPct !== null ? Math.round(roiPct * 100) / 100 : null,
      by_day: byDay,
      top_contexts: topContexts,
      generated_at: new Date().toISOString(),
    });
  } catch (e) {
    console.error('[/api/v1/admin/affiliate/stats]', e.message);
    return jsonResponse(res, 500, { error: 'Erreur agrégation stats', detail: e.message });
  }
}

// ─── GET /r/ — 1st-party redirect anti-AdBlock (Niveau 3, endpoint anodin) ───
// Params: b=bookmaker, c=context, mid=matchId, sp=sport, lg=league, m=market, s=selection
// Effet: lookup affiliate → compose sub-id → INSERT click → 302 vers URL finale (avec pid/bid/subid/cid GA)
// Sécurité: aucun cookie posé côté pariscore.fr, GDPR-safe by-design.
if (pathname === '/r/' || pathname === '/r') {
  if (req.method !== 'GET') {
    res.writeHead(405, { 'Allow': 'GET' });
    return res.end();
  }
  const bookmaker = String(query.b || '').toLowerCase().trim();
  if (!bookmaker) {
    res.writeHead(400, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('missing b param');
  }
  let aff;
  try {
    if (bookmaker === 'best' || bookmaker === 'auto') {
      // Fallback meilleur affilié actif (priority DESC) — utile pour CTA contextuels qui veulent
      // que la prio serveur (Coteur/GA/direct) tranche, pas le client.
      aff = sqldb.prepare('SELECT * FROM affiliates WHERE active = 1 ORDER BY priority DESC LIMIT 1').get();
    } else {
      aff = sqldb.prepare('SELECT * FROM affiliates WHERE bookmaker = ? AND active = 1').get(bookmaker);
    }
  } catch (e) {
    console.error('[/r/] DB lookup failed:', e.message);
    res.writeHead(500, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('lookup failed');
  }
  if (!aff) {
    res.writeHead(404, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('affiliate not found');
  }
  const user = getAuthUser(req);
  const clickId = genClickId();
  const subid = composeSubId(aff.subid_template, {
    userId:    user && user.userId ? `u${user.userId}` : 'anon',
    sport:     query.sp,
    league:    query.lg,
    matchId:   query.mid,
    context:   query.c,
    market:    query.m,
    selection: query.s,
  });
  const targetUrl = buildAffiliateRedirectUrl(aff, subid, clickId);
  if (!targetUrl) {
    res.writeHead(500, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('affiliate URL build failed');
  }
  // INSERT click row best-effort — ne bloque pas le redirect si erreur
  try {
    sqldb.prepare(`INSERT INTO affiliate_clicks
      (affiliate_id, match_id, user_ip, user_agent, click_id, subid, sport, league, context, market, selection, user_id)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`).run(
      aff.id,
      query.mid || 'unknown',
      req.socket && req.socket.remoteAddress || 'unknown',
      req.headers['user-agent'] || '',
      clickId,
      subid,
      query.sp || null,
      query.lg || null,
      query.c  || null,
      query.m  || null,
      query.s  || null,
      user && user.userId || null
    );
  } catch (e) {
    console.error('[/r/] click INSERT failed:', e.message);
  }
  res.writeHead(302, {
    'Location': targetUrl,
    'Cache-Control': 'no-store, no-cache, must-revalidate',
    'Pragma': 'no-cache',
  });
  return res.end();
}

// ─── /cb/ — S2S postback Gambling-Affiliation (conversion ingest) ────────────
// Méthode: GET ou POST  (GA envoie souvent en GET, certains réseaux POST — on accepte les deux)
// Params:
//   token   = secret partagé (env GA_POSTBACK_TOKEN) — sinon route 503
//   cid     = click_id (UUID renvoyé par /r/ — clé unique idempotence)
//   payout  = montant conversion EUR (float, ex "12.50") OU centimes int (auto-detect)
//   type    = 'cpa' | 'revshare' | 'cpl' | 'hybrid' (optionnel, déduit sinon)
//   subid   = fallback si cid non fourni (lookup via subid)
// Réponse: 200 'OK' (ack postback) ou status d'erreur en texte brut.
// Idempotence: UPDATE WHERE converted_at IS NULL → replay = no-op silencieux.
if (pathname === '/cb/' || pathname === '/cb') {
  if (req.method !== 'GET' && req.method !== 'POST') {
    res.writeHead(405, { 'Allow': 'GET, POST' });
    return res.end();
  }
  const expectedToken = process.env.GA_POSTBACK_TOKEN;
  if (!expectedToken) {
    console.error('[/cb/] GA_POSTBACK_TOKEN not set — postback disabled');
    res.writeHead(503, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('postback disabled');
  }
  const providedToken = String(query.token || '');
  // Comparaison time-safe pour éviter timing attack
  if (providedToken.length !== expectedToken.length ||
      !crypto.timingSafeEqual(Buffer.from(providedToken), Buffer.from(expectedToken))) {
    console.warn('[/cb/] token mismatch from', req.socket && req.socket.remoteAddress);
    res.writeHead(401, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('unauthorized');
  }
  const cid = String(query.cid || '').trim();
  const subidFallback = String(query.subid || '').trim();
  if (!cid && !subidFallback) {
    res.writeHead(400, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('missing cid or subid');
  }
  // Parse payout — accepte "12.50" (EUR) ou "1250" (cents) — heuristique: contient '.' → EUR
  let payoutCents = 0;
  const payoutRaw = String(query.payout || '0').trim();
  if (payoutRaw.includes('.') || payoutRaw.includes(',')) {
    payoutCents = Math.round(parseFloat(payoutRaw.replace(',', '.')) * 100);
  } else {
    payoutCents = parseInt(payoutRaw, 10) || 0;
  }
  if (!Number.isFinite(payoutCents) || payoutCents < 0) payoutCents = 0;
  const conversionType = String(query.type || 'cpa').toLowerCase().slice(0, 16);
  // UPDATE idempotent : WHERE converted_at IS NULL → replay = 0 rows
  try {
    let info;
    if (cid) {
      info = sqldb.prepare(`UPDATE affiliate_clicks
        SET converted_at = strftime('%s','now'), payout_cents = ?, conversion_type = ?
        WHERE click_id = ? AND converted_at IS NULL`).run(payoutCents, conversionType, cid);
    } else {
      // Fallback subid (match le plus récent non converti)
      info = sqldb.prepare(`UPDATE affiliate_clicks
        SET converted_at = strftime('%s','now'), payout_cents = ?, conversion_type = ?
        WHERE id = (
          SELECT id FROM affiliate_clicks WHERE subid = ? AND converted_at IS NULL
          ORDER BY clicked_at DESC LIMIT 1
        )`).run(payoutCents, conversionType, subidFallback);
    }
    if (info.changes === 0) {
      // Click introuvable OU déjà converti — log mais retour OK (GA n'a pas à savoir)
      console.warn('[/cb/] no row updated — cid=', cid, 'subid=', subidFallback, '(unknown or replay)');
    } else {
      console.log('[/cb/] conversion ingested — cid=', cid || `subid:${subidFallback}`, 'payout_cents=', payoutCents, 'type=', conversionType);
    }
  } catch (e) {
    console.error('[/cb/] UPDATE failed:', e.message);
    res.writeHead(500, { 'Content-Type': 'text/plain; charset=utf-8' });
    return res.end('update failed');
  }
  // Ack standard postback iGaming : "OK" en texte brut
  res.writeHead(200, { 'Content-Type': 'text/plain; charset=utf-8', 'Cache-Control': 'no-store' });
  return res.end('OK');
}

