try { globalThis.__tennisVBWarm = buildTennisValueBets; } catch (_) { /* noop */ }

// ── BSD Tennis Predictions (ML CatBoost) — bulk → Map (PAS de N+1) ───────────
// Branche les prédictions BSD au tableau : proba ML, confiance, O/U sets/jeux,
