    level, accuracy: acc != null ? parseFloat((acc * 100).toFixed(1)) : null,
    sample: n, ci_low: parseFloat((low * 100).toFixed(1)),
    surface_acc: s && s.n >= 20 ? parseFloat((s.acc * 100).toFixed(1)) : null,
    surface_n: s ? s.n : 0,
