// W6 (bd q1w5) — Upcoming matches feed pour cron_sps_updater.py Python sidecar.
// Contract: .context/sps_pipeline_contract.md. Réutilise buildTennisValueBets (cache
// VB chaud) puis filtre [now+lookahead_min_h, now+lookahead_max_h] + surface ∈
// {clay,grass,hard} + tour optionnel. Renvoie player IDs sources pour SPS join sur
// tennis_matches_internal.{winner,loser}_player_id.
//
// Caps & telemetry — module-scope refs (voir module-scope SPS_UPCOMING_* declarations
// pour hoisting hors handler — sinon TDZ vs /api/v1/sources/health qui les lit en amont).
// Voir rapport QA .context/test-report-w6-tennis-upcoming.md
//   W1 405 vs 404 ↓  W2 whitelist tour ↓  W3 cap max ↓  W4 dynamic scan ↓  W5 token opt-in ↓
if (pathname === '/api/v1/tennis/upcoming') {
  // W1 — 405 instead of fallthrough 404 for non-GET.
  if (req.method !== 'GET') {
    res.setHeader('Allow', 'GET');
    return jsonResponse(res, 405, { error: 'method_not_allowed', allow: 'GET' });
  }
  // W5 — opt-in internal token. Active uniquement si SPS_INTERNAL_TOKEN env set.
  if (process.env.SPS_INTERNAL_TOKEN) {
    const sent = req.headers['x-pariscore-internal-token'];
    if (sent !== process.env.SPS_INTERNAL_TOKEN) {
      return jsonResponse(res, 401, { error: 'unauthorized', hint: 'missing or invalid x-pariscore-internal-token header' });
    }
  }
  const _t0 = Date.now();
  SPS_UPCOMING_TELEMETRY.calls_total += 1;
  const _minRaw = parseInt(query.lookahead_min_h, 10);
  const _maxRaw = parseInt(query.lookahead_max_h, 10);
  const lookaheadMinH = Math.max(0, Math.min(SPS_UPCOMING_CAP_HOURS, Number.isFinite(_minRaw) ? _minRaw : 24));
  const lookaheadMaxH = Math.max(lookaheadMinH, Math.min(SPS_UPCOMING_CAP_HOURS, Number.isFinite(_maxRaw) ? _maxRaw : 36));
  // W2 — whitelist tour (ignore non-ATP/WTA silently to keep idempotent for clients).
  const _tourRaw = String(query.tour || '').toUpperCase();
  const tourFilter = (_tourRaw === 'ATP' || _tourRaw === 'WTA') ? _tourRaw : '';
  const nowMs = Date.now();
  const loMs = nowMs + lookaheadMinH * 3600_000;
  const hiMs = nowMs + lookaheadMaxH * 3600_000;
  // W4 — scan dynamique. Couvre tous les jours UTC chevauchant [loMs, hiMs] + 1
  // jour de marge pour fuseaux. Cap 8 jours (= SPS_UPCOMING_CAP_HOURS / 24 + 1).
  const datesCount = Math.min(8, Math.ceil(lookaheadMaxH / 24) + 1);
  const dates = [];
  for (let offset = 0; offset < datesCount; offset++) {
    const d = new Date(nowMs + offset * 86_400_000);
    dates.push(d.toISOString().slice(0, 10));
  }
  const collected = new Map(); // id → raw match
  for (const d of dates) {
    let dayOut;
    try { dayOut = await buildTennisValueBets({ date: d }); } catch (_) { continue; }
    if (!dayOut || dayOut.status !== 200) continue;
    if (dayOut.body && dayOut.body.meta && dayOut.body.meta.loading === false) {
      SPS_UPCOMING_TELEMETRY.cache_hits += 1;  // best-effort heuristic
    }
    for (const m of (dayOut.body && dayOut.body.matches) || []) {
      if (m && m.id != null && !collected.has(m.id)) collected.set(m.id, m);
    }
  }
  const matches = [];
  for (const m of collected.values()) {
    const startMs = m.start_time ? Date.parse(m.start_time) : NaN;
    if (!Number.isFinite(startMs) || startMs < loMs || startMs > hiMs) continue;
    const surface = String(m.surface || '').toLowerCase();
    if (surface !== 'clay' && surface !== 'grass' && surface !== 'hard') continue;
    const tour = String(m.tour || 'ATP').toUpperCase();
    if (tourFilter && tour !== tourFilter) continue;
    const p1 = m.player1 || {};
    const p2 = m.player2 || {};
    if (p1.id == null || p2.id == null) continue;
    matches.push({
      id: String(m.id),
      surface,
      tour,
      home_player_id: String(p1.id),
      away_player_id: String(p2.id),
      commence_time: new Date(startMs).toISOString(),
      tourney_name: (m.tournament && (m.tournament.name || m.tournament)) || null,
      round: m.round || m.round_name || null,
      best_of: m.best_of || null,
      home_player_name: p1.name || p1.short_name || null,
      away_player_name: p2.name || p2.short_name || null,
    });
  }
  matches.sort((a, b) => a.commence_time.localeCompare(b.commence_time));
  const warnings = [];
  if (Number.isFinite(_maxRaw) && _maxRaw > SPS_UPCOMING_CAP_HOURS) {
    warnings.push('lookahead_max_h_capped');
  }
  if (_tourRaw && !tourFilter) {
    warnings.push('tour_filter_ignored');
  }
  const latencyMs = Date.now() - _t0;
  SPS_UPCOMING_TELEMETRY.last_call_at = new Date(nowMs).toISOString();
  SPS_UPCOMING_TELEMETRY.last_latency_ms = latencyMs;
  SPS_UPCOMING_TELEMETRY.last_status = 200;
  return jsonResponse(res, 200, {
    matches,
    meta: {
      now_utc: new Date(nowMs).toISOString(),
      lookahead_min_h: lookaheadMinH,
      lookahead_max_h: lookaheadMaxH,
      tour_filter: tourFilter || null,
      dates_scanned: dates,
      total: matches.length,
      latency_ms: latencyMs,
      warnings,
    },
  });
}
// SPS batch endpoint — GET /api/v1/sps?ids=m1,m2,m3 (bd q1w5 R1).
// Reads player_surface_scores for up to N match_ids in one call. Eliminates the
// N+1 fetch pattern of the per-match endpoint when the UI renders 150+ rows.
// Response: { results: { match_id: [...players] | null }, count, missing[] }
if (pathname === '/api/v1/sps' && req.method === 'GET') {
  const idsRaw = String(query.ids || '').trim();
  if (!idsRaw) {
    return jsonResponse(res, 400, { error: 'ids_required', detail: 'comma-separated match_ids in ?ids=' });
  }
  const ids = idsRaw.split(',').map(s => s.trim()).filter(Boolean);
  // Cap at 250 to keep response <100KB and avoid URL/query parser limits.
  const SPS_BATCH_CAP = 250;
  if (ids.length > SPS_BATCH_CAP) {
    return jsonResponse(res, 400, { error: 'too_many_ids', cap: SPS_BATCH_CAP, requested: ids.length });
  }
  // Validate each id with the same allowlist as the per-match route.
  const allowed = /^[A-Za-z0-9_\-:.]+$/;
  const validIds = ids.filter(id => id.length <= 128 && allowed.test(id));
  const rejectedCount = ids.length - validIds.length;
  if (!validIds.length) {
    return jsonResponse(res, 400, { error: 'no_valid_ids', rejected: rejectedCount });
  }
  try {
    const placeholders = validIds.map(() => '?').join(',');
    const rows = sqldb.prepare(`
      SELECT player_id, surface, circuit, sps, aptitude_score,
             confidence_full, matches_played, computed_at, match_id
        FROM player_surface_scores
       WHERE match_id IN (${placeholders})
       ORDER BY match_id, player_id ASC
    `).all(...validIds);
    const now = Date.now();
    const grouped = Object.create(null);
    for (const id of validIds) grouped[id] = null;
    for (const r of rows) {
      if (!grouped[r.match_id]) grouped[r.match_id] = [];
      grouped[r.match_id].push({
        player_id: r.player_id,
        surface: r.surface,
        circuit: r.circuit,
        sps: r.sps != null ? Math.round(r.sps * 100) / 100 : null,
        aptitude_score: r.aptitude_score != null ? Math.round(r.aptitude_score * 100) / 100 : null,
        confidence_full: !!r.confidence_full,
        matches_played: r.matches_played,
        computed_at: new Date(r.computed_at).toISOString(),
        age_ms: now - r.computed_at,
      });
    }
    const missing = validIds.filter(id => grouped[id] === null);
    return jsonResponse(res, 200, {
      results: grouped,
      count: rows.length,
      requested: validIds.length,
      missing,
      rejected: rejectedCount,
    });
  } catch (e) {
    console.warn('[/api/v1/sps batch]', e.message);
    return jsonResponse(res, 500, { error: 'sps_batch_failed', detail: e.message });
  }
}
// Reject method mismatch on batch path (otherwise falls through to startsWith path).
if (pathname === '/api/v1/sps') {
  res.setHeader('Allow', 'GET');
  return jsonResponse(res, 405, { error: 'method_not_allowed', allow: 'GET' });
}
// SPS read endpoint — GET /api/v1/sps/:matchId (bd q1w5 task #3).
// Reads player_surface_scores rows for a given match, returns the 2 player SPS
// payloads (or 404 if neither found). Consumer = UI Tennis Value Bets _tvbPFRow.
// Idempotent + no side effects. Pro Tennis gate exempted (alignée /upcoming W6).
if (pathname.startsWith('/api/v1/sps/')) {
  if (req.method !== 'GET') {
    res.setHeader('Allow', 'GET');
    return jsonResponse(res, 405, { error: 'method_not_allowed', allow: 'GET' });
  }
  const rawId = decodeURIComponent(pathname.slice('/api/v1/sps/'.length)).trim();
  if (!rawId || rawId.length > 128 || !/^[A-Za-z0-9_\-:.]+$/.test(rawId)) {
    return jsonResponse(res, 400, { error: 'invalid_match_id', detail: 'match_id alnum + _ - : . only, max 128 chars' });
  }
  try {
    const rows = sqldb.prepare(`
      SELECT player_id, surface, circuit, sps, aptitude_score,
             confidence_full, matches_played, computed_at
        FROM player_surface_scores
       WHERE match_id = ?
       ORDER BY player_id ASC
    `).all(rawId);
    if (!rows.length) {
      return jsonResponse(res, 404, {
        error: 'sps_not_found',
        match_id: rawId,
        hint: 'cron_sps_updater.py may not have processed this match yet. Wait next cron cycle or trigger manually with PARISCORE_SPS_DRY_RUN=0.',
      });
    }
    const now = Date.now();
    const players = rows.map(r => ({
      player_id: r.player_id,
      surface: r.surface,
      circuit: r.circuit,
      sps: r.sps != null ? Math.round(r.sps * 100) / 100 : null,
      aptitude_score: r.aptitude_score != null ? Math.round(r.aptitude_score * 100) / 100 : null,
      confidence_full: !!r.confidence_full,
      matches_played: r.matches_played,
      computed_at: new Date(r.computed_at).toISOString(),
      age_ms: now - r.computed_at,
    }));
    return jsonResponse(res, 200, {
      match_id: rawId,
      count: players.length,
      players,
    });
  } catch (e) {
    console.warn('[/api/v1/sps]', e.message);
    return jsonResponse(res, 500, { error: 'sps_lookup_failed', detail: e.message });
  }
}
// AI-AL Tennis — analyse Gemini "Deep Data" formatée Telegram. Lookup match via buildTennisValueBets.
if (pathname.startsWith('/api/v1/ai/tennis-analyze/') && req.method === 'GET') {
  const matchId = decodeURIComponent(pathname.split('/api/v1/ai/tennis-analyze/')[1] || '').trim();
  console.log('[AI TENNIS] Requête reçue pour le match ID: ' + matchId);
  if (!GEMINI_API_KEY) return jsonResponse(res, 503, { error: 'Clé Gemini non configurée' });
  if (!matchId) return jsonResponse(res, 400, { error: 'matchId requis' });

  const cacheKey = `deep_tennis_v1_${matchId}`;
  const cached = getCachedAIAnalysis(cacheKey);
  if (cached?.text) {
    console.log(`  [TennisAI] HIT cache — ${matchId}`);
    return jsonResponse(res, 200, { text: cached.text, provider: cached.provider || 'cache', _from_cache: true });
  }

  let match = null;
  try {
    const out = await buildTennisValueBets({});
    const list = (out && out.body && Array.isArray(out.body.matches)) ? out.body.matches : [];
    match = list.find(m => String(m.id) === String(matchId));
  } catch (e) {
    console.warn('  [TennisAI] buildTennisValueBets erreur:', e.message);
  }
  if (!match) return jsonResponse(res, 404, { error: 'Match tennis non trouvé', matchId });

  const p1 = (match.player1 && match.player1.name) || '—';
  const p2 = (match.player2 && match.player2.name) || '—';

  // bd p2if Phase 3 — Press context Tennis (RSS L'Equipe Tennis / BBC Tennis / ESPN Tennis / TWUSA)
  // 5s timeout fallback : si feeds lents, prompt fallback narrative (back-compat).
  let pressCtxTennis = null;
  try {
    pressCtxTennis = await Promise.race([
      fetchPressContext(p1, p2, 'tennis'),
      new Promise(r => setTimeout(() => r(null), 5000)),
    ]);
  } catch (e) { console.warn('  [TennisAI] fetchPressContext KO:', e.message); }
  const p1Country = (match.player1 && match.player1.country) || '';
  const p2Country = (match.player2 && match.player2.country) || '';
  const tournament = match.tournament || '—';
  const round = match.round || '';
  const surface = match.surface || 'Surface non précisée';
  const tour = match.tour || '—';
  const court = match.court || '';
  const startTime = match.start_time
    ? new Date(match.start_time).toLocaleString('fr-FR', { timeZone: 'Europe/Paris', dateStyle: 'full', timeStyle: 'short' })
    : '—';

  const odds = match.odds || {};
  const fair = match.fair || {};
  const edge = match.edge || {};
  const evModel = match.ev_model || {};
  const bestEv = match.best_ev_model || {};
  const elo = (match.predictions && match.predictions.elo) || null;
  const blended = (match.predictions && match.predictions.blended) || null;
  const setProbs = (match.predictions && match.predictions.set_probs) || null;

  const fmtPct = (v) => (v == null ? '—' : (typeof v === 'number' ? (v <= 1 ? (v * 100).toFixed(1) + '%' : safeFixed(v, 1) + '%') : '—'));
  const dataBlock = `
[DONNÉES DU MATCH FOURNIES PAR PARISCORE]
Tournoi : ${tournament}${round ? ' — ' + round : ''}
Tour : ${tour}${court ? ' · Court : ' + court : ''}
Surface : ${surface}
Date/Heure (Paris) : ${startTime}

[JOUEURS]
${p1}${p1Country ? ' (' + p1Country + ')' : ''}
${p2}${p2Country ? ' (' + p2Country + ')' : ''}

[COTES BOOKMAKERS H2H]
${p1} : ${odds.p1 ? odds.p1.odds + ' (' + (odds.p1.book || '—') + ')' : '—'}
${p2} : ${odds.p2 ? odds.p2.odds + ' (' + (odds.p2.book || '—') + ')' : '—'}

[PROBABILITÉS DEVIGED (Shin-Hurley)]
${p1} : ${fair.p1 != null ? safeFixed(fair.p1, 1) + '%' : '—'} | ${p2} : ${fair.p2 != null ? safeFixed(fair.p2, 1) + '%' : '—'} | Marge book : ${fair.margin != null ? safeFixed(fair.margin, 2) + '%' : '—'}

[ELO SURFACE-SPLIT]
${p1} : ${elo && elo.p1_elo != null ? Math.round(elo.p1_elo) : '—'}
${p2} : ${elo && elo.p2_elo != null ? Math.round(elo.p2_elo) : '—'}
P(${p1} gagne) Elo : ${elo ? fmtPct(elo.p1) : '—'}

[PROBABILITÉ BLENDED (Elo + BSD ML si dispo)]
${p1} : ${blended ? fmtPct(blended.p1) : '—'} | ${p2} : ${blended ? fmtPct(blended.p2) : '—'}

[EV MODÈLE vs MARCHÉ]
${p1} EV : ${evModel.p1 != null ? safeFixed(evModel.p1, 2) + '%' : '—'}
${p2} EV : ${evModel.p2 != null ? safeFixed(evModel.p2, 2) + '%' : '—'}
Best EV : ${bestEv.side === 'p1' ? p1 : (bestEv.side === 'p2' ? p2 : '—')} ${bestEv.ev != null ? safeFixed(bestEv.ev, 2) + '%' : '—'} @ cote ${bestEv.odds ?? '—'} (${bestEv.book ?? '—'})

[MARKOV — PROBABILITÉS DE SET]
P(2-0) : ${setProbs ? fmtPct(setProbs.p_2_0) : '—'} | P(2-1) : ${setProbs ? fmtPct(setProbs.p_2_1) : '—'}
P(0-2) : ${setProbs ? fmtPct(setProbs.p_0_2) : '—'} | P(1-2) : ${setProbs ? fmtPct(setProbs.p_1_2) : '—'}
${(pressCtxTennis && pressCtxTennis.articleCount > 0) ? `
[REVUE DE PRESSE REELLE — ${pressCtxTennis.articleCount} articles via ${(pressCtxTennis.sourceNames || []).join(', ')}]
${pressCtxTennis.text}
[FIN REVUE DE PRESSE REELLE]
` : ''}`;

  const _pressTennisInstruction = (pressCtxTennis && pressCtxTennis.articleCount > 0)
    ? `PRIORITE ABSOLUE — La section [REVUE DE PRESSE REELLE] ci-dessous contient ${pressCtxTennis.articleCount} articles réels. Au minimum 3 des 5 items de la section "📰 REVUE DE PRESSE" doivent être grounded sur ces articles : mets le nom du média en gras puis paraphrase l'angle/dynamique évoqué. Complete avec narratifs probables si besoin.`
    : `Tu n'as pas accès à une recherche web en direct. Génère 5 narratifs médiatiques pertinents et plausibles que la presse sportive aurait produits sur ce match.`;

  const systemPrompt = `Agis comme un expert en paris sportifs (Tennis) et un data analyst. Je vais te fournir les données d'un match (avec les cotes, les joueurs, et parfois la météo/horaire). Génère une analyse "Deep Data" et rédige un message prêt à être publié sur Telegram.
     CONTRAINTES STRICTES :
     1. Ne mentionne JAMAIS et n'utilise JAMAIS de sources de données spécifiques externes comme "Tennis Abstract".
     2. Le message final doit être intégralement encapsulé dans un bloc de code brut (\`\`\`text ... \`\`\`) pour que je puisse le copier facilement sans casser le formatage.
     3. Le ton doit être professionnel, analytique et orienté "Value Bet" (Trader).
     STRUCTURE OBLIGATOIRE DU MESSAGE TELEGRAM :
     - TITRE : Accrocheur, avec le nom du tournoi, le stade de la compétition et des émojis.
     - INTRO : Courte présentation du contexte et des cotes affichées.
     - 📊 DEEP DATA & PROJECTIONS : Estime de manière cohérente pour les deux joueurs : Le PowerScore (sur 100), La probabilité de victoire finale du tournoi (W%), Le principal atout sur cette surface précise.
     - 📰 REVUE DE PRESSE (AVIS MÉDIAS) : ${_pressTennisInstruction} Appuie-toi sur le tournoi, la surface, les nationalités, le ranking et la forme récente des joueurs.
       Sélectionne les 5 médias selon les nationalités des joueurs (panel international par défaut si les nationalités sont mixtes/inconnues : **L'Équipe**, **Marca**, **Sky Sports**, **ESPN**, **TalkSport**). Adapte si pertinent : France (L'Équipe, Eurosport), Espagne (Marca, AS), UK (Sky Sports, BBC Sport, The Guardian), USA (ESPN, Tennis Channel), Italie (Gazzetta dello Sport, Corriere dello Sport), Allemagne (Kicker, Bild), Australie (Wide World of Sports).
       Format strict, 5 items numérotés sur 1 à 2 lignes maximum chacun :
       1. **[Nom du Média]** : "Citation ou analyse résumée sur la dynamique d'un des deux joueurs (forme, surface, head-to-head, mental)."
       2. **[Nom du Média]** : "..."
       3. **[Nom du Média]** : "..."
       4. **[Nom du Média]** : "..."
       5. **[Nom du Média]** : "..."
       Varie les angles : forme actuelle, performance sur la surface, head-to-head, pression psychologique, value bet débattu, tactique attendue (service/retour, fond de court vs filet).

     - 💰 TOP 3 PARIS À JOUER : Propose 3 paris pertinents basés sur les cotes ou estimés : 1. Le Bankroll Builder (Pari très "safe") + Analyse courte. 2. La Value (Le meilleur rapport risque/gain) + Analyse courte. 3. Le Risk (Grosse cote / Pari fun) + Analyse courte.
     - ⚠️ L'AVIS DU TRADER : Un avertissement ou un conseil final sur le piège à éviter dans ce match.

${dataBlock}`;

  try {
    console.log(`  [TennisAI] Appel Gemini — ${p1} vs ${p2}`);
    const gemRes = await httpsPost(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_API_KEY}`,
      {
        contents: [{ parts: [{ text: systemPrompt }] }],
        safetySettings: GEMINI_SAFETY_SETTINGS,
        generationConfig: { temperature: 0.8, maxOutputTokens: 4096 },
      }
    );
    let text = '';
    let provider = 'gemini';
    if (gemRes.status === 200) {
      text = (gemRes.data && gemRes.data.candidates && gemRes.data.candidates[0] && gemRes.data.candidates[0].content && gemRes.data.candidates[0].content.parts && gemRes.data.candidates[0].content.parts[0] && gemRes.data.candidates[0].content.parts[0].text) || '';
    } else {
      console.warn(`  [TennisAI] Gemini KO (${gemRes.status}) — tentative fallback providers`);
    }
    // Fallback : Groq / Grok / OpenRouter si Gemini KO ou vide.
    if (!text) {
      for (const prov of AI_DEEP_PROVIDERS) {
        if (prov.type !== 'openai') continue;
        try {
          console.log(`  [TennisAI] Fallback → ${prov.name}`);
          const r = await httpsPost(`https://${prov.host}${prov.path}`, {
            model: prov.model,
            messages: [{ role: 'user', content: systemPrompt }],
            temperature: 0.8,
            max_tokens: 4096,
          }, {
            'Authorization': `Bearer ${prov.key}`,
            'HTTP-Referer': 'https://pariscore.io',
            'X-Title': 'PariScore AI-AL Tennis',
          });
          if (r.status === 200) {
            const t = (r.data && r.data.choices && r.data.choices[0] && r.data.choices[0].message && r.data.choices[0].message.content) || '';
            if (t) { text = t; provider = prov.name; break; }
          } else {
            console.warn(`  [TennisAI] ${prov.name} → HTTP ${r.status}`);
          }
        } catch (provErr) {
          console.warn(`  [TennisAI] ${prov.name} → ${provErr.message}`);
        }
      }
    }
    if (!text) {
      if (gemRes.status !== 200) return jsonResponse(res, gemRes.status, gemRes.data);
      return jsonResponse(res, 500, { error: 'Tous les providers IA ont échoué ou renvoyé une réponse vide' });
    }
    saveAIAnalysisToCache(cacheKey, { text, provider });
    console.log(`  [TennisAI] OK via ${provider} — ${text.length} chars`);
    return jsonResponse(res, 200, { text, provider });
  } catch (e) {
    console.error('  [TennisAI] Erreur:', e.message);
    return jsonResponse(res, 500, { error: e.message });
  }
}

