// ─── BSD MCP Enrichissements onglet Foot (bd 8oov) ──────────────────────────
// Proxies BSD pour lineups, shotmap, incidents, predictions ML, polymarket, broadcasts.
// Pattern: /api/v1/bsd/<kind>/<matchId>  (matchId = id frontend OU _bsd_event_id direct)
// Gate: footPro (déjà appliqué par srvPlanGate). Cache: api_cache sqlite (TTL adaptés).
// Format réponse: { source:'bsd', event_id, data, cached:bool, fetched_at }
// Safe-fail: retourne 200 + data:null si BSD upstream KO (UI affiche placeholder).
// bd 3vn — TTL lookup via getCacheTTL (cache_profiles.json + env override).
// Fallbacks hardcoded préservés pour ZÉRO régression si profile.json absent.
const DEBUG_BSD = !!process.env.DEBUG_BSD;
const BSD_ENRICH_TTL = new Proxy({}, {
  get(_t, kind) {
    switch (kind) {
      case 'lineups':      return getCacheTTL('bsd_lineups',      6 * 3600 * 1000);
      case 'shotmap':      return getCacheTTL('bsd_shotmap',      2 * 60 * 1000);
      case 'incidents':    return getCacheTTL('bsd_incidents',    60 * 1000);
      case 'predictions':  return getCacheTTL('bsd_predictions',  6 * 3600 * 1000);
      case 'polymarket':   return getCacheTTL('bsd_polymarket',   5 * 60 * 1000);
      case 'broadcasts':   return getCacheTTL('bsd_broadcasts',   24 * 3600 * 1000);
      case 'compare_odds': return getCacheTTL('bsd_compare_odds', 5 * 60 * 1000);
      case 'social':       return getCacheTTL('bsd_social',       30 * 60 * 1000);
      case 'best_odds':    return getCacheTTL('bsd_best_odds',    5 * 60 * 1000);
      case 'clips':        return getCacheTTL('bsd_clips',        24 * 3600 * 1000);
      default: return undefined;
    }
  }
});

function _bsdResolveEventId(matchId) {
  // Accepte: id frontend (ex "bsd_207463_2026-05-21"), _bsd_event_id direct (int), fixture_id
  if (!matchId) return null;
  const s = String(matchId).trim();
  if (/^\d+$/.test(s)) return s;
  // Lookup db.matches
  const m = db.matches.find(x => x.id === s) ||
            db.matches.find(x => String(x.fixture_id) === s) ||
            (typeof cachedMatches !== 'undefined' && cachedMatches.find(x => x.id === s));
  if (m && m._bsd_event_id) return String(m._bsd_event_id);
  // Parse pattern bsd_<id>_<date>
  const mm = s.match(/^bsd_(\d+)_/);
  if (mm) return mm[1];
  return null;
}

async function _bsdEnrichFetch(kind, eventId) {
  const cacheKey = `bsd_enrich_${kind}_${eventId}`;
  const ttl = BSD_ENRICH_TTL[kind] || 5 * 60 * 1000;
  const cached = apiCacheGet(cacheKey);
  if (cached !== null && cached !== undefined) {
    return { data: cached === '__NEG__' ? null : cached, cached: true };
  }
  let endpoint = null;
  // bd c81b fix : bsdFetch ajoute prefix /api/ deja, donc relative path sans /api/api/ double
  switch (kind) {
    case 'lineups':     endpoint = `/v2/events/${eventId}/lineups/`; break;
    // bd j6pz fix : endpoint correct = /v2/events/{id}/stats/ (retourne shotmap+stats+momentum+xg_per_minute+avg_positions)
    // L'ancien /shotmap/ retournait 404 (n'existe pas). Preserve key 'shotmap' pour rétrocompat lookup cache.
    case 'shotmap':     endpoint = `/v2/events/${eventId}/stats/`; break;
    case 'incidents':   endpoint = `/v2/events/${eventId}/incidents/`; break;
    case 'predictions': endpoint = `/predictions/?event=${eventId}`; break;
    case 'polymarket':  endpoint = `/odds/polymarket/?event=${eventId}`; break;
    case 'broadcasts':  endpoint = `/broadcasts/?event=${eventId}`; break;
    case 'compare_odds': endpoint = `/odds/compare/?event=${eventId}`; break;
    case 'social':      endpoint = `/v2/social/?event=${eventId}&limit=20`; break;
    case 'best_odds':   endpoint = `/v2/odds/best/?event=${eventId}`; break;  // bd j6pz Phase 2
    case 'clips':       endpoint = `/v2/events/${eventId}/clips/`; break;
    default: throw new Error(`unknown bsd kind: ${kind}`);
  }
  if (DEBUG_BSD) console.log(`[DEBUG COMPOS] Request URL: ${endpoint} (kind=${kind}, eventId=${eventId})`);
  const res = await bsdFetch(endpoint);
  if (!res || res.status !== 200 || !res.data) {
    if (DEBUG_BSD) console.log(`[DEBUG COMPOS] BSD upstream returned status=${res?.status} for ${endpoint}`);
    apiCacheSet(cacheKey, '__NEG__', `bsd_${kind}`, ttl);
    return { data: null, cached: false };
  }
  apiCacheSet(cacheKey, res.data, `bsd_${kind}`, ttl);
  return { data: res.data, cached: false };
}

const BSD_ENRICH_PATHS = ['lineups', 'shotmap', 'incidents', 'predictions', 'polymarket', 'broadcasts', 'compare_odds', 'social', 'best_odds'];

// bd j6pz Phase 2 — Bookmakers registry global BSD (pas per-event). Cache 24h.
let _bsdBookmakersCache = null;
let _bsdBookmakersCacheAt = 0;
const BSD_BOOKMAKERS_TTL = 24 * 3600 * 1000;
async function bsdFetchBookmakers() {
  const now = Date.now();
  if (_bsdBookmakersCache && (now - _bsdBookmakersCacheAt) < BSD_BOOKMAKERS_TTL) {
    return { data: _bsdBookmakersCache, cached: true };
  }
  const res = await bsdFetch('/v2/bookmakers/');
  if (!res || res.status !== 200 || !res.data) return { data: null, cached: false };
  _bsdBookmakersCache = res.data;
  _bsdBookmakersCacheAt = now;
  return { data: res.data, cached: false };
}

// ═══════════════════════════════════════════════════════════════════════════════
// bd cy9h — Context Engine météo partial (innovation backlog ligne 259)
//
// Open-Meteo API zero-key (https://open-meteo.com) :
//   * Geocoding API (search city → lat/lon/country)
//   * Forecast API (hourly temp/precipitation/wind 16d max)
//   * Pas de signup, pas de rate limit hard public usage
//
// Cache strategy :
//   * geocode → api_cache key geo_<normName> TTL 30d (rarely change)
//   * weather → api_cache key weather_<matchId> TTL 1h (forecast stable courte fenêtre)
//
// Use case edge math (future) : pluie >3mm/h corrélée -8% λ both sides
// (passes longues moins précises, contrôle balle dégradé).
// ═══════════════════════════════════════════════════════════════════════════════
async function _geocodeCity(name) {
  if (!name || typeof name !== 'string') return null;
  const cacheKey = `geo_${normName(name)}`;
  const cached = apiCacheGet(cacheKey);
  if (cached) return cached;
  if (cached === null) return null; // neg cache hit (apiCacheGet returns null on miss too — but we save explicitly below)
  try {
    const res = await httpsGet(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(name)}&count=1&language=fr`, {}, 8000);
    if (res && res.status === 200 && res.data && Array.isArray(res.data.results) && res.data.results.length > 0) {
      const r = res.data.results[0];
      const out = { lat: r.latitude, lon: r.longitude, name: r.name, country: r.country_code };
      apiCacheSet(cacheKey, out, 'open_meteo_geo', 30 * 24 * 3600 * 1000);
      return out;
    }
  } catch (_) { /* swallow */ }
  return null;
}

async function _fetchOpenMeteoForecast(lat, lon, kickoffIso) {
  if (typeof lat !== 'number' || typeof lon !== 'number') return null;
  try {
    const url = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&hourly=temperature_2m,precipitation,wind_speed_10m,weather_code&timezone=auto&forecast_days=2`;
    const res = await httpsGet(url, {}, 8000);
    if (!res || res.status !== 200 || !res.data || !res.data.hourly || !Array.isArray(res.data.hourly.time)) return null;
    const h = res.data.hourly;
    // Find closest hour to kickoff time
    const kickoffMs = Date.parse(kickoffIso);
    if (!Number.isFinite(kickoffMs)) return null;
    let bestIdx = 0, bestDiff = Infinity;
    for (let i = 0; i < h.time.length; i++) {
      const diff = Math.abs(Date.parse(h.time[i]) - kickoffMs);
      if (diff < bestDiff) { bestDiff = diff; bestIdx = i; }
    }
    return {
      time: h.time[bestIdx],
      temp_c: h.temperature_2m ? h.temperature_2m[bestIdx] : null,
      precipitation_mm: h.precipitation ? h.precipitation[bestIdx] : null,
      wind_kmh: h.wind_speed_10m ? h.wind_speed_10m[bestIdx] : null,
      weather_code: h.weather_code ? h.weather_code[bestIdx] : null,
    };
  } catch (_) { return null; }
}

// WMO weather code → label FR + icon emoji (subset commun matches sport)
function _weatherCodeLabel(code) {
  if (code == null) return { label: 'inconnu', icon: '·' };
  const c = Number(code);
  if (c === 0) return { label: 'ensoleillé', icon: '☀' };
  if (c >= 1 && c <= 3) return { label: 'nuageux', icon: '⛅' };
  if (c >= 45 && c <= 48) return { label: 'brouillard', icon: '🌫' };
  if (c >= 51 && c <= 57) return { label: 'bruine', icon: '🌦' };
  if (c >= 61 && c <= 67) return { label: 'pluie', icon: '🌧' };
  if (c >= 71 && c <= 77) return { label: 'neige', icon: '🌨' };
  if (c >= 80 && c <= 82) return { label: 'averses', icon: '🌦' };
  if (c >= 95 && c <= 99) return { label: 'orage', icon: '⛈' };
  return { label: 'variable', icon: '·' };
}

// ═══════════════════════════════════════════════════════════════════════════════
// bd i8gw — Context Engine kilométrage déplacements (innovation backlog finalize)
//
// Compute distance jet-lag travel équipe extérieure → stade match. Edge math :
// distance >500km corrélée fatigue/perf dégradée joueurs visiteurs (passes,
// duels, finissage). Réutilise _geocodeCity bd cy9h + cache api_cache.
//
// Fatigue factor heuristique (deferred edge math sur λ_away) :
//   <300km   ×1.00 (déplacement local, pas d'impact)
//   300-500  ×0.98
//   500-1000 ×0.95
//   1000-2500 ×0.92
//   >2500    ×0.88 (intercontinental, jet-lag majeur)
// ═══════════════════════════════════════════════════════════════════════════════
function _haversineKm(lat1, lon1, lat2, lon2) {
  if (typeof lat1 !== 'number' || typeof lon1 !== 'number' || typeof lat2 !== 'number' || typeof lon2 !== 'number') return null;
  const R = 6371; // earth radius km
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat / 2) ** 2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) ** 2;
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return Math.round(R * c);
}

function _travelFatigueFactor(km) {
  if (km == null) return 1.0;
  if (km < 300) return 1.0;
  if (km < 500) return 0.98;
  if (km < 1000) return 0.95;
  if (km < 2500) return 0.92;
  return 0.88;
}

async function computeMatchTravelDistance(match) {
  if (!match || !match.id) return null;
  const cacheKey = `travel_${match.id}`;
  const cached = apiCacheGet(cacheKey);
  if (cached) return cached;

  // Geocode home venue/city (réutilise chain identique fetchWeatherForMatch)
  const homeCands = [match.venue_city, match.venue, match.home_team_city, match.home_team].filter(c => c && typeof c === 'string');
  let homeGeo = null;
  for (const c of homeCands) {
    homeGeo = await _geocodeCity(c);
    if (homeGeo) break;
  }
  // Geocode away team city
  const awayCands = [match.away_team_city, match.away_team].filter(c => c && typeof c === 'string');
  let awayGeo = null;
  for (const c of awayCands) {
    awayGeo = await _geocodeCity(c);
    if (awayGeo) break;
  }
  if (!homeGeo || !awayGeo) return null;
  const km = _haversineKm(homeGeo.lat, homeGeo.lon, awayGeo.lat, awayGeo.lon);
  if (km == null) return null;
  const out = {
    distance_km: km,
    home_city: homeGeo.name,
    home_country: homeGeo.country,
    away_city: awayGeo.name,
    away_country: awayGeo.country,
    fatigue_factor: _travelFatigueFactor(km),
    bucket: km < 300 ? 'local' : km < 500 ? 'court' : km < 1000 ? 'moyen' : km < 2500 ? 'long' : 'intercontinental',
  };
  apiCacheSet(cacheKey, out, 'context_travel', 30 * 24 * 3600 * 1000);
  return out;
}

async function fetchWeatherForMatch(match) {
  if (!match || !match.commence_time) return null;
  const cacheKey = `weather_${match.id || ''}`;
  if (!match.id) return null;
  const cached = apiCacheGet(cacheKey);
  if (cached) return cached;
  // Chain candidates pour geocode (best effort)
  const candidates = [match.venue_city, match.venue, match.home_team_city, match.home_team].filter(c => c && typeof c === 'string');
  let geo = null;
  for (const c of candidates) {
    geo = await _geocodeCity(c);
    if (geo) break;
  }
  if (!geo) return null;
  const forecast = await _fetchOpenMeteoForecast(geo.lat, geo.lon, match.commence_time);
  if (!forecast) return null;
  const labelInfo = _weatherCodeLabel(forecast.weather_code);
  const out = {
    ...forecast,
    city: geo.name,
    country: geo.country,
    label_fr: labelInfo.label,
    icon: labelInfo.icon,
    geocode_from: candidates[0] || null,
  };
  apiCacheSet(cacheKey, out, 'open_meteo_weather', 3600 * 1000);
  return out;
}

// bd 82th — BSD Phase 4 fetchers per-id (referees + venues + leagues). Cache plus long.
const BSD_REFEREE_TTL = 24 * 3600 * 1000; // career stats consolidated (Bzzoiro v2 — stable)
const BSD_VENUE_TTL = 12 * 3600 * 1000;
const BSD_LEAGUE_TTL = 24 * 3600 * 1000;
const _bsdRefereeCache = new Map();   // id -> {data, ts}
const _bsdVenueCache = new Map();
const _bsdLeagueCache = new Map();

async function bsdFetchById(kind, id) {
  if (!id || !/^\d+$/.test(String(id))) return { data: null, cached: false };
  let cache, ttl, path;
  if (kind === 'referee') { cache = _bsdRefereeCache; ttl = BSD_REFEREE_TTL; path = `/v2/referees/${id}/`; }
  else if (kind === 'venue') { cache = _bsdVenueCache; ttl = BSD_VENUE_TTL; path = `/v2/venues/${id}/`; }
  else if (kind === 'league') { cache = _bsdLeagueCache; ttl = BSD_LEAGUE_TTL; path = `/v2/leagues/${id}/`; }
  else return { data: null, cached: false };
  const now = Date.now();
  const cached = cache.get(String(id));
  if (cached && (now - cached.ts) < ttl) return { data: cached.data, cached: true };
  const res = await bsdFetch(path);
  if (!res || res.status !== 200 || !res.data) {
    cache.set(String(id), { data: null, ts: now }); // neg cache
    return { data: null, cached: false };
  }
  cache.set(String(id), { data: res.data, ts: now });
  return { data: res.data, cached: false };
}

// BSD v2 — event-level referee cache (5min — handles last-minute swap per Bzzoiro announcement)
const _bsdEventRefCache = new Map();
const BSD_EVENT_REF_TTL = 5 * 60 * 1000;

// Fetches live referee from /api/v2/events/{id}/ then career profile from /api/v2/referees/{id}/.
// Returns normalized object {id, name, country, country_code, games, yc_total, rc_total, yc_per_game, rc_per_game}.
async function fetchBSDRefereeForMatch(match) {
  const eid = match._bsd_event_id ? String(match._bsd_event_id) : null;
  if (!eid) return null;
  const cKey = `ev_ref_${eid}`;
  const cached = _bsdEventRefCache.get(cKey);
  if (cached && (Date.now() - cached.ts) < BSD_EVENT_REF_TTL) return cached.data;
  try {
    const evRes = await bsdFetch(`/api/v2/events/${eid}/`);
    const ev = evRes?.data;
    if (!ev) return null;
    const refObj = typeof ev.referee === 'object' && ev.referee !== null ? ev.referee : null;
    const refId = refObj?.id != null ? String(refObj.id) : null;
    const refName = refObj?.name || (typeof ev.referee === 'string' ? ev.referee : null);
    if (!refName && !refId) return null;
    let profile = null;
    if (refId) {
      const { data } = await bsdFetchById('referee', refId);
      profile = data;
    }
    // Normalise across possible BSD v2 response shapes
    const games   = profile?.matches ?? profile?.statistics?.matches ?? profile?.games ?? null;
    const ycTotal = profile?.yellowCards ?? profile?.statistics?.yellowCards ?? profile?.yellow_cards ?? null;
    const rcTotal = profile?.redCards ?? profile?.statistics?.redCards ?? profile?.red_cards ?? null;
    const ycPG    = games && ycTotal != null ? Math.round((ycTotal / games) * 10) / 10
                  : (profile?.yellowCardsPerGame ?? profile?.yc_per_game ?? null);
    const rcPG    = games && rcTotal != null ? Math.round((rcTotal / games) * 100) / 100
                  : (profile?.redCardsPerGame ?? profile?.rc_per_game ?? null);
    const result = {
      id:           refId,
      name:         refName || profile?.name || null,
      country:      refObj?.country || profile?.country || null,
      country_code: (refObj?.country_code || profile?.country_code || '').toLowerCase() || null,
      games,
      yc_total: ycTotal,
      rc_total: rcTotal,
      yc_per_game: ycPG,
      rc_per_game: rcPG,
    };
    _bsdEventRefCache.set(cKey, { data: result, ts: Date.now() });
    return result;
  } catch (_) {
    return null;
  }
}

// bd ueg0 — Sentiment heuristique léger sur texte tweet/news. Pas d'ML : keyword scoring rapide.
// Retourne {score: -1..+1, label: 'positive'|'neutral'|'negative'}.
function computeSocialSentiment(text) {
  if (!text || typeof text !== 'string') return { score: 0, label: 'neutral' };
  const t = text.toLowerCase();
  const positive = /\b(win|won|wins|victory|champion|champions|title|trophy|trophée|trophy|gagn[éeèe]|victoire|amazing|stunner|brilliant|magnifique|incroyable|hat[- ]?trick|goal of the season|goal of the month|🏆|🎉|🔥|💪|⭐|🌟|👏)\b/g;
  const negative = /\b(lose|lost|loss|defeat|defeated|injury|injured|blessé|blessure|broken|fracture|déception|disappointing|crisis|crise|sacked|fired|limogé|terrible|awful|😢|💔|😞)\b/g;
  const pos = (t.match(positive) || []).length;
  const neg = (t.match(negative) || []).length;
  const score = (pos - neg) / Math.max(1, pos + neg);
  const label = score > 0.2 ? 'positive' : score < -0.2 ? 'negative' : 'neutral';
  return { score: Math.round(score * 100) / 100, label };
}

// bd ueg0 — Aggregate social buzz : count + sentiment moyen + breakdown types.
function aggregateSocialBuzz(items) {
  if (!Array.isArray(items) || items.length === 0) {
    return { count: 0, sentiment_score: 0, sentiment_label: 'neutral', by_type: {}, top_items: [] };
  }
  let totalScore = 0;
  const byType = {};
  for (const it of items) {
    const text = `${it.text || ''} ${it.title || ''}`;
    const s = computeSocialSentiment(text);
    it._sentiment = s;
    totalScore += s.score;
    const tp = it.type || 'unknown';
    byType[tp] = (byType[tp] || 0) + 1;
  }
  const avg = totalScore / items.length;
  return {
    count: items.length,
    sentiment_score: Math.round(avg * 100) / 100,
    sentiment_label: avg > 0.2 ? 'positive' : avg < -0.2 ? 'negative' : 'neutral',
    by_type: byType,
    top_items: items.slice(0, 10).map(it => ({
      id: it.id,
      type: it.type,
      url: it.url,
      text: it.text,
      title: it.title,
      thumbnail: it.thumbnail,
      account: it.account ? { handle: it.account.handle, name: it.account.name, verified: !!it.account.verified } : null,
      published_at: it.published_at,
      sentiment: it._sentiment || { score: 0, label: 'neutral' },
    })),
  };
}
