              const xgH = detail?.actual_home_xg ?? detail?.home_xg_live ?? null;
              const xgA = detail?.actual_away_xg ?? detail?.away_xg_live ?? null;
              recordLiveXGSnapshot(m.id, minute, xgH, xgA);
