// bd dl49 Phase 3 — daily ETL accumulation tennis_matches_internal.
// Spawn child process (isolated, no main-thread block during ~5s SQL+parse work).
// Schedule: 02:00 Europe/Paris (off-peak, after BSD/ESPN end-of-day snapshots cron).
function _runTennisInternalEtlJob() {
  return new Promise((resolve) => {
    const cp = require('child_process');
    const etlPath = require('path').join(__dirname, 'tools', 'build-tennis-internal-history.js');
    console.log('  [Cron:TennisInternalETL] Lancement build-tennis-internal-history…');
    const t0 = Date.now();
    const child = cp.spawn(process.execPath, [etlPath], {
      cwd: __dirname,
      env: process.env,
      stdio: ['ignore', 'pipe', 'pipe'],
    });
    let stderrTail = '';
    let stdoutTail = '';
    child.stdout.on('data', (b) => { stdoutTail = (stdoutTail + b.toString()).slice(-2000); });
    child.stderr.on('data', (b) => { stderrTail = (stderrTail + b.toString()).slice(-2000); });
    child.on('close', (code) => {
      const elapsed = Date.now() - t0;
      const _sm = stdoutTail.match(/total\s*:\s*(\d+)/); const summary = _sm ? _sm[1] : '?';
      if (code === 0) {
        console.log(`  [Cron:TennisInternalETL] ✓ ETL OK (${elapsed}ms, total=${summary})`);
      } else {
        console.warn(`  [Cron:TennisInternalETL] ⚠ exit=${code} (${elapsed}ms) stderr: ${stderrTail.slice(-300)}`);
      }
      resolve();
    });
    child.on('error', (err) => {
      console.warn('  [Cron:TennisInternalETL] spawn error:', err.message);
      resolve();
    });
  });
}
(function _scheduleTennisInternalEtl() {
  const delayMs = _msUntilNextParisHour(2);
  const nextRun = new Date(Date.now() + delayMs);
  console.log(`  [Cron:TennisInternalETL] schedulé · prochain run ${nextRun.toISOString()} (~${Math.round(delayMs/60000)}min)`);
  setTimeout(() => {
    _runTennisInternalEtlJob();
    setInterval(_runTennisInternalEtlJob, 24 * 3600 * 1000).unref();
  }, delayMs).unref();
})();

(function _scheduleSPSUpdater() {
  const delayMs = _msUntilNextParisHour(2) + 5 * 60 * 1000;
  const nextRun = new Date(Date.now() + delayMs);
  console.log(`  [Cron:SPS] schedulé · prochain run ${nextRun.toISOString()} (~${Math.round(delayMs/60000)}min)`);
  function _runSPS() {
    const cp = require('child_process');
    const spsPath = require('path').join(__dirname, 'cron_sps_updater.py');
    console.log('  [Cron:SPS] démarrage cron_sps_updater.py…');
    const spsEnv = Object.assign({}, process.env, { PARISCORE_LOOKAHEAD_MIN: '0', PARISCORE_LOOKAHEAD_MAX: '48' });
    const child = cp.spawn('python3', [spsPath], { cwd: __dirname, env: spsEnv, stdio: ['ignore', 'pipe', 'pipe'] });
    child.stdout.on('data', d => process.stdout.write('[Cron:SPS] ' + d));
    child.stderr.on('data', d => process.stderr.write('[Cron:SPS] ' + d));
    child.on('exit', code => console.log(`  [Cron:SPS] terminé (exit ${code})`));
    child.on('error', err => console.warn('  [Cron:SPS] spawn error:', err.message));
  }
  setTimeout(() => { _runSPS(); setInterval(_runSPS, 24 * 3600 * 1000).unref(); }, delayMs).unref();
})();

